"use client";

import { useState, useEffect } from "react";
import dynamic from "next/dynamic";
import TweetGenerator from "@/components/TweetGenerator";
import AccountAnalyzer from "@/components/AccountAnalyzer";
import ThreadBuilder from "@/components/ThreadBuilder";
import ReplyGenerator from "@/components/ReplyGenerator";
import QuoteGenerator from "@/components/QuoteGenerator";
import { saveCustomPersona } from "@/lib/personas";
import { Persona, SavedPersona } from "@/types";

// Dynamic imports for client-only components
const HistoryPanel = dynamic(() => import("@/components/HistoryPanel"), { ssr: false });
const ThemeToggle = dynamic(() => import("@/components/ThemeToggle"), { ssr: false });
const SavedPersonas = dynamic(() => import("@/components/personas/SavedPersonas"), { ssr: false });
const ViralInspiration = dynamic(() => import("@/components/ViralInspiration"), { ssr: false });
const CompetitorAnalysis = dynamic(() => import("@/components/CompetitorAnalysis"), { ssr: false });
const Dashboard = dynamic(() => import("@/components/Dashboard"), { ssr: false });
const NotificationSettings = dynamic(() => import("@/components/NotificationSettings"), { ssr: false });

type TabType = "generate" | "thread" | "reply" | "quote" | "analyze" | "personas" | "viral" | "competitors" | "dashboard" | "notifications";

export default function Home() {
  const [activeTab, setActiveTab] = useState<TabType>("generate");
  const [refreshKey, setRefreshKey] = useState(0);
  const [historyOpen, setHistoryOpen] = useState(false);
  const [mounted, setMounted] = useState(false);

  useEffect(() => {
    setMounted(true);
  }, []);

  const [selectedPersonaId, setSelectedPersonaId] = useState<string | undefined>();

  const handlePersonaCreated = (persona: Persona) => {
    saveCustomPersona(persona);
    setRefreshKey(prev => prev + 1);
    setActiveTab("personas");
  };

  const handleUsePersona = (persona: SavedPersona) => {
    setSelectedPersonaId(persona.id);
    setRefreshKey(prev => prev + 1);
    setActiveTab("generate");
  };

  // State for viral inspiration prefilled topic
  const [inspireTopic, setInspireTopic] = useState<string | undefined>();

  const handleInspire = (topic: string, _style: string) => {
    setInspireTopic(topic);
    setActiveTab("generate");
  };

  const handleCompetitorPersona = (persona: { name: string; style: string; tone: string }) => {
    // For now, just switch to generate tab - persona can be used manually
    console.log("Competitor persona:", persona);
    setActiveTab("generate");
  };

  const tabs = [
    { id: "generate" as TabType, label: "Tweet", icon: "⚡", gradient: "from-red-500 to-rose-600" },
    { id: "thread" as TabType, label: "Thread", icon: "🧵", gradient: "from-purple-500 to-pink-600" },
    { id: "reply" as TabType, label: "Reply", icon: "💬", gradient: "from-cyan-500 to-blue-600" },
    { id: "quote" as TabType, label: "Quote", icon: "🔁", gradient: "from-amber-500 to-orange-600" },
    { id: "analyze" as TabType, label: "Analiz", icon: "🔍", gradient: "from-emerald-500 to-teal-600" },
    { id: "personas" as TabType, label: "Personalar", icon: "👤", gradient: "from-indigo-500 to-purple-600" },
    { id: "viral" as TabType, label: "Viral Ilham", icon: "🔥", gradient: "from-orange-500 to-red-600" },
    { id: "competitors" as TabType, label: "Rakipler", icon: "🎯", gradient: "from-teal-500 to-cyan-600" },
    { id: "dashboard" as TabType, label: "Dashboard", icon: "📊", gradient: "from-violet-500 to-purple-600" },
    { id: "notifications" as TabType, label: "Bildirimler", icon: "🔔", gradient: "from-yellow-500 to-amber-600" },
  ];

  return (
    <main className="min-h-screen bg-gradient-to-br from-gray-900 to-black p-4 md:p-8 transition-colors duration-300">
      <div className="max-w-4xl mx-auto">
        {/* Top Bar */}
        {mounted && (
          <div className="flex justify-end gap-2 mb-4">
            <button
              onClick={() => setHistoryOpen(true)}
              className="p-2 rounded-full bg-gray-800 hover:bg-gray-700 transition-colors"
              title="Tweet Geçmişi"
            >
              <span className="text-xl">📚</span>
            </button>
            <ThemeToggle />
          </div>
        )}

        <header className="text-center mb-8">
          <h1 className="text-4xl md:text-5xl font-bold text-white mb-3">
            <span className="text-red-500">X</span>patla Clone
          </h1>
          <p className="text-gray-400 text-lg">
            X'te viral olmak artık kolay
          </p>
        </header>

        {/* Tab Navigation - XPatla Style */}
        <div className="flex justify-center mb-8">
          <div className="inline-flex flex-wrap justify-center gap-1 bg-gray-800/50 backdrop-blur rounded-xl p-1.5 shadow-lg border border-gray-700/50">
            {tabs.map((tab) => (
              <button
                key={tab.id}
                onClick={() => setActiveTab(tab.id)}
                className={`px-4 py-2.5 rounded-lg font-medium transition-all text-sm ${
                  activeTab === tab.id
                    ? `bg-gradient-to-r ${tab.gradient} text-white shadow-md`
                    : "text-gray-400 hover:text-white"
                }`}
              >
                {tab.icon} {tab.label}
              </button>
            ))}
          </div>
        </div>

        {/* Tab Content */}
        {activeTab === "generate" && <TweetGenerator refreshKey={refreshKey} selectedPersonaId={selectedPersonaId} inspireTopic={inspireTopic} />}
        {activeTab === "thread" && <ThreadBuilder refreshKey={refreshKey} selectedPersonaId={selectedPersonaId} />}
        {activeTab === "reply" && <ReplyGenerator refreshKey={refreshKey} selectedPersonaId={selectedPersonaId} />}
        {activeTab === "quote" && <QuoteGenerator refreshKey={refreshKey} selectedPersonaId={selectedPersonaId} />}
        {activeTab === "analyze" && <AccountAnalyzer onPersonaCreated={handlePersonaCreated} />}
        {activeTab === "personas" && <SavedPersonas onUsePersona={handleUsePersona} refreshKey={refreshKey} />}
        {activeTab === "viral" && <ViralInspiration onInspire={handleInspire} />}
        {activeTab === "competitors" && <CompetitorAnalysis onUsePersona={handleCompetitorPersona} />}
        {activeTab === "dashboard" && <Dashboard />}
        {activeTab === "notifications" && <NotificationSettings />}
      </div>

      {/* History Panel */}
      <HistoryPanel isOpen={historyOpen} onClose={() => setHistoryOpen(false)} />
    </main>
  );
}

