    21→  styleAnalysis: StyleAnalysis;  // Detaylı stil analizi
    22→  createdAt: string;
    23→  updatedAt: string;
    24→  tweetCount: number;            // Bu persona ile üretilen tweet sayısı
    25→}
    26→
    27→export interface StyleAnalysis {
    28→  tone: string;
    29→  topics: string[];
    30→  emojiUsage: "none" | "minimal" | "moderate" | "heavy";
    31→  hashtagUsage: "none" | "minimal" | "moderate" | "heavy";
    32→  averageLength: number;
    33→  writingStyle: string;
