    42→export interface AnalyzeResponse {
    43→  success: boolean;
    44→  data?: {
    45→    username: string;
    46→    displayName: string;
    47→    bio: string;
    48→    tweets: string[];
    49→    analysis: StyleAnalysis;
    50→    persona: Persona;
    51→  };
    52→  error?: string;
    53→}
    54→
    55→// Tweet Format Tipleri (XPatla benzeri)
    56→export type TweetFormat = "micro" | "normal" | "thunder" | "thread";
    57→
    58→export interface TweetGenerationRequest {
    59→  topic: string;
    60→  persona: string;
    61→  length: "short" | "medium" | "long";
    62→  tone: string;
    63→  format?: TweetFormat;
    64→  threadLength?: 3 | 5 | 10;
    65→}
    66→
    67→// Thread için özel tip
    68→export interface ThreadTweet {
    69→  position: number;
    70→  content: string;
    71→  isHook?: boolean; // İlk tweet mi
    72→}
    73→
    74→export interface GeneratedThread {
    75→  tweets: ThreadTweet[];
    76→  topic: string;
    77→  totalScore: number;
    78→  reasoning: string;
    79→}
    80→
    81→export interface TweetScore {
    82→  hook_strength: number;
    83→  engagement_potential: number;
    84→  algorithm_fit: number;
    85→  persona_match: number;
    86→  originality: number;
    87→  total: number;
    88→}
    89→
    90→// X Algorithm Enhanced Score (Based on Phoenix model)
    91→export interface XAlgorithmScore {
    92→  total: number;
    93→  hook_strength: number;
    94→  engagement_potential: number;
    95→  viral_potential: number;
    96→  algorithm_fit: number;
    97→  content_quality: number;
    98→  predictions: EngagementPredictions;
    99→  strengths: string[];
   100→  improvements: string[];
   101→}
   102→
   103→// Engagement predictions (19 key action types inspired by X Algorithm's Phoenix model)
   104→export interface EngagementPredictions {
   105→  // Core engagement (12 original)
   106→  favorite_score: number;       // Like olasılığı
   107→  reply_score: number;          // Yanıt olasılığı
   108→  repost_score: number;         // Retweet olasılığı
   109→  click_score: number;          // Tıklama olasılığı
   110→  profile_click_score: number;  // Profil ziyareti olasılığı
   111→  share_score: number;          // Paylaşım olasılığı
   112→  dwell_score: number;          // Tweet üzerinde kalma süresi
   113→  quote_score: number;          // Quote tweet olasılığı
   114→  follow_author_score: number;  // Takip olasılığı
   115→  bookmark_score: number;       // Kaydetme olasılığı
   116→
   117→  // Extended engagement (Faz 2 - 7 new)
   118→  photo_expand_score: number;       // Fotoğraf genişletme
   119→  share_via_dm_score: number;       // DM ile paylaşım
   120→  share_via_copy_link_score: number; // Link kopyalama
   121→  cont_dwell_time_score: number;    // Sürekli okuma
   122→  quoted_click_score: number;       // Alıntı tıklama
   123→
   124→  // Negatif sinyaller (enhanced)
   125→  not_interested_score: number; // İlgilenmiyorum olasılığı
   126→  skip_score: number;           // Atlama olasılığı
   127→  block_author_score: number;   // Engelleme riski
   128→  mute_author_score: number;    // Sessize alma riski
   129→  report_score: number;         // Şikayet riski
   130→}
   131→
   132→// Faz 3: Sentiment Analysis
   133→export interface SentimentAnalysis {
   134→  score: number;                // -1 to 1
   135→  label: 'positive' | 'negative' | 'neutral';
   136→  confidence: number;           // 0-1
   137→  toxicityRisk: number;         // 0-1
   138→  positiveWords: string[];
   139→  negativeWords: string[];
   140→  toxicWords: string[];
   141→  recommendation: string;
   142→}
   143→
   144→// Faz 3: Hashtag Analysis
   145→export interface HashtagAnalysis {
   146→  hashtags: string[];
   147→  count: number;
   148→  qualityScore: number;         // 0-100
   149→  isOptimalCount: boolean;      // 1-2 ideal
   150→  issues: string[];
   151→  recommendations: string[];
   152→}
   153→
   154→// Faz 3: Posting Time Recommendation
   155→export interface PostingTimeRecommendation {
   156→  currentHour: number;
   157→  currentDay: string;
   158→  timezone: string;
   159→  isOptimalNow: boolean;
   160→  currentTimeScore: number;     // 0-100
   161→  bestTimesToday: string[];
   162→  bestDays: string[];
   163→  recommendation: string;
   164→  schedule: {
   165→    day: string;
   166→    times: { hour: string; score: number; label: string }[];
   167→  }[];
   168→}
   169→
   170→// Faz 3: Comprehensive Analysis Result
   171→export interface ContentAnalysisResult {
   172→  xScore: XAlgorithmScore;
   173→  sentiment: SentimentAnalysis;
   174→  hashtags: HashtagAnalysis;
   175→  postingTime: PostingTimeRecommendation;
   176→  topRecommendations: string[];
   177→  alerts: string[];
   178→}
   179→
   180→export interface GeneratedTweet {
   181→  content: string;
   182→  score: TweetScore;
   183→  reasoning: string;
   184→  xScore?: XAlgorithmScore; // Enhanced X Algorithm score
   185→}
   186→
   187→export interface APIResponse {
   188→  success: boolean;
   189→  data?: GeneratedTweet | GeneratedTweet[];
   190→  error?: string;
   191→}
   192→
   193→// Tweet Geçmişi
   194→export interface HistoryItem {
   195→  id: string;
   196→  type: "tweet" | "thread" | "reply" | "quote";
   197→  content: string | ThreadTweet[];
   198→  topic: string;
   199→  persona: string;
   200→  personaId?: string;           // Bağlı persona ID'si
   201→  score: number;
   202→  isFavorite: boolean;
   203→  createdAt: string;
   204→  posted?: boolean;
   205→  postedAt?: string;
   206→  tweetId?: string;
   207→}
   208→
   209→// Tema
   210→export type Theme = "dark" | "light";
   211→
   212→// ============================================
   213→// Strict Enum Types (Faz 2)
   214→// ============================================
   215→
   216→export type TweetLength = "short" | "medium" | "long";
   217→export type TweetTone = "professional" | "casual" | "humorous" | "inspiring" | "educational";
   218→export type ReplyStyle = "agree" | "disagree" | "question" | "add_value" | "witty";
   219→export type QuoteStyle = "insight" | "hot_take" | "story" | "data" | "contrarian";
   220→
   221→// ============================================
   222→// Discriminated History Types (Faz 2)
   223→// ============================================
   224→
   225→export interface TweetHistoryItem extends Omit<HistoryItem, 'content' | 'type'> {
   226→  type: 'tweet';
   227→  content: string;
   228→}
   229→
   230→export interface ThreadHistoryItem extends Omit<HistoryItem, 'content' | 'type'> {
   231→  type: 'thread';
   232→  content: ThreadTweet[];
   233→}
   234→
   235→export interface QuoteHistoryItem extends Omit<HistoryItem, 'content' | 'type'> {
   236→  type: 'quote';
   237→  content: string;
   238→}
   239→
   240→export interface ReplyHistoryItem extends Omit<HistoryItem, 'content' | 'type'> {
   241→  type: 'reply';
   242→  content: string;
   243→}
   244→
   245→export type DiscriminatedHistoryItem =
   246→  | TweetHistoryItem
   247→  | ThreadHistoryItem
   248→  | QuoteHistoryItem
   249→  | ReplyHistoryItem;
   250→
   251→// ============================================
   252→// Type Guards (Faz 2)
   253→// ============================================
   254→
   255→export function isTweetHistory(item: HistoryItem): item is TweetHistoryItem {
   256→  return item.type === 'tweet' && typeof item.content === 'string';
   257→}
   258→
   259→export function isThreadHistory(item: HistoryItem): item is ThreadHistoryItem {
   260→  return item.type === 'thread' && Array.isArray(item.content);
   261→}
   262→
