export interface Persona {
  id: string;
  name: string;
  description: string;
  style: string;
  tone: string;
  example_tweets: string[];
  isCustom?: boolean;
  sourceUsername?: string;
  analyzedAt?: string;
}

// Kaydedilmiş Persona (Analiz edilmiş hesaplar için genişletilmiş tip)
export interface SavedPersona extends Persona {
  isCustom: true;
  sourceUsername: string;
  analyzedAt: string;
  displayName: string;
  bio: string;
  originalTweets: string[];      // Analiz edilen orijinal tweet'ler
  styleAnalysis: StyleAnalysis;  // Detaylı stil analizi
  createdAt: string;
  updatedAt: string;
  tweetCount: number;            // Bu persona ile üretilen tweet sayısı
}

export interface StyleAnalysis {
  tone: string;
  topics: string[];
  emojiUsage: "none" | "minimal" | "moderate" | "heavy";
  hashtagUsage: "none" | "minimal" | "moderate" | "heavy";
  averageLength: number;
  writingStyle: string;
  vocabulary: string;
  engagement_patterns: string[];
}

export interface AnalyzeRequest {
  username: string;
}

export interface AnalyzeResponse {
  success: boolean;
  data?: {
    username: string;
    displayName: string;
    bio: string;
    tweets: string[];
    analysis: StyleAnalysis;
    persona: Persona;
  };
  error?: string;
}

// Tweet Format Tipleri (XPatla benzeri)
export type TweetFormat = "micro" | "normal" | "thunder" | "thread";

export interface TweetGenerationRequest {
  topic: string;
  persona: string;
  length: "short" | "medium" | "long";
  tone: string;
  format?: TweetFormat;
  threadLength?: 3 | 5 | 10;
}

// Thread için özel tip
export interface ThreadTweet {
  position: number;
  content: string;
  isHook?: boolean; // İlk tweet mi
}

export interface GeneratedThread {
  tweets: ThreadTweet[];
  topic: string;
  totalScore: number;
  reasoning: string;
}

export interface TweetScore {
  hook_strength: number;
  engagement_potential: number;
  algorithm_fit: number;
  persona_match: number;
  originality: number;
  total: number;
}

// X Algorithm Enhanced Score (Based on Phoenix model)
export interface XAlgorithmScore {
  total: number;
  hook_strength: number;
  engagement_potential: number;
  viral_potential: number;
  algorithm_fit: number;
  content_quality: number;
  predictions: EngagementPredictions;
  strengths: string[];
  improvements: string[];
}

// Engagement predictions (19 key action types inspired by X Algorithm's Phoenix model)
export interface EngagementPredictions {
  // Core engagement (12 original)
  favorite_score: number;       // Like olasılığı
  reply_score: number;          // Yanıt olasılığı
  repost_score: number;         // Retweet olasılığı
  click_score: number;          // Tıklama olasılığı
  profile_click_score: number;  // Profil ziyareti olasılığı
  share_score: number;          // Paylaşım olasılığı
  dwell_score: number;          // Tweet üzerinde kalma süresi
  quote_score: number;          // Quote tweet olasılığı
  follow_author_score: number;  // Takip olasılığı
  bookmark_score: number;       // Kaydetme olasılığı

  // Extended engagement (Faz 2 - 7 new)
  photo_expand_score: number;       // Fotoğraf genişletme
  share_via_dm_score: number;       // DM ile paylaşım
  share_via_copy_link_score: number; // Link kopyalama
  cont_dwell_time_score: number;    // Sürekli okuma
  quoted_click_score: number;       // Alıntı tıklama

  // Negatif sinyaller (enhanced)
  not_interested_score: number; // İlgilenmiyorum olasılığı
  skip_score: number;           // Atlama olasılığı
  block_author_score: number;   // Engelleme riski
  mute_author_score: number;    // Sessize alma riski
  report_score: number;         // Şikayet riski
}

// Faz 3: Sentiment Analysis
export interface SentimentAnalysis {
  score: number;                // -1 to 1
  label: 'positive' | 'negative' | 'neutral';
  confidence: number;           // 0-1
  toxicityRisk: number;         // 0-1
  positiveWords: string[];
  negativeWords: string[];
  toxicWords: string[];
  recommendation: string;
}

// Faz 3: Hashtag Analysis
export interface HashtagAnalysis {
  hashtags: string[];
  count: number;
  qualityScore: number;         // 0-100
  isOptimalCount: boolean;      // 1-2 ideal
  issues: string[];
  recommendations: string[];
}

// Faz 3: Posting Time Recommendation
export interface PostingTimeRecommendation {
  currentHour: number;
  currentDay: string;
  timezone: string;
  isOptimalNow: boolean;
  currentTimeScore: number;     // 0-100
  bestTimesToday: string[];
  bestDays: string[];
  recommendation: string;
  schedule: {
    day: string;
    times: { hour: string; score: number; label: string }[];
  }[];
}

// Faz 3: Comprehensive Analysis Result
export interface ContentAnalysisResult {
  xScore: XAlgorithmScore;
  sentiment: SentimentAnalysis;
  hashtags: HashtagAnalysis;
  postingTime: PostingTimeRecommendation;
  topRecommendations: string[];
  alerts: string[];
}

export interface GeneratedTweet {
  content: string;
  score: TweetScore;
  reasoning: string;
  xScore?: XAlgorithmScore; // Enhanced X Algorithm score
}

export interface APIResponse {
  success: boolean;
  data?: GeneratedTweet | GeneratedTweet[];
  error?: string;
}

// Tweet Geçmişi
export interface HistoryItem {
  id: string;
  type: "tweet" | "thread" | "reply" | "quote";
  content: string | ThreadTweet[];
  topic: string;
  persona: string;
  personaId?: string;           // Bağlı persona ID'si
  score: number;
  isFavorite: boolean;
  createdAt: string;
  posted?: boolean;
  postedAt?: string;
  tweetId?: string;
}

// Tema
export type Theme = "dark" | "light";

// ============================================
// Strict Enum Types (Faz 2)
// ============================================

export type TweetLength = "short" | "medium" | "long";
export type TweetTone = "professional" | "casual" | "humorous" | "inspiring" | "educational";
export type ReplyStyle = "agree" | "disagree" | "question" | "add_value" | "witty";
export type QuoteStyle = "insight" | "hot_take" | "story" | "data" | "contrarian";

// ============================================
// Discriminated History Types (Faz 2)
// ============================================

export interface TweetHistoryItem extends Omit<HistoryItem, 'content' | 'type'> {
  type: 'tweet';
  content: string;
}

export interface ThreadHistoryItem extends Omit<HistoryItem, 'content' | 'type'> {
  type: 'thread';
  content: ThreadTweet[];
}

export interface QuoteHistoryItem extends Omit<HistoryItem, 'content' | 'type'> {
  type: 'quote';
  content: string;
}

export interface ReplyHistoryItem extends Omit<HistoryItem, 'content' | 'type'> {
  type: 'reply';
  content: string;
}

export type DiscriminatedHistoryItem =
  | TweetHistoryItem
  | ThreadHistoryItem
  | QuoteHistoryItem
  | ReplyHistoryItem;

// ============================================
// Type Guards (Faz 2)
// ============================================

export function isTweetHistory(item: HistoryItem): item is TweetHistoryItem {
  return item.type === 'tweet' && typeof item.content === 'string';
}

export function isThreadHistory(item: HistoryItem): item is ThreadHistoryItem {
  return item.type === 'thread' && Array.isArray(item.content);
}

export function isQuoteHistory(item: HistoryItem): item is QuoteHistoryItem {
  return item.type === 'quote' && typeof item.content === 'string';
}

export function isReplyHistory(item: HistoryItem): item is ReplyHistoryItem {
  return item.type === 'reply' && typeof item.content === 'string';
}

export function isStringContent(content: string | ThreadTweet[]): content is string {
  return typeof content === 'string';
}

export function isThreadContent(content: string | ThreadTweet[]): content is ThreadTweet[] {
  return Array.isArray(content);
}

// ============================================
// API Response Types (Faz 2)
// ============================================

export interface ApiResponse<T> {
  success: boolean;
  data?: T;
  error?: string;
  retryAfter?: number;
}

export interface ApiErrorResponse {
  success: false;
  error: string;
  retryAfter?: number;
}

export interface ApiSuccessResponse<T> {
  success: true;
  data: T;
}

// Type guards for API responses
export function isApiSuccess<T>(response: ApiResponse<T>): response is ApiSuccessResponse<T> {
  return response.success === true && response.data !== undefined;
}

export function isApiError<T>(response: ApiResponse<T>): response is ApiErrorResponse {
  return response.success === false;
}

// ============================================
// Viral Tweet Types (from scraper)
// ============================================

export interface ViralTweet {
  id?: string;
  tweetId: string;
  content: string;
  authorUsername: string;
  authorDisplayName?: string;
  likes: number;
  retweets: number;
  replies?: number;
  hookType: string;
  hookScore: number;
  sentiment?: string;
  scrapedAt?: string;
  createdAt?: string;
}

export interface PatternPerformance {
  pattern: string;
  avgEngagement: number;
  avgLikes: number;
  avgRetweets: number;
  count: number;
}

export interface CompetitorProfile {
  username: string;
  displayName: string;
  followers: number;
  avgLikes: number;
  avgRetweets: number;
  topTweets: ViralTweet[];
  hookDistribution: Record<string, number>;
  bestPostingHours: number[];
}

export interface NotificationConfig {
  telegramBotToken?: string;
  telegramChatId?: string;
  discordWebhookUrl?: string;
  enableViralAlerts: boolean;
  enablePostingReminders: boolean;
  enableDailyReport: boolean;
}

export interface ScraperApiResponse<T> {
  success: boolean;
  data?: T;
  error?: string;
  total?: number;
}

