    14→  inspireTopic?: string;
    15→}
    16→
    17→// Tweet format bilgileri
    18→const tweetFormats = [
    19→  {
    20→    id: "micro" as TweetFormat,
    21→    name: "Micro",
    22→    description: "Kısa, vurucu, tek satır",
