    41→    color: "from-red-500 to-rose-500"
    42→  }
    43→];
    44→
    45→export default function TweetGenerator({ refreshKey, selectedPersonaId, inspireTopic }: TweetGeneratorProps) {
    46→  const [formData, setFormData] = useState<TweetGenerationRequest>({
    47→    topic: "",
    48→    persona: "data_driven",
    49→    length: "medium",
    50→    tone: "Profesyonel",
    51→    format: "normal"
    52→  });
    53→
    54→  const [allPersonas, setAllPersonas] = useState<Persona[]>(defaultPersonas);
    55→  const [generatedTweets, setGeneratedTweets] = useState<GeneratedTweet[]>([]);
    56→  const [loading, setLoading] = useState(false);
    57→  const [error, setError] = useState<string | null>(null);
    58→  const [retryAfter, setRetryAfter] = useState<number | undefined>(undefined);
    59→  const [mounted, setMounted] = useState(false);
    60→  const [followerCount, setFollowerCount] = useState<number | undefined>(undefined);
    61→  const abortControllerRef = useRef<AbortController | null>(null);
    62→
    63→  useEffect(() => {
    64→    setMounted(true);
    65→    const custom = getCustomPersonas();
    66→    const saved = getSavedPersonas();
    67→    // Saved personaları da custom olarak ekle
    68→    const savedAsCustom = saved.map(p => ({
    69→      ...p,
    70→      isCustom: true as const,
    71→    }));
    72→    setAllPersonas([...savedAsCustom, ...custom, ...defaultPersonas]);
    73→  }, [refreshKey]);
    74→
    75→  // selectedPersonaId değiştiğinde persona'yı seç
    76→  useEffect(() => {
    77→    if (selectedPersonaId) {
    78→      const savedPersona = getSavedPersonaById(selectedPersonaId);
    79→      if (savedPersona) {
    80→        setFormData(prev => ({ ...prev, persona: savedPersona.id }));
    81→      }
    82→    }
    83→  }, [selectedPersonaId]);
    84→
    85→  // inspireTopic değiştiğinde topic'i ayarla (viral inspiration'dan gelen)
    86→  useEffect(() => {
    87→    if (inspireTopic) {
    88→      setFormData(prev => ({ ...prev, topic: inspireTopic }));
    89→    }
    90→  }, [inspireTopic]);
    91→
    92→  // Cleanup on unmount
    93→  useEffect(() => {
    94→    return () => {
    95→      abortControllerRef.current?.abort();
    96→    };
    97→  }, []);
    98→
    99→  const handleCancel = useCallback(() => {
   100→    abortControllerRef.current?.abort();
   101→    setLoading(false);
   102→    setError("Istek iptal edildi");
   103→  }, []);
   104→
   105→  // Hydration için: client mount olana kadar sadece default personaları göster
   106→  const displayPersonas = mounted ? allPersonas : defaultPersonas;
   107→
   108→  const handleSubmit = async (e: React.FormEvent) => {
   109→    e.preventDefault();
   110→
   111→    if (!formData.topic.trim()) {
   112→      setError("Lütfen bir konu girin");
   113→      return;
   114→    }
   115→
   116→    // Cancel any ongoing request
   117→    abortControllerRef.current?.abort();
   118→    abortControllerRef.current = new AbortController();
   119→
   120→    setLoading(true);
   121→    setError(null);
   122→    setRetryAfter(undefined);
   123→    setGeneratedTweets([]);
   124→
   125→    try {
   126→      const selectedPersona = allPersonas.find(p => p.id === formData.persona);
   127→
   128→      // Format'a göre length ayarla
