   139→
   140→      const response = await fetch("/api/generate", {
   141→        method: "POST",
   142→        headers: { "Content-Type": "application/json" },
   143→        body: JSON.stringify(requestBody),
   144→        signal: abortControllerRef.current.signal,
   145→      });
   146→
   147→      const result = await response.json();
   148→
   149→      if (result.success && result.data) {
   150→        const tweets = Array.isArray(result.data) ? result.data : [result.data];
   151→        setGeneratedTweets(tweets);
   152→
   153→        // Save to history
   154→        const selectedPersona = allPersonas.find(p => p.id === formData.persona);
   155→        const savedPersona = getSavedPersonaById(formData.persona);
   156→
   157→        tweets.forEach((tweet: GeneratedTweet) => {
   158→          addToHistory({
