   215→              id="topic"
   216→              rows={3}
   217→              value={formData.topic}
   218→              onChange={(e) => setFormData({ ...formData, topic: e.target.value })}
   219→              className="w-full px-4 py-3 bg-gray-900/50 border border-gray-700 rounded-xl focus:ring-2 focus:ring-red-500 focus:border-transparent text-white placeholder-gray-500 resize-none"
   220→              placeholder="Örn: Yapay zekanın geleceği hakkında düşüncelerim..."
   221→            />
   222→          </div>
   223→
   224→          {/* Tweet Format Selection - XPatla Style */}
   225→          <div>
   226→            <label className="block text-sm font-medium text-gray-300 mb-3">
