   239→                      : "border-gray-700 bg-gray-900/50 text-gray-400 hover:border-gray-600"
   240→                  }`}
   241→                >
   242→                  <div className="text-2xl mb-1" aria-hidden="true">{format.icon}</div>
   243→                  <div className="font-semibold text-sm">{format.name}</div>
