"use client";

import { useState, useEffect, useRef, useCallback } from "react";
import { defaultPersonas, getCustomPersonas, deleteCustomPersona } from "@/lib/personas";
import { GeneratedTweet, TweetGenerationRequest, Persona, TweetFormat } from "@/types";
import { addToHistory } from "@/lib/history";
import { getSavedPersonas, getSavedPersonaById, incrementPersonaTweetCount } from "@/lib/personaStorage";
import TweetDisplay from "./TweetDisplay";
import { LoadingButton, ErrorMessage } from "@/components/ui";

interface TweetGeneratorProps {
  refreshKey?: number;
  selectedPersonaId?: string;
  inspireTopic?: string;
}

// Tweet format bilgileri
const tweetFormats = [
  {
    id: "micro" as TweetFormat,
    name: "Micro",
    description: "Kısa, vurucu, tek satır",
    icon: "⚡",
    charLimit: "50-100",
    color: "from-yellow-500 to-orange-500"
  },
  {
    id: "normal" as TweetFormat,
    name: "Normal",
    description: "Standart tweet formatı",
    icon: "📝",
    charLimit: "150-280",
    color: "from-blue-500 to-indigo-500"
  },
  {
    id: "thunder" as TweetFormat,
    name: "Thunder",
    description: "Uzun, detaylı, hikaye",
    icon: "🔥",
    charLimit: "280-500",
    color: "from-red-500 to-rose-500"
  }
];

export default function TweetGenerator({ refreshKey, selectedPersonaId, inspireTopic }: TweetGeneratorProps) {
  const [formData, setFormData] = useState<TweetGenerationRequest>({
    topic: "",
    persona: "data_driven",
    length: "medium",
    tone: "Profesyonel",
    format: "normal"
  });

  const [allPersonas, setAllPersonas] = useState<Persona[]>(defaultPersonas);
  const [generatedTweets, setGeneratedTweets] = useState<GeneratedTweet[]>([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [retryAfter, setRetryAfter] = useState<number | undefined>(undefined);
  const [mounted, setMounted] = useState(false);
  const [followerCount, setFollowerCount] = useState<number | undefined>(undefined);
  const abortControllerRef = useRef<AbortController | null>(null);

  useEffect(() => {
    setMounted(true);
    const custom = getCustomPersonas();
    const saved = getSavedPersonas();
    // Saved personaları da custom olarak ekle
    const savedAsCustom = saved.map(p => ({
      ...p,
      isCustom: true as const,
    }));
    setAllPersonas([...savedAsCustom, ...custom, ...defaultPersonas]);
  }, [refreshKey]);

  // selectedPersonaId değiştiğinde persona'yı seç
  useEffect(() => {
    if (selectedPersonaId) {
      const savedPersona = getSavedPersonaById(selectedPersonaId);
      if (savedPersona) {
        setFormData(prev => ({ ...prev, persona: savedPersona.id }));
      }
    }
  }, [selectedPersonaId]);

  // inspireTopic değiştiğinde topic'i ayarla (viral inspiration'dan gelen)
  useEffect(() => {
    if (inspireTopic) {
      setFormData(prev => ({ ...prev, topic: inspireTopic }));
    }
  }, [inspireTopic]);

  // Cleanup on unmount
  useEffect(() => {
    return () => {
      abortControllerRef.current?.abort();
    };
  }, []);

  const handleCancel = useCallback(() => {
    abortControllerRef.current?.abort();
    setLoading(false);
    setError("Istek iptal edildi");
  }, []);

  // Hydration için: client mount olana kadar sadece default personaları göster
  const displayPersonas = mounted ? allPersonas : defaultPersonas;

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();

    if (!formData.topic.trim()) {
      setError("Lütfen bir konu girin");
      return;
    }

    // Cancel any ongoing request
    abortControllerRef.current?.abort();
    abortControllerRef.current = new AbortController();

    setLoading(true);
    setError(null);
    setRetryAfter(undefined);
    setGeneratedTweets([]);

    try {
      const selectedPersona = allPersonas.find(p => p.id === formData.persona);

      // Format'a göre length ayarla
      let length = formData.length;
      if (formData.format === "micro") length = "short";
      else if (formData.format === "thunder") length = "long";
      else length = "medium";

      const requestBody = {
        ...formData,
        length,
        customPersona: selectedPersona?.isCustom ? selectedPersona : undefined,
      };

      const response = await fetch("/api/generate", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(requestBody),
        signal: abortControllerRef.current.signal,
      });

      const result = await response.json();

      if (result.success && result.data) {
        const tweets = Array.isArray(result.data) ? result.data : [result.data];
        setGeneratedTweets(tweets);

        // Save to history
        const selectedPersona = allPersonas.find(p => p.id === formData.persona);
        const savedPersona = getSavedPersonaById(formData.persona);

        tweets.forEach((tweet: GeneratedTweet) => {
          addToHistory({
            type: "tweet",
            content: tweet.content,
            topic: formData.topic,
            persona: selectedPersona?.name || formData.persona,
            personaId: savedPersona?.id, // Saved persona ise ID'sini kaydet
            score: tweet.score.total,
          });

          // Saved persona ise tweet sayısını artır
          if (savedPersona) {
            incrementPersonaTweetCount(savedPersona.id);
          }
        });
      } else {
        setError(result.error || "Bir hata oluştu");
        if (result.retryAfter) {
          setRetryAfter(result.retryAfter);
        }
      }
    } catch (err: any) {
      if (err.name === 'AbortError') {
        return; // Request was cancelled, don't set error
      }
      setError(err.message || "Bağlantı hatası");
    } finally {
      setLoading(false);
    }
  };

  const handleDeletePersona = (id: string) => {
    deleteCustomPersona(id);
    const custom = getCustomPersonas();
    setAllPersonas([...custom, ...defaultPersonas]);
    if (formData.persona === id) {
      setFormData({ ...formData, persona: "data_driven" });
    }
  };

  return (
    <div className="space-y-6">
      <div className="bg-gray-800/50 backdrop-blur rounded-2xl shadow-xl p-6 border border-gray-700/50">
        <div className="flex items-center gap-3 mb-6">
          <span className="text-3xl" aria-hidden="true">⚡</span>
          <div>
            <h2 className="text-xl font-bold text-white">Tweet Uretici</h2>
            <p className="text-sm text-gray-400">Saniyede icerik uret</p>
          </div>
        </div>

        <form onSubmit={handleSubmit} className="space-y-5">
          {/* Topic Input */}
          <div>
            <label htmlFor="topic" className="block text-sm font-medium text-gray-300 mb-2">
              Konu / Fikir
            </label>
            <textarea
              id="topic"
              rows={3}
              value={formData.topic}
              onChange={(e) => setFormData({ ...formData, topic: e.target.value })}
              className="w-full px-4 py-3 bg-gray-900/50 border border-gray-700 rounded-xl focus:ring-2 focus:ring-red-500 focus:border-transparent text-white placeholder-gray-500 resize-none"
              placeholder="Örn: Yapay zekanın geleceği hakkında düşüncelerim..."
            />
          </div>

          {/* Tweet Format Selection - XPatla Style */}
          <div>
            <label className="block text-sm font-medium text-gray-300 mb-3">
              Format
            </label>
            <div className="grid grid-cols-3 gap-3">
              {tweetFormats.map((format) => (
                <button
                  key={format.id}
                  type="button"
                  onClick={() => setFormData({ ...formData, format: format.id })}
                  aria-pressed={formData.format === format.id}
                  className={`relative p-4 rounded-xl border-2 transition-all ${
                    formData.format === format.id
                      ? `border-transparent bg-gradient-to-br ${format.color} text-white shadow-lg scale-105`
                      : "border-gray-700 bg-gray-900/50 text-gray-400 hover:border-gray-600"
                  }`}
                >
                  <div className="text-2xl mb-1" aria-hidden="true">{format.icon}</div>
                  <div className="font-semibold text-sm">{format.name}</div>
                  <div className={`text-xs mt-1 ${formData.format === format.id ? "text-white/80" : "text-gray-500"}`}>
                    {format.charLimit} kar
                  </div>
                </button>
              ))}
            </div>
          </div>

          {/* Follower Count Input (Optional) */}
          <div>
            <label htmlFor="follower-count" className="block text-sm font-medium text-gray-300 mb-2">
              Takipci Sayiniz (Opsiyonel)
            </label>
            <input
              id="follower-count"
              type="number"
              min="0"
              value={followerCount || ""}
              onChange={(e) => setFollowerCount(e.target.value ? parseInt(e.target.value, 10) : undefined)}
              className="w-full px-4 py-3 bg-gray-900/50 border border-gray-700 rounded-xl focus:ring-2 focus:ring-red-500 focus:border-transparent text-white placeholder-gray-500"
              placeholder="Orn: 5000"
            />
            <p className="text-xs text-gray-500 mt-1">Performans tahmini icin takipci sayinizi girin</p>
          </div>

          {/* Persona Selection */}
          <div>
            <label className="block text-sm font-medium text-gray-300 mb-2">
              Stil / Persona
            </label>

            {/* Custom Personas */}
            {displayPersonas.filter(p => p.isCustom).length > 0 && (
              <div className="mb-3">
                <span className="text-xs font-medium text-emerald-400 uppercase tracking-wide">Analiz Edilen</span>
                <div className="mt-2 flex flex-wrap gap-2">
                  {displayPersonas.filter(p => p.isCustom).map((p) => (
                    <div
                      key={p.id}
                      className={`group relative inline-flex items-center gap-2 px-3 py-2 rounded-lg border cursor-pointer transition-all ${
                        formData.persona === p.id
                          ? "border-emerald-500 bg-emerald-500/20 text-emerald-400"
                          : "border-gray-700 bg-gray-900/50 text-gray-400 hover:border-gray-600"
                      }`}
                      onClick={() => setFormData({ ...formData, persona: p.id })}
                    >
                      <span className="text-sm font-medium">@{p.sourceUsername}</span>
                      <button
                        onClick={(e) => {
                          e.stopPropagation();
                          handleDeletePersona(p.id);
                        }}
                        aria-label={`@${p.sourceUsername} personasini sil`}
                        className="opacity-0 group-hover:opacity-100 text-red-400 hover:text-red-300 transition-opacity"
                      >
                        <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24" aria-hidden="true">
                          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" />
                        </svg>
                      </button>
                    </div>
                  ))}
                </div>
              </div>
            )}

            {/* Default Personas */}
            <select
              value={displayPersonas.find(p => p.id === formData.persona)?.isCustom ? "" : formData.persona}
              onChange={(e) => setFormData({ ...formData, persona: e.target.value })}
              className="w-full px-4 py-3 bg-gray-900/50 border border-gray-700 rounded-xl focus:ring-2 focus:ring-red-500 focus:border-transparent text-white"
            >
              <option value="" disabled className="bg-gray-900">Hazır persona seçin...</option>
              {displayPersonas.filter(p => !p.isCustom).map((p) => (
                <option key={p.id} value={p.id} className="bg-gray-900">
                  {p.name} - {p.description}
                </option>
              ))}
            </select>
          </div>

          <ErrorMessage
            error={error}
            onDismiss={() => { setError(null); setRetryAfter(undefined); }}
            onRetry={() => handleSubmit({ preventDefault: () => {} } as React.FormEvent)}
            retryAfter={retryAfter}
          />

          <LoadingButton
            type="submit"
            loading={loading}
            loadingText="Icerik Uretiliyor..."
            colorScheme="red"
            onCancel={handleCancel}
          >
            Tweet Uret
          </LoadingButton>
        </form>
      </div>

      {/* Generated Tweets */}
      {generatedTweets.length > 0 && <TweetDisplay tweets={generatedTweets} />}

      {/* Performance Prediction */}
      {generatedTweets.length > 0 && followerCount && followerCount > 0 && (
        <div className="bg-gray-800/50 backdrop-blur rounded-2xl shadow-xl p-6 border border-gray-700/50">
          <div className="flex items-center gap-3 mb-4">
            <span className="text-2xl" aria-hidden="true">📈</span>
            <div>
              <h3 className="text-lg font-bold text-white">Performans Tahmini</h3>
              <p className="text-sm text-gray-400">{followerCount.toLocaleString("tr-TR")} takipci icin</p>
            </div>
          </div>

          <div className="space-y-4">
            {generatedTweets.map((tweet, index) => {
              const xScore = tweet.xScore;
              if (!xScore) return null;

              const predictions = xScore.predictions;
              const totalScore = xScore.total;

              // Calculate estimates
              const baseLikes = predictions.favorite_score * followerCount * 0.02;
              const baseRetweets = predictions.repost_score * followerCount * 0.005;
              const baseReplies = predictions.reply_score * followerCount * 0.003;

              // Confidence level
              const confidence = totalScore < 40 ? "Dusuk" : totalScore < 70 ? "Orta" : "Yuksek";
              const confidenceColor = totalScore < 40 ? "text-red-400" : totalScore < 70 ? "text-amber-400" : "text-emerald-400";

              // Range multipliers
              const minMultiplier = 0.5;
              const maxMultiplier = 1.5;

              return (
                <div key={index} className="p-4 bg-gray-900/50 rounded-xl border border-gray-700/50">
                  <div className="flex items-center justify-between mb-3">
                    <span className="text-sm font-medium text-gray-400">Tweet #{index + 1}</span>
                    <span className={`text-sm font-medium ${confidenceColor}`}>
                      Guven: {confidence} ({totalScore}/100)
                    </span>
                  </div>

                  <div className="grid grid-cols-3 gap-4">
                    {/* Likes Estimate */}
                    <div className="text-center p-3 bg-gray-800/50 rounded-lg">
                      <div className="flex items-center justify-center gap-1 mb-1">
                        <svg className="w-4 h-4 text-red-400" fill="currentColor" viewBox="0 0 20 20">
                          <path fillRule="evenodd" d="M3.172 5.172a4 4 0 015.656 0L10 6.343l1.172-1.171a4 4 0 115.656 5.656L10 17.657l-6.828-6.829a4 4 0 010-5.656z" clipRule="evenodd" />
                        </svg>
                        <span className="text-sm text-gray-400">Begeni</span>
                      </div>
                      <p className="text-lg font-bold text-white">
                        {Math.round(baseLikes * minMultiplier).toLocaleString("tr-TR")} - {Math.round(baseLikes * maxMultiplier).toLocaleString("tr-TR")}
                      </p>
                    </div>

                    {/* Retweets Estimate */}
                    <div className="text-center p-3 bg-gray-800/50 rounded-lg">
                      <div className="flex items-center justify-center gap-1 mb-1">
                        <svg className="w-4 h-4 text-green-400" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" />
                        </svg>
                        <span className="text-sm text-gray-400">Retweet</span>
                      </div>
                      <p className="text-lg font-bold text-white">
                        {Math.round(baseRetweets * minMultiplier).toLocaleString("tr-TR")} - {Math.round(baseRetweets * maxMultiplier).toLocaleString("tr-TR")}
                      </p>
                    </div>

                    {/* Replies Estimate */}
                    <div className="text-center p-3 bg-gray-800/50 rounded-lg">
                      <div className="flex items-center justify-center gap-1 mb-1">
                        <svg className="w-4 h-4 text-blue-400" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M8 12h.01M12 12h.01M16 12h.01M21 12c0 4.418-4.03 8-9 8a9.863 9.863 0 01-4.255-.949L3 20l1.395-3.72C3.512 15.042 3 13.574 3 12c0-4.418 4.03-8 9-8s9 3.582 9 8z" />
                        </svg>
                        <span className="text-sm text-gray-400">Yanit</span>
                      </div>
                      <p className="text-lg font-bold text-white">
                        {Math.round(baseReplies * minMultiplier).toLocaleString("tr-TR")} - {Math.round(baseReplies * maxMultiplier).toLocaleString("tr-TR")}
                      </p>
                    </div>
                  </div>

                  <p className="text-xs text-gray-500 mt-3 text-center">
                    * Tahminler X algoritma skorlarina dayanmaktadir. Gercek sonuclar farklilik gosterebilir.
                  </p>
                </div>
              );
            })}
          </div>
        </div>
      )}
    </div>
  );
}

