"use client";

import { useState, useEffect, useMemo } from "react";
import { getHistory } from "@/lib/history";
import { HistoryItem } from "@/types";

function formatNumber(num: number): string {
  if (num >= 1000000) return (num / 1000000).toFixed(1) + "M";
  if (num >= 1000) return (num / 1000).toFixed(1) + "K";
  return num.toString();
}

const HOOK_TYPE_COLORS: Record<string, string> = {
  tweet: "#ef4444",
  thread: "#a855f7",
  reply: "#06b6d4",
  quote: "#f97316",
};

const DAY_NAMES = ["Paz", "Pzt", "Sal", "Car", "Per", "Cum", "Cmt"];

export default function Dashboard() {
  const [history, setHistory] = useState<HistoryItem[]>([]);
  const [mounted, setMounted] = useState(false);

  useEffect(() => {
    setMounted(true);
    setHistory(getHistory());
  }, []);

  // Stats calculations
  const stats = useMemo(() => {
    if (!mounted || history.length === 0) {
      return {
        total: 0,
        avgScore: 0,
        favorites: 0,
        mostUsedPersona: "-",
        todayCount: 0,
        weekCount: 0,
      };
    }

    const now = new Date();
    const today = new Date(now.getFullYear(), now.getMonth(), now.getDate());
    const weekAgo = new Date(today.getTime() - 7 * 24 * 60 * 60 * 1000);

    const todayItems = history.filter((h) => new Date(h.createdAt) >= today);
    const weekItems = history.filter((h) => new Date(h.createdAt) >= weekAgo);

    const personaCount: Record<string, number> = {};
    history.forEach((h) => {
      personaCount[h.persona] = (personaCount[h.persona] || 0) + 1;
    });
    const mostUsedPersona = Object.entries(personaCount).sort((a, b) => b[1] - a[1])[0]?.[0] || "-";

    return {
      total: history.length,
      avgScore: Math.round(history.reduce((sum, h) => sum + h.score, 0) / history.length),
      favorites: history.filter((h) => h.isFavorite).length,
      mostUsedPersona,
      todayCount: todayItems.length,
      weekCount: weekItems.length,
    };
  }, [history, mounted]);

  // Hourly distribution (CSS bar chart)
  const hourlyDistribution = useMemo(() => {
    const hours = Array(24).fill(0);
    history.forEach((h) => {
      const hour = new Date(h.createdAt).getHours();
      hours[hour]++;
    });
    return hours;
  }, [history]);

  const maxHourly = Math.max(...hourlyDistribution, 1);

  // Type distribution (for pie chart)
  const typeDistribution = useMemo(() => {
    const types: Record<string, number> = { tweet: 0, thread: 0, reply: 0, quote: 0 };
    history.forEach((h) => {
      if (types[h.type] !== undefined) {
        types[h.type]++;
      }
    });
    return types;
  }, [history]);

  const totalTypes = Object.values(typeDistribution).reduce((a, b) => a + b, 0) || 1;

  // Weekly trend (last 7 days)
  const weeklyTrend = useMemo(() => {
    const days: { day: string; count: number; avgScore: number }[] = [];
    const now = new Date();

    for (let i = 6; i >= 0; i--) {
      const date = new Date(now.getTime() - i * 24 * 60 * 60 * 1000);
      const dayStart = new Date(date.getFullYear(), date.getMonth(), date.getDate());
      const dayEnd = new Date(dayStart.getTime() + 24 * 60 * 60 * 1000);

      const dayItems = history.filter((h) => {
        const itemDate = new Date(h.createdAt);
        return itemDate >= dayStart && itemDate < dayEnd;
      });

      days.push({
        day: DAY_NAMES[date.getDay()],
        count: dayItems.length,
        avgScore: dayItems.length > 0 ? Math.round(dayItems.reduce((sum, h) => sum + h.score, 0) / dayItems.length) : 0,
      });
    }

    return days;
  }, [history]);

  const maxWeeklyCount = Math.max(...weeklyTrend.map((d) => d.count), 1);

  // SVG Pie Chart calculation
  const pieChartSegments = useMemo(() => {
    const segments: { type: string; percentage: number; offset: number; color: string }[] = [];
    let offset = 0;

    Object.entries(typeDistribution).forEach(([type, count]) => {
      const percentage = (count / totalTypes) * 100;
      segments.push({
        type,
        percentage,
        offset,
        color: HOOK_TYPE_COLORS[type] || "#6b7280",
      });
      offset += percentage;
    });

    return segments;
  }, [typeDistribution, totalTypes]);

  if (!mounted) {
    return (
      <div className="bg-gray-800/50 backdrop-blur rounded-2xl p-8 border border-gray-700/50">
        <div className="flex items-center justify-center gap-3 text-gray-400">
          <svg className="animate-spin h-5 w-5" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
            <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4" />
            <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z" />
          </svg>
          <span>Dashboard yukleniyor...</span>
        </div>
      </div>
    );
  }

  return (
    <div className="space-y-6">
      {/* Header */}
      <div className="bg-gray-800/50 backdrop-blur rounded-2xl shadow-xl p-6 border border-gray-700/50">
        <div className="flex items-center gap-3 mb-6">
          <span className="text-3xl" aria-hidden="true">📊</span>
          <div>
            <h2 className="text-xl font-bold text-white">Dashboard</h2>
            <p className="text-sm text-gray-400">Uretim istatistikleriniz</p>
          </div>
        </div>

        {/* Stats Cards */}
        <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
          <div className="bg-gray-900/50 rounded-xl p-4 border border-gray-700/50">
            <p className="text-sm text-gray-400 mb-1">Toplam Tweet</p>
            <p className="text-2xl font-bold text-white">{formatNumber(stats.total)}</p>
          </div>
          <div className="bg-gray-900/50 rounded-xl p-4 border border-gray-700/50">
            <p className="text-sm text-gray-400 mb-1">Ortalama Skor</p>
            <p className="text-2xl font-bold text-violet-400">{stats.avgScore}/100</p>
          </div>
          <div className="bg-gray-900/50 rounded-xl p-4 border border-gray-700/50">
            <p className="text-sm text-gray-400 mb-1">Favoriler</p>
            <p className="text-2xl font-bold text-amber-400">{stats.favorites}</p>
          </div>
          <div className="bg-gray-900/50 rounded-xl p-4 border border-gray-700/50">
            <p className="text-sm text-gray-400 mb-1">En Cok Kullanilan</p>
            <p className="text-lg font-bold text-emerald-400 truncate">{stats.mostUsedPersona}</p>
          </div>
        </div>
      </div>

      {/* Charts Row */}
      <div className="grid md:grid-cols-2 gap-6">
        {/* Hourly Distribution Bar Chart */}
        <div className="bg-gray-800/50 backdrop-blur rounded-2xl p-6 border border-gray-700/50">
          <h3 className="text-lg font-semibold text-white mb-4">Saatlik Uretim Dagilimi</h3>
          <div className="flex items-end gap-1 h-40">
            {hourlyDistribution.map((count, hour) => (
              <div key={hour} className="flex-1 flex flex-col items-center gap-1" title={`${hour}:00 - ${count} tweet`}>
                <div
                  className="w-full bg-gradient-to-t from-violet-600 to-purple-400 rounded-t transition-all duration-300"
                  style={{ height: `${(count / maxHourly) * 100}%`, minHeight: count > 0 ? "4px" : "0" }}
                />
                {hour % 4 === 0 && <span className="text-xs text-gray-500">{hour}</span>}
              </div>
            ))}
          </div>
          <p className="text-sm text-gray-400 mt-3 text-center">
            En verimli saat: {hourlyDistribution.indexOf(Math.max(...hourlyDistribution))}:00
          </p>
        </div>

        {/* Type Distribution Pie Chart (SVG) */}
        <div className="bg-gray-800/50 backdrop-blur rounded-2xl p-6 border border-gray-700/50">
          <h3 className="text-lg font-semibold text-white mb-4">Icerik Tipi Dagilimi</h3>
          <div className="flex items-center justify-center gap-8">
            {/* SVG Pie Chart */}
            <div className="relative w-32 h-32">
              <svg viewBox="0 0 32 32" className="w-full h-full transform -rotate-90">
                {pieChartSegments.map((segment, index) => {
                  const circumference = 2 * Math.PI * 15;
                  const strokeDasharray = (segment.percentage / 100) * circumference;
                  const strokeDashoffset = -(segment.offset / 100) * circumference;

                  return (
                    <circle
                      key={segment.type}
                      cx="16"
                      cy="16"
                      r="15"
                      fill="none"
                      stroke={segment.color}
                      strokeWidth="2"
                      strokeDasharray={`${strokeDasharray} ${circumference}`}
                      strokeDashoffset={strokeDashoffset}
                      className="transition-all duration-500"
                    />
                  );
                })}
              </svg>
              <div className="absolute inset-0 flex items-center justify-center">
                <span className="text-2xl font-bold text-white">{stats.total}</span>
              </div>
            </div>

            {/* Legend */}
            <div className="space-y-2">
              {Object.entries(typeDistribution).map(([type, count]) => (
                <div key={type} className="flex items-center gap-2">
                  <div className="w-3 h-3 rounded-full" style={{ backgroundColor: HOOK_TYPE_COLORS[type] }} />
                  <span className="text-sm text-gray-300 capitalize">{type}</span>
                  <span className="text-sm text-gray-500">({count})</span>
                </div>
              ))}
            </div>
          </div>
        </div>
      </div>

      {/* Weekly Trend */}
      <div className="bg-gray-800/50 backdrop-blur rounded-2xl p-6 border border-gray-700/50">
        <h3 className="text-lg font-semibold text-white mb-4">Son 7 Gun</h3>
        <div className="grid grid-cols-7 gap-2">
          {weeklyTrend.map((day, index) => (
            <div key={index} className="text-center">
              <div className="h-24 flex items-end justify-center mb-2">
                <div
                  className="w-full max-w-[40px] bg-gradient-to-t from-violet-600 to-purple-400 rounded-t transition-all duration-300"
                  style={{ height: `${(day.count / maxWeeklyCount) * 100}%`, minHeight: day.count > 0 ? "8px" : "0" }}
                />
              </div>
              <p className="text-xs font-medium text-gray-300">{day.day}</p>
              <p className="text-xs text-gray-500">{day.count} tweet</p>
              {day.avgScore > 0 && <p className="text-xs text-violet-400">{day.avgScore} skor</p>}
            </div>
          ))}
        </div>
        <div className="mt-4 pt-4 border-t border-gray-700/50 grid grid-cols-2 gap-4">
          <div className="text-center">
            <p className="text-sm text-gray-400">Bu Hafta</p>
            <p className="text-xl font-bold text-white">{stats.weekCount} tweet</p>
          </div>
          <div className="text-center">
            <p className="text-sm text-gray-400">Bugun</p>
            <p className="text-xl font-bold text-emerald-400">{stats.todayCount} tweet</p>
          </div>
        </div>
      </div>

      {/* Empty State */}
      {history.length === 0 && (
        <div className="bg-gray-800/50 backdrop-blur rounded-2xl p-8 text-center border border-gray-700/50">
          <span className="text-4xl mb-4 block">📊</span>
          <p className="text-gray-400">Henuz icerik uretmediniz. Tweet uretmeye baslayin!</p>
        </div>
      )}
    </div>
  );
}

