   324→                <div className="text-2xl mb-1">😊</div>
   325→                <div className="text-xs text-gray-500">Emoji</div>
   326→                <div className="font-medium text-white text-sm">{getUsageLabel(result.analysis.emojiUsage)}</div>
   327→              </div>
   328→              <div className="bg-gray-800/50 rounded-lg p-3 text-center border border-gray-700/50">
   329→                <div className="text-2xl mb-1">#</div>
   330→                <div className="text-xs text-gray-500">Hashtag</div>
   331→                <div className="font-medium text-white text-sm">{getUsageLabel(result.analysis.hashtagUsage)}</div>
   332→              </div>
   333→              <div className="bg-gray-800/50 rounded-lg p-3 text-center border border-gray-700/50">
   334→                <div className="text-2xl mb-1">📏</div>
   335→                <div className="text-xs text-gray-500">Ort. Uzunluk</div>
   336→                <div className="font-medium text-white text-sm">{result.analysis.averageLength} kar.</div>
   337→              </div>
   338→            </div>
   339→
   340→            <div className="space-y-3">
   341→              <div>
   342→                <span className="text-sm font-medium text-gray-300">Konular: </span>
   343→                <span className="text-sm text-gray-400">
   344→                  {result.analysis.topics.join(", ")}
   345→                </span>
   346→              </div>
   347→              <div>
   348→                <span className="text-sm font-medium text-gray-300">Yazım Tarzı: </span>
   349→                <span className="text-sm text-gray-400">
   350→                  {result.analysis.writingStyle}
   351→                </span>
   352→              </div>
   353→            </div>
   354→          </div>
   355→
   356→          {/* Örnek Tweet'ler */}
   357→          <div className="bg-gray-900/50 rounded-xl p-5 border border-gray-700/50">
   358→            <h4 className="font-semibold text-white mb-4">Örnek Tweet'ler</h4>
   359→            <div className="space-y-3">
   360→              {result.persona.example_tweets.slice(0, 3).map((tweet, i) => (
   361→                <div key={i} className="bg-gray-800/50 rounded-lg p-4 text-sm text-gray-300 border-l-4 border-emerald-500">
   362→                  {tweet}
   363→                </div>
   364→              ))}
   365→            </div>
   366→          </div>
   367→
   368→          {/* Kaydet Butonu */}
   369→          <button
   370→            onClick={handleSavePersona}
   371→            className="w-full bg-gradient-to-r from-emerald-500 to-teal-600 hover:from-emerald-600 hover:to-teal-700 text-white font-semibold py-4 px-6 rounded-xl shadow-lg transform transition hover:scale-[1.02]"
   372→          >
   373→            ✨ Bu Tarzı Persona Olarak Kaydet
   374→          </button>
   375→        </div>
   376→      )}
   377→    </div>
   378→  );
   379→}
