"use client";

import { useState } from "react";
import { Persona, StyleAnalysis } from "@/types";
import { saveSavedPersona } from "@/lib/personaStorage";

interface AnalysisResult {
  username: string;
  displayName: string;
  bio: string;
  tweets: string[];
  analysis: StyleAnalysis;
  persona: Persona;
}

interface AccountAnalyzerProps {
  onPersonaCreated: (persona: Persona) => void;
}

export default function AccountAnalyzer({ onPersonaCreated }: AccountAnalyzerProps) {
  const [username, setUsername] = useState("");
  const [manualTweets, setManualTweets] = useState("");
  const [mode, setMode] = useState<"auto" | "manual" | "browser">("browser");
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [result, setResult] = useState<AnalysisResult | null>(null);

  const handleAnalyze = async (e: React.FormEvent) => {
    e.preventDefault();

    if (mode === "manual") {
      if (!username.trim() || !manualTweets.trim()) {
        setError("Lütfen kullanıcı adı ve tweet'leri girin");
        return;
      }
    } else if (mode === "browser") {
      if (!username.trim()) {
        setError("Lütfen bir kullanıcı adı girin");
        return;
      }
      // Browser modu için özel mesaj göster
      setError("🌐 Claude'a söyleyin: '@" + username.trim() + "' hesabını analiz et");
      setLoading(false);
      return;
    } else {
      if (!username.trim()) {
        setError("Lütfen bir kullanıcı adı girin");
        return;
      }
    }

    setLoading(true);
    setError(null);
    setResult(null);

    try {
      const response = await fetch("/api/analyze", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          username: username.trim(),
          mode,
          manualTweets: mode === "manual" ? manualTweets.trim() : undefined,
        }),
      });

      const data = await response.json();

      if (data.success && data.data) {
        setResult(data.data);
      } else {
        setError(data.error || "Analiz başarısız oldu");
      }
    } catch (err: any) {
      setError(err.message || "Bağlantı hatası");
    } finally {
      setLoading(false);
    }
  };

  // Browser modunda dışarıdan tweet set etmek için
  const _setBrowserTweets = (tweets: string[], _displayName: string, _bio: string) => {
    // Bu fonksiyon Claude tarafından çağrılacak
    const tweetsText = tweets.join("\n");
    setManualTweets(tweetsText);
    setMode("manual");
    // Otomatik submit
    handleAnalyzeWithData(tweets);
  };

  const handleAnalyzeWithData = async (tweets: string[]) => {
    setLoading(true);
    setError(null);
    setResult(null);

    try {
      const response = await fetch("/api/analyze", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          username: username.trim(),
          mode: "manual",
          manualTweets: tweets.join("\n"),
        }),
      });

      const data = await response.json();

      if (data.success && data.data) {
        setResult(data.data);
      } else {
        setError(data.error || "Analiz başarısız oldu");
      }
    } catch (err: any) {
      setError(err.message || "Bağlantı hatası");
    } finally {
      setLoading(false);
    }
  };

  const handleSavePersona = () => {
    if (result?.persona && result.analysis) {
      // SavedPersona olarak kaydet (detaylı bilgilerle)
      const savedPersona = saveSavedPersona({
        username: result.username,
        displayName: result.displayName,
        bio: result.bio || "",
        originalTweets: result.tweets,
        styleAnalysis: result.analysis,
        persona: {
          name: result.persona.name,
          description: result.persona.description,
          style: result.persona.style,
          tone: result.persona.tone,
          example_tweets: result.persona.example_tweets,
        },
      });

      // Eski sisteme de bildir (uyumluluk için)
      onPersonaCreated({
        ...result.persona,
        id: savedPersona.id,
        isCustom: true,
        sourceUsername: result.username,
        analyzedAt: savedPersona.analyzedAt,
      });

      setResult(null);
      setUsername("");
      setManualTweets("");
    }
  };

  const getUsageLabel = (usage: string) => {
    const labels: Record<string, string> = {
      none: "Hiç",
      minimal: "Az",
      moderate: "Orta",
      heavy: "Çok",
    };
    return labels[usage] || usage;
  };

  return (
    <div className="bg-gray-800/50 backdrop-blur rounded-2xl shadow-xl p-6 border border-gray-700/50">
      <div className="flex items-center gap-3 mb-6">
        <span className="text-3xl">🔍</span>
        <div>
          <h2 className="text-xl font-bold text-white">Hesap Analizi</h2>
          <p className="text-sm text-gray-400">Yazım tarzını klonla</p>
        </div>
      </div>

      <form onSubmit={handleAnalyze} className="space-y-5">
        {/* Mode Toggle */}
        <div className="flex gap-2 p-1.5 bg-gray-900/50 rounded-xl border border-gray-700/50">
          <button
            type="button"
            onClick={() => setMode("browser")}
            className={`flex-1 py-2.5 px-4 rounded-lg text-sm font-medium transition-all ${
              mode === "browser"
                ? "bg-gradient-to-r from-emerald-500 to-teal-600 text-white shadow-lg"
                : "text-gray-400 hover:text-white"
            }`}
          >
            🌐 Tarayıcı
          </button>
          <button
            type="button"
            onClick={() => setMode("auto")}
            className={`flex-1 py-2.5 px-4 rounded-lg text-sm font-medium transition-all ${
              mode === "auto"
                ? "bg-gradient-to-r from-emerald-500 to-teal-600 text-white shadow-lg"
                : "text-gray-400 hover:text-white"
            }`}
          >
            🔗 Apify
          </button>
          <button
            type="button"
            onClick={() => setMode("manual")}
            className={`flex-1 py-2.5 px-4 rounded-lg text-sm font-medium transition-all ${
              mode === "manual"
                ? "bg-gradient-to-r from-emerald-500 to-teal-600 text-white shadow-lg"
                : "text-gray-400 hover:text-white"
            }`}
          >
            ✏️ Manuel
          </button>
        </div>

        {/* Kullanıcı Adı */}
        <div>
          <label htmlFor="username" className="block text-sm font-medium text-gray-300 mb-2">
            X Kullanıcı Adı
          </label>
          <div className="relative">
            <span className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-500">@</span>
            <input
              type="text"
              id="username"
              value={username}
              onChange={(e) => setUsername(e.target.value.replace("@", ""))}
              className="w-full pl-8 pr-4 py-3 bg-gray-900/50 border border-gray-700 rounded-xl focus:ring-2 focus:ring-emerald-500 focus:border-transparent text-white placeholder-gray-500"
              placeholder="acerionsjournal"
            />
          </div>
          {mode === "auto" && (
            <p className="mt-2 text-sm text-gray-500">
              Tweet'ler otomatik olarak çekilecek (Apify API kullanılır)
            </p>
          )}
          {mode === "browser" && (
            <p className="mt-2 text-sm text-emerald-400">
              Claude, X.com'dan tweet'leri tarayıcı ile çekecek. Kullanıcı adını girip bekleyin.
            </p>
          )}
        </div>

        {/* Manuel Tweet Girişi - Sadece manuel modda göster */}
        {mode === "manual" && (
          <div>
            <label htmlFor="tweets" className="block text-sm font-medium text-gray-300 mb-2">
              Tweet'ler (Her satıra bir tweet)
            </label>
            <textarea
              id="tweets"
              rows={8}
              value={manualTweets}
              onChange={(e) => setManualTweets(e.target.value)}
              className="w-full px-4 py-3 bg-gray-900/50 border border-gray-700 rounded-xl focus:ring-2 focus:ring-emerald-500 focus:border-transparent text-white placeholder-gray-500 resize-none font-mono text-sm"
              placeholder={`Hesabın tweet'lerini buraya yapıştırın...

Örnek:
Bugün harika bir gün, yeni projeme başladım!
Yapay zeka hakkında düşüncelerim: Gelecek çok parlak.
Sabah kahvemi içerken bu thread'i yazdım 🧵`}
            />
            <p className="mt-2 text-sm text-gray-500">
              X'ten kopyaladığınız tweet'leri yapıştırın. AI yazım tarzını analiz edecek.
            </p>
          </div>
        )}

        {error && (
          <div className={`px-4 py-3 rounded-xl ${
            error.startsWith("🌐")
              ? "bg-emerald-500/10 border border-emerald-500/30 text-emerald-400"
              : "bg-red-500/10 border border-red-500/30 text-red-400"
          }`}>
            {error}
          </div>
        )}

        <button
          type="submit"
          disabled={loading}
          className="w-full bg-gradient-to-r from-emerald-500 to-teal-600 hover:from-emerald-600 hover:to-teal-700 text-white font-semibold py-4 px-6 rounded-xl shadow-lg transform transition hover:scale-[1.02] disabled:opacity-50 disabled:cursor-not-allowed disabled:transform-none"
        >
          {loading ? (
            <span className="flex items-center justify-center">
              <svg className="animate-spin -ml-1 mr-3 h-5 w-5 text-white" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
                <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
              </svg>
              Stil Analiz Ediliyor...
            </span>
          ) : (
            "🔍 Tarzı Analiz Et"
          )}
        </button>
      </form>

      {result && (
        <div className="mt-8 space-y-5">
          {/* Profil Bilgisi */}
          <div className="bg-gray-900/50 rounded-xl p-5 border border-gray-700/50">
            <div className="flex items-start gap-4">
              <div className="w-14 h-14 bg-gradient-to-br from-emerald-500 to-teal-600 rounded-full flex items-center justify-center text-white text-xl font-bold">
                {result.displayName.charAt(0).toUpperCase()}
              </div>
              <div className="flex-1">
                <h3 className="text-lg font-bold text-white">
                  {result.displayName}
                </h3>
                <p className="text-gray-500">@{result.username}</p>
                {result.bio && (
                  <p className="mt-2 text-gray-400 text-sm">{result.bio}</p>
                )}
              </div>
            </div>
          </div>

          {/* Analiz Sonuçları */}
          <div className="bg-gray-900/50 rounded-xl p-5 border border-gray-700/50">
            <h4 className="font-semibold text-white mb-4">Stil Analizi</h4>
            <div className="grid grid-cols-2 md:grid-cols-4 gap-3 mb-4">
              <div className="bg-gray-800/50 rounded-lg p-3 text-center border border-gray-700/50">
                <div className="text-2xl mb-1">🎭</div>
                <div className="text-xs text-gray-500">Ton</div>
                <div className="font-medium text-white text-sm">{result.analysis.tone}</div>
              </div>
              <div className="bg-gray-800/50 rounded-lg p-3 text-center border border-gray-700/50">
                <div className="text-2xl mb-1">😊</div>
                <div className="text-xs text-gray-500">Emoji</div>
                <div className="font-medium text-white text-sm">{getUsageLabel(result.analysis.emojiUsage)}</div>
              </div>
              <div className="bg-gray-800/50 rounded-lg p-3 text-center border border-gray-700/50">
                <div className="text-2xl mb-1">#</div>
                <div className="text-xs text-gray-500">Hashtag</div>
                <div className="font-medium text-white text-sm">{getUsageLabel(result.analysis.hashtagUsage)}</div>
              </div>
              <div className="bg-gray-800/50 rounded-lg p-3 text-center border border-gray-700/50">
                <div className="text-2xl mb-1">📏</div>
                <div className="text-xs text-gray-500">Ort. Uzunluk</div>
                <div className="font-medium text-white text-sm">{result.analysis.averageLength} kar.</div>
              </div>
            </div>

            <div className="space-y-3">
              <div>
                <span className="text-sm font-medium text-gray-300">Konular: </span>
                <span className="text-sm text-gray-400">
                  {result.analysis.topics.join(", ")}
                </span>
              </div>
              <div>
                <span className="text-sm font-medium text-gray-300">Yazım Tarzı: </span>
                <span className="text-sm text-gray-400">
                  {result.analysis.writingStyle}
                </span>
              </div>
            </div>
          </div>

          {/* Örnek Tweet'ler */}
          <div className="bg-gray-900/50 rounded-xl p-5 border border-gray-700/50">
            <h4 className="font-semibold text-white mb-4">Örnek Tweet'ler</h4>
            <div className="space-y-3">
              {result.persona.example_tweets.slice(0, 3).map((tweet, i) => (
                <div key={i} className="bg-gray-800/50 rounded-lg p-4 text-sm text-gray-300 border-l-4 border-emerald-500">
                  {tweet}
                </div>
              ))}
            </div>
          </div>

          {/* Kaydet Butonu */}
          <button
            onClick={handleSavePersona}
            className="w-full bg-gradient-to-r from-emerald-500 to-teal-600 hover:from-emerald-600 hover:to-teal-700 text-white font-semibold py-4 px-6 rounded-xl shadow-lg transform transition hover:scale-[1.02]"
          >
            ✨ Bu Tarzı Persona Olarak Kaydet
          </button>
        </div>
      )}
    </div>
  );
}

