     3→import { useState, useEffect } from "react";
     4→import { defaultPersonas, getCustomPersonas } from "@/lib/personas";
     5→import { GeneratedThread, Persona, XAlgorithmScore } from "@/types";
     6→import { addToHistory } from "@/lib/history";
     7→import { getSavedPersonas, getSavedPersonaById, incrementPersonaTweetCount } from "@/lib/personaStorage";
     8→import { copyToClipboard, getTotalScoreGradient, threadToText } from "@/lib/utils";
     9→import { LoadingButton, ErrorMessage } from "@/components/ui";
    10→import { ThreadTweetCard, ThreadStats, ThreadAnalysisPanel } from "@/components/thread";
    11→
    12→interface ThreadTweetWithScore {
    13→  position: number;
    14→  content: string;
    15→  isHook?: boolean;
    16→  xScore?: XAlgorithmScore;
    17→}
    18→
    19→interface ThreadAnalysis {
    20→  hookScore: number;
    21→  averageEngagement: number;
    22→  adjustedScores: number[];
    23→  strengths: string[];
    24→  improvements: string[];
    25→}
    26→
    27→interface ExtendedGeneratedThread extends Omit<GeneratedThread, 'tweets'> {
    28→  tweets: ThreadTweetWithScore[];
    29→  threadAnalysis?: ThreadAnalysis;
    30→}
    31→
    32→interface ThreadBuilderProps {
    33→  refreshKey?: number;
    34→  selectedPersonaId?: string;
    35→}
    36→
    37→export default function ThreadBuilder({ refreshKey, selectedPersonaId }: ThreadBuilderProps) {
    38→  const [topic, setTopic] = useState("");
    39→  const [persona, setPersona] = useState("data_driven");
    40→  const [threadLength, setThreadLength] = useState<3 | 5 | 10>(5);
    41→  const [allPersonas, setAllPersonas] = useState<Persona[]>(defaultPersonas);
    42→  const [generatedThread, setGeneratedThread] = useState<ExtendedGeneratedThread | null>(null);
    43→  const [loading, setLoading] = useState(false);
    44→  const [error, setError] = useState<string | null>(null);
    45→  const [retryAfter, setRetryAfter] = useState<number | undefined>(undefined);
    46→  const [copiedAll, setCopiedAll] = useState(false);
    47→
    48→  useEffect(() => {
    49→    const custom = getCustomPersonas();
    50→    const saved = getSavedPersonas();
    51→    const savedAsCustom = saved.map(p => ({ ...p, isCustom: true as const }));
    52→    setAllPersonas([...savedAsCustom, ...custom, ...defaultPersonas]);
    53→  }, [refreshKey]);
    54→
    55→  useEffect(() => {
    56→    if (selectedPersonaId) {
    57→      const savedPersona = getSavedPersonaById(selectedPersonaId);
    58→      if (savedPersona) {
    59→        setPersona(savedPersona.id);
    60→      }
    61→    }
    62→  }, [selectedPersonaId]);
    63→
    64→  const handleSubmit = async (e: React.FormEvent) => {
    65→    e.preventDefault();
    66→
    67→    if (!topic.trim()) {
    68→      setError("Lutfen bir konu girin");
    69→      return;
    70→    }
    71→
    72→    setLoading(true);
    73→    setError(null);
    74→    setRetryAfter(undefined);
    75→    setGeneratedThread(null);
    76→
    77→    try {
    78→      const selectedPersona = allPersonas.find(p => p.id === persona);
    79→      const requestBody = {
    80→        topic: topic.trim(),
    81→        persona,
    82→        threadLength,
    83→        customPersona: selectedPersona?.isCustom ? selectedPersona : undefined,
    84→      };
    85→
    86→      const response = await fetch("/api/thread", {
    87→        method: "POST",
    88→        headers: { "Content-Type": "application/json" },
    89→        body: JSON.stringify(requestBody),
    90→      });
    91→
    92→      const result = await response.json();
    93→
    94→      if (result.success && result.data) {
    95→        setGeneratedThread(result.data);
    96→
    97→        const selectedPersona = allPersonas.find(p => p.id === persona);
    98→        const savedPersona = getSavedPersonaById(persona);
    99→
   100→        addToHistory({
   101→          type: "thread",
   102→          content: result.data.tweets,
   103→          topic: topic.trim(),
   104→          persona: selectedPersona?.name || persona,
   105→          personaId: savedPersona?.id,
   106→          score: result.data.totalScore,
   107→        });
   108→
   109→        if (savedPersona) {
   110→          incrementPersonaTweetCount(savedPersona.id);
   111→        }
   112→      } else {
   113→        setError(result.error || "Thread olusturulamadi");
   114→        if (result.retryAfter) {
   115→          setRetryAfter(result.retryAfter);
   116→        }
   117→      }
   118→    } catch (err) {
   119→      const message = err instanceof Error ? err.message : "Baglanti hatasi";
   120→      setError(message);
   121→    } finally {
   122→      setLoading(false);
   123→    }
   124→  };
   125→
   126→  const handleCopyAll = async () => {
   127→    if (!generatedThread) return;
   128→    const allTweets = threadToText(generatedThread.tweets);
   129→    const success = await copyToClipboard(allTweets);
   130→    if (success) {
   131→      setCopiedAll(true);
   132→      setTimeout(() => setCopiedAll(false), 2000);
   133→    }
   134→  };
   135→
   136→  return (
   137→    <div className="space-y-6">
   138→      <div className="bg-gray-800/50 backdrop-blur rounded-2xl shadow-xl p-6 border border-gray-700/50">
   139→        <div className="flex items-center gap-3 mb-6">
   140→          <span className="text-3xl" aria-hidden="true">🧵</span>
   141→          <div>
   142→            <h2 className="text-xl font-bold text-white">Thread Builder</h2>
   143→            <p className="text-sm text-gray-400">Viral thread'ler olustur</p>
   144→          </div>
   145→        </div>
   146→
   147→        <form onSubmit={handleSubmit} className="space-y-5">
   148→          {/* Topic Input */}
   149→          <div>
   150→            <label htmlFor="topic" className="block text-sm font-medium text-gray-300 mb-2">
   151→              Thread Konusu
   152→            </label>
   153→            <textarea
   154→              id="topic"
   155→              rows={3}
   156→              value={topic}
   157→              onChange={(e) => setTopic(e.target.value)}
   158→              className="w-full px-4 py-3 bg-gray-900/50 border border-gray-700 rounded-xl focus:ring-2 focus:ring-purple-500 focus:border-transparent text-white placeholder-gray-500 resize-none"
   159→              placeholder="Orn: Yapay zeka ile para kazanmanin 5 yolu..."
   160→            />
   161→          </div>
   162→
   163→          {/* Persona ve Thread Length */}
   164→          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
   165→            {/* Persona Selection */}
   166→            <div>
   167→              <label htmlFor="persona" className="block text-sm font-medium text-gray-300 mb-2">
   168→                Persona / Stil
   169→              </label>
   170→              <select
   171→                id="persona"
   172→                value={persona}
   173→                onChange={(e) => setPersona(e.target.value)}
   174→                className="w-full px-4 py-3 bg-gray-900/50 border border-gray-700 rounded-xl focus:ring-2 focus:ring-purple-500 focus:border-transparent text-white"
   175→              >
   176→                {allPersonas.filter(p => p.isCustom).length > 0 && (
   177→                  <optgroup label="Analiz Edilen Hesaplar" className="bg-gray-900">
   178→                    {allPersonas.filter(p => p.isCustom).map((p) => (
   179→                      <option key={p.id} value={p.id} className="bg-gray-900">
   180→                        @{p.sourceUsername}
   181→                      </option>
   182→                    ))}
   183→                  </optgroup>
   184→                )}
   185→                <optgroup label="Hazir Personalar" className="bg-gray-900">
   186→                  {allPersonas.filter(p => !p.isCustom).map((p) => (
   187→                    <option key={p.id} value={p.id} className="bg-gray-900">
   188→                      {p.name}
   189→                    </option>
   190→                  ))}
   191→                </optgroup>
   192→              </select>
   193→            </div>
   194→
   195→            {/* Thread Length */}
   196→            <div>
   197→              <label className="block text-sm font-medium text-gray-300 mb-2">
   198→                Thread Uzunlugu
   199→              </label>
   200→              <div className="flex gap-2" role="group" aria-label="Thread uzunlugu secimi">
   201→                {[3, 5, 10].map((len) => (
   202→                  <button
   203→                    key={len}
   204→                    type="button"
   205→                    onClick={() => setThreadLength(len as 3 | 5 | 10)}
   206→                    aria-pressed={threadLength === len}
   207→                    className={`flex-1 py-3 px-4 rounded-xl font-medium transition-all ${
   208→                      threadLength === len
   209→                        ? "bg-gradient-to-r from-purple-500 to-pink-600 text-white shadow-lg"
   210→                        : "bg-gray-900/50 border border-gray-700 text-gray-400 hover:border-gray-600"
   211→                    }`}
   212→                  >
   213→                    {len} Tweet
   214→                  </button>
   215→                ))}
   216→              </div>
   217→            </div>
   218→          </div>
   219→
   220→          <ErrorMessage
   221→            error={error}
   222→            onDismiss={() => { setError(null); setRetryAfter(undefined); }}
   223→            onRetry={() => handleSubmit({ preventDefault: () => {} } as React.FormEvent)}
   224→            retryAfter={retryAfter}
   225→          />
   226→
   227→          <LoadingButton
   228→            type="submit"
   229→            loading={loading}
   230→            loadingText="Thread Olusturuluyor..."
