"use client";

import { useState, useEffect } from "react";
import { defaultPersonas, getCustomPersonas } from "@/lib/personas";
import { GeneratedThread, Persona, XAlgorithmScore } from "@/types";
import { addToHistory } from "@/lib/history";
import { getSavedPersonas, getSavedPersonaById, incrementPersonaTweetCount } from "@/lib/personaStorage";
import { copyToClipboard, getTotalScoreGradient, threadToText } from "@/lib/utils";
import { LoadingButton, ErrorMessage } from "@/components/ui";
import { ThreadTweetCard, ThreadStats, ThreadAnalysisPanel } from "@/components/thread";

interface ThreadTweetWithScore {
  position: number;
  content: string;
  isHook?: boolean;
  xScore?: XAlgorithmScore;
}

interface ThreadAnalysis {
  hookScore: number;
  averageEngagement: number;
  adjustedScores: number[];
  strengths: string[];
  improvements: string[];
}

interface ExtendedGeneratedThread extends Omit<GeneratedThread, 'tweets'> {
  tweets: ThreadTweetWithScore[];
  threadAnalysis?: ThreadAnalysis;
}

interface ThreadBuilderProps {
  refreshKey?: number;
  selectedPersonaId?: string;
}

export default function ThreadBuilder({ refreshKey, selectedPersonaId }: ThreadBuilderProps) {
  const [topic, setTopic] = useState("");
  const [persona, setPersona] = useState("data_driven");
  const [threadLength, setThreadLength] = useState<3 | 5 | 10>(5);
  const [allPersonas, setAllPersonas] = useState<Persona[]>(defaultPersonas);
  const [generatedThread, setGeneratedThread] = useState<ExtendedGeneratedThread | null>(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [retryAfter, setRetryAfter] = useState<number | undefined>(undefined);
  const [copiedAll, setCopiedAll] = useState(false);

  useEffect(() => {
    const custom = getCustomPersonas();
    const saved = getSavedPersonas();
    const savedAsCustom = saved.map(p => ({ ...p, isCustom: true as const }));
    setAllPersonas([...savedAsCustom, ...custom, ...defaultPersonas]);
  }, [refreshKey]);

  useEffect(() => {
    if (selectedPersonaId) {
      const savedPersona = getSavedPersonaById(selectedPersonaId);
      if (savedPersona) {
        setPersona(savedPersona.id);
      }
    }
  }, [selectedPersonaId]);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();

    if (!topic.trim()) {
      setError("Lutfen bir konu girin");
      return;
    }

    setLoading(true);
    setError(null);
    setRetryAfter(undefined);
    setGeneratedThread(null);

    try {
      const selectedPersona = allPersonas.find(p => p.id === persona);
      const requestBody = {
        topic: topic.trim(),
        persona,
        threadLength,
        customPersona: selectedPersona?.isCustom ? selectedPersona : undefined,
      };

      const response = await fetch("/api/thread", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(requestBody),
      });

      const result = await response.json();

      if (result.success && result.data) {
        setGeneratedThread(result.data);

        const selectedPersona = allPersonas.find(p => p.id === persona);
        const savedPersona = getSavedPersonaById(persona);

        addToHistory({
          type: "thread",
          content: result.data.tweets,
          topic: topic.trim(),
          persona: selectedPersona?.name || persona,
          personaId: savedPersona?.id,
          score: result.data.totalScore,
        });

        if (savedPersona) {
          incrementPersonaTweetCount(savedPersona.id);
        }
      } else {
        setError(result.error || "Thread olusturulamadi");
        if (result.retryAfter) {
          setRetryAfter(result.retryAfter);
        }
      }
    } catch (err) {
      const message = err instanceof Error ? err.message : "Baglanti hatasi";
      setError(message);
    } finally {
      setLoading(false);
    }
  };

  const handleCopyAll = async () => {
    if (!generatedThread) return;
    const allTweets = threadToText(generatedThread.tweets);
    const success = await copyToClipboard(allTweets);
    if (success) {
      setCopiedAll(true);
      setTimeout(() => setCopiedAll(false), 2000);
    }
  };

  return (
    <div className="space-y-6">
      <div className="bg-gray-800/50 backdrop-blur rounded-2xl shadow-xl p-6 border border-gray-700/50">
        <div className="flex items-center gap-3 mb-6">
          <span className="text-3xl" aria-hidden="true">🧵</span>
          <div>
            <h2 className="text-xl font-bold text-white">Thread Builder</h2>
            <p className="text-sm text-gray-400">Viral thread'ler olustur</p>
          </div>
        </div>

        <form onSubmit={handleSubmit} className="space-y-5">
          {/* Topic Input */}
          <div>
            <label htmlFor="topic" className="block text-sm font-medium text-gray-300 mb-2">
              Thread Konusu
            </label>
            <textarea
              id="topic"
              rows={3}
              value={topic}
              onChange={(e) => setTopic(e.target.value)}
              className="w-full px-4 py-3 bg-gray-900/50 border border-gray-700 rounded-xl focus:ring-2 focus:ring-purple-500 focus:border-transparent text-white placeholder-gray-500 resize-none"
              placeholder="Orn: Yapay zeka ile para kazanmanin 5 yolu..."
            />
          </div>

          {/* Persona ve Thread Length */}
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            {/* Persona Selection */}
            <div>
              <label htmlFor="persona" className="block text-sm font-medium text-gray-300 mb-2">
                Persona / Stil
              </label>
              <select
                id="persona"
                value={persona}
                onChange={(e) => setPersona(e.target.value)}
                className="w-full px-4 py-3 bg-gray-900/50 border border-gray-700 rounded-xl focus:ring-2 focus:ring-purple-500 focus:border-transparent text-white"
              >
                {allPersonas.filter(p => p.isCustom).length > 0 && (
                  <optgroup label="Analiz Edilen Hesaplar" className="bg-gray-900">
                    {allPersonas.filter(p => p.isCustom).map((p) => (
                      <option key={p.id} value={p.id} className="bg-gray-900">
                        @{p.sourceUsername}
                      </option>
                    ))}
                  </optgroup>
                )}
                <optgroup label="Hazir Personalar" className="bg-gray-900">
                  {allPersonas.filter(p => !p.isCustom).map((p) => (
                    <option key={p.id} value={p.id} className="bg-gray-900">
                      {p.name}
                    </option>
                  ))}
                </optgroup>
              </select>
            </div>

            {/* Thread Length */}
            <div>
              <label className="block text-sm font-medium text-gray-300 mb-2">
                Thread Uzunlugu
              </label>
              <div className="flex gap-2" role="group" aria-label="Thread uzunlugu secimi">
                {[3, 5, 10].map((len) => (
                  <button
                    key={len}
                    type="button"
                    onClick={() => setThreadLength(len as 3 | 5 | 10)}
                    aria-pressed={threadLength === len}
                    className={`flex-1 py-3 px-4 rounded-xl font-medium transition-all ${
                      threadLength === len
                        ? "bg-gradient-to-r from-purple-500 to-pink-600 text-white shadow-lg"
                        : "bg-gray-900/50 border border-gray-700 text-gray-400 hover:border-gray-600"
                    }`}
                  >
                    {len} Tweet
                  </button>
                ))}
              </div>
            </div>
          </div>

          <ErrorMessage
            error={error}
            onDismiss={() => { setError(null); setRetryAfter(undefined); }}
            onRetry={() => handleSubmit({ preventDefault: () => {} } as React.FormEvent)}
            retryAfter={retryAfter}
          />

          <LoadingButton
            type="submit"
            loading={loading}
            loadingText="Thread Olusturuluyor..."
            colorScheme="purple"
          >
            🧵 Thread Olustur
          </LoadingButton>
        </form>
      </div>

      {/* Generated Thread Display */}
      {generatedThread && (
        <div className="bg-gray-800/50 backdrop-blur rounded-2xl shadow-xl p-6 border border-gray-700/50">
          <div className="flex items-center justify-between mb-6 border-b border-gray-700/50 pb-4">
            <div className="flex items-center gap-3">
              <h3 className="text-xl font-bold text-white">
                Olusturulan Thread
              </h3>
              <span className={`bg-gradient-to-r ${getTotalScoreGradient(generatedThread.totalScore)} text-white px-3 py-1 rounded-lg text-sm font-bold`}>
                {generatedThread.totalScore}/100
              </span>
            </div>
            <button
              onClick={handleCopyAll}
              aria-label={copiedAll ? "Kopyalandi" : "Tum thread'i kopyala"}
              className={`flex items-center gap-2 px-4 py-2 rounded-lg transition ${
                copiedAll
                  ? "bg-green-500 text-white"
                  : "bg-purple-500 hover:bg-purple-600 text-white"
              }`}
            >
              {copiedAll ? (
                <>
                  <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24" aria-hidden="true">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5 13l4 4L19 7" />
                  </svg>
                  Kopyalandi!
                </>
              ) : (
                <>
                  <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24" aria-hidden="true">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M8 16H6a2 2 0 01-2-2V6a2 2 0 012-2h8a2 2 0 012 2v2m-6 12h8a2 2 0 002-2v-8a2 2 0 00-2-2h-8a2 2 0 00-2 2v8a2 2 0 002 2z" />
                  </svg>
                  Tumunu Kopyala
                </>
              )}
            </button>
          </div>

          {/* Thread Timeline */}
          <div className="space-y-4">
            {generatedThread.tweets.map((tweet, index) => (
              <ThreadTweetCard
                key={index}
                tweet={tweet}
                index={index}
                isLast={index === generatedThread.tweets.length - 1}
              />
            ))}
          </div>

          {/* Thread Analysis */}
          {generatedThread.threadAnalysis && (
            <div className="mt-6 space-y-4">
              <ThreadStats
                hookScore={generatedThread.threadAnalysis.hookScore}
                averageEngagement={generatedThread.threadAnalysis.averageEngagement}
                totalScore={generatedThread.totalScore}
              />
              <ThreadAnalysisPanel
                strengths={generatedThread.threadAnalysis.strengths}
                improvements={generatedThread.threadAnalysis.improvements}
              />
            </div>
          )}

          {/* Reasoning */}
          {generatedThread.reasoning && (
            <div className="mt-6 bg-purple-500/10 border border-purple-500/30 rounded-xl p-4">
              <h4 className="text-sm font-semibold text-purple-400 mb-2">
                AI Analizi
              </h4>
              <p className="text-gray-300 text-sm">
                {generatedThread.reasoning}
              </p>
            </div>
          )}
        </div>
      )}
    </div>
  );
}

