"use client";

import { useState, useEffect } from "react";
import { defaultPersonas, getCustomPersonas } from "@/lib/personas";
import { Persona, XAlgorithmScore } from "@/types";
import { addToHistory } from "@/lib/history";
import { getSavedPersonas, getSavedPersonaById, incrementPersonaTweetCount } from "@/lib/personaStorage";
import { copyToClipboard, getTotalScoreGradient, getScoreColor, getCategoryColor } from "@/lib/utils";
import { LoadingButton, ErrorMessage } from "@/components/ui";

interface QuoteGeneratorProps {
  refreshKey?: number;
  selectedPersonaId?: string;
}

interface GeneratedQuote {
  content: string;
  style: string;
  xScore: XAlgorithmScore;
}

interface QuoteResult {
  originalTweet: string;
  quotes: GeneratedQuote[];
  persona: string;
  style: string;
}

const quoteStyles = [
  { id: "insight", name: "Icgoru", icon: "🧠", description: "Derin analiz ekle" },
  { id: "hot_take", name: "Hot Take", icon: "🔥", description: "Cesur gorus sun" },
  { id: "story", name: "Hikaye", icon: "📖", description: "Kisisel deneyim" },
  { id: "data", name: "Veri", icon: "📊", description: "Rakamlarla destekle" },
  { id: "contrarian", name: "Zit Gorus", icon: "🔄", description: "Farkli perspektif" },
];

export default function QuoteGenerator({ refreshKey, selectedPersonaId }: QuoteGeneratorProps) {
  const [originalTweet, setOriginalTweet] = useState("");
  const [persona, setPersona] = useState("data_driven");
  const [quoteStyle, setQuoteStyle] = useState("insight");
  const [allPersonas, setAllPersonas] = useState<Persona[]>(defaultPersonas);
  const [result, setResult] = useState<QuoteResult | null>(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [retryAfter, setRetryAfter] = useState<number | undefined>(undefined);
  const [copiedIndex, setCopiedIndex] = useState<number | null>(null);

  useEffect(() => {
    const custom = getCustomPersonas();
    const saved = getSavedPersonas();
    const savedAsCustom = saved.map(p => ({ ...p, isCustom: true as const }));
    setAllPersonas([...savedAsCustom, ...custom, ...defaultPersonas]);
  }, [refreshKey]);

  useEffect(() => {
    if (selectedPersonaId) {
      const savedPersona = getSavedPersonaById(selectedPersonaId);
      if (savedPersona) {
        setPersona(savedPersona.id);
      }
    }
  }, [selectedPersonaId]);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();

    if (!originalTweet.trim()) {
      setError("Lutfen bir tweet girin");
      return;
    }

    setLoading(true);
    setError(null);
    setRetryAfter(undefined);
    setResult(null);

    try {
      const selectedPersona = allPersonas.find(p => p.id === persona);
      const response = await fetch("/api/quote", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          originalTweet: originalTweet.trim(),
          persona,
          quoteStyle,
          customPersona: selectedPersona?.isCustom ? selectedPersona : undefined,
        }),
      });

      const data = await response.json();

      if (data.success && data.data) {
        setResult(data.data);

        const selectedPersona = allPersonas.find(p => p.id === persona);
        const savedPersona = getSavedPersonaById(persona);

        data.data.quotes.forEach((quote: GeneratedQuote) => {
          addToHistory({
            type: "quote",
            content: quote.content,
            topic: originalTweet.trim().slice(0, 100) + "...",
            persona: selectedPersona?.name || persona,
            personaId: savedPersona?.id,
            score: quote.xScore.total,
          });

          if (savedPersona) {
            incrementPersonaTweetCount(savedPersona.id);
          }
        });
      } else {
        setError(data.error || "Quote tweet olusturulamadi");
        if (data.retryAfter) {
          setRetryAfter(data.retryAfter);
        }
      }
    } catch (err) {
      const message = err instanceof Error ? err.message : "Baglanti hatasi";
      setError(message);
    } finally {
      setLoading(false);
    }
  };

  const handleCopy = async (content: string, index: number) => {
    const success = await copyToClipboard(content);
    if (success) {
      setCopiedIndex(index);
      setTimeout(() => setCopiedIndex(null), 2000);
    }
  };

  return (
    <div className="space-y-6">
      <div className="bg-gray-800/50 backdrop-blur rounded-2xl shadow-xl p-6 border border-gray-700/50">
        <div className="flex items-center gap-3 mb-6">
          <span className="text-3xl" aria-hidden="true">🔁</span>
          <div>
            <h2 className="text-xl font-bold text-white">Quote Tweet</h2>
            <p className="text-sm text-gray-400">Deger katan quote'lar uret</p>
          </div>
        </div>

        <form onSubmit={handleSubmit} className="space-y-5">
          {/* Original Tweet Input */}
          <div>
            <label htmlFor="originalTweet" className="block text-sm font-medium text-gray-300 mb-2">
              Orijinal Tweet
            </label>
            <textarea
              id="originalTweet"
              rows={4}
              value={originalTweet}
              onChange={(e) => setOriginalTweet(e.target.value)}
              className="w-full px-4 py-3 bg-gray-900/50 border border-gray-700 rounded-xl focus:ring-2 focus:ring-amber-500 focus:border-transparent text-white placeholder-gray-500 resize-none"
              placeholder="Quote yapmak istediginiz tweet'i yapistirin..."
            />
          </div>

          {/* Quote Style Selection */}
          <div>
            <label className="block text-sm font-medium text-gray-300 mb-3">
              Quote Stili
            </label>
            <div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-5 gap-2" role="group" aria-label="Quote stili secimi">
              {quoteStyles.map((style) => (
                <button
                  key={style.id}
                  type="button"
                  onClick={() => setQuoteStyle(style.id)}
                  aria-pressed={quoteStyle === style.id}
                  className={`p-3 rounded-xl border transition-all text-center ${
                    quoteStyle === style.id
                      ? "border-amber-500 bg-amber-500/20 text-amber-400"
                      : "border-gray-700 bg-gray-900/50 text-gray-400 hover:border-gray-600"
                  }`}
                >
                  <div className="text-xl mb-1" aria-hidden="true">{style.icon}</div>
                  <div className="text-xs font-medium">{style.name}</div>
                </button>
              ))}
            </div>
          </div>

          {/* Persona Selection */}
          <div>
            <label htmlFor="persona" className="block text-sm font-medium text-gray-300 mb-2">
              Persona / Stil
            </label>
            <select
              id="persona"
              value={persona}
              onChange={(e) => setPersona(e.target.value)}
              className="w-full px-4 py-3 bg-gray-900/50 border border-gray-700 rounded-xl focus:ring-2 focus:ring-amber-500 focus:border-transparent text-white"
            >
              {allPersonas.filter(p => p.isCustom).length > 0 && (
                <optgroup label="Analiz Edilen Hesaplar" className="bg-gray-900">
                  {allPersonas.filter(p => p.isCustom).map((p) => (
                    <option key={p.id} value={p.id} className="bg-gray-900">
                      @{p.sourceUsername}
                    </option>
                  ))}
                </optgroup>
              )}
              <optgroup label="Hazir Personalar" className="bg-gray-900">
                {allPersonas.filter(p => !p.isCustom).map((p) => (
                  <option key={p.id} value={p.id} className="bg-gray-900">
                    {p.name}
                  </option>
                ))}
              </optgroup>
            </select>
          </div>

          <ErrorMessage
            error={error}
            onDismiss={() => { setError(null); setRetryAfter(undefined); }}
            onRetry={() => handleSubmit({ preventDefault: () => {} } as React.FormEvent)}
            retryAfter={retryAfter}
          />

          <LoadingButton
            type="submit"
            loading={loading}
            loadingText="Quote'lar Olusturuluyor..."
            colorScheme="amber"
          >
            🔁 Quote Onerileri Uret
          </LoadingButton>
        </form>
      </div>

      {/* Generated Quotes */}
      {result && (
        <div className="bg-gray-800/50 backdrop-blur rounded-2xl shadow-xl p-6 border border-gray-700/50">
          <div className="flex items-center justify-between mb-6 border-b border-gray-700/50 pb-4">
            <h3 className="text-xl font-bold text-white">
              Quote Onerileri
            </h3>
            <span className="text-sm text-gray-400">
              {result.quotes.length} oneri
            </span>
          </div>

          {/* Original Tweet Preview */}
          <div className="bg-gray-900/50 rounded-xl p-4 mb-5 border border-gray-700/50">
            <div className="text-xs text-gray-500 mb-2">Orijinal Tweet:</div>
            <p className="text-gray-300 text-sm">{result.originalTweet}</p>
          </div>

          {/* Quote Cards */}
          <div className="space-y-4">
            {result.quotes.map((quote, index) => (
              <div
                key={index}
                className="bg-gray-900/50 rounded-xl p-4 border border-gray-700/50 hover:border-amber-500/50 transition-all"
              >
                {/* Header with Score Badge */}
                <div className="flex items-start justify-between mb-3">
                  <div className="flex items-center gap-2">
                    <span className="text-lg" aria-hidden="true">
                      {quoteStyles.find(s => s.id === quote.style)?.icon || "🔁"}
                    </span>
                    <span className="text-xs text-gray-500 capitalize">{quote.style}</span>
                  </div>
                  <span className={`bg-gradient-to-r ${getTotalScoreGradient(quote.xScore.total)} text-white px-3 py-1 rounded-lg text-sm font-bold`}>
                    X {quote.xScore.total}/100
                  </span>
                </div>

                <p className="text-white mb-4">{quote.content}</p>

                {/* X Algorithm Score Breakdown */}
                <div className="bg-gray-800/50 rounded-lg p-3 mb-3">
                  <div className="text-xs text-gray-400 mb-2 font-medium">X Algorithm Analizi</div>
                  <div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-5 gap-2 text-xs">
                    {[
                      { label: "Hook", key: "hook_strength" as const },
                      { label: "Engagement", key: "engagement_potential" as const },
                      { label: "Viral", key: "viral_potential" as const },
                      { label: "Algoritma", key: "algorithm_fit" as const },
                      { label: "Kalite", key: "content_quality" as const },
                    ].map((item) => (
                      <div key={item.key} className="text-center">
                        <div className="text-gray-500 mb-1">{item.label}</div>
                        <div className="h-1.5 bg-gray-700 rounded-full overflow-hidden">
                          <div
                            className={`h-full ${getCategoryColor(quote.xScore[item.key])} transition-all`}
                            style={{ width: `${(quote.xScore[item.key] / 20) * 100}%` }}
                            role="progressbar"
                            aria-valuenow={quote.xScore[item.key]}
                            aria-valuemin={0}
                            aria-valuemax={20}
                          />
                        </div>
                        <div className={`font-bold mt-1 ${getScoreColor(quote.xScore[item.key], 20)}`}>
                          {quote.xScore[item.key]}
                        </div>
                      </div>
                    ))}
                  </div>
                </div>

                {/* Engagement Predictions */}
                <div className="flex flex-wrap gap-2 mb-3 text-xs">
                  <span className="px-2 py-1 bg-gray-800 rounded text-gray-400">
                    ❤️ {Math.round(quote.xScore.predictions.favorite_score * 100)}%
                  </span>
                  <span className="px-2 py-1 bg-gray-800 rounded text-gray-400">
                    💬 {Math.round(quote.xScore.predictions.reply_score * 100)}%
                  </span>
                  <span className="px-2 py-1 bg-gray-800 rounded text-gray-400">
                    🔁 {Math.round(quote.xScore.predictions.repost_score * 100)}%
                  </span>
                  <span className="px-2 py-1 bg-gray-800 rounded text-gray-400">
                    🔖 {Math.round(quote.xScore.predictions.bookmark_score * 100)}%
                  </span>
                </div>

                {/* Strengths & Improvements */}
                {(quote.xScore.strengths.length > 0 || quote.xScore.improvements.length > 0) && (
                  <div className="grid grid-cols-1 sm:grid-cols-2 gap-2 mb-3 text-xs">
                    {quote.xScore.strengths.length > 0 && (
                      <div className="bg-green-500/10 border border-green-500/30 rounded-lg p-2">
                        <div className="text-green-400 font-medium mb-1 flex items-center gap-1">
                          <span aria-hidden="true">✓</span> Guclu Yonler
                        </div>
                        {quote.xScore.strengths.slice(0, 2).map((s, i) => (
                          <div key={i} className="text-gray-400">{s}</div>
                        ))}
                      </div>
                    )}
                    {quote.xScore.improvements.length > 0 && (
                      <div className="bg-yellow-500/10 border border-yellow-500/30 rounded-lg p-2">
                        <div className="text-yellow-400 font-medium mb-1 flex items-center gap-1">
                          <span aria-hidden="true">↑</span> Gelistirilebilir
                        </div>
                        {quote.xScore.improvements.slice(0, 2).map((s, i) => (
                          <div key={i} className="text-gray-400">{s}</div>
                        ))}
                      </div>
                    )}
                  </div>
                )}

                <div className="flex items-center justify-between text-sm">
                  <span className="text-gray-500">{quote.content.length} karakter</span>
                  <button
                    onClick={() => handleCopy(quote.content, index)}
                    aria-label={copiedIndex === index ? "Kopyalandi" : `Quote ${index + 1}'i kopyala`}
                    className={`flex items-center gap-1 px-3 py-1.5 rounded-lg transition ${
                      copiedIndex === index
                        ? "bg-green-500 text-white"
                        : "bg-amber-500 hover:bg-amber-600 text-white"
                    }`}
                  >
                    {copiedIndex === index ? (
                      <>
                        <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24" aria-hidden="true">
                          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5 13l4 4L19 7" />
                        </svg>
                        Kopyalandi
                      </>
                    ) : (
                      <>
                        <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24" aria-hidden="true">
                          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M8 16H6a2 2 0 01-2-2V6a2 2 0 012-2h8a2 2 0 012 2v2m-6 12h8a2 2 0 002-2v-8a2 2 0 00-2-2h-8a2 2 0 00-2 2v8a2 2 0 002 2z" />
                        </svg>
                        Kopyala
                      </>
                    )}
                  </button>
                </div>
              </div>
            ))}
          </div>
        </div>
      )}
    </div>
  );
}

