"use client";

import { useState, useEffect, useCallback, useRef } from "react";
import { HistoryItem } from "@/types";
import {
  getHistory,
  toggleFavorite,
  deleteHistoryItem,
  clearHistory,
  downloadExport,
  getFavorites,
  getPostedItems,
  getUnpostedItems,
} from "@/lib/history";
import { ConfirmDialog, EmptyState } from "@/components/ui";
import { HistoryItemCard, HistoryFilters, HistoryToolbar } from "@/components/history";

interface HistoryPanelProps {
  isOpen: boolean;
  onClose: () => void;
}

type FilterType = "all" | "favorites" | "posted" | "unposted";

export default function HistoryPanel({ isOpen, onClose }: HistoryPanelProps) {
  const [history, setHistory] = useState<HistoryItem[]>([]);
  const [filter, setFilter] = useState<FilterType>("all");
  const [typeFilter, setTypeFilter] = useState<string>("all");
  const [showClearConfirm, setShowClearConfirm] = useState(false);
  const [deleteConfirm, setDeleteConfirm] = useState<{ show: boolean; id: string | null }>({ show: false, id: null });
  const panelRef = useRef<HTMLDivElement>(null);

  const loadHistory = useCallback(() => {
    let items: HistoryItem[];
    switch (filter) {
      case "favorites":
        items = getFavorites();
        break;
      case "posted":
        items = getPostedItems();
        break;
      case "unposted":
        items = getUnpostedItems();
        break;
      default:
        items = getHistory();
    }
    setHistory(items);
  }, [filter]);

  useEffect(() => {
    if (isOpen) {
      loadHistory();
    }
  }, [isOpen, loadHistory]);

  // Escape key to close
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (e.key === "Escape" && isOpen) {
        onClose();
      }
    };
    document.addEventListener("keydown", handleKeyDown);
    return () => document.removeEventListener("keydown", handleKeyDown);
  }, [isOpen, onClose]);

  // Focus trap
  useEffect(() => {
    if (isOpen && panelRef.current) {
      panelRef.current.focus();
    }
  }, [isOpen]);

  const handleToggleFavorite = (id: string) => {
    toggleFavorite(id);
    loadHistory();
  };

  const handleDeleteClick = (id: string) => {
    setDeleteConfirm({ show: true, id });
  };

  const handleDeleteConfirm = () => {
    if (deleteConfirm.id) {
      deleteHistoryItem(deleteConfirm.id);
      loadHistory();
    }
    setDeleteConfirm({ show: false, id: null });
  };

  const handleClearAll = () => {
    clearHistory();
    loadHistory();
    setShowClearConfirm(false);
  };

  const handleExport = (format: "json" | "txt") => {
    downloadExport(format);
  };

  const filteredHistory = typeFilter === "all"
    ? history
    : history.filter(h => h.type === typeFilter);

  if (!isOpen) return null;

  return (
    <div
      className="fixed inset-0 bg-black/60 backdrop-blur-sm z-50 flex items-center justify-center p-4"
      role="dialog"
      aria-modal="true"
      aria-labelledby="history-panel-title"
    >
      <div
        ref={panelRef}
        tabIndex={-1}
        className="bg-[#16181c] rounded-2xl w-full max-w-full sm:max-w-2xl md:max-w-4xl max-h-[85vh] overflow-hidden border border-gray-800 outline-none"
      >
        {/* Header */}
        <div className="p-4 border-b border-gray-800 flex items-center justify-between">
          <div className="flex items-center gap-3">
            <span className="text-2xl" aria-hidden="true">📚</span>
            <h2 id="history-panel-title" className="text-xl font-bold">Tweet Gecmisi</h2>
            <span className="text-sm text-gray-500">({filteredHistory.length} kayit)</span>
          </div>
          <button
            onClick={onClose}
            aria-label="Paneli kapat"
            className="p-2 hover:bg-gray-800 rounded-full transition-colors"
          >
            <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24" aria-hidden="true">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" />
            </svg>
          </button>
        </div>

        {/* Toolbar */}
        <div className="p-4 border-b border-gray-800 flex flex-wrap gap-3 items-center justify-between">
          <HistoryFilters
            filter={filter}
            onFilterChange={setFilter}
            typeFilter={typeFilter}
            onTypeFilterChange={setTypeFilter}
          />
          <HistoryToolbar
            onExport={handleExport}
            onClearAll={() => setShowClearConfirm(true)}
            hasItems={history.length > 0}
          />
        </div>

        {/* Content */}
        <div className="overflow-y-auto max-h-[calc(85vh-180px)] p-4">
          {filteredHistory.length === 0 ? (
            <EmptyState
              icon="📭"
              title="Henuz kayit yok"
              description="Tweet olusturdugunuzda burada gorunecek"
            />
          ) : (
            <div className="space-y-4">
              {filteredHistory.map((item) => (
                <HistoryItemCard
                  key={item.id}
                  item={item}
                  onToggleFavorite={handleToggleFavorite}
                  onDelete={handleDeleteClick}
                />
              ))}
            </div>
          )}
        </div>
      </div>

      {/* Confirm Dialogs */}
      <ConfirmDialog
        isOpen={showClearConfirm}
        title="Gecmisi Temizle"
        message="Tum gecmis silinecek. Bu islem geri alinamaz."
        variant="danger"
        confirmText="Temizle"
        onConfirm={handleClearAll}
        onCancel={() => setShowClearConfirm(false)}
      />

      <ConfirmDialog
        isOpen={deleteConfirm.show}
        title="Kaydi Sil"
        message="Bu kayit kalici olarak silinecek."
        variant="warning"
        confirmText="Sil"
        onConfirm={handleDeleteConfirm}
        onCancel={() => setDeleteConfirm({ show: false, id: null })}
      />
    </div>
  );
}

