"use client";

import { useState, useEffect, useCallback } from "react";
import { CompetitorProfile } from "@/types";
import { safeGetJSON, safeSetJSON } from "@/lib/storage";
import { LoadingButton, ErrorMessage } from "@/components/ui";

interface CompetitorAnalysisProps {
  onUsePersona: (persona: { name: string; style: string; tone: string }) => void;
}

const SCRAPER_API_URL = typeof window !== "undefined"
  ? (window as unknown as { __SCRAPER_API_URL?: string }).__SCRAPER_API_URL || "http://localhost:3001"
  : "http://localhost:3001";

const COMPETITORS_STORAGE_KEY = "xpatla_competitors";

const MOCK_COMPETITOR_DATA: CompetitorProfile = {
  username: "demo_user",
  displayName: "Demo Kullanici",
  followers: 125000,
  avgLikes: 2500,
  avgRetweets: 450,
  topTweets: [
    { tweetId: "mock-1", content: "Basarinin sirri: Her gun kucuk adimlar atmak.", authorUsername: "demo_user", likes: 5200, retweets: 890, hookType: "statement", hookScore: 78 },
    { tweetId: "mock-2", content: "10 yilda ogrendigim en onemli 5 ders (thread):", authorUsername: "demo_user", likes: 8400, retweets: 1200, hookType: "data", hookScore: 85 },
    { tweetId: "mock-3", content: "Herkes LinkedIn'de network kurmak istiyor ama kimse gercek iliskiler kurmuyor.", authorUsername: "demo_user", likes: 3800, retweets: 620, hookType: "contrarian", hookScore: 82 },
  ],
  hookDistribution: { data: 35, story: 25, contrarian: 20, question: 15, statement: 5 },
  bestPostingHours: [9, 12, 18, 20, 21],
};

const HOOK_TYPE_LABELS: Record<string, string> = { data: "Veri/Rakam", contrarian: "Zit Gorus", story: "Hikaye", question: "Soru", statement: "Aciklama" };

function formatNumber(num: number): string {
  if (num >= 1000000) return (num / 1000000).toFixed(1) + "M";
  if (num >= 1000) return (num / 1000).toFixed(1) + "K";
  return num.toString();
}

export default function CompetitorAnalysis({ onUsePersona }: CompetitorAnalysisProps) {
  const [username, setUsername] = useState("");
  const [competitors, setCompetitors] = useState<string[]>([]);
  const [selectedCompetitor, setSelectedCompetitor] = useState<string | null>(null);
  const [competitorData, setCompetitorData] = useState<CompetitorProfile | null>(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [isOffline, setIsOffline] = useState(false);

  useEffect(() => {
    const saved = safeGetJSON<string[]>(COMPETITORS_STORAGE_KEY, []);
    setCompetitors(saved);
    if (saved.length > 0 && !selectedCompetitor) setSelectedCompetitor(saved[0]);
  }, [selectedCompetitor]);

  useEffect(() => {
    if (selectedCompetitor) fetchCompetitorData(selectedCompetitor);
  }, [selectedCompetitor]);

  const fetchCompetitorData = async (user: string) => {
    setLoading(true);
    setError(null);
    try {
      const res = await fetch(`${SCRAPER_API_URL}/api/competitors/${user}`, { signal: AbortSignal.timeout(10000) });
      if (res.ok) {
        const data = await res.json();
        if (data.success && data.data) {
          setCompetitorData(data.data);
          setIsOffline(false);
          return;
        }
      }
      throw new Error("API yanit vermedi");
    } catch {
      setIsOffline(true);
      setCompetitorData({
        ...MOCK_COMPETITOR_DATA,
        username: user,
        displayName: `@${user}`,
        topTweets: MOCK_COMPETITOR_DATA.topTweets.map((t) => ({ ...t, authorUsername: user })),
      });
    } finally {
      setLoading(false);
    }
  };

  const addCompetitor = useCallback(() => {
    const cleanUsername = username.trim().replace(/^@/, "");
    if (!cleanUsername) {
      setError("Lutfen bir kullanici adi girin");
      return;
    }
    if (competitors.includes(cleanUsername)) {
      setError("Bu hesap zaten eklenmis");
      return;
    }
    const newCompetitors = [...competitors, cleanUsername];
    setCompetitors(newCompetitors);
    safeSetJSON(COMPETITORS_STORAGE_KEY, newCompetitors);
    setSelectedCompetitor(cleanUsername);
    setUsername("");
    setError(null);
  }, [username, competitors]);

  const removeCompetitor = useCallback(
    (user: string) => {
      const newCompetitors = competitors.filter((c) => c !== user);
      setCompetitors(newCompetitors);
      safeSetJSON(COMPETITORS_STORAGE_KEY, newCompetitors);
      if (selectedCompetitor === user) {
        setSelectedCompetitor(newCompetitors[0] || null);
        setCompetitorData(null);
      }
    },
    [competitors, selectedCompetitor]
  );

  const handleUseAsPersona = () => {
    if (!competitorData) return;
    const dominantHook = Object.entries(competitorData.hookDistribution).sort((a, b) => b[1] - a[1])[0]?.[0] || "statement";
    const styleDescription = `@${competitorData.username} tarzinda: ${HOOK_TYPE_LABELS[dominantHook] || dominantHook} agirlikli, ortalama ${formatNumber(competitorData.avgLikes)} begeni alan tweetler`;
    onUsePersona({
      name: `@${competitorData.username} Tarzi`,
      style: styleDescription,
      tone: dominantHook === "contrarian" ? "provocative" : dominantHook === "story" ? "narrative" : "informative",
    });
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === "Enter") {
      e.preventDefault();
      addCompetitor();
    }
  };

  const maxDistribution = competitorData ? Math.max(...Object.values(competitorData.hookDistribution), 1) : 1;

  return (
    <div className="space-y-6">
      {isOffline && (
        <div className="bg-amber-500/10 border border-amber-500/30 text-amber-400 px-4 py-3 rounded-xl flex items-center gap-3">
          <svg className="w-5 h-5 flex-shrink-0" fill="none" viewBox="0 0 24 24" stroke="currentColor">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" />
          </svg>
          <span>Demo veriler gosteriliyor - Scraper baglantisi yok</span>
        </div>
      )}

      <div className="bg-gray-800/50 backdrop-blur rounded-2xl shadow-xl p-6 border border-gray-700/50">
        <div className="flex items-center gap-3 mb-6">
          <span className="text-3xl" aria-hidden="true">🎯</span>
          <div>
            <h2 className="text-xl font-bold text-white">Rakip Analizi</h2>
            <p className="text-sm text-gray-400">Rakiplerinizin stratejilerini analiz edin</p>
          </div>
        </div>

        <div className="space-y-4">
          <div>
            <label htmlFor="competitor-username" className="block text-sm font-medium text-gray-300 mb-2">
              Rakip Hesap Ekle
            </label>
            <div className="flex gap-2">
              <input
                id="competitor-username"
                type="text"
                value={username}
                onChange={(e) => setUsername(e.target.value)}
                onKeyDown={handleKeyDown}
                className="flex-1 px-4 py-3 bg-gray-900/50 border border-gray-700 rounded-xl focus:ring-2 focus:ring-teal-500 focus:border-transparent text-white placeholder-gray-500"
                placeholder="@kullaniciadi"
              />
              <button
                onClick={addCompetitor}
                className="px-6 py-3 bg-gradient-to-r from-teal-500 to-cyan-600 hover:from-teal-600 hover:to-cyan-700 text-white font-medium rounded-xl transition-all hover:scale-105"
              >
                Ekle
              </button>
            </div>
          </div>

          <ErrorMessage error={error} onDismiss={() => setError(null)} />

          {competitors.length > 0 && (
            <div className="flex flex-wrap gap-2">
              {competitors.map((comp) => (
                <div
                  key={comp}
                  onClick={() => setSelectedCompetitor(comp)}
                  className={`group flex items-center gap-2 px-3 py-2 rounded-lg cursor-pointer transition-all ${
                    selectedCompetitor === comp
                      ? "bg-teal-500/20 border border-teal-500/50 text-teal-400"
                      : "bg-gray-900/50 border border-gray-700 text-gray-400 hover:border-gray-600"
                  }`}
                >
                  <span className="font-medium">@{comp}</span>
                  <button
                    onClick={(e) => {
                      e.stopPropagation();
                      removeCompetitor(comp);
                    }}
                    aria-label={`@${comp} hesabini kaldir`}
                    className="opacity-0 group-hover:opacity-100 text-red-400 hover:text-red-300 transition-opacity"
                  >
                    <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" />
                    </svg>
                  </button>
                </div>
              ))}
            </div>
          )}
        </div>
      </div>

      {loading ? (
        <div className="bg-gray-800/50 backdrop-blur rounded-2xl p-8 border border-gray-700/50">
          <div className="flex items-center justify-center gap-3 text-gray-400">
            <svg className="animate-spin h-5 w-5" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
              <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4" />
              <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z" />
            </svg>
            <span>Rakip verileri yukleniyor...</span>
          </div>
        </div>
      ) : competitorData ? (
        <div className="space-y-6">
          <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
            <div className="bg-gray-800/50 backdrop-blur rounded-xl p-4 border border-gray-700/50">
              <p className="text-sm text-gray-400 mb-1">Takipci</p>
              <p className="text-2xl font-bold text-white">{formatNumber(competitorData.followers)}</p>
            </div>
            <div className="bg-gray-800/50 backdrop-blur rounded-xl p-4 border border-gray-700/50">
              <p className="text-sm text-gray-400 mb-1">Ort. Begeni</p>
              <p className="text-2xl font-bold text-red-400">{formatNumber(competitorData.avgLikes)}</p>
            </div>
            <div className="bg-gray-800/50 backdrop-blur rounded-xl p-4 border border-gray-700/50">
              <p className="text-sm text-gray-400 mb-1">Ort. Retweet</p>
              <p className="text-2xl font-bold text-green-400">{formatNumber(competitorData.avgRetweets)}</p>
            </div>
            <div className="bg-gray-800/50 backdrop-blur rounded-xl p-4 border border-gray-700/50">
              <p className="text-sm text-gray-400 mb-1">Engagement</p>
              <p className="text-2xl font-bold text-blue-400">
                {(((competitorData.avgLikes + competitorData.avgRetweets) / competitorData.followers) * 100).toFixed(2)}%
              </p>
            </div>
          </div>

          <div className="bg-gray-800/50 backdrop-blur rounded-2xl p-6 border border-gray-700/50">
            <h3 className="text-lg font-semibold text-white mb-4">Hook Tipi Dagilimi</h3>
            <div className="space-y-3">
              {Object.entries(competitorData.hookDistribution)
                .sort((a, b) => b[1] - a[1])
                .map(([hookType, value]) => (
                  <div key={hookType} className="space-y-1">
                    <div className="flex justify-between text-sm">
                      <span className="text-gray-300">{HOOK_TYPE_LABELS[hookType] || hookType}</span>
                      <span className="text-gray-400">{value}%</span>
                    </div>
                    <div className="h-3 bg-gray-700 rounded-full overflow-hidden">
                      <div
                        className="h-full bg-gradient-to-r from-teal-500 to-cyan-500 rounded-full transition-all duration-500"
                        style={{ width: `${(value / maxDistribution) * 100}%` }}
                      />
                    </div>
                  </div>
                ))}
            </div>
          </div>

          <div className="bg-gray-800/50 backdrop-blur rounded-2xl p-6 border border-gray-700/50">
            <h3 className="text-lg font-semibold text-white mb-4">En Iyi Paylasim Saatleri</h3>
            <div className="flex items-end gap-1 h-32">
