                const isActive = competitorData.bestPostingHours.includes(hour);
                return (
                  <div key={hour} className="flex-1 flex flex-col items-center gap-1" title={`${hour}:00`}>
                    <div
                      className={`w-full rounded-t transition-all duration-300 ${
                        isActive ? "bg-gradient-to-t from-teal-600 to-cyan-400" : "bg-gray-700"
                      }`}
                      style={{ height: isActive ? "100%" : "20%" }}
                    />
                    {hour % 4 === 0 && <span className="text-xs text-gray-500">{hour}</span>}
                  </div>
                );
              })}
            </div>
            <p className="text-sm text-gray-400 mt-3">
              En iyi saatler: {competitorData.bestPostingHours.map((h) => `${h}:00`).join(", ")}
