            <div className="space-y-4">
              {competitorData.topTweets.map((tweet, index) => (
                <div key={tweet.tweetId} className="p-4 bg-gray-900/50 rounded-xl border border-gray-700/50">
                  <div className="flex items-center gap-2 mb-2">
                    <span className="text-lg font-bold text-gray-500">#{index + 1}</span>
                    {tweet.hookType && (
                      <span className="px-2 py-0.5 text-xs rounded-full bg-teal-500/20 text-teal-400 border border-teal-500/30">
                        {HOOK_TYPE_LABELS[tweet.hookType] || tweet.hookType}
                      </span>
                    )}
                  </div>
                  <p className="text-white mb-3">{tweet.content}</p>
                  <div className="flex items-center gap-4 text-sm text-gray-400">
                    <span className="flex items-center gap-1">
                      <svg className="w-4 h-4 text-red-400" fill="currentColor" viewBox="0 0 20 20">
                        <path fillRule="evenodd" d="M3.172 5.172a4 4 0 015.656 0L10 6.343l1.172-1.171a4 4 0 115.656 5.656L10 17.657l-6.828-6.829a4 4 0 010-5.656z" clipRule="evenodd" />
                      </svg>
                      {formatNumber(tweet.likes)}
                    </span>
                    <span className="flex items-center gap-1">
                      <svg className="w-4 h-4 text-green-400" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" />
                      </svg>
                      {formatNumber(tweet.retweets)}
                    </span>
                    <span className="flex items-center gap-1 ml-auto">
                      <span className="text-amber-400 font-medium">{tweet.hookScore}</span>
                      <span className="text-gray-500">/100</span>
                    </span>
                  </div>
                </div>
              ))}
            </div>
          </div>

          <LoadingButton type="button" loading={false} colorScheme="cyan" onClick={handleUseAsPersona}>
            Bu Hesap Gibi Yaz
          </LoadingButton>
        </div>
      ) : competitors.length === 0 ? (
        <div className="bg-gray-800/50 backdrop-blur rounded-2xl p-8 text-center border border-gray-700/50">
          <span className="text-4xl mb-4 block">🎯</span>
          <p className="text-gray-400">Analiz etmek icin bir rakip hesap ekleyin</p>
        </div>
      ) : null}
    </div>
  );
}

