"use client";

import { useState, useEffect } from "react";
import { NotificationConfig } from "@/types";
import { safeGetJSON, safeSetJSON } from "@/lib/storage";
import { LoadingButton, ErrorMessage } from "@/components/ui";

const SCRAPER_API_URL = typeof window !== "undefined"
  ? (window as unknown as { __SCRAPER_API_URL?: string }).__SCRAPER_API_URL || "http://localhost:3001"
  : "http://localhost:3001";

const NOTIFICATIONS_STORAGE_KEY = "xpatla_notifications";

const DEFAULT_CONFIG: NotificationConfig = {
  telegramBotToken: "",
  telegramChatId: "",
  discordWebhookUrl: "",
  enableViralAlerts: false,
  enablePostingReminders: false,
  enableDailyReport: false,
};

export default function NotificationSettings() {
  const [config, setConfig] = useState<NotificationConfig>(DEFAULT_CONFIG);
  const [loading, setLoading] = useState(false);
  const [testLoading, setTestLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [success, setSuccess] = useState<string | null>(null);
  const [mounted, setMounted] = useState(false);

  useEffect(() => {
    setMounted(true);
    const saved = safeGetJSON<NotificationConfig>(NOTIFICATIONS_STORAGE_KEY, DEFAULT_CONFIG);
    setConfig(saved);
  }, []);

  const handleSave = () => {
    setLoading(true);
    setError(null);
    setSuccess(null);

    try {
      const saveResult = safeSetJSON(NOTIFICATIONS_STORAGE_KEY, config);
      if (saveResult) {
        setSuccess("Ayarlar basariyla kaydedildi!");
        setTimeout(() => setSuccess(null), 3000);
      } else {
        setError("Ayarlar kaydedilemedi");
      }
    } catch {
      setError("Bir hata olustu");
    } finally {
      setLoading(false);
    }
  };

  const handleTestNotification = async () => {
    setTestLoading(true);
    setError(null);
    setSuccess(null);

    try {
      const res = await fetch(`${SCRAPER_API_URL}/api/notifications/test`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(config),
        signal: AbortSignal.timeout(10000),
      });

      if (res.ok) {
        const data = await res.json();
        if (data.success) {
          setSuccess("Test bildirimi gonderildi!");
        } else {
          setError(data.error || "Test bildirimi gonderilemedi");
        }
      } else {
        throw new Error("API yanit vermedi");
      }
    } catch {
      // Offline mode - simulate success for demo
      setSuccess("Demo: Test bildirimi simule edildi (Scraper baglantisi yok)");
    } finally {
      setTestLoading(false);
      setTimeout(() => {
        setSuccess(null);
        setError(null);
      }, 5000);
    }
  };

  const handleToggle = (key: keyof NotificationConfig) => {
    setConfig((prev) => ({
      ...prev,
      [key]: !prev[key],
    }));
  };

  if (!mounted) {
    return (
      <div className="bg-gray-800/50 backdrop-blur rounded-2xl p-8 border border-gray-700/50">
        <div className="flex items-center justify-center gap-3 text-gray-400">
          <svg className="animate-spin h-5 w-5" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
            <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4" />
            <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z" />
          </svg>
          <span>Ayarlar yukleniyor...</span>
        </div>
      </div>
    );
  }

  return (
    <div className="space-y-6">
      {/* Header */}
      <div className="bg-gray-800/50 backdrop-blur rounded-2xl shadow-xl p-6 border border-gray-700/50">
        <div className="flex items-center gap-3 mb-6">
          <span className="text-3xl" aria-hidden="true">🔔</span>
          <div>
            <h2 className="text-xl font-bold text-white">Bildirim Ayarlari</h2>
            <p className="text-sm text-gray-400">Telegram ve Discord entegrasyonlari</p>
          </div>
        </div>

        {/* Success Message */}
        {success && (
          <div className="mb-4 bg-green-500/10 border border-green-500/30 text-green-400 px-4 py-3 rounded-xl flex items-center gap-3">
            <svg className="w-5 h-5 flex-shrink-0" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5 13l4 4L19 7" />
            </svg>
            <span>{success}</span>
          </div>
        )}

        <ErrorMessage error={error} onDismiss={() => setError(null)} />

        <div className="space-y-6">
          {/* Telegram Section */}
          <div className="p-4 bg-gray-900/50 rounded-xl border border-gray-700/50">
            <div className="flex items-center gap-2 mb-4">
              <svg className="w-6 h-6 text-blue-400" viewBox="0 0 24 24" fill="currentColor">
                <path d="M11.944 0A12 12 0 0 0 0 12a12 12 0 0 0 12 12 12 12 0 0 0 12-12A12 12 0 0 0 12 0a12 12 0 0 0-.056 0zm4.962 7.224c.1-.002.321.023.465.14a.506.506 0 0 1 .171.325c.016.093.036.306.02.472-.18 1.898-.962 6.502-1.36 8.627-.168.9-.499 1.201-.82 1.23-.696.065-1.225-.46-1.9-.902-1.056-.693-1.653-1.124-2.678-1.8-1.185-.78-.417-1.21.258-1.91.177-.184 3.247-2.977 3.307-3.23.007-.032.014-.15-.056-.212s-.174-.041-.249-.024c-.106.024-1.793 1.14-5.061 3.345-.48.33-.913.49-1.302.48-.428-.008-1.252-.241-1.865-.44-.752-.245-1.349-.374-1.297-.789.027-.216.325-.437.893-.663 3.498-1.524 5.83-2.529 6.998-3.014 3.332-1.386 4.025-1.627 4.476-1.635z" />
              </svg>
              <h3 className="text-lg font-semibold text-white">Telegram</h3>
            </div>

            <div className="space-y-4">
              <div>
                <label htmlFor="telegram-token" className="block text-sm font-medium text-gray-300 mb-2">
                  Bot Token
                </label>
                <input
                  id="telegram-token"
                  type="password"
                  value={config.telegramBotToken || ""}
                  onChange={(e) => setConfig({ ...config, telegramBotToken: e.target.value })}
                  className="w-full px-4 py-3 bg-gray-800/50 border border-gray-700 rounded-xl focus:ring-2 focus:ring-yellow-500 focus:border-transparent text-white placeholder-gray-500"
                  placeholder="123456789:ABCdefGHIjklMNOpqrsTUVwxyz"
                />
                <p className="text-xs text-gray-500 mt-1">@BotFather'dan aldiginiz token</p>
              </div>

              <div>
                <label htmlFor="telegram-chat" className="block text-sm font-medium text-gray-300 mb-2">
                  Chat ID
                </label>
                <input
                  id="telegram-chat"
                  type="text"
                  value={config.telegramChatId || ""}
                  onChange={(e) => setConfig({ ...config, telegramChatId: e.target.value })}
                  className="w-full px-4 py-3 bg-gray-800/50 border border-gray-700 rounded-xl focus:ring-2 focus:ring-yellow-500 focus:border-transparent text-white placeholder-gray-500"
                  placeholder="-1001234567890"
                />
                <p className="text-xs text-gray-500 mt-1">@userinfobot ile ogrenebilirsiniz</p>
              </div>
            </div>
          </div>

          {/* Discord Section */}
          <div className="p-4 bg-gray-900/50 rounded-xl border border-gray-700/50">
            <div className="flex items-center gap-2 mb-4">
              <svg className="w-6 h-6 text-indigo-400" viewBox="0 0 24 24" fill="currentColor">
                <path d="M20.317 4.3698a19.7913 19.7913 0 00-4.8851-1.5152.0741.0741 0 00-.0785.0371c-.211.3753-.4447.8648-.6083 1.2495-1.8447-.2762-3.68-.2762-5.4868 0-.1636-.3933-.4058-.8742-.6177-1.2495a.077.077 0 00-.0785-.037 19.7363 19.7363 0 00-4.8852 1.515.0699.0699 0 00-.0321.0277C.5334 9.0458-.319 13.5799.0992 18.0578a.0824.0824 0 00.0312.0561c2.0528 1.5076 4.0413 2.4228 5.9929 3.0294a.0777.0777 0 00.0842-.0276c.4616-.6304.8731-1.2952 1.226-1.9942a.076.076 0 00-.0416-.1057c-.6528-.2476-1.2743-.5495-1.8722-.8923a.077.077 0 01-.0076-.1277c.1258-.0943.2517-.1923.3718-.2914a.0743.0743 0 01.0776-.0105c3.9278 1.7933 8.18 1.7933 12.0614 0a.0739.0739 0 01.0785.0095c.1202.099.246.1981.3728.2924a.077.077 0 01-.0066.1276 12.2986 12.2986 0 01-1.873.8914.0766.0766 0 00-.0407.1067c.3604.698.7719 1.3628 1.225 1.9932a.076.076 0 00.0842.0286c1.961-.6067 3.9495-1.5219 6.0023-3.0294a.077.077 0 00.0313-.0552c.5004-5.177-.8382-9.6739-3.5485-13.6604a.061.061 0 00-.0312-.0286zM8.02 15.3312c-1.1825 0-2.1569-1.0857-2.1569-2.419 0-1.3332.9555-2.4189 2.157-2.4189 1.2108 0 2.1757 1.0952 2.1568 2.419 0 1.3332-.9555 2.4189-2.1569 2.4189zm7.9748 0c-1.1825 0-2.1569-1.0857-2.1569-2.419 0-1.3332.9554-2.4189 2.1569-2.4189 1.2108 0 2.1757 1.0952 2.1568 2.419 0 1.3332-.946 2.4189-2.1568 2.4189Z" />
              </svg>
              <h3 className="text-lg font-semibold text-white">Discord</h3>
            </div>

            <div>
              <label htmlFor="discord-webhook" className="block text-sm font-medium text-gray-300 mb-2">
                Webhook URL
              </label>
              <input
                id="discord-webhook"
                type="password"
                value={config.discordWebhookUrl || ""}
                onChange={(e) => setConfig({ ...config, discordWebhookUrl: e.target.value })}
                className="w-full px-4 py-3 bg-gray-800/50 border border-gray-700 rounded-xl focus:ring-2 focus:ring-yellow-500 focus:border-transparent text-white placeholder-gray-500"
                placeholder="https://discord.com/api/webhooks/..."
              />
              <p className="text-xs text-gray-500 mt-1">Kanal ayarlari - Entegrasyonlar - Webhook</p>
            </div>
          </div>

          {/* Notification Toggles */}
          <div className="p-4 bg-gray-900/50 rounded-xl border border-gray-700/50">
            <h3 className="text-lg font-semibold text-white mb-4">Bildirim Turleri</h3>

            <div className="space-y-4">
              {/* Viral Alerts Toggle */}
              <div className="flex items-center justify-between">
                <div>
                  <p className="text-sm font-medium text-gray-300">Viral Uyarilari</p>
                  <p className="text-xs text-gray-500">Trend konular hakkinda bildirim al</p>
                </div>
                <button
                  type="button"
                  onClick={() => handleToggle("enableViralAlerts")}
                  className={`relative inline-flex h-6 w-11 items-center rounded-full transition-colors ${
                    config.enableViralAlerts ? "bg-yellow-500" : "bg-gray-700"
                  }`}
                  role="switch"
                  aria-checked={config.enableViralAlerts}
                >
                  <span
                    className={`inline-block h-4 w-4 transform rounded-full bg-white transition-transform ${
                      config.enableViralAlerts ? "translate-x-6" : "translate-x-1"
                    }`}
                  />
                </button>
              </div>

              {/* Posting Reminders Toggle */}
              <div className="flex items-center justify-between">
                <div>
                  <p className="text-sm font-medium text-gray-300">Paylasim Hatirlaticisi</p>
                  <p className="text-xs text-gray-500">En iyi saatlerde hatirlatma al</p>
                </div>
                <button
                  type="button"
                  onClick={() => handleToggle("enablePostingReminders")}
                  className={`relative inline-flex h-6 w-11 items-center rounded-full transition-colors ${
                    config.enablePostingReminders ? "bg-yellow-500" : "bg-gray-700"
                  }`}
                  role="switch"
                  aria-checked={config.enablePostingReminders}
                >
                  <span
                    className={`inline-block h-4 w-4 transform rounded-full bg-white transition-transform ${
                      config.enablePostingReminders ? "translate-x-6" : "translate-x-1"
                    }`}
                  />
                </button>
              </div>

              {/* Daily Report Toggle */}
              <div className="flex items-center justify-between">
                <div>
                  <p className="text-sm font-medium text-gray-300">Gunluk Rapor</p>
                  <p className="text-xs text-gray-500">Her gun ozet rapor al</p>
                </div>
                <button
                  type="button"
                  onClick={() => handleToggle("enableDailyReport")}
                  className={`relative inline-flex h-6 w-11 items-center rounded-full transition-colors ${
                    config.enableDailyReport ? "bg-yellow-500" : "bg-gray-700"
                  }`}
                  role="switch"
                  aria-checked={config.enableDailyReport}
                >
                  <span
                    className={`inline-block h-4 w-4 transform rounded-full bg-white transition-transform ${
                      config.enableDailyReport ? "translate-x-6" : "translate-x-1"
                    }`}
                  />
                </button>
              </div>
            </div>
          </div>

          {/* Action Buttons */}
          <div className="flex gap-3">
            <LoadingButton type="button" loading={loading} colorScheme="amber" onClick={handleSave} fullWidth={false}>
              Kaydet
            </LoadingButton>

            <button
              type="button"
              onClick={handleTestNotification}
              disabled={testLoading || (!config.telegramBotToken && !config.discordWebhookUrl)}
              className={`px-6 py-3 rounded-xl font-medium transition-all ${
                testLoading || (!config.telegramBotToken && !config.discordWebhookUrl)
                  ? "bg-gray-700 text-gray-500 cursor-not-allowed"
                  : "bg-gray-700 text-white hover:bg-gray-600"
              }`}
            >
              {testLoading ? (
                <span className="flex items-center gap-2">
                  <svg className="animate-spin h-4 w-4" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
                    <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4" />
                    <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z" />
                  </svg>
                  Test Ediliyor...
                </span>
              ) : (
                "Test Gonder"
              )}
            </button>
          </div>
        </div>
      </div>

      {/* Info Card */}
      <div className="bg-gray-800/50 backdrop-blur rounded-2xl p-6 border border-gray-700/50">
        <h3 className="text-lg font-semibold text-white mb-3">Nasil Calisir?</h3>
        <div className="space-y-3 text-sm text-gray-400">
          <p>
            <span className="text-blue-400 font-medium">Telegram:</span> @BotFather ile yeni bot olusturun, token'i buraya girin.
            Botunuza mesaj gonderip chat ID'nizi ogrenin.
          </p>
          <p>
            <span className="text-indigo-400 font-medium">Discord:</span> Sunucu ayarlarindan bir kanal secin, Entegrasyonlar - Webhook
            olusturun ve URL'i buraya yapistin.
          </p>
          <p>
            <span className="text-yellow-400 font-medium">Bildirimler:</span> Etkinlestirdiginiz bildirim turlerine gore
            otomatik mesajlar alacaksiniz.
          </p>
        </div>
      </div>
    </div>
  );
}

