   297→                </div>
   298→
   299→                <p className="text-white mb-4 leading-relaxed">{tweet.content}</p>
   300→
   301→                <div className="flex items-center justify-between">
   302→                  <div className="flex items-center gap-4 text-sm text-gray-400">
   303→                    <span className="flex items-center gap-1">
   304→                      <svg className="w-4 h-4 text-red-400" fill="currentColor" viewBox="0 0 20 20">
   305→                        <path fillRule="evenodd" d="M3.172 5.172a4 4 0 015.656 0L10 6.343l1.172-1.171a4 4 0 115.656 5.656L10 17.657l-6.828-6.829a4 4 0 010-5.656z" clipRule="evenodd" />
   306→                      </svg>
