"use client";

import { useState, useEffect, useCallback } from "react";
import { ViralTweet, PatternPerformance } from "@/types";
import { LoadingButton, ErrorMessage } from "@/components/ui";

interface ViralInspirationProps {
  onInspire: (topic: string, style: string) => void;
}

const SCRAPER_API_URL = typeof window !== "undefined"
  ? (window as unknown as { __SCRAPER_API_URL?: string }).__SCRAPER_API_URL || "http://localhost:3001"
  : "http://localhost:3001";

// Mock data for graceful degradation
const MOCK_VIRAL_TWEETS: ViralTweet[] = [
  {
    tweetId: "mock-1",
    content: "Yapay zeka 2025'te 10 meslegi tamamen degistirecek. Iste hangileri ve neden...",
    authorUsername: "techguru",
    likes: 15420,
    retweets: 3200,
    hookType: "data",
    hookScore: 92,
  },
  {
    tweetId: "mock-2",
    content: "Herkes AI'in isleri yok edecegini soyluyor. Kimse AI'in yaratacagi yeni mesleklerden bahsetmiyor.",
    authorUsername: "contrarian_tr",
    likes: 8900,
    retweets: 2100,
    hookType: "contrarian",
    hookScore: 88,
  },
  {
    tweetId: "mock-3",
    content: "Dun bir startup kurucusuyla konustum. Bana anlattigi hikaye tum bakis acimi degistirdi:",
    authorUsername: "startup_stories",
    likes: 12300,
    retweets: 2800,
    hookType: "story",
    hookScore: 85,
  },
  {
    tweetId: "mock-4",
    content: "Thread: 7 yilda 0'dan 1M takipciye nasil ulastim? Iste tam sureci...",
    authorUsername: "growth_master",
    likes: 18500,
    retweets: 4200,
    hookType: "data",
    hookScore: 94,
  },
  {
    tweetId: "mock-5",
    content: "Basarili insanlarin %90'i bu sabah rutinine sahip. Siz de deneyin:",
    authorUsername: "daily_habits",
    likes: 9800,
    retweets: 2400,
    hookType: "data",
    hookScore: 82,
  },
];

const MOCK_PATTERNS: PatternPerformance[] = [
  { pattern: "data", avgEngagement: 4500, avgLikes: 3200, avgRetweets: 1300, count: 156 },
  { pattern: "contrarian", avgEngagement: 3800, avgLikes: 2700, avgRetweets: 1100, count: 89 },
  { pattern: "story", avgEngagement: 3500, avgLikes: 2500, avgRetweets: 1000, count: 124 },
  { pattern: "question", avgEngagement: 3200, avgLikes: 2200, avgRetweets: 1000, count: 201 },
  { pattern: "statement", avgEngagement: 2800, avgLikes: 2000, avgRetweets: 800, count: 312 },
];

const HOOK_TYPE_LABELS: Record<string, { label: string; color: string }> = {
  data: { label: "Veri/Rakam", color: "bg-blue-500/20 text-blue-400 border-blue-500/30" },
  contrarian: { label: "Zit Gorus", color: "bg-purple-500/20 text-purple-400 border-purple-500/30" },
  story: { label: "Hikaye", color: "bg-amber-500/20 text-amber-400 border-amber-500/30" },
  question: { label: "Soru", color: "bg-cyan-500/20 text-cyan-400 border-cyan-500/30" },
  statement: { label: "Aciklama", color: "bg-green-500/20 text-green-400 border-green-500/30" },
};

function formatNumber(num: number): string {
  if (num >= 1000000) return (num / 1000000).toFixed(1) + "M";
  if (num >= 1000) return (num / 1000).toFixed(1) + "K";
  return num.toString();
}

export default function ViralInspiration({ onInspire }: ViralInspirationProps) {
  const [topic, setTopic] = useState("");
  const [viralTweets, setViralTweets] = useState<ViralTweet[]>([]);
  const [patterns, setPatterns] = useState<PatternPerformance[]>([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [isOffline, setIsOffline] = useState(false);
  const [activeTab, setActiveTab] = useState<"tweets" | "patterns" | "trends">("tweets");

  // Check scraper connection and load initial data
  useEffect(() => {
    checkScraperConnection();
    loadPatterns();
  }, []);

  const checkScraperConnection = async () => {
    try {
      const res = await fetch(`${SCRAPER_API_URL}/api/health`, {
        signal: AbortSignal.timeout(3000),
      });
      setIsOffline(!res.ok);
    } catch {
      setIsOffline(true);
    }
  };

  const loadPatterns = async () => {
    try {
      const res = await fetch(`${SCRAPER_API_URL}/api/patterns`, {
        signal: AbortSignal.timeout(5000),
      });
      if (res.ok) {
        const data = await res.json();
        if (data.success && data.data) {
          setPatterns(data.data);
          return;
        }
      }
    } catch {
      // Scraper offline
    }
    setPatterns(MOCK_PATTERNS);
  };

  const searchViralTweets = useCallback(async () => {
    if (!topic.trim()) {
      setError("Lutfen bir konu girin");
      return;
    }

    setLoading(true);
    setError(null);

    try {
      const res = await fetch(
        `${SCRAPER_API_URL}/api/viral-tweets?topic=${encodeURIComponent(topic)}&limit=20`,
        { signal: AbortSignal.timeout(10000) }
      );

      if (res.ok) {
        const data = await res.json();
        if (data.success && data.data) {
          setViralTweets(data.data);
          setIsOffline(false);
          return;
        }
      }
      throw new Error("API yanit vermedi");
    } catch {
      setIsOffline(true);
      // Filter mock data by topic (simple simulation)
      const filtered = MOCK_VIRAL_TWEETS.filter(
        (t) =>
          t.content.toLowerCase().includes(topic.toLowerCase()) ||
          topic.toLowerCase().includes("yapay zeka") ||
          topic.toLowerCase().includes("ai") ||
          topic.toLowerCase().includes("tech")
      );
      setViralTweets(filtered.length > 0 ? filtered : MOCK_VIRAL_TWEETS);
    } finally {
      setLoading(false);
    }
  }, [topic]);

  const handleInspire = (tweet: ViralTweet) => {
    const style = tweet.hookType || "statement";
    onInspire(tweet.content.slice(0, 100), style);
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === "Enter" && !e.shiftKey) {
      e.preventDefault();
      searchViralTweets();
    }
  };

  const maxEngagement = Math.max(...patterns.map((p) => p.avgEngagement), 1);

  return (
    <div className="space-y-6">
      {/* Offline Banner */}
      {isOffline && (
        <div className="bg-amber-500/10 border border-amber-500/30 text-amber-400 px-4 py-3 rounded-xl flex items-center gap-3">
          <svg className="w-5 h-5 flex-shrink-0" fill="none" viewBox="0 0 24 24" stroke="currentColor">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" />
          </svg>
          <span>Demo veriler gosteriliyor - Scraper baglantisi yok</span>
        </div>
      )}

      {/* Search Section */}
      <div className="bg-gray-800/50 backdrop-blur rounded-2xl shadow-xl p-6 border border-gray-700/50">
        <div className="flex items-center gap-3 mb-6">
          <span className="text-3xl" aria-hidden="true">🔥</span>
          <div>
            <h2 className="text-xl font-bold text-white">Viral Ilham</h2>
            <p className="text-sm text-gray-400">Viral tweetlerden ilham al</p>
          </div>
        </div>

        <div className="space-y-4">
          <div>
            <label htmlFor="viral-topic" className="block text-sm font-medium text-gray-300 mb-2">
              Konu Ara
            </label>
            <input
              id="viral-topic"
              type="text"
              value={topic}
              onChange={(e) => setTopic(e.target.value)}
              onKeyDown={handleKeyDown}
              className="w-full px-4 py-3 bg-gray-900/50 border border-gray-700 rounded-xl focus:ring-2 focus:ring-orange-500 focus:border-transparent text-white placeholder-gray-500"
              placeholder="Orn: yapay zeka, startup, teknoloji..."
            />
          </div>

          <ErrorMessage error={error} onDismiss={() => setError(null)} />

          <LoadingButton
            type="button"
            loading={loading}
            loadingText="Aranıyor..."
            colorScheme="amber"
            onClick={searchViralTweets}
          >
            Viral Tweetleri Ara
          </LoadingButton>
        </div>
      </div>

      {/* Tabs */}
      <div className="flex gap-2 bg-gray-800/30 p-1 rounded-xl">
        <button
          onClick={() => setActiveTab("tweets")}
          className={`flex-1 px-4 py-2 rounded-lg font-medium transition-all ${
            activeTab === "tweets"
              ? "bg-gradient-to-r from-orange-500 to-red-600 text-white"
              : "text-gray-400 hover:text-white"
          }`}
        >
          Viral Tweetler ({viralTweets.length})
        </button>
        <button
          onClick={() => setActiveTab("patterns")}
          className={`flex-1 px-4 py-2 rounded-lg font-medium transition-all ${
            activeTab === "patterns"
              ? "bg-gradient-to-r from-orange-500 to-red-600 text-white"
              : "text-gray-400 hover:text-white"
          }`}
        >
          Pattern Performansi
        </button>
        <button
          onClick={() => setActiveTab("trends")}
          className={`flex-1 px-4 py-2 rounded-lg font-medium transition-all ${
            activeTab === "trends"
              ? "bg-gradient-to-r from-orange-500 to-red-600 text-white"
              : "text-gray-400 hover:text-white"
          }`}
        >
          Trend Konular
        </button>
      </div>

      {/* Viral Tweets Tab */}
      {activeTab === "tweets" && (
        <div className="space-y-4">
          {viralTweets.length === 0 ? (
            <div className="bg-gray-800/50 backdrop-blur rounded-2xl p-8 text-center border border-gray-700/50">
              <span className="text-4xl mb-4 block">🔍</span>
              <p className="text-gray-400">Viral tweetleri gormek icin bir konu arayin</p>
            </div>
          ) : (
            viralTweets.map((tweet) => (
              <div
                key={tweet.tweetId}
                className="bg-gray-800/50 backdrop-blur rounded-xl p-5 border border-gray-700/50 hover:border-gray-600/50 transition-colors"
              >
                <div className="flex items-start justify-between gap-4 mb-3">
                  <div className="flex items-center gap-2">
                    <span className="text-gray-400">@{tweet.authorUsername}</span>
                    {tweet.hookType && HOOK_TYPE_LABELS[tweet.hookType] && (
                      <span className={`px-2 py-0.5 text-xs rounded-full border ${HOOK_TYPE_LABELS[tweet.hookType].color}`}>
                        {HOOK_TYPE_LABELS[tweet.hookType].label}
                      </span>
                    )}
                  </div>
                  <div className="flex items-center gap-1 text-sm">
                    <span className="text-amber-400 font-bold">{tweet.hookScore}</span>
                    <span className="text-gray-500">/100</span>
                  </div>
                </div>

                <p className="text-white mb-4 leading-relaxed">{tweet.content}</p>

                <div className="flex items-center justify-between">
                  <div className="flex items-center gap-4 text-sm text-gray-400">
                    <span className="flex items-center gap-1">
                      <svg className="w-4 h-4 text-red-400" fill="currentColor" viewBox="0 0 20 20">
                        <path fillRule="evenodd" d="M3.172 5.172a4 4 0 015.656 0L10 6.343l1.172-1.171a4 4 0 115.656 5.656L10 17.657l-6.828-6.829a4 4 0 010-5.656z" clipRule="evenodd" />
                      </svg>
                      {formatNumber(tweet.likes)}
                    </span>
                    <span className="flex items-center gap-1">
                      <svg className="w-4 h-4 text-green-400" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" />
                      </svg>
                      {formatNumber(tweet.retweets)}
                    </span>
                    {tweet.replies !== undefined && (
                      <span className="flex items-center gap-1">
                        <svg className="w-4 h-4 text-blue-400" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M8 12h.01M12 12h.01M16 12h.01M21 12c0 4.418-4.03 8-9 8a9.863 9.863 0 01-4.255-.949L3 20l1.395-3.72C3.512 15.042 3 13.574 3 12c0-4.418 4.03-8 9-8s9 3.582 9 8z" />
                        </svg>
                        {formatNumber(tweet.replies)}
                      </span>
                    )}
                  </div>

                  <button
                    onClick={() => handleInspire(tweet)}
                    className="px-4 py-2 bg-gradient-to-r from-orange-500 to-red-600 hover:from-orange-600 hover:to-red-700 text-white text-sm font-medium rounded-lg transition-all hover:scale-105"
                  >
                    Bu Tweet Gibi Yaz
                  </button>
                </div>
              </div>
            ))
          )}
        </div>
      )}

      {/* Pattern Performance Tab */}
      {activeTab === "patterns" && (
        <div className="bg-gray-800/50 backdrop-blur rounded-2xl p-6 border border-gray-700/50">
          <h3 className="text-lg font-semibold text-white mb-4">Hook Pattern Performansi</h3>
          <div className="space-y-4">
            {patterns.map((pattern) => {
              const info = HOOK_TYPE_LABELS[pattern.pattern] || {
                label: pattern.pattern,
                color: "bg-gray-500/20 text-gray-400 border-gray-500/30",
              };
              const widthPercent = (pattern.avgEngagement / maxEngagement) * 100;

              return (
                <div key={pattern.pattern} className="space-y-2">
                  <div className="flex items-center justify-between">
                    <div className="flex items-center gap-2">
                      <span className={`px-2 py-0.5 text-xs rounded-full border ${info.color}`}>
                        {info.label}
                      </span>
                      <span className="text-sm text-gray-400">({pattern.count} tweet)</span>
                    </div>
                    <span className="text-sm font-medium text-white">
                      {formatNumber(pattern.avgEngagement)} ort. etkilesim
                    </span>
                  </div>
                  {/* CSS-only bar chart */}
                  <div className="h-3 bg-gray-700 rounded-full overflow-hidden">
                    <div
                      className="h-full bg-gradient-to-r from-orange-500 to-red-500 rounded-full transition-all duration-500"
                      style={{ width: `${widthPercent}%` }}
                    />
                  </div>
                  <div className="flex justify-between text-xs text-gray-500">
                    <span>{formatNumber(pattern.avgLikes)} begeni</span>
                    <span>{formatNumber(pattern.avgRetweets)} retweet</span>
                  </div>
                </div>
              );
            })}
          </div>

          <div className="mt-6 p-4 bg-gray-900/50 rounded-xl border border-gray-700/50">
            <h4 className="text-sm font-medium text-gray-300 mb-2">Tavsiye</h4>
            <p className="text-sm text-gray-400">
              Veri/Rakam iceren hook'lar en yuksek etkilesimi aliyor. Tweetlerinizde somut rakamlar ve
              istatistikler kullanmak viral olma sansinizi artirabilir.
            </p>
          </div>
        </div>
      )}

      {/* Trend Topics Tab */}
      {activeTab === "trends" && (
        <div className="bg-gray-800/50 backdrop-blur rounded-2xl p-6 border border-gray-700/50">
          <h3 className="text-lg font-semibold text-white mb-4">Trend Konular</h3>
          <div className="grid grid-cols-2 gap-3">
            {[
              { topic: "Yapay Zeka", icon: "🤖", trend: "+45%" },
              { topic: "Startup", icon: "🚀", trend: "+32%" },
              { topic: "Kripto", icon: "💰", trend: "+28%" },
              { topic: "Verimlilik", icon: "⚡", trend: "+25%" },
              { topic: "Kariyer", icon: "📈", trend: "+22%" },
              { topic: "Egitim", icon: "📚", trend: "+18%" },
            ].map((item) => (
              <button
                key={item.topic}
                onClick={() => {
                  setTopic(item.topic);
                  setActiveTab("tweets");
                }}
                className="flex items-center justify-between p-4 bg-gray-900/50 border border-gray-700/50 rounded-xl hover:border-orange-500/50 hover:bg-gray-800/50 transition-all"
              >
                <div className="flex items-center gap-3">
                  <span className="text-2xl">{item.icon}</span>
                  <span className="text-white font-medium">{item.topic}</span>
                </div>
                <span className="text-green-400 text-sm font-medium">{item.trend}</span>
              </button>
            ))}
          </div>

          <div className="mt-6 p-4 bg-gray-900/50 rounded-xl border border-gray-700/50">
            <h4 className="text-sm font-medium text-gray-300 mb-2">Nasil Kullanilir?</h4>
            <p className="text-sm text-gray-400">
              Trend bir konuya tiklayin, o konudaki viral tweetler otomatik aranacak. "Bu Tweet Gibi Yaz"
              butonuyla sectiginiz viral tweet'in stilinde yeni icerik uretebilirsiniz.
            </p>
          </div>
        </div>
      )}
    </div>
  );
}

