"use client";

import { useState, useEffect } from "react";
import { Theme } from "@/types";
import { toggleTheme, initTheme } from "@/lib/theme";

export default function ThemeToggle() {
  const [theme, setTheme] = useState<Theme>("dark");
  const [mounted, setMounted] = useState(false);

  useEffect(() => {
    setMounted(true);
    const currentTheme = initTheme();
    setTheme(currentTheme);
  }, []);

  const handleToggle = () => {
    const newTheme = toggleTheme();
    setTheme(newTheme);
  };

  if (!mounted) {
    return (
      <button className="p-2 rounded-full bg-gray-800 w-10 h-10" />
    );
  }

  return (
    <button
      onClick={handleToggle}
      className="p-2 rounded-full bg-gray-800 hover:bg-gray-700 transition-all duration-300 group"
      title={theme === "dark" ? "Aydınlık Tema" : "Karanlık Tema"}
    >
      {theme === "dark" ? (
        <svg
          className="w-6 h-6 text-yellow-400 group-hover:rotate-12 transition-transform"
          fill="none"
          stroke="currentColor"
          viewBox="0 0 24 24"
        >
          <path
            strokeLinecap="round"
            strokeLinejoin="round"
            strokeWidth={2}
            d="M12 3v1m0 16v1m9-9h-1M4 12H3m15.364 6.364l-.707-.707M6.343 6.343l-.707-.707m12.728 0l-.707.707M6.343 17.657l-.707.707M16 12a4 4 0 11-8 0 4 4 0 018 0z"
          />
        </svg>
      ) : (
        <svg
          className="w-6 h-6 text-blue-400 group-hover:-rotate-12 transition-transform"
          fill="none"
          stroke="currentColor"
          viewBox="0 0 24 24"
        >
          <path
            strokeLinecap="round"
            strokeLinejoin="round"
            strokeWidth={2}
            d="M20.354 15.354A9 9 0 018.646 3.646 9.003 9.003 0 0012 21a9.003 9.003 0 008.354-5.646z"
          />
        </svg>
      )}
    </button>
  );
}

"use client";

import { useState } from "react";
import { GeneratedTweet, SentimentAnalysis, HashtagAnalysis, PostingTimeRecommendation } from "@/types";
import { getScoreColor, getTotalScoreGradient, copyToClipboard, formatScore } from "@/lib/utils";
import { XAlgorithmScoreCard, ScoreDisplay } from "@/components/ui";

interface ExtendedGeneratedTweet extends GeneratedTweet {
  sentiment?: SentimentAnalysis;
  hashtags?: HashtagAnalysis;
  postingTime?: PostingTimeRecommendation;
}

interface TweetDisplayProps {
  tweets: ExtendedGeneratedTweet[];
}

const rankBadges = [
  { label: "En Iyi", color: "from-yellow-400 to-amber-500", icon: "1" },
  { label: "2. Secim", color: "from-gray-400 to-gray-500", icon: "2" },
  { label: "3. Secim", color: "from-amber-600 to-amber-700", icon: "3" },
];

export default function TweetDisplay({ tweets }: TweetDisplayProps) {
  const [copiedIndex, setCopiedIndex] = useState<number | null>(null);
  const [selectedIndex, setSelectedIndex] = useState(0);
  const [showXScore, setShowXScore] = useState(true);

  const handleCopy = async (content: string, index: number) => {
    const success = await copyToClipboard(content);
    if (success) {
      setCopiedIndex(index);
      setTimeout(() => setCopiedIndex(null), 2000);
    }
  };

  const getRankBadge = (index: number) => rankBadges[index] || rankBadges[2];
  const selectedTweet = tweets[selectedIndex];

  return (
    <div className="bg-gray-800/50 backdrop-blur rounded-2xl shadow-xl p-6 border border-gray-700/50 space-y-5">
      {/* Header */}
      <div className="flex items-center justify-between border-b border-gray-700/50 pb-4">
        <h2 className="text-xl font-bold text-white">
          Uretilen Tweet'ler
        </h2>
        <span className="text-sm text-gray-400">
          {tweets.length} varyasyon
        </span>
      </div>

      {/* Tweet Tabs */}
      <div className="flex gap-2 overflow-x-auto pb-2" role="tablist">
        {tweets.map((tweet, index) => {
          const badge = getRankBadge(index);
          return (
            <button
              key={index}
              onClick={() => setSelectedIndex(index)}
              role="tab"
              aria-selected={selectedIndex === index}
              aria-controls={`tweet-panel-${index}`}
              className={`flex-shrink-0 px-4 py-3 rounded-xl transition-all ${
                selectedIndex === index
                  ? "bg-gradient-to-r from-red-500 to-rose-600 text-white shadow-lg scale-105"
                  : "bg-gray-900/50 border border-gray-700 text-gray-400 hover:bg-gray-800"
              }`}
            >
              <div className="flex items-center gap-2">
                <span className="text-lg" aria-hidden="true">{badge.icon}</span>
                <div className="text-left">
                  <div className="font-medium text-sm">{badge.label}</div>
                  <div className={`text-xs ${selectedIndex === index ? "text-white/80" : "text-gray-500"}`}>
                    Skor: {tweet.score.total}
                  </div>
                </div>
              </div>
            </button>
          );
        })}
      </div>

      {/* Selected Tweet Content */}
      <div
        id={`tweet-panel-${selectedIndex}`}
        role="tabpanel"
        className="bg-gray-900/50 rounded-xl p-5 border border-gray-700/50"
      >
        <div className="flex items-start space-x-3 mb-4">
          <div className="w-11 h-11 bg-gradient-to-br from-red-500 to-rose-600 rounded-full flex items-center justify-center text-white font-bold text-sm">
            AI
          </div>
          <div className="flex-1">
            <div className="flex items-center gap-2">
              <div className="font-semibold text-white">Tweet Generator</div>
              <div className={`bg-gradient-to-r ${getRankBadge(selectedIndex).color} text-white text-xs px-2 py-0.5 rounded-full font-medium`}>
                {getRankBadge(selectedIndex).label}
              </div>
            </div>
            <div className="text-gray-500 text-sm">@ai_tweets</div>
          </div>
          <div className={`bg-gradient-to-r ${getTotalScoreGradient(selectedTweet.xScore?.total || selectedTweet.score.total)} text-white px-3 py-1.5 rounded-lg font-bold flex items-center gap-1`}>
            {selectedTweet.xScore && <span className="text-xs" aria-hidden="true">X</span>}
            {formatScore(selectedTweet.xScore?.total || selectedTweet.score.total)}/100
          </div>
        </div>

        <p className="text-white text-lg whitespace-pre-wrap leading-relaxed">
          {selectedTweet.content}
        </p>

        <div className="mt-4 flex items-center justify-between text-gray-500 text-sm">
          <span>{selectedTweet.content.length} karakter</span>
          <div className="flex items-center gap-3">
            <button
              onClick={() => handleCopy(selectedTweet.content, selectedIndex)}
              aria-label={copiedIndex === selectedIndex ? "Kopyalandi" : "Tweet'i kopyala"}
              className={`flex items-center gap-2 px-4 py-2 rounded-lg transition ${
                copiedIndex === selectedIndex
                  ? "bg-green-500 text-white"
                  : "bg-red-500 hover:bg-red-600 text-white"
              }`}
            >
              {copiedIndex === selectedIndex ? (
                <>
                  <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24" aria-hidden="true">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5 13l4 4L19 7" />
                  </svg>
                  <span>Kopyalandi!</span>
                </>
              ) : (
                <>
                  <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24" aria-hidden="true">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M8 16H6a2 2 0 01-2-2V6a2 2 0 012-2h8a2 2 0 012 2v2m-6 12h8a2 2 0 002-2v-8a2 2 0 00-2-2h-8a2 2 0 00-2 2v8a2 2 0 002 2z" />
                  </svg>
                  <span>Kopyala</span>
                </>
              )}
            </button>
          </div>
        </div>
      </div>

      {/* Quick Compare Cards */}
      <div className="grid grid-cols-1 sm:grid-cols-2 md:grid-cols-3 gap-3">
        {tweets.map((tweet, index) => (
          <button
            key={index}
            onClick={() => setSelectedIndex(index)}
            aria-label={`${getRankBadge(index).label} tweet'i sec`}
            className={`text-left cursor-pointer p-4 rounded-xl border transition-all ${
              selectedIndex === index
                ? "border-red-500 bg-red-500/10"
                : "border-gray-700 bg-gray-900/30 hover:border-gray-600"
            }`}
          >
            <div className="flex items-center justify-between mb-2">
              <span className="text-lg" aria-hidden="true">{getRankBadge(index).icon}</span>
              <span className={`font-bold ${getScoreColor(tweet.score.total, 100)}`}>
                {tweet.score.total}
              </span>
            </div>
            <p className="text-sm text-gray-400 line-clamp-3">
              {tweet.content}
            </p>
          </button>
        ))}
      </div>

      {/* Score Toggle */}
      <div className="flex items-center justify-between">
        <h3 className="text-lg font-semibold text-white">
          {showXScore ? "X Algoritmasi Skoru" : "Temel Skorlama"}
        </h3>
        <button
          onClick={() => setShowXScore(!showXScore)}
          aria-expanded={showXScore}
          aria-label={showXScore ? "Temel skora gec" : "X Algoritmasina gec"}
          className="flex items-center gap-2 px-3 py-1.5 bg-gray-800 hover:bg-gray-700 rounded-lg text-sm text-gray-300 transition"
        >
          <span aria-hidden="true">{showXScore ? "X" : "#"}</span>
          {showXScore ? "Temel Skora Gec" : "X Algoritmasina Gec"}
        </button>
      </div>

      {/* X Algorithm Score Display */}
      {showXScore && selectedTweet.xScore ? (
        <XAlgorithmScoreCard
          xScore={selectedTweet.xScore}
          variant="full"
          showPredictions={true}
          showStrengths={true}
          showImprovements={true}
        />
      ) : (
        /* Basic Score Display */
        <div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-5 gap-3">
          {[
            { label: "Hook", key: "hook_strength" as const, icon: "🎯" },
            { label: "Etkilesim", key: "engagement_potential" as const, icon: "💬" },
            { label: "Algoritma", key: "algorithm_fit" as const, icon: "⚡" },
            { label: "Persona", key: "persona_match" as const, icon: "👤" },
            { label: "Ozgunluk", key: "originality" as const, icon: "✨" }
          ].map((item) => (
            <div key={item.key} className="bg-gray-900/50 rounded-lg p-3 border border-gray-700/50">
              <ScoreDisplay
                score={selectedTweet.score[item.key]}
                maxScore={20}
                label={item.label}
                icon={item.icon}
                size="sm"
              />
            </div>
          ))}
        </div>
      )}

      {/* FAZ 3: Sentiment, Hashtag & Posting Time Analysis */}
      {(selectedTweet.sentiment || selectedTweet.hashtags || selectedTweet.postingTime) && (
        <div className="space-y-4">
          <h3 className="text-lg font-semibold text-white flex items-center gap-2">
            <span aria-hidden="true">🧠</span> Kapsamli Icerik Analizi
          </h3>

          <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
            {/* Sentiment Analysis */}
            {selectedTweet.sentiment && (
              <div className={`rounded-xl p-4 border ${
                selectedTweet.sentiment.toxicityRisk > 0.3
                  ? "bg-red-500/10 border-red-500/30"
                  : selectedTweet.sentiment.label === 'positive'
                  ? "bg-green-500/10 border-green-500/30"
                  : selectedTweet.sentiment.label === 'negative'
                  ? "bg-yellow-500/10 border-yellow-500/30"
                  : "bg-gray-800/50 border-gray-700/50"
              }`}>
                <div className="flex items-center justify-between mb-3">
                  <h4 className="text-sm font-semibold text-white flex items-center gap-2">
                    <span aria-hidden="true">😊</span> Duygu Analizi
                  </h4>
                  <span className={`text-xs px-2 py-1 rounded-full font-medium ${
                    selectedTweet.sentiment.label === 'positive'
                      ? "bg-green-500/20 text-green-400"
                      : selectedTweet.sentiment.label === 'negative'
                      ? "bg-red-500/20 text-red-400"
                      : "bg-gray-500/20 text-gray-400"
                  }`}>
                    {selectedTweet.sentiment.label === 'positive' ? 'Pozitif' :
                     selectedTweet.sentiment.label === 'negative' ? 'Negatif' : 'Notr'}
                  </span>
                </div>

                {selectedTweet.sentiment.toxicityRisk > 0.3 && (
                  <div className="bg-red-500/20 text-red-400 text-xs px-2 py-1 rounded mb-2" role="alert">
                    Toxicity Risk: {Math.round(selectedTweet.sentiment.toxicityRisk * 100)}%
                  </div>
                )}

                <div className="text-xs text-gray-400 mb-2">
                  {selectedTweet.sentiment.recommendation}
                </div>

                {selectedTweet.sentiment.positiveWords.length > 0 && (
                  <div className="flex flex-wrap gap-1 mt-2">
                    {selectedTweet.sentiment.positiveWords.slice(0, 3).map((w, i) => (
                      <span key={i} className="text-xs bg-green-500/20 text-green-400 px-2 py-0.5 rounded">
                        {w}
                      </span>
                    ))}
                  </div>
                )}
              </div>
            )}

            {/* Hashtag Analysis */}
            {selectedTweet.hashtags && (
              <div className={`rounded-xl p-4 border ${
                selectedTweet.hashtags.isOptimalCount
                  ? "bg-green-500/10 border-green-500/30"
                  : selectedTweet.hashtags.count > 3
                  ? "bg-red-500/10 border-red-500/30"
                  : "bg-yellow-500/10 border-yellow-500/30"
              }`}>
                <div className="flex items-center justify-between mb-3">
                  <h4 className="text-sm font-semibold text-white flex items-center gap-2">
                    <span aria-hidden="true">#</span> Hashtag Analizi
                  </h4>
                  <span className={`text-xs px-2 py-1 rounded-full font-medium ${
                    selectedTweet.hashtags.qualityScore >= 80
                      ? "bg-green-500/20 text-green-400"
                      : selectedTweet.hashtags.qualityScore >= 50
                      ? "bg-yellow-500/20 text-yellow-400"
                      : "bg-red-500/20 text-red-400"
                  }`}>
                    {selectedTweet.hashtags.qualityScore}/100
                  </span>
                </div>

                <div className="text-sm text-gray-300 mb-2">
                  {selectedTweet.hashtags.count} hashtag
                  {selectedTweet.hashtags.isOptimalCount ? " (optimal)" : " (1-2 ideal)"}
                </div>

                {selectedTweet.hashtags.hashtags.length > 0 && (
                  <div className="flex flex-wrap gap-1 mb-2">
                    {selectedTweet.hashtags.hashtags.map((tag, i) => (
                      <span key={i} className="text-xs bg-blue-500/20 text-blue-400 px-2 py-0.5 rounded">
                        {tag}
                      </span>
                    ))}
                  </div>
                )}

                {selectedTweet.hashtags.issues.length > 0 && (
                  <div className="text-xs text-yellow-400 mt-2">
                    {selectedTweet.hashtags.issues[0]}
                  </div>
                )}
              </div>
            )}

            {/* Posting Time */}
            {selectedTweet.postingTime && (
              <div className={`rounded-xl p-4 border ${
                selectedTweet.postingTime.isOptimalNow
                  ? "bg-green-500/10 border-green-500/30"
                  : selectedTweet.postingTime.currentTimeScore >= 60
                  ? "bg-yellow-500/10 border-yellow-500/30"
                  : "bg-gray-800/50 border-gray-700/50"
              }`}>
                <div className="flex items-center justify-between mb-3">
                  <h4 className="text-sm font-semibold text-white flex items-center gap-2">
                    <span aria-hidden="true">⏰</span> Paylasim Zamani
                  </h4>
                  <span className={`text-xs px-2 py-1 rounded-full font-medium ${
                    selectedTweet.postingTime.isOptimalNow
                      ? "bg-green-500/20 text-green-400"
                      : selectedTweet.postingTime.currentTimeScore >= 60
                      ? "bg-yellow-500/20 text-yellow-400"
                      : "bg-gray-500/20 text-gray-400"
                  }`}>
                    {selectedTweet.postingTime.currentTimeScore}/100
                  </span>
                </div>

                <div className="text-sm text-gray-300 mb-2">
                  {selectedTweet.postingTime.currentDay}, {selectedTweet.postingTime.currentHour}:00
                </div>

                <div className="text-xs text-gray-400 mb-2">
                  {selectedTweet.postingTime.recommendation}
                </div>

                <div className="text-xs text-gray-500">
                  En iyi saatler: {selectedTweet.postingTime.bestTimesToday.slice(0, 3).join(", ")}
                </div>
              </div>
            )}
          </div>
        </div>
      )}

      {/* AI Reasoning */}
      {selectedTweet.reasoning && (
        <div className="bg-red-500/10 border border-red-500/30 rounded-xl p-4">
          <h3 className="text-sm font-semibold text-red-400 mb-2">
            AI Analizi
          </h3>
          <p className="text-gray-300 text-sm">
            {selectedTweet.reasoning}
          </p>
        </div>
      )}
    </div>
  );
}

