    44→function calculateScore(content: string, _persona: string, _reasoning: string): TweetScore {
    45→  // Basit bir skorlama algoritması
    46→  // Gerçek uygulamada daha sofistike bir sistem kullanılabilir
    47→
    48→  const length = content.length;
    49→  const hasEmoji = /\p{Emoji}/u.test(content);
    50→  const hasHashtag = content.includes("#");
    51→  const hasQuestion = content.includes("?");
    52→  const hasNumbers = /\d/.test(content);
    53→
    54→  let hook_strength = 15;
    55→  if (content.startsWith("🚀") || content.startsWith("💡") || content.startsWith("⚡")) hook_strength += 3;
    56→  if (hasQuestion) hook_strength += 2;
    57→
    58→  let engagement_potential = 14;
    59→  if (hasEmoji) engagement_potential += 3;
    60→  if (hasQuestion) engagement_potential += 3;
    61→
    62→  let algorithm_fit = 16;
    63→  if (length >= 200 && length <= 280) algorithm_fit += 2;
    64→  if (hasHashtag) algorithm_fit += 2;
    65→
    66→  const persona_match = 17;
    67→
    68→  let originality = 16;
    69→  if (hasNumbers) originality += 2;
    70→
    71→  const total = hook_strength + engagement_potential + algorithm_fit + persona_match + originality;
    72→
    73→  return {
    74→    hook_strength,
    75→    engagement_potential,
    76→    algorithm_fit,
    77→    persona_match,
    78→    originality,
    79→    total
    80→  };
    81→}
    82→
    83→export async function POST(request: NextRequest) {
    84→  try {
    85→    // CSRF Protection: Validate origin
    86→    const origin = request.headers.get("origin");
    87→    const host = request.headers.get("host");
    88→    if (origin) {
    89→      const allowedOrigins = [
    90→        `http://${host}`,
    91→        `https://${host}`,
    92→        process.env.NEXT_PUBLIC_BASE_URL,
    93→      ].filter(Boolean);
