import { NextRequest, NextResponse } from "next/server";
import OpenAI from "openai";
import { defaultPersonas } from "@/lib/personas";
import { GeneratedTweet, TweetScore, Persona } from "@/types";
import {
  generateXAlgorithmScore,
  analyzeSentiment,
  analyzeHashtags,
  getPostingTimeRecommendation,
} from "@/lib/xAlgorithmScoring";
import {
  validateTopic,
  validateLength,
  validateTone,
  validatePersona,
  sanitizeForPrompt,
  checkRateLimit,
  getClientIdentifier,
  getErrorMessage,
} from "@/lib/validation";

const openai = new OpenAI({
  apiKey: process.env.OPENAI_API_KEY,
});

const MODEL = process.env.OPENAI_MODEL || "gpt-4o-mini";

// Rate limit config: 30 requests per minute for generate endpoint
const RATE_LIMIT_CONFIG = { windowMs: 60 * 1000, maxRequests: 30 };

function getLengthGuideline(length: string): string {
  switch (length) {
    case "short":
      return "140-200 karakter arası";
    case "medium":
      return "200-280 karakter arası";
    case "long":
      return "280-500 karakter arası";
    default:
      return "200-280 karakter arası";
  }
}

function calculateScore(content: string, _persona: string, _reasoning: string): TweetScore {
  // Basit bir skorlama algoritması
  // Gerçek uygulamada daha sofistike bir sistem kullanılabilir

  const length = content.length;
  const hasEmoji = /\p{Emoji}/u.test(content);
  const hasHashtag = content.includes("#");
  const hasQuestion = content.includes("?");
  const hasNumbers = /\d/.test(content);

  let hook_strength = 15;
  if (content.startsWith("🚀") || content.startsWith("💡") || content.startsWith("⚡")) hook_strength += 3;
  if (hasQuestion) hook_strength += 2;

  let engagement_potential = 14;
  if (hasEmoji) engagement_potential += 3;
  if (hasQuestion) engagement_potential += 3;

  let algorithm_fit = 16;
  if (length >= 200 && length <= 280) algorithm_fit += 2;
  if (hasHashtag) algorithm_fit += 2;

  const persona_match = 17;

  let originality = 16;
  if (hasNumbers) originality += 2;

  const total = hook_strength + engagement_potential + algorithm_fit + persona_match + originality;

  return {
    hook_strength,
    engagement_potential,
    algorithm_fit,
    persona_match,
    originality,
    total
  };
}

export async function POST(request: NextRequest) {
  try {
    // CSRF Protection: Validate origin
    const origin = request.headers.get("origin");
    const host = request.headers.get("host");
    if (origin) {
      const allowedOrigins = [
        `http://${host}`,
        `https://${host}`,
        process.env.NEXT_PUBLIC_BASE_URL,
      ].filter(Boolean);
      if (!allowedOrigins.some(allowed => origin === allowed)) {
        return NextResponse.json(
          { success: false, error: "Geçersiz kaynak" },
          { status: 403 }
        );
      }
    }

    // Rate limiting check
    const clientId = getClientIdentifier(request);
    const rateLimit = checkRateLimit(clientId, RATE_LIMIT_CONFIG);

    if (!rateLimit.allowed) {
      return NextResponse.json(
        {
          success: false,
          error: "Çok fazla istek. Lütfen biraz bekleyin.",
          retryAfter: Math.ceil(rateLimit.resetIn / 1000)
        },
        {
          status: 429,
          headers: {
            "Retry-After": String(Math.ceil(rateLimit.resetIn / 1000)),
            "X-RateLimit-Remaining": String(rateLimit.remaining),
          }
        }
      );
    }

    // Safe JSON parsing
    let body;
    try {
      body = await request.json();
    } catch {
      return NextResponse.json(
        { success: false, error: "Geçersiz istek formatı" },
        { status: 400 }
      );
    }

    const { topic, persona, length, tone, customPersona } = body;

    // Validate topic
    const topicValidation = validateTopic(topic);
    if (!topicValidation.valid) {
      return NextResponse.json(
        { success: false, error: topicValidation.error },
        { status: 400 }
      );
    }
    const sanitizedTopic = topicValidation.sanitized as string;

    // Validate length
    const lengthValidation = validateLength(length);
    if (!lengthValidation.valid) {
      return NextResponse.json(
        { success: false, error: lengthValidation.error },
        { status: 400 }
      );
    }
    const validatedLength = lengthValidation.sanitized as string;

    // Validate tone
    const toneValidation = validateTone(tone);
    const validatedTone = toneValidation.sanitized as string;

    // Validate persona
    let personaData: Persona | undefined;

    if (customPersona) {
      const personaValidation = validatePersona(customPersona);
      if (!personaValidation.valid) {
        return NextResponse.json(
          { success: false, error: personaValidation.error },
          { status: 400 }
        );
      }
      personaData = personaValidation.sanitized as Persona;
    } else if (persona) {
      personaData = defaultPersonas.find(p => p.id === persona);
    }

    if (!personaData) {
      return NextResponse.json(
        { success: false, error: "Geçersiz persona" },
        { status: 400 }
      );
    }

    const lengthGuideline = getLengthGuideline(validatedLength);

    const systemPrompt = `Sen bir UZMAN ghostwriter'sın. Görevin: Verilen kişinin yazım tarzını BİREBİR TAKLİT ederek tweet yazmak.

═══════════════════════════════════════════════════════════════
TAKLİT EDİLECEK KİŞİ: ${sanitizeForPrompt(personaData.name)}

📝 TANIM: ${sanitizeForPrompt(personaData.description)}

🎭 YAZIM STİLİ (BU ÇOK ÖNEMLİ - BİREBİR UYGULA):
${sanitizeForPrompt(personaData.style)}

🎯 TON: ${sanitizeForPrompt(personaData.tone)}

REFERANS TWEET'LER (Bu tweet'lerin YAPISINI, RİTMİNİ, DİLİNİ analiz et):
${personaData.example_tweets.map((t, i) => `[${i + 1}] "${sanitizeForPrompt(t)}"`).join("\n\n")}

═══════════════════════════════════════════════════════════════
TAKLİT REHBERİ (MUTLAKA UYGULA):
═══════════════════════════════════════════════════════════════

1. CÜMLE YAPISI:
   - Yukarıdaki tweet'lerde cümleler kısa mı uzun mu? → AYNI YAP
   - Virgül, nokta kullanımı nasıl? → AYNI YAP
   - "..." veya "-" gibi işaretler var mı? → AYNI YAP

2. KELİME SEÇİMİ:
   - Türkçe mi İngilizce kelimeler mi ağırlıklı? → AYNI YAP
   - Günlük/samimi mi resmi mi? → AYNI YAP
   - Tekrarlayan ifadeler var mı? → KULLAN

3. AÇILIŞ STİLİ:
   - Tweet'ler nasıl başlıyor? (Soru ile? Düz cümle ile? Emoji ile?)
   - Bu açılış stilini TAKLİT ET

4. KAPANIŞ STİLİ:
   - Tweet'ler nasıl bitiyor? (Çağrı ile? Düşünce ile? Emoji ile?)
   - Bu kapanış stilini TAKLİT ET

5. EMOJİ & HASHTAG:
   - Örnek tweet'lerde emoji var mı? Hangileri? → AYNI TARZI KULLAN
   - Hashtag kullanıyor mu? → AYNI TARZI KULLAN

GÖREV PARAMETRELERİ:
📏 Uzunluk: ${lengthGuideline}
🎭 Ton vurgusu: ${validatedTone}

═══════════════════════════════════════════════════════════════
KESİN KURALLAR:
═══════════════════════════════════════════════════════════════
❌ YAPMA:
- Generic/sıradan tweet yazma
- Kendi stilini katma
- "Tweet:" veya açıklama ekleme
- Persona'nın kullanmadığı emoji/hashtag kullanma

✅ YAP:
- Bu kişi yazmış gibi yaz (ghostwriting)
- Onun kelime dağarcığını kullan
- Onun cümle ritmini kullan
- Onun açılış/kapanış stilini kullan

═══════════════════════════════════════════════════════════════
ÇIKTI: Sadece tweet metnini yaz. Başka hiçbir şey ekleme.
═══════════════════════════════════════════════════════════════`;

    // 3 farklı varyasyon için promptlar (sanitized inputs)
    const safePersonaName = sanitizeForPrompt(personaData.name);
    const variationPrompts = [
      {
        userPrompt: `Konu: ${sanitizedTopic}

Bu konu hakkında ${safePersonaName} tarzında bir tweet yaz.
VARYASYON 1: Doğrudan ve net bir yaklaşım. Konuya direkt gir.`,
        style: "Doğrudan"
      },
      {
        userPrompt: `Konu: ${sanitizedTopic}

Bu konu hakkında ${safePersonaName} tarzında bir tweet yaz.
VARYASYON 2: Soru veya merak uyandıran bir açılış kullan. Etkileşim odaklı yaz.`,
        style: "Etkileşimci"
      },
      {
        userPrompt: `Konu: ${sanitizedTopic}

Bu konu hakkında ${safePersonaName} tarzında bir tweet yaz.
VARYASYON 3: Kişisel bir hikaye veya gözlem ile başla. Samimi ve bağ kurucu ol.`,
        style: "Hikayeci"
      }
    ];

    // Paralel olarak 3 tweet üret
    const tweetPromises = variationPrompts.map(async (variation) => {
      const completion = await openai.chat.completions.create({
        model: MODEL,
        messages: [
          { role: "system", content: systemPrompt },
          { role: "user", content: variation.userPrompt }
        ],
        temperature: 0.85,
        max_tokens: 500,
      });
      return {
        content: completion.choices[0]?.message?.content?.trim() || "",
        style: variation.style
      };
    });

    const tweetResults = await Promise.all(tweetPromises);

    // Her tweet için skorlama ve reasoning üret (paralel)
    const resultsPromises = tweetResults.map(async (tweet) => {
      const reasoningCompletion = await openai.chat.completions.create({
        model: MODEL,
        messages: [
          {
            role: "system",
            content: `Sen bir uzman tweet analisti olarak bu tweet'in neden etkili olduğunu kısaca açıkla (2-3 cümle).
Tweet stili: ${tweet.style}
Persona ile uyumunu, hook gücünü ve etkileşim potansiyelini değerlendir.`
          },
          {
            role: "user",
            content: `Tweet: "${tweet.content}"\n\nBu tweet'in güçlü yönlerini analiz et.`
          }
        ],
        temperature: 0.7,
        max_tokens: 200,
      });

      const reasoning = reasoningCompletion.choices[0]?.message?.content?.trim() || "";
      const score = calculateScore(tweet.content, persona, reasoning);

      // Generate X Algorithm enhanced score
      const xScore = generateXAlgorithmScore(tweet.content, {
        isThread: false,
        isReply: false,
        isQuote: false,
        hasMedia: false,
        personaMatch: score.persona_match / 20, // Normalize to 0-1
      });

      // Faz 3: Sentiment, Hashtag, and Posting Time analysis
      const sentiment = analyzeSentiment(tweet.content);
      const hashtags = analyzeHashtags(tweet.content);
      const postingTime = getPostingTimeRecommendation();

      return {
        content: tweet.content,
        score,
        reasoning,
        xScore,
        sentiment,
        hashtags,
        postingTime,
      } as GeneratedTweet & {
        sentiment: typeof sentiment;
        hashtags: typeof hashtags;
        postingTime: typeof postingTime;
      };
    });

    const results = await Promise.all(resultsPromises);

    // Sort by X Algorithm score (more accurate)
    results.sort((a, b) => (b.xScore?.total || b.score.total) - (a.xScore?.total || a.score.total));

    return NextResponse.json({
      success: true,
      data: results
    });

  } catch (error: unknown) {
    console.error("API Error:", error);

    const errorMessage = getErrorMessage(error);
    const isOpenAIError = errorMessage.toLowerCase().includes("openai") ||
                          errorMessage.toLowerCase().includes("api key");

    return NextResponse.json(
      {
        success: false,
        error: isOpenAIError ? "Servis geçici olarak kullanılamıyor" : "Tweet oluşturulurken bir hata oluştu"
      },
      { status: 500 }
    );
  }
}

