import { NextRequest, NextResponse } from "next/server";
import OpenAI from "openai";
import { StyleAnalysis, Persona } from "@/types";
import {
  validateUsername,
  validateManualTweets,
  sanitizeForPrompt,
  checkRateLimit,
  getClientIdentifier,
  getErrorMessage,
  safeJSONParse,
  LIMITS,
} from "@/lib/validation";

const openai = new OpenAI({
  apiKey: process.env.OPENAI_API_KEY,
});

const MODEL = process.env.OPENAI_MODEL || "gpt-4o-mini";

// Rate limit config: 10 requests per minute for analyze (most expensive)
const RATE_LIMIT_CONFIG = { windowMs: 60 * 1000, maxRequests: 10 };

// Apify timeout configuration
const APIFY_CONFIG = {
  MAX_WAIT_MS: 60000,      // 60 seconds max total wait
  MAX_POLL_ATTEMPTS: 30,   // Max polling attempts
  POLL_INTERVAL_MS: 2000,  // 2 seconds between polls
} as const;

async function fetchTweetsWithApify(username: string): Promise<{ tweets: string[]; displayName: string; bio: string }> {
  const cleanUsername = username.replace("@", "").trim();
  const apifyToken = process.env.APIFY_API_TOKEN;

  if (!apifyToken || apifyToken === "your_apify_token_here") {
    throw new Error("APIFY_TOKEN_MISSING");
  }

  try {
    // Apify Twitter Scraper'ı çalıştır
    const runResponse = await fetch(
      `https://api.apify.com/v2/acts/apidojo~tweet-scraper/runs?token=${apifyToken}`,
      {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          startUrls: [{ url: `https://twitter.com/${cleanUsername}` }],
          maxTweets: 50,
          onlyVerified: false,
          proxyConfig: { useApifyProxy: true },
        }),
      }
    );

    if (!runResponse.ok) {
      throw new Error("Apify çalıştırılamadı");
    }

    const runData = await runResponse.json();
    const runId = runData.data.id;

    // Sonuçları bekle (max 60 saniye with strict timeout)
    let attempts = 0;
    let datasetItems: any[] = [];
    const startTime = Date.now();

    while (attempts < APIFY_CONFIG.MAX_POLL_ATTEMPTS) {
      // Check total elapsed time
      const elapsed = Date.now() - startTime;
      if (elapsed >= APIFY_CONFIG.MAX_WAIT_MS) {
        throw new Error("Zaman aşımı: Tweet çekme işlemi çok uzun sürdü. Lütfen tekrar deneyin.");
      }

      await new Promise(r => setTimeout(r, APIFY_CONFIG.POLL_INTERVAL_MS));

      const statusResponse = await fetch(
        `https://api.apify.com/v2/acts/apidojo~tweet-scraper/runs/${runId}?token=${apifyToken}`
      );

      if (!statusResponse.ok) {
        throw new Error("Apify durum kontrolü başarısız");
      }

      const statusData = await statusResponse.json();

      if (statusData.data.status === "SUCCEEDED") {
        const datasetId = statusData.data.defaultDatasetId;
        const itemsResponse = await fetch(
          `https://api.apify.com/v2/datasets/${datasetId}/items?token=${apifyToken}`
        );
        if (!itemsResponse.ok) {
          throw new Error("Veri seti alınamadı");
        }
        datasetItems = await itemsResponse.json();
        break;
      } else if (statusData.data.status === "FAILED" || statusData.data.status === "ABORTED") {
        throw new Error("Scraping başarısız oldu");
      }

      attempts++;
    }

    // Check if we exhausted attempts without getting data
    if (attempts >= APIFY_CONFIG.MAX_POLL_ATTEMPTS && datasetItems.length === 0) {
      throw new Error("Maksimum deneme sayısına ulaşıldı. Lütfen tekrar deneyin.");
    }

    if (datasetItems.length === 0) {
      throw new Error("Tweet bulunamadı");
    }

    const tweets = datasetItems
      .filter((item: any) => item.full_text && !item.full_text.startsWith("RT @"))
      .map((item: any) => item.full_text)
      .slice(0, 50);

    const firstItem = datasetItems[0];
    const displayName = firstItem?.user?.name || cleanUsername;
    const bio = firstItem?.user?.description || "";

    return { tweets, displayName, bio };
  } catch (error: any) {
    throw new Error(error.message || "Apify hatası");
  }
}

async function fetchTweets(username: string): Promise<{ tweets: string[]; displayName: string; bio: string }> {
  // Önce Apify'ı dene
  try {
    return await fetchTweetsWithApify(username);
  } catch (apifyError: any) {
    if (apifyError.message === "APIFY_TOKEN_MISSING") {
      throw new Error("Apify API token ayarlanmamış. .env dosyasına APIFY_API_TOKEN ekleyin.");
    }
    throw apifyError;
  }
}

async function analyzeStyle(tweets: string[], username: string, bio: string): Promise<{ analysis: StyleAnalysis; persona: Persona }> {
  // Sanitize all inputs for prompt safety
  const safeUsername = sanitizeForPrompt(username);
  const safeBio = sanitizeForPrompt(bio || "Belirtilmemiş").slice(0, LIMITS.BIO_MAX_LENGTH);
  const safeTweets = tweets.map(t => sanitizeForPrompt(t).slice(0, LIMITS.TWEET_MAX_LENGTH));

  const prompt = `Sen bir uzman sosyal medya analisti ve dilbilimcisin. Aşağıdaki tweet'leri DERİN bir şekilde analiz et ve bu kişinin benzersiz yazım tarzını çıkar.

KULLANICI: @${safeUsername}
BIO: ${safeBio}

TWEET'LER (${safeTweets.length} adet):
${safeTweets.map((t, i) => `[${i + 1}] ${t}`).join("\n\n")}

═══════════════════════════════════════
ANALİZ TALİMATLARI:
═══════════════════════════════════════

1. CÜMLE YAPISI ANALİZİ:
   - Kısa mı uzun cümleler mi tercih ediyor?
   - Bağlaçları nasıl kullanıyor?
   - Noktalama işaretlerini nasıl kullanıyor?

2. KELİME SEÇİMİ:
   - Günlük/samimi mi yoksa resmi kelimeler mi?
   - Türkçe mi İngilizce terimler mi tercih ediyor?
   - Tekrarlayan kelime kalıpları var mı?

3. RETORİK TEKNİKLER:
   - Soru soruyor mu?
   - Liste yapıyor mu?
   - Metafor kullanıyor mu?
   - Dikkat çekici açılışlar yapıyor mu?

4. DUYGUSAL TON:
   - İyimser/kötümser/nötr mü?
   - Motivasyonel mi bilgilendirici mi?
   - Espri anlayışı nasıl?

5. ETKİLEŞİM STİLİ:
   - Doğrudan mı konuşuyor yoksa genel mi?
   - "Biz" mi "ben" mi kullanıyor?
   - Takipçilere nasıl sesleniyor?

JSON FORMATI:
