    "topics": ["Ana konular - 3-5 madde"],
    "emojiUsage": "none | minimal | moderate | heavy",
    "hashtagUsage": "none | minimal | moderate | heavy",
    "averageLength": <ortalama karakter sayısı>,
    "writingStyle": "Detaylı yazım tarzı açıklaması (3-4 cümle). Cümle yapısı, noktalama, kelime seçimi dahil.",
    "vocabulary": "Kelime dağarcığı analizi - resmi/günlük, Türkçe/İngilizce tercih, sık kullandığı ifadeler",
    "engagement_patterns": ["Etkileşim kalıpları - 3 madde"]
  },
  "persona": {
    "name": "@${safeUsername} Tarzı",
    "description": "Bu kişinin tweet tarzının özeti (1 cümle, çarpıcı)",
    "style": "Bu kişi gibi tweet yazabilmek için TAKLİT REHBERİ: Nasıl başlamalı, hangi kelimeleri kullanmalı, nasıl bitirmeli, nelere dikkat etmeli (4-5 cümle, ÇOK DETAYLI)",
    "tone": "Ana ton",
    "example_tweets": ["En karakteristik 5 tweet - bu kişinin tarzını en iyi yansıtanlar"]
  }
}

ÖNEMLİ:
- Sadece JSON döndür
- example_tweets'e GERÇEK tweet'lerden seç, uydurma
- style alanı ÇOK DETAYLI olmalı - biri bunu okuyunca bu kişi gibi yazabilmeli`;

  const completion = await openai.chat.completions.create({
    model: MODEL,
