export async function POST(request: NextRequest) {
  try {
    // CSRF Protection: Validate origin
    const origin = request.headers.get("origin");
    const host = request.headers.get("host");
    if (origin) {
      const allowedOrigins = [
        `http://${host}`,
        `https://${host}`,
        process.env.NEXT_PUBLIC_BASE_URL,
      ].filter(Boolean);
      if (!allowedOrigins.some(allowed => origin === allowed)) {
        return NextResponse.json(
          { success: false, error: "Geçersiz kaynak" },
          { status: 403 }
        );
      }
    }

    // Rate limiting check
    const clientId = getClientIdentifier(request);
    const rateLimit = checkRateLimit(clientId, RATE_LIMIT_CONFIG);

    if (!rateLimit.allowed) {
      return NextResponse.json(
        {
          success: false,
          error: "Çok fazla istek. Lütfen biraz bekleyin.",
          retryAfter: Math.ceil(rateLimit.resetIn / 1000)
        },
        {
          status: 429,
          headers: {
            "Retry-After": String(Math.ceil(rateLimit.resetIn / 1000)),
            "X-RateLimit-Remaining": String(rateLimit.remaining),
          }
        }
      );
    }

    // Safe JSON parsing
    let body;
    try {
      body = await request.json();
    } catch {
      return NextResponse.json(
        { success: false, error: "Geçersiz istek formatı" },
        { status: 400 }
      );
    }

    const { username, mode, manualTweets } = body;

    // Validate username
    const usernameValidation = validateUsername(username);
    if (!usernameValidation.valid) {
      return NextResponse.json(
        { success: false, error: usernameValidation.error },
        { status: 400 }
      );
    }
    const sanitizedUsername = usernameValidation.sanitized as string;

    let tweets: string[] = [];
    let displayName = sanitizedUsername;
    let bio = "";

    if (mode === "manual" && manualTweets) {
      // Validate manual tweets with proper bounds
      const tweetsValidation = validateManualTweets(manualTweets);
      if (!tweetsValidation.valid) {
        return NextResponse.json(
          { success: false, error: tweetsValidation.error },
          { status: 400 }
        );
      }
      tweets = tweetsValidation.sanitized as string[];
    } else {
      // Otomatik çekme (Apify)
      try {
        const result = await fetchTweets(sanitizedUsername);
        tweets = result.tweets.map(t => sanitizeForPrompt(t));
        displayName = sanitizeForPrompt(result.displayName);
        bio = sanitizeForPrompt(result.bio);
      } catch (fetchError) {
        const errorMessage = getErrorMessage(fetchError);
        return NextResponse.json(
          {
            success: false,
            error: errorMessage.includes("APIFY")
              ? "Apify API token ayarlanmamış"
              : "Otomatik tweet çekme başarısız. Manuel giriş yapın."
          },
          { status: 400 }
        );
      }
    }

    // Stil analizi yap
    const { analysis, persona } = await analyzeStyle(tweets, sanitizedUsername, bio);

    return NextResponse.json({
      success: true,
      data: {
        username: sanitizedUsername,
        displayName,
        bio,
        tweets,
        analysis,
        persona,
      },
    });
  } catch (error: unknown) {
    console.error("Analyze API Error:", error);

    const errorMessage = getErrorMessage(error);
    const isOpenAIError = errorMessage.toLowerCase().includes("openai") ||
                          errorMessage.toLowerCase().includes("api key");

    return NextResponse.json(
      {
        success: false,
        error: isOpenAIError ? "Servis geçici olarak kullanılamıyor" : "Analiz sırasında bir hata oluştu"
      },
      { status: 500 }
    );
  }
}

