import { NextRequest, NextResponse } from "next/server";
import OpenAI from "openai";
import { ThreadTweet, Persona } from "@/types";
import { defaultPersonas } from "@/lib/personas";
import { generateXAlgorithmScore, calculateThreadScore as calcXThreadScore, XAlgorithmScore as XScoreType } from "@/lib/xAlgorithmScoring";
import {
  validateTopic,
  validateThreadLength,
  validatePersona,
  sanitizeForPrompt,
  checkRateLimit,
  getClientIdentifier,
  getErrorMessage,
  safeJSONParse,
} from "@/lib/validation";

const openai = new OpenAI({
  apiKey: process.env.OPENAI_API_KEY,
});

const MODEL = process.env.OPENAI_MODEL || "gpt-4o-mini";

// Rate limit config: 20 requests per minute for thread endpoint (more expensive)
const RATE_LIMIT_CONFIG = { windowMs: 60 * 1000, maxRequests: 20 };

export async function POST(request: NextRequest) {
  try {
    // CSRF Protection: Validate origin
    const origin = request.headers.get("origin");
    const host = request.headers.get("host");
    if (origin) {
      const allowedOrigins = [
        `http://${host}`,
        `https://${host}`,
        process.env.NEXT_PUBLIC_BASE_URL,
      ].filter(Boolean);
      if (!allowedOrigins.some(allowed => origin === allowed)) {
        return NextResponse.json(
          { success: false, error: "Geçersiz kaynak" },
          { status: 403 }
        );
      }
    }

    // Rate limiting check
    const clientId = getClientIdentifier(request);
    const rateLimit = checkRateLimit(clientId, RATE_LIMIT_CONFIG);

    if (!rateLimit.allowed) {
      return NextResponse.json(
        {
          success: false,
          error: "Çok fazla istek. Lütfen biraz bekleyin.",
          retryAfter: Math.ceil(rateLimit.resetIn / 1000)
        },
        {
          status: 429,
          headers: {
            "Retry-After": String(Math.ceil(rateLimit.resetIn / 1000)),
            "X-RateLimit-Remaining": String(rateLimit.remaining),
          }
        }
      );
    }

    // Safe JSON parsing
    let body;
    try {
      body = await request.json();
    } catch {
      return NextResponse.json(
        { success: false, error: "Geçersiz istek formatı" },
        { status: 400 }
      );
    }

    const { topic, persona, threadLength, customPersona } = body;

    // Validate topic
    const topicValidation = validateTopic(topic);
    if (!topicValidation.valid) {
      return NextResponse.json(
        { success: false, error: topicValidation.error },
        { status: 400 }
      );
    }
    const sanitizedTopic = topicValidation.sanitized as string;

    // Validate threadLength with strict bounds (DOS protection)
    const threadLengthValidation = validateThreadLength(threadLength);
    if (!threadLengthValidation.valid) {
      return NextResponse.json(
        { success: false, error: threadLengthValidation.error },
        { status: 400 }
      );
    }
    const validatedThreadLength = threadLengthValidation.sanitized as number;

    // Validate persona
    let personaData: Persona | undefined;

    if (customPersona) {
      const personaValidation = validatePersona(customPersona);
      if (!personaValidation.valid) {
        return NextResponse.json(
          { success: false, error: personaValidation.error },
          { status: 400 }
        );
      }
      personaData = personaValidation.sanitized as Persona;
    } else if (persona) {
      personaData = defaultPersonas.find(p => p.id === persona);
    }

    if (!personaData) {
      // Fallback to first persona with safety check
      if (defaultPersonas.length === 0) {
        return NextResponse.json(
          { success: false, error: "Persona yapılandırması eksik" },
          { status: 500 }
        );
      }
      personaData = defaultPersonas[0];
    }

    // Sanitize persona data for prompt
    const safePersonaName = sanitizeForPrompt(personaData.name);
    const safePersonaDesc = sanitizeForPrompt(personaData.description);
    const safePersonaStyle = sanitizeForPrompt(personaData.style);
    const safePersonaTone = sanitizeForPrompt(personaData.tone);

    const systemPrompt = `Sen dünya çapında bir Twitter/X içerik stratejisti ve viral thread yazarısın.

GÖREV: Verilen konu hakkında ${validatedThreadLength} tweetlik bir thread oluştur.

PERSONA: ${safePersonaName}
TANIM: ${safePersonaDesc}
YAZIM TARZI: ${safePersonaStyle}
TON: ${safePersonaTone}

THREAD YAZIM KURALLARI:

1. İLK TWEET (HOOK):
   - EN ÖNEMLİ tweet - insanları thread'e çekmeli
   - Merak uyandırıcı, çarpıcı bir açılış
   - "🧵" veya thread belirteci kullanma
   - Tek başına da değerli olmalı

2. GELİŞME TWEETLERİ:
   - Her tweet tek bir fikir/bilgi içermeli
   - Önceki tweet ile bağlantılı ama bağımsız okunabilir
   - Değer katmalı, dolgu olmamalı
   - Numaralandırma kullanma (1/, 2/ gibi)

3. KAPANIŞ TWEETİ:
   - Özet veya çağrı (CTA) içermeli
   - Etkileşim daveti (soru, yorum isteği)
   - Akılda kalıcı son söz

4. GENEL:
   - Her tweet max 280 karakter
   - Persona'nın tarzına sadık kal
   - Doğal geçişler kullan
   - Emoji kullanımı persona'ya uygun olsun

JSON FORMATI:
{
  "tweets": [
    {"position": 1, "content": "Hook tweet...", "isHook": true},
    {"position": 2, "content": "İkinci tweet..."},
    ...
    {"position": ${validatedThreadLength}, "content": "Kapanış tweet..."}
  ],
  "reasoning": "Bu thread'in neden etkili olduğunun kısa açıklaması"
}

SADECE JSON döndür, başka bir şey yazma.`;

    const userPrompt = `Konu: ${sanitizedTopic}

${validatedThreadLength} tweetlik bir thread oluştur. ${safePersonaName} tarzında yaz.`;

    const completion = await openai.chat.completions.create({
      model: MODEL,
      messages: [
        { role: "system", content: systemPrompt },
        { role: "user", content: userPrompt }
      ],
      temperature: 0.8,
      max_tokens: 2000,
    });

    const content = completion.choices[0]?.message?.content || "";

    // Safe JSON parse with error handling
    const parseResult = safeJSONParse<{ tweets: ThreadTweet[]; reasoning?: string }>(content);

    if (!parseResult.success) {
      return NextResponse.json(
        { success: false, error: "Thread yanıtı işlenemedi. Lütfen tekrar deneyin." },
        { status: 500 }
      );
    }

    const parsed = parseResult.data;

    // Validate parsed data structure
    if (!parsed.tweets || !Array.isArray(parsed.tweets) || parsed.tweets.length === 0) {
      return NextResponse.json(
        { success: false, error: "Geçersiz thread yapısı" },
        { status: 500 }
      );
    }

    // Thread skorlama with detailed per-tweet scores
    const { totalScore, tweetScores, threadAnalysis } = calculateThreadScoreDetailed(parsed.tweets);

    // Attach xScore to each tweet
    const tweetsWithScores = parsed.tweets.map((tweet: ThreadTweet, index: number) => ({
      ...tweet,
      xScore: tweetScores[index],
    }));

    const result = {
      tweets: tweetsWithScores,
      topic: sanitizedTopic,
      totalScore,
      reasoning: parsed.reasoning || "Thread başarıyla oluşturuldu.",
      threadAnalysis,
    };

    return NextResponse.json({
      success: true,
      data: result
    });

  } catch (error: unknown) {
    console.error("Thread API Error:", error);

    const errorMessage = getErrorMessage(error);
    const isOpenAIError = errorMessage.toLowerCase().includes("openai") ||
                          errorMessage.toLowerCase().includes("api key");

    return NextResponse.json(
      {
        success: false,
        error: isOpenAIError ? "Servis geçici olarak kullanılamıyor" : "Thread oluşturulurken bir hata oluştu"
      },
      { status: 500 }
    );
  }
}

function calculateThreadScoreDetailed(tweets: ThreadTweet[]): {
  totalScore: number;
  tweetScores: XScoreType[];
  threadAnalysis: {
    hookScore: number;
    averageEngagement: number;
    adjustedScores: number[];
    strengths: string[];
    improvements: string[];
  };
} {
  // Use X Algorithm scoring for each tweet
  const tweetScores = tweets.map((tweet) =>
    generateXAlgorithmScore(tweet.content, {
      isThread: true,
      isReply: false,
      isQuote: false,
      hasMedia: false,
    })
  );

  // Apply diversity decay and calculate total
  const threadResult = calcXThreadScore(tweetScores);

  // Collect strengths and improvements from all tweets
  const allStrengths = new Set<string>();
  const allImprovements = new Set<string>();

  tweetScores.forEach((score) => {
    score.strengths.forEach(s => allStrengths.add(s));
    score.improvements.forEach(i => allImprovements.add(i));
  });

  // Thread-specific analysis
  const hookTweet = tweetScores[0];
  if (hookTweet.hook_strength >= 16) {
    allStrengths.add("Hook tweet çok güçlü - dikkat çekici açılış");
  } else if (hookTweet.hook_strength < 12) {
    allImprovements.add("Hook tweet güçlendirilmeli - ilk tweet çok önemli");
  }

  if (threadResult.averageEngagement >= 14) {
    allStrengths.add("Thread genelinde yüksek etkileşim potansiyeli");
  }

  return {
    totalScore: threadResult.totalScore,
    tweetScores,
    threadAnalysis: {
      hookScore: threadResult.hookScore,
      averageEngagement: threadResult.averageEngagement,
      adjustedScores: threadResult.adjustedScores,
      strengths: Array.from(allStrengths).slice(0, 4),
      improvements: Array.from(allImprovements).slice(0, 4),
    },
  };
}

