import { NextRequest, NextResponse } from "next/server";
import OpenAI from "openai";
import { defaultPersonas } from "@/lib/personas";
import { Persona, XAlgorithmScore } from "@/types";
import { generateXAlgorithmScore } from "@/lib/xAlgorithmScoring";
import {
  validateOriginalTweet,
  validateReplyStyle,
  validatePersona,
  sanitizeForPrompt,
  checkRateLimit,
  getClientIdentifier,
  getErrorMessage,
  safeJSONParse,
} from "@/lib/validation";

const openai = new OpenAI({
  apiKey: process.env.OPENAI_API_KEY,
});

const MODEL = process.env.OPENAI_MODEL || "gpt-4o-mini";

// Rate limit config: 30 requests per minute
const RATE_LIMIT_CONFIG = { windowMs: 60 * 1000, maxRequests: 30 };

export async function POST(request: NextRequest) {
  try {
    // CSRF Protection: Validate origin
    const origin = request.headers.get("origin");
    const host = request.headers.get("host");
    if (origin) {
      const allowedOrigins = [
        `http://${host}`,
        `https://${host}`,
        process.env.NEXT_PUBLIC_BASE_URL,
      ].filter(Boolean);
      if (!allowedOrigins.some(allowed => origin === allowed)) {
        return NextResponse.json(
          { success: false, error: "Geçersiz kaynak" },
          { status: 403 }
        );
      }
    }

    // Rate limiting check
    const clientId = getClientIdentifier(request);
    const rateLimit = checkRateLimit(clientId, RATE_LIMIT_CONFIG);

    if (!rateLimit.allowed) {
      return NextResponse.json(
        {
          success: false,
          error: "Çok fazla istek. Lütfen biraz bekleyin.",
          retryAfter: Math.ceil(rateLimit.resetIn / 1000)
        },
        {
          status: 429,
          headers: {
            "Retry-After": String(Math.ceil(rateLimit.resetIn / 1000)),
            "X-RateLimit-Remaining": String(rateLimit.remaining),
          }
        }
      );
    }

    // Safe JSON parsing
    let body;
    try {
      body = await request.json();
    } catch {
      return NextResponse.json(
        { success: false, error: "Geçersiz istek formatı" },
        { status: 400 }
      );
    }

    const { originalTweet, persona, customPersona, replyStyle } = body;

    // Validate original tweet
    const tweetValidation = validateOriginalTweet(originalTweet);
    if (!tweetValidation.valid) {
      return NextResponse.json(
        { success: false, error: tweetValidation.error },
        { status: 400 }
      );
    }
    const sanitizedTweet = tweetValidation.sanitized as string;

    // Validate reply style
    const styleValidation = validateReplyStyle(replyStyle);
    if (!styleValidation.valid) {
      return NextResponse.json(
        { success: false, error: styleValidation.error },
        { status: 400 }
      );
    }
    const validatedStyle = styleValidation.sanitized as string;

    // Validate persona
    let selectedPersona: Persona | undefined;
    if (customPersona) {
      const personaValidation = validatePersona(customPersona);
      if (!personaValidation.valid) {
        return NextResponse.json(
          { success: false, error: personaValidation.error },
          { status: 400 }
        );
      }
      selectedPersona = personaValidation.sanitized as Persona;
    } else if (persona) {
      selectedPersona = defaultPersonas.find((p) => p.id === persona);
    }

    if (!selectedPersona) {
      // Fallback to first persona with safety check
      if (defaultPersonas.length === 0) {
        return NextResponse.json(
          { success: false, error: "Persona yapılandırması eksik" },
          { status: 500 }
        );
      }
      selectedPersona = defaultPersonas[0];
    }

    // Sanitize persona data
    const safePersonaName = sanitizeForPrompt(selectedPersona.name);
    const safePersonaTone = sanitizeForPrompt(selectedPersona.tone);
    const safePersonaStyle = sanitizeForPrompt(selectedPersona.style);
    const safeExamples = selectedPersona.example_tweets?.slice(0, 2).map(t => sanitizeForPrompt(t)).join(" | ") || "Yok";

    const styleDescriptions: Record<string, string> = {
      agree: "Tweet'e katılarak, destekleyici ve pozitif bir şekilde",
      disagree: "Saygılı bir şekilde farklı bir bakış açısı sunarak",
      question: "Merak uyandıran, düşündürücü bir soru sorarak",
      add_value: "Konuya ek bilgi veya farklı bir perspektif ekleyerek",
      witty: "Esprili, akıllıca ve dikkat çekici bir şekilde"
    };

    const styleDescription = styleDescriptions[validatedStyle] || styleDescriptions.add_value;

    const systemPrompt = `Sen viral X (Twitter) reply'ları yazan bir uzmansın.

PERSONA:
- İsim: ${safePersonaName}
- Ton: ${safePersonaTone}
- Yazım tarzı: ${safePersonaStyle}
- Örnek tweet'ler: ${safeExamples}

REPLY STİLİ: ${styleDescription}

KURALLAR:
1. Reply maksimum 200 karakter olmalı
2. Orijinal tweet'e doğrudan cevap ver
3. Etkileşim potansiyeli yüksek olmalı
4. Persona'nın tarzına uygun yaz
5. Doğal ve samimi ol
6. Spam gibi görünme

3 farklı reply önerisi üret.

JSON formatında döndür:
{
  "replies": [
    {
      "content": "Reply metni",
      "style": "Kullanılan stil (agree/disagree/question/add_value/witty)"
    }
  ]
}`;

    const response = await openai.chat.completions.create({
      model: MODEL,
      messages: [
        { role: "system", content: systemPrompt },
        { role: "user", content: `Orijinal Tweet:\n"${sanitizedTweet}"\n\n${styleDescription} 3 farklı reply önerisi üret.` }
      ],
      temperature: 0.8,
      response_format: { type: "json_object" },
    });

    const content = response.choices[0].message.content;
    if (!content) {
      return NextResponse.json(
        { success: false, error: "API yanıtı boş" },
        { status: 500 }
      );
    }

    // Safe JSON parse
    const parseResult = safeJSONParse<{ replies: Array<{ content: string; style: string }> }>(content);

    if (!parseResult.success) {
      return NextResponse.json(
        { success: false, error: "Reply yanıtı işlenemedi. Lütfen tekrar deneyin." },
        { status: 500 }
      );
    }

    const result = parseResult.data;

    // Validate result structure
    if (!result.replies || !Array.isArray(result.replies)) {
      return NextResponse.json(
        { success: false, error: "Geçersiz reply yapısı" },
        { status: 500 }
      );
    }

    // Apply X Algorithm scoring to each reply
    const scoredReplies = result.replies.map((reply: { content: string; style: string }) => {
      const xScore = generateXAlgorithmScore(reply.content, {
        isThread: false,
        isReply: true,
        isQuote: false,
        hasMedia: false,
      });

      return {
        content: reply.content,
        style: reply.style,
        xScore,
      };
    });

    // Sort by X Algorithm score (highest first)
    scoredReplies.sort((a: { xScore: XAlgorithmScore }, b: { xScore: XAlgorithmScore }) =>
      b.xScore.total - a.xScore.total
    );

    return NextResponse.json({
      success: true,
      data: {
        originalTweet: sanitizedTweet,
        replies: scoredReplies,
        persona: selectedPersona.name,
        style: validatedStyle
      },
    });
  } catch (error: unknown) {
    console.error("Reply generation error:", error);

    const errorMessage = getErrorMessage(error);
    const isOpenAIError = errorMessage.toLowerCase().includes("openai") ||
                          errorMessage.toLowerCase().includes("api key");

    return NextResponse.json(
      {
        success: false,
        error: isOpenAIError ? "Servis geçici olarak kullanılamıyor" : "Reply oluşturulamadı"
      },
      { status: 500 }
    );
  }
}

