import { NextRequest, NextResponse } from "next/server";
import OpenAI from "openai";
import { defaultPersonas } from "@/lib/personas";
import { Persona, XAlgorithmScore } from "@/types";
import { generateXAlgorithmScore } from "@/lib/xAlgorithmScoring";
import {
  validateOriginalTweet,
  validateQuoteStyle,
  validatePersona,
  sanitizeForPrompt,
  checkRateLimit,
  getClientIdentifier,
  getErrorMessage,
  safeJSONParse,
} from "@/lib/validation";

const openai = new OpenAI({
  apiKey: process.env.OPENAI_API_KEY,
});

const MODEL = process.env.OPENAI_MODEL || "gpt-4o-mini";

// Rate limit config: 30 requests per minute
const RATE_LIMIT_CONFIG = { windowMs: 60 * 1000, maxRequests: 30 };

export async function POST(request: NextRequest) {
  try {
    // CSRF Protection: Validate origin
    const origin = request.headers.get("origin");
    const host = request.headers.get("host");
    if (origin) {
      const allowedOrigins = [
        `http://${host}`,
        `https://${host}`,
        process.env.NEXT_PUBLIC_BASE_URL,
      ].filter(Boolean);
      if (!allowedOrigins.some(allowed => origin === allowed)) {
        return NextResponse.json(
          { success: false, error: "Geçersiz kaynak" },
          { status: 403 }
        );
      }
    }

    // Rate limiting check
    const clientId = getClientIdentifier(request);
    const rateLimit = checkRateLimit(clientId, RATE_LIMIT_CONFIG);

    if (!rateLimit.allowed) {
      return NextResponse.json(
        {
          success: false,
          error: "Çok fazla istek. Lütfen biraz bekleyin.",
          retryAfter: Math.ceil(rateLimit.resetIn / 1000)
        },
        {
          status: 429,
          headers: {
            "Retry-After": String(Math.ceil(rateLimit.resetIn / 1000)),
            "X-RateLimit-Remaining": String(rateLimit.remaining),
          }
        }
      );
    }

    // Safe JSON parsing
    let body;
    try {
      body = await request.json();
    } catch {
      return NextResponse.json(
        { success: false, error: "Geçersiz istek formatı" },
        { status: 400 }
      );
    }

    const { originalTweet, persona, customPersona, quoteStyle } = body;

    // Validate original tweet
    const tweetValidation = validateOriginalTweet(originalTweet);
    if (!tweetValidation.valid) {
      return NextResponse.json(
        { success: false, error: tweetValidation.error },
        { status: 400 }
      );
    }
    const sanitizedTweet = tweetValidation.sanitized as string;

    // Validate quote style
    const styleValidation = validateQuoteStyle(quoteStyle);
    if (!styleValidation.valid) {
      return NextResponse.json(
        { success: false, error: styleValidation.error },
        { status: 400 }
      );
    }
    const validatedStyle = styleValidation.sanitized as string;

    // Validate persona
    let selectedPersona: Persona | undefined;
    if (customPersona) {
      const personaValidation = validatePersona(customPersona);
      if (!personaValidation.valid) {
        return NextResponse.json(
          { success: false, error: personaValidation.error },
          { status: 400 }
        );
      }
      selectedPersona = personaValidation.sanitized as Persona;
    } else if (persona) {
      selectedPersona = defaultPersonas.find((p) => p.id === persona);
    }

    if (!selectedPersona) {
      // Fallback to first persona with safety check
      if (defaultPersonas.length === 0) {
        return NextResponse.json(
          { success: false, error: "Persona yapılandırması eksik" },
          { status: 500 }
        );
      }
      selectedPersona = defaultPersonas[0];
    }

    // Sanitize persona data
    const safePersonaName = sanitizeForPrompt(selectedPersona.name);
    const safePersonaTone = sanitizeForPrompt(selectedPersona.tone);
    const safePersonaStyle = sanitizeForPrompt(selectedPersona.style);
    const safeExamples = selectedPersona.example_tweets?.slice(0, 2).map(t => sanitizeForPrompt(t)).join(" | ") || "Yok";

    const styleDescriptions: Record<string, string> = {
      insight: "Derinlemesine bir içgörü veya analiz ekleyerek. Konuyu farklı bir açıdan ele al.",
      hot_take: "Cesur, dikkat çekici ve tartışmaya açık bir görüş ekleyerek. Viral potansiyeli yüksek olsun.",
      story: "Kişisel bir deneyim veya hikaye ekleyerek. Duygusal bağ kur.",
      data: "Rakamlar, istatistikler veya somut veriler ekleyerek. Güvenilirlik kat.",
      contrarian: "Zıt veya beklenmedik bir bakış açısı sunarak. Düşündürücü ol."
    };

    const styleDescription = styleDescriptions[validatedStyle] || styleDescriptions.insight;

    const systemPrompt = `Sen viral X (Twitter) quote tweet'leri yazan bir uzmansın.

PERSONA:
- İsim: ${safePersonaName}
- Ton: ${safePersonaTone}
- Yazım tarzı: ${safePersonaStyle}
- Örnek tweet'ler: ${safeExamples}

QUOTE STİLİ: ${styleDescription}

KURALLAR:
1. Quote tweet maksimum 280 karakter olmalı
2. Orijinal tweet'e değer katmalı
3. Sadece "This" veya "💯" gibi boş quote'lar YASAK
4. Viral potansiyeli yüksek olmalı
5. Persona'nın tarzına uygun yaz
6. Hook ile başla (ilk cümle dikkat çekici olmalı)

3 farklı quote tweet önerisi üret.

JSON formatında döndür:
{
  "quotes": [
    {
      "content": "Quote tweet metni",
      "style": "Kullanılan stil"
    }
  ]
}`;

    const response = await openai.chat.completions.create({
      model: MODEL,
      messages: [
        { role: "system", content: systemPrompt },
        { role: "user", content: `Orijinal Tweet:\n"${sanitizedTweet}"\n\n${styleDescription} 3 farklı quote tweet önerisi üret.` }
      ],
      temperature: 0.85,
      response_format: { type: "json_object" },
    });

    const content = response.choices[0].message.content;
    if (!content) {
      return NextResponse.json(
        { success: false, error: "API yanıtı boş" },
        { status: 500 }
      );
    }

    // Safe JSON parse
    const parseResult = safeJSONParse<{ quotes: Array<{ content: string; style: string }> }>(content);

    if (!parseResult.success) {
      return NextResponse.json(
        { success: false, error: "Quote yanıtı işlenemedi. Lütfen tekrar deneyin." },
        { status: 500 }
      );
    }

    const result = parseResult.data;

    // Validate result structure
    if (!result.quotes || !Array.isArray(result.quotes)) {
      return NextResponse.json(
        { success: false, error: "Geçersiz quote yapısı" },
        { status: 500 }
      );
    }

    // Apply X Algorithm scoring to each quote
    const scoredQuotes = result.quotes.map((quote: { content: string; style: string }) => {
      const xScore = generateXAlgorithmScore(quote.content, {
        isThread: false,
        isReply: false,
        isQuote: true,
        hasMedia: false,
      });

      return {
        content: quote.content,
        style: quote.style,
        xScore,
      };
    });

    // Sort by X Algorithm score (highest first)
    scoredQuotes.sort((a: { xScore: XAlgorithmScore }, b: { xScore: XAlgorithmScore }) =>
      b.xScore.total - a.xScore.total
    );

    return NextResponse.json({
      success: true,
      data: {
        originalTweet: sanitizedTweet,
        quotes: scoredQuotes,
        persona: selectedPersona.name,
        style: validatedStyle
      },
    });
  } catch (error: unknown) {
    console.error("Quote generation error:", error);

    const errorMessage = getErrorMessage(error);
    const isOpenAIError = errorMessage.toLowerCase().includes("openai") ||
                          errorMessage.toLowerCase().includes("api key");

    return NextResponse.json(
      {
        success: false,
        error: isOpenAIError ? "Servis geçici olarak kullanılamıyor" : "Quote tweet oluşturulamadı"
      },
      { status: 500 }
    );
  }
}

