     1→/**
     2→ * Shared utility functions for Tweet Generator
     3→ * Consolidates duplicate code from multiple components
     4→ */
     5→
     6→import type { ThreadTweet } from '@/types';
     7→
     8→// ============================================
     9→// Score Color Functions
    10→// ============================================
    11→
    12→/**
    13→ * Get text color class based on score percentage
    14→ * Used for individual category scores (0-20 scale)
    15→ */
    16→export function getScoreColor(score: number, max: number = 20): string {
    17→  const percentage = (score / max) * 100;
    18→  if (percentage >= 80) return 'text-green-400';
    19→  if (percentage >= 60) return 'text-yellow-400';
    20→  return 'text-red-400';
    21→}
    22→
    23→/**
    24→ * Get background/border color classes based on score
    25→ * Used for score containers and cards
    26→ */
    27→export function getScoreBgColor(score: number): string {
    28→  if (score >= 80) return 'bg-green-500/20 border-green-500/30';
    29→  if (score >= 60) return 'bg-yellow-500/20 border-yellow-500/30';
    30→  return 'bg-red-500/20 border-red-500/30';
    31→}
    32→
    33→/**
    34→ * Get progress bar background color based on score
    35→ * Used for category score progress bars
    36→ */
    37→export function getCategoryColor(score: number, max: number = 20): string {
    38→  const percentage = (score / max) * 100;
    39→  if (percentage >= 80) return 'bg-green-500';
    40→  if (percentage >= 60) return 'bg-yellow-500';
    41→  return 'bg-red-500';
    42→}
    43→
    44→/**
    45→ * Get gradient classes for total score display
    46→ * Used for main score badges
    47→ */
    48→export function getTotalScoreGradient(score: number): string {
    49→  if (score >= 80) return 'from-green-500 to-emerald-600';
    50→  if (score >= 60) return 'from-yellow-500 to-orange-600';
    51→  return 'from-red-500 to-rose-600';
    52→}
    53→
    54→/**
    55→ * Get ring/glow color for score highlights
    56→ */
    57→export function getScoreRingColor(score: number): string {
    58→  if (score >= 80) return 'ring-green-500/30';
    59→  if (score >= 60) return 'ring-yellow-500/30';
    60→  return 'ring-red-500/30';
    61→}
    62→
    63→// ============================================
    64→// Clipboard Functions
    65→// ============================================
    66→
    67→/**
    68→ * Copy text to clipboard with error handling
    69→ * Returns true on success, false on failure
    70→ */
    71→export async function copyToClipboard(text: string): Promise<boolean> {
    72→  try {
    73→    await navigator.clipboard.writeText(text);
    74→    return true;
    75→  } catch {
    76→    return false;
    77→  }
    78→}
    79→
    80→/**
    81→ * Convert thread tweets to copyable text format
    82→ */
    83→export function threadToText(tweets: ThreadTweet[]): string {
    84→  return tweets.map((t, i) => `${i + 1}/${tweets.length}\n${t.content}`).join('\n\n---\n\n');
    85→}
    86→
    87→// ============================================
    88→// Formatting Functions
    89→// ============================================
    90→
    91→/**
    92→ * Format score number for display (rounded)
    93→ */
    94→export function formatScore(score: number): string {
    95→  return Math.round(score).toString();
    96→}
    97→
    98→/**
    99→ * Format date string for display
   100→ */
   101→export function formatDate(dateString: string): string {
   102→  const date = new Date(dateString);
   103→  return date.toLocaleDateString('tr-TR', {
   104→    day: 'numeric',
