/**
 * Shared utility functions for Tweet Generator
 * Consolidates duplicate code from multiple components
 */

import type { ThreadTweet } from '@/types';

// ============================================
// Score Color Functions
// ============================================

/**
 * Get text color class based on score percentage
 * Used for individual category scores (0-20 scale)
 */
export function getScoreColor(score: number, max: number = 20): string {
  const percentage = (score / max) * 100;
  if (percentage >= 80) return 'text-green-400';
  if (percentage >= 60) return 'text-yellow-400';
  return 'text-red-400';
}

/**
 * Get background/border color classes based on score
 * Used for score containers and cards
 */
export function getScoreBgColor(score: number): string {
  if (score >= 80) return 'bg-green-500/20 border-green-500/30';
  if (score >= 60) return 'bg-yellow-500/20 border-yellow-500/30';
  return 'bg-red-500/20 border-red-500/30';
}

/**
 * Get progress bar background color based on score
 * Used for category score progress bars
 */
export function getCategoryColor(score: number, max: number = 20): string {
  const percentage = (score / max) * 100;
  if (percentage >= 80) return 'bg-green-500';
  if (percentage >= 60) return 'bg-yellow-500';
  return 'bg-red-500';
}

/**
 * Get gradient classes for total score display
 * Used for main score badges
 */
export function getTotalScoreGradient(score: number): string {
  if (score >= 80) return 'from-green-500 to-emerald-600';
  if (score >= 60) return 'from-yellow-500 to-orange-600';
  return 'from-red-500 to-rose-600';
}

/**
 * Get ring/glow color for score highlights
 */
export function getScoreRingColor(score: number): string {
  if (score >= 80) return 'ring-green-500/30';
  if (score >= 60) return 'ring-yellow-500/30';
  return 'ring-red-500/30';
}

// ============================================
// Clipboard Functions
// ============================================

/**
 * Copy text to clipboard with error handling
 * Returns true on success, false on failure
 */
export async function copyToClipboard(text: string): Promise<boolean> {
  try {
    await navigator.clipboard.writeText(text);
    return true;
  } catch {
    return false;
  }
}

/**
 * Convert thread tweets to copyable text format
 */
export function threadToText(tweets: ThreadTweet[]): string {
  return tweets.map((t, i) => `${i + 1}/${tweets.length}\n${t.content}`).join('\n\n---\n\n');
}

// ============================================
// Formatting Functions
// ============================================

/**
 * Format score number for display (rounded)
 */
export function formatScore(score: number): string {
  return Math.round(score).toString();
}

/**
 * Format date string for display
 */
export function formatDate(dateString: string): string {
  const date = new Date(dateString);
  return date.toLocaleDateString('tr-TR', {
    day: 'numeric',
    month: 'short',
    hour: '2-digit',
    minute: '2-digit',
  });
}

/**
 * Format character count with limit indicator
 */
export function formatCharacterCount(count: number, limit: number = 280): string {
  return `${count}/${limit}`;
}

/**
 * Get rank badge emoji for tweet ranking
 */
export function getRankBadge(index: number): string {
  const badges = ['1', '2', '3'];
  return badges[index] || (index + 1).toString();
}

// ============================================
// Score Category Constants
// ============================================

export interface ScoreCategory {
  key: 'hook_strength' | 'engagement_potential' | 'viral_potential' | 'algorithm_fit' | 'content_quality';
  label: string;
  labelTr: string;
  icon: string;
  description: string;
}

export const SCORE_CATEGORIES: readonly ScoreCategory[] = [
  {
    key: 'hook_strength',
    label: 'Hook',
    labelTr: 'Hook',
    icon: '🎯',
    description: 'Ilk satirin dikkat cekiciligi',
  },
  {
    key: 'engagement_potential',
    label: 'Engagement',
    labelTr: 'Etkilesim',
    icon: '💬',
    description: 'Yorum ve tartisma potansiyeli',
  },
  {
    key: 'viral_potential',
    label: 'Viral',
    labelTr: 'Viral',
    icon: '🚀',
    description: 'Paylasim ve yayilma potansiyeli',
  },
  {
    key: 'algorithm_fit',
    label: 'Algorithm',
    labelTr: 'Algoritma',
    icon: '⚡',
    description: 'X algoritmasina uygunluk',
  },
  {
    key: 'content_quality',
    label: 'Quality',
    labelTr: 'Kalite',
    icon: '✨',
    description: 'Icerik kalitesi ve orijinallik',
  },
] as const;

// ============================================
// Engagement Prediction Constants
// ============================================

export interface EngagementLabel {
  key: string;
  label: string;
  labelTr: string;
  icon: string;
}

export const ENGAGEMENT_LABELS: readonly EngagementLabel[] = [
  { key: 'favorite_score', label: 'Like', labelTr: 'Begeni', icon: '❤️' },
  { key: 'reply_score', label: 'Reply', labelTr: 'Yanit', icon: '💬' },
  { key: 'repost_score', label: 'Retweet', labelTr: 'RT', icon: '🔁' },
  { key: 'click_score', label: 'Click', labelTr: 'Tikla', icon: '👆' },
  { key: 'share_score', label: 'Share', labelTr: 'Paylas', icon: '📤' },
  { key: 'bookmark_score', label: 'Bookmark', labelTr: 'Kaydet', icon: '🔖' },
] as const;

// ============================================
// History Type Helpers
// ============================================

export interface TypeInfo {
  icon: string;
  label: string;
  color: string;
}

export function getTypeInfo(type: string): TypeInfo {
  const types: Record<string, TypeInfo> = {
    tweet: { icon: '📝', label: 'Tweet', color: 'text-blue-400' },
    thread: { icon: '🧵', label: 'Thread', color: 'text-purple-400' },
    reply: { icon: '↩️', label: 'Yanit', color: 'text-green-400' },
    quote: { icon: '💬', label: 'Alinti', color: 'text-amber-400' },
  };
  return types[type] || { icon: '📄', label: 'Icerik', color: 'text-gray-400' };
}

// ============================================
// Content Helpers
// ============================================

/**
 * Check if content is a thread (array of tweets)
 */
export function isThreadContent(content: string | ThreadTweet[]): content is ThreadTweet[] {
  return Array.isArray(content);
}

/**
 * Get content preview text (truncated if needed)
 * Handles edge cases like empty arrays and null content
 */
export function getContentPreview(content: string | ThreadTweet[], maxLength: number = 100): string {
  if (isThreadContent(content)) {
    // Handle empty array case
    if (content.length === 0) {
      return '[Boş thread]';
    }
    const firstTweet = content[0]?.content;
    // Handle missing or invalid content
    if (typeof firstTweet !== 'string' || !firstTweet) {
      return '[Geçersiz içerik]';
    }
    return firstTweet.length > maxLength ? firstTweet.slice(0, maxLength) + '...' : firstTweet;
  }
  // Handle non-string content
  if (typeof content !== 'string') {
    return '[Bilinmeyen içerik]';
  }
  if (!content) {
    return '[Boş içerik]';
  }
  return content.length > maxLength ? content.slice(0, maxLength) + '...' : content;
}

/**
 * Get full content as string (for copying)
 */
export function getContentAsText(content: string | ThreadTweet[]): string {
  if (isThreadContent(content)) {
    return threadToText(content);
  }
  return content;
}

