     5→
     6→// ============================================
     7→// Error Message Constants
     8→// ============================================
     9→
    10→export const ERROR_MESSAGES = {
    11→  // Network Errors
    12→  NETWORK: 'Internet baglantinizi kontrol edin',
    13→  TIMEOUT: 'Istek zaman asimina ugradi. Tekrar deneyin.',
