    28→  INVALID_LENGTH: 'Gecersiz uzunluk secimi',
    29→  INVALID_TONE: 'Gecersiz ton secimi',
    30→  INVALID_STYLE: 'Gecersiz stil secimi',
    31→
    32→  // API Errors
    33→  API_ERROR: 'Servis gecici olarak kullanilamiyor',
    34→  AI_ERROR: 'AI yanit uretirken hata olustu',
    35→  PARSE_ERROR: 'Yanit islenirken hata olustu',
    36→  SERVER_ERROR: 'Sunucu hatasi. Lutfen daha sonra tekrar deneyin.',
    37→
    38→  // Storage Errors
    39→  STORAGE_FULL: 'Yerel depolama dolu. Eski kayitlari silin.',
    40→  STORAGE_ERROR: 'Veri kaydedilemedi',
    41→
    42→  // Generic
    43→  UNKNOWN: 'Beklenmeyen bir hata olustu',
    44→  TRY_AGAIN: 'Bir hata olustu. Lutfen tekrar deneyin.',
    45→} as const;
    46→
    47→export type ErrorCode = keyof typeof ERROR_MESSAGES;
    48→
    49→// ============================================
    50→// Error Message Helpers
    51→// ============================================
    52→
    53→/**
    54→ * Get user-friendly error message from any error type
    55→ */
    56→export function getErrorMessage(
    57→  error: unknown,
    58→  context?: { seconds?: number; endpoint?: string }
    59→): string {
    60→  // Handle rate limit with seconds placeholder
    61→  if (context?.seconds && isRateLimitError(error)) {
    62→    const baseMessage = context.endpoint
    63→      ? getRateLimitMessageForEndpoint(context.endpoint)
    64→      : ERROR_MESSAGES.RATE_LIMIT;
    65→    return baseMessage.replace('{seconds}', String(context.seconds));
    66→  }
    67→
    68→  // Handle Error objects
    69→  if (error instanceof Error) {
    70→    const message = error.message.toLowerCase();
    71→
    72→    // Network errors
    73→    if (message.includes('fetch') || message.includes('network')) {
    74→      return ERROR_MESSAGES.NETWORK;
    75→    }
    76→    if (message.includes('timeout') || message.includes('aborted')) {
    77→      return ERROR_MESSAGES.TIMEOUT;
    78→    }
    79→
    80→    // Rate limit from error message
    81→    if (message.includes('429') || message.includes('rate')) {
    82→      return ERROR_MESSAGES.RATE_LIMIT.replace('{seconds}', '60');
    83→    }
    84→
    85→    // Server errors
    86→    if (message.includes('500') || message.includes('server')) {
    87→      return ERROR_MESSAGES.SERVER_ERROR;
    88→    }
    89→
    90→    // Return the actual message if it's user-friendly
    91→    if (error.message.length < 100 && !message.includes('error')) {
    92→      return error.message;
    93→    }
    94→
    95→    return ERROR_MESSAGES.UNKNOWN;
    96→  }
    97→
    98→  // Handle string errors
    99→  if (typeof error === 'string') {
   100→    // Rate limit string
   101→    if (error.includes('429') || error.toLowerCase().includes('rate')) {
   102→      return ERROR_MESSAGES.RATE_LIMIT.replace('{seconds}', '60');
   103→    }
   104→
   105→    // Return if reasonable length
   106→    if (error.length < 150) {
   107→      return error;
   108→    }
   109→
   110→    return ERROR_MESSAGES.UNKNOWN;
   111→  }
   112→
   113→  // Handle API response objects
   114→  if (error && typeof error === 'object' && 'error' in error) {
   115→    const apiError = error as { error: string; retryAfter?: number };
   116→    if (apiError.retryAfter) {
   117→      return ERROR_MESSAGES.RATE_LIMIT.replace('{seconds}', String(apiError.retryAfter));
   118→    }
   119→    return apiError.error || ERROR_MESSAGES.UNKNOWN;
   120→  }
   121→
   122→  return ERROR_MESSAGES.UNKNOWN;
   123→}
   124→
   125→/**
   126→ * Check if error is a rate limit error
   127→ */
   128→export function isRateLimitError(error: unknown): boolean {
   129→  if (error instanceof Error) {
   130→    const message = error.message.toLowerCase();
   131→    return message.includes('429') || message.includes('rate') || message.includes('too many');
   132→  }
   133→
   134→  if (typeof error === 'string') {
   135→    const lower = error.toLowerCase();
   136→    return lower.includes('429') || lower.includes('rate') || lower.includes('too many');
   137→  }
   138→
   139→  if (error && typeof error === 'object') {
   140→    if ('retryAfter' in error) return true;
   141→    if ('error' in error) {
   142→      const errStr = String((error as { error: string }).error).toLowerCase();
   143→      return errStr.includes('rate') || errStr.includes('429');
   144→    }
   145→  }
   146→
   147→  return false;
   148→}
   149→
   150→/**
   151→ * Get rate limit message for specific endpoint
   152→ */
   153→function getRateLimitMessageForEndpoint(endpoint: string): string {
   154→  if (endpoint.includes('generate')) return ERROR_MESSAGES.RATE_LIMIT_GENERATE;
   155→  if (endpoint.includes('thread')) return ERROR_MESSAGES.RATE_LIMIT_THREAD;
   156→  if (endpoint.includes('quote')) return ERROR_MESSAGES.RATE_LIMIT_QUOTE;
   157→  if (endpoint.includes('reply')) return ERROR_MESSAGES.RATE_LIMIT_REPLY;
   158→  return ERROR_MESSAGES.RATE_LIMIT;
   159→}
   160→
   161→/**
   162→ * Check if error is a network error
   163→ */
   164→export function isNetworkError(error: unknown): boolean {
   165→  if (error instanceof Error) {
   166→    const message = error.message.toLowerCase();
   167→    return (
   168→      message.includes('fetch') ||
   169→      message.includes('network') ||
   170→      message.includes('connection') ||
   171→      message.includes('offline')
   172→    );
   173→  }
   174→  return false;
   175→}
   176→
   177→/**
   178→ * Extract retry-after seconds from error
   179→ */
   180→export function getRetryAfterSeconds(error: unknown): number | null {
   181→  if (error && typeof error === 'object' && 'retryAfter' in error) {
   182→    return (error as { retryAfter: number }).retryAfter;
   183→  }
   184→
   185→  if (error instanceof Error) {
   186→    // Try to extract from message like "retry after 60 seconds"
   187→    const match = error.message.match(/(\d+)\s*(?:saniye|seconds?)/i);
   188→    if (match) {
   189→      return parseInt(match[1], 10);
   190→    }
   191→  }
   192→
   193→  return null;
   194→}
   195→
   196→// ============================================
   197→// Error Display Helpers
   198→// ============================================
   199→
   200→export interface ErrorDisplayInfo {
   201→  message: string;
   202→  canRetry: boolean;
   203→  retryAfter?: number;
   204→  severity: 'error' | 'warning' | 'info';
   205→}
   206→
   207→// ============================================
   208→// Environment Validation
   209→// ============================================
   210→
   211→export interface EnvValidationResult {
   212→  valid: boolean;
   213→  errors: string[];
   214→  warnings: string[];
   215→}
   216→
   217→export function validateEnvironment(): EnvValidationResult {
   218→  const errors: string[] = [];
   219→  const warnings: string[] = [];
   220→
   221→  // Required: OpenAI API Key
   222→  if (!process.env.OPENAI_API_KEY) {
   223→    errors.push('OPENAI_API_KEY is not set');
   224→  } else if (process.env.OPENAI_API_KEY.length < 20) {
   225→    errors.push('OPENAI_API_KEY appears to be invalid (too short)');
   226→  }
   227→
   228→  // Optional but recommended: Apify Token
   229→  if (!process.env.APIFY_API_TOKEN || process.env.APIFY_API_TOKEN === 'your_apify_token_here') {
   230→    warnings.push('APIFY_API_TOKEN is not set - auto tweet fetching will not work');
   231→  }
   232→
   233→  // Warn if using default model
   234→  if (!process.env.OPENAI_MODEL) {
   235→    warnings.push('OPENAI_MODEL not set - using default gpt-4o-mini');
   236→  }
   237→
   238→  return {
   239→    valid: errors.length === 0,
   240→    errors,
   241→    warnings,
   242→  };
   243→}
   244→
   245→export function getEnvStatus(): { openai: boolean; apify: boolean; model: string } {
   246→  return {
   247→    openai: !!process.env.OPENAI_API_KEY && process.env.OPENAI_API_KEY.length > 20,
   248→    apify: !!process.env.APIFY_API_TOKEN && process.env.APIFY_API_TOKEN !== 'your_apify_token_here',
   249→    model: process.env.OPENAI_MODEL || 'gpt-4o-mini',
   250→  };
   251→}
   252→
   253→/**
   254→ * Get comprehensive error display info
   255→ */
   256→export function getErrorDisplayInfo(error: unknown): ErrorDisplayInfo {
   257→  const isRateLimit = isRateLimitError(error);
   258→  const isNetwork = isNetworkError(error);
   259→  const retryAfter = getRetryAfterSeconds(error);
