/**
 * Centralized error handling for Tweet Generator
 * User-friendly error messages in Turkish
 */

// ============================================
// Error Message Constants
// ============================================

export const ERROR_MESSAGES = {
  // Network Errors
  NETWORK: 'Internet baglantinizi kontrol edin',
  TIMEOUT: 'Istek zaman asimina ugradi. Tekrar deneyin.',
  FETCH_FAILED: 'Sunucuya baglanilamadi. Lutfen tekrar deneyin.',

  // Rate Limiting
  RATE_LIMIT: 'Cok fazla istek. {seconds} saniye bekleyin.',
  RATE_LIMIT_GENERATE: 'Tweet uretimi icin {seconds} saniye bekleyin.',
  RATE_LIMIT_THREAD: 'Thread olusturma icin {seconds} saniye bekleyin.',
  RATE_LIMIT_QUOTE: 'Alinti tweet icin {seconds} saniye bekleyin.',
  RATE_LIMIT_REPLY: 'Yanit olusturma icin {seconds} saniye bekleyin.',

  // Validation Errors
  EMPTY_TOPIC: 'Lutfen bir konu girin',
  EMPTY_TWEET: 'Lutfen bir tweet girin',
  TOPIC_TOO_LONG: 'Konu cok uzun (max 500 karakter)',
  TWEET_TOO_LONG: 'Tweet cok uzun (max 500 karakter)',
  INVALID_LENGTH: 'Gecersiz uzunluk secimi',
  INVALID_TONE: 'Gecersiz ton secimi',
  INVALID_STYLE: 'Gecersiz stil secimi',

  // API Errors
  API_ERROR: 'Servis gecici olarak kullanilamiyor',
  AI_ERROR: 'AI yanit uretirken hata olustu',
  PARSE_ERROR: 'Yanit islenirken hata olustu',
  SERVER_ERROR: 'Sunucu hatasi. Lutfen daha sonra tekrar deneyin.',

  // Storage Errors
  STORAGE_FULL: 'Yerel depolama dolu. Eski kayitlari silin.',
  STORAGE_ERROR: 'Veri kaydedilemedi',

  // Generic
  UNKNOWN: 'Beklenmeyen bir hata olustu',
  TRY_AGAIN: 'Bir hata olustu. Lutfen tekrar deneyin.',
} as const;

export type ErrorCode = keyof typeof ERROR_MESSAGES;

// ============================================
// Error Message Helpers
// ============================================

/**
 * Get user-friendly error message from any error type
 */
export function getErrorMessage(
  error: unknown,
  context?: { seconds?: number; endpoint?: string }
): string {
  // Handle rate limit with seconds placeholder
  if (context?.seconds && isRateLimitError(error)) {
    const baseMessage = context.endpoint
      ? getRateLimitMessageForEndpoint(context.endpoint)
      : ERROR_MESSAGES.RATE_LIMIT;
    return baseMessage.replace('{seconds}', String(context.seconds));
  }

  // Handle Error objects
  if (error instanceof Error) {
    const message = error.message.toLowerCase();

    // Network errors
    if (message.includes('fetch') || message.includes('network')) {
      return ERROR_MESSAGES.NETWORK;
    }
    if (message.includes('timeout') || message.includes('aborted')) {
      return ERROR_MESSAGES.TIMEOUT;
    }

    // Rate limit from error message
    if (message.includes('429') || message.includes('rate')) {
      return ERROR_MESSAGES.RATE_LIMIT.replace('{seconds}', '60');
    }

    // Server errors
    if (message.includes('500') || message.includes('server')) {
      return ERROR_MESSAGES.SERVER_ERROR;
    }

    // Return the actual message if it's user-friendly
    if (error.message.length < 100 && !message.includes('error')) {
      return error.message;
    }

    return ERROR_MESSAGES.UNKNOWN;
  }

  // Handle string errors
  if (typeof error === 'string') {
    // Rate limit string
    if (error.includes('429') || error.toLowerCase().includes('rate')) {
      return ERROR_MESSAGES.RATE_LIMIT.replace('{seconds}', '60');
    }

    // Return if reasonable length
    if (error.length < 150) {
      return error;
    }

    return ERROR_MESSAGES.UNKNOWN;
  }

  // Handle API response objects
  if (error && typeof error === 'object' && 'error' in error) {
    const apiError = error as { error: string; retryAfter?: number };
    if (apiError.retryAfter) {
      return ERROR_MESSAGES.RATE_LIMIT.replace('{seconds}', String(apiError.retryAfter));
    }
    return apiError.error || ERROR_MESSAGES.UNKNOWN;
  }

  return ERROR_MESSAGES.UNKNOWN;
}

/**
 * Check if error is a rate limit error
 */
export function isRateLimitError(error: unknown): boolean {
  if (error instanceof Error) {
    const message = error.message.toLowerCase();
    return message.includes('429') || message.includes('rate') || message.includes('too many');
  }

  if (typeof error === 'string') {
    const lower = error.toLowerCase();
    return lower.includes('429') || lower.includes('rate') || lower.includes('too many');
  }

  if (error && typeof error === 'object') {
    if ('retryAfter' in error) return true;
    if ('error' in error) {
      const errStr = String((error as { error: string }).error).toLowerCase();
      return errStr.includes('rate') || errStr.includes('429');
    }
  }

  return false;
}

/**
 * Get rate limit message for specific endpoint
 */
function getRateLimitMessageForEndpoint(endpoint: string): string {
  if (endpoint.includes('generate')) return ERROR_MESSAGES.RATE_LIMIT_GENERATE;
  if (endpoint.includes('thread')) return ERROR_MESSAGES.RATE_LIMIT_THREAD;
  if (endpoint.includes('quote')) return ERROR_MESSAGES.RATE_LIMIT_QUOTE;
  if (endpoint.includes('reply')) return ERROR_MESSAGES.RATE_LIMIT_REPLY;
  return ERROR_MESSAGES.RATE_LIMIT;
}

/**
 * Check if error is a network error
 */
export function isNetworkError(error: unknown): boolean {
  if (error instanceof Error) {
    const message = error.message.toLowerCase();
    return (
      message.includes('fetch') ||
      message.includes('network') ||
      message.includes('connection') ||
      message.includes('offline')
    );
  }
  return false;
}

/**
 * Extract retry-after seconds from error
 */
export function getRetryAfterSeconds(error: unknown): number | null {
  if (error && typeof error === 'object' && 'retryAfter' in error) {
    return (error as { retryAfter: number }).retryAfter;
  }

  if (error instanceof Error) {
    // Try to extract from message like "retry after 60 seconds"
    const match = error.message.match(/(\d+)\s*(?:saniye|seconds?)/i);
    if (match) {
      return parseInt(match[1], 10);
    }
  }

  return null;
}

// ============================================
// Error Display Helpers
// ============================================

export interface ErrorDisplayInfo {
  message: string;
  canRetry: boolean;
  retryAfter?: number;
  severity: 'error' | 'warning' | 'info';
}

// ============================================
// Environment Validation
// ============================================

export interface EnvValidationResult {
  valid: boolean;
  errors: string[];
  warnings: string[];
}

export function validateEnvironment(): EnvValidationResult {
  const errors: string[] = [];
  const warnings: string[] = [];

  // Required: OpenAI API Key
  if (!process.env.OPENAI_API_KEY) {
    errors.push('OPENAI_API_KEY is not set');
  } else if (process.env.OPENAI_API_KEY.length < 20) {
    errors.push('OPENAI_API_KEY appears to be invalid (too short)');
  }

  // Optional but recommended: Apify Token
  if (!process.env.APIFY_API_TOKEN || process.env.APIFY_API_TOKEN === 'your_apify_token_here') {
    warnings.push('APIFY_API_TOKEN is not set - auto tweet fetching will not work');
  }

  // Warn if using default model
  if (!process.env.OPENAI_MODEL) {
    warnings.push('OPENAI_MODEL not set - using default gpt-4o-mini');
  }

  return {
    valid: errors.length === 0,
    errors,
    warnings,
  };
}

export function getEnvStatus(): { openai: boolean; apify: boolean; model: string } {
  return {
    openai: !!process.env.OPENAI_API_KEY && process.env.OPENAI_API_KEY.length > 20,
    apify: !!process.env.APIFY_API_TOKEN && process.env.APIFY_API_TOKEN !== 'your_apify_token_here',
    model: process.env.OPENAI_MODEL || 'gpt-4o-mini',
  };
}

/**
 * Get comprehensive error display info
 */
export function getErrorDisplayInfo(error: unknown): ErrorDisplayInfo {
  const isRateLimit = isRateLimitError(error);
  const isNetwork = isNetworkError(error);
  const retryAfter = getRetryAfterSeconds(error);

  return {
    message: getErrorMessage(error, retryAfter ? { seconds: retryAfter } : undefined),
    canRetry: !isRateLimit || (retryAfter !== null && retryAfter <= 0),
    retryAfter: retryAfter ?? undefined,
    severity: isRateLimit ? 'warning' : isNetwork ? 'warning' : 'error',
  };
}

