import { HistoryItem, ThreadTweet } from "@/types";
import { safeGetJSON, safeSetJSON } from "./storage";

const HISTORY_KEY = "tweet_history";
const MAX_HISTORY = 100;

// Simple mutex for preventing race conditions in history operations
let operationInProgress = false;

function withLock<T>(operation: () => T): T {
  if (operationInProgress) {
    // Queue the operation for later (simplified approach for client-side)
    return operation(); // For now, just execute - full mutex would need async
  }
  operationInProgress = true;
  try {
    return operation();
  } finally {
    operationInProgress = false;
  }
}

export function getHistory(): HistoryItem[] {
  if (typeof window === "undefined") return [];
  return safeGetJSON<HistoryItem[]>(HISTORY_KEY, []);
}

export function addToHistory(item: Omit<HistoryItem, "id" | "createdAt" | "isFavorite">): HistoryItem {
  return withLock(() => {
    const history = getHistory();
    const newItem: HistoryItem = {
      ...item,
      id: `${Date.now()}-${Math.random().toString(36).substr(2, 9)}`,
      isFavorite: false,
      createdAt: new Date().toISOString(),
    };

    history.unshift(newItem);

    // Max limit
    if (history.length > MAX_HISTORY) {
      history.pop();
    }

    safeSetJSON(HISTORY_KEY, history);
    return newItem;
  });
}

export function toggleFavorite(id: string): boolean {
  return withLock(() => {
    const history = getHistory();
    const item = history.find(h => h.id === id);
    if (item) {
      item.isFavorite = !item.isFavorite;
      safeSetJSON(HISTORY_KEY, history);
      return item.isFavorite;
    }
    return false;
  });
}

export function getFavorites(): HistoryItem[] {
  return getHistory().filter(h => h.isFavorite);
}

export function deleteHistoryItem(id: string): void {
  withLock(() => {
    const history = getHistory().filter(h => h.id !== id);
    safeSetJSON(HISTORY_KEY, history);
  });
}

export function clearHistory(): void {
  safeSetJSON(HISTORY_KEY, []);
}

export function exportHistory(format: "json" | "txt"): string {
  const history = getHistory();

  if (format === "json") {
    return JSON.stringify(history, null, 2);
  }

  // TXT format with type-safe content handling
  return history.map((item, index) => {
    let content: string;
    if (Array.isArray(item.content)) {
      // Type-safe thread content check
      const isValidThread = item.content.every(
        (t): t is ThreadTweet => typeof t === "object" && t !== null && "content" in t && typeof t.content === "string"
      );
      if (isValidThread && item.content.length > 0) {
        content = item.content.map((t, i) => `  ${i + 1}. ${t.content}`).join("\n");
      } else {
        content = "[Geçersiz thread formatı]";
      }
    } else if (typeof item.content === "string") {
      content = item.content;
    } else {
      content = "[Bilinmeyen içerik formatı]";
    }

    return `
═══════════════════════════════════════
#${index + 1} - ${item.type.toUpperCase()} ${item.isFavorite ? "⭐" : ""}
Tarih: ${new Date(item.createdAt).toLocaleString("tr-TR")}
Konu: ${item.topic}
Persona: ${item.persona}
Skor: ${item.score}/100
───────────────────────────────────────
${content}
═══════════════════════════════════════`;
  }).join("\n\n");
}

export function downloadExport(format: "json" | "txt"): boolean {
  try {
    const content = exportHistory(format);
    const blob = new Blob([content], { type: format === "json" ? "application/json" : "text/plain" });
    const url = URL.createObjectURL(blob);
    const a = document.createElement("a");
    a.href = url;
    a.download = `tweet-history-${new Date().toISOString().split("T")[0]}.${format}`;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    // Delay revoke to ensure download starts
    setTimeout(() => URL.revokeObjectURL(url), 100);
    return true;
  } catch (error) {
    console.error("Download export failed:", error);
    return false;
  }
}

export function markAsPosted(id: string, tweetId: string): void {
  withLock(() => {
    const history = getHistory();
    const item = history.find(h => h.id === id);
    if (item) {
      item.posted = true;
      item.postedAt = new Date().toISOString();
      item.tweetId = tweetId;
      safeSetJSON(HISTORY_KEY, history);
    }
  });
}

export function getPostedItems(): HistoryItem[] {
  return getHistory().filter(h => h.posted);
}

export function getUnpostedItems(): HistoryItem[] {
  return getHistory().filter(h => !h.posted);
}

