// Client-side only functions with safe localStorage access
export function getCustomPersonas(): Persona[] {
  if (typeof window === "undefined") return [];
  try {
    const stored = localStorage.getItem(STORAGE_KEY);
    if (!stored) return [];
    const parsed = JSON.parse(stored);
    // Validate it's an array
    return Array.isArray(parsed) ? parsed : [];
  } catch (error) {
    console.error("Failed to parse custom personas:", error);
    return [];
  }
}

export function saveCustomPersona(persona: Persona): void {
  if (typeof window === "undefined") return;
  try {
    const existing = getCustomPersonas();
    const filtered = existing.filter(p => p.id !== persona.id);
    filtered.unshift(persona);
    localStorage.setItem(STORAGE_KEY, JSON.stringify(filtered));
  } catch (error) {
    console.error("Failed to save custom persona:", error);
  }
}

export function deleteCustomPersona(id: string): void {
  if (typeof window === "undefined") return;
  try {
    const existing = getCustomPersonas();
    const filtered = existing.filter(p => p.id !== id);
    localStorage.setItem(STORAGE_KEY, JSON.stringify(filtered));
  } catch (error) {
    console.error("Failed to delete custom persona:", error);
  }
}

export function getAllPersonas(): Persona[] {
  return [...getCustomPersonas(), ...defaultPersonas];
}

export function getPersonaById(id: string): Persona | undefined {
  return getAllPersonas().find(p => p.id === id);
}

// Legacy export for backward compatibility
export const personas = defaultPersonas;

