    53→/**
    54→ * Sanitizes text for use in prompts to prevent injection attacks
    55→ * Escapes special characters and removes control sequences
    56→ */
    57→export function sanitizeForPrompt(text: string): string {
    58→  if (typeof text !== "string") return "";
    59→
    60→  return text
    61→    // Remove null bytes and control characters
    62→    .replace(/[\x00-\x08\x0B\x0C\x0E-\x1F\x7F]/g, "")
    63→    // Escape potential prompt injection patterns
    64→    .replace(/---+/g, "-")
    65→    .replace(/===+/g, "=")
    66→    .replace(/\n{3,}/g, "\n\n")
    67→    // Remove potential system prompt overrides
    68→    .replace(/system\s*:/gi, "")
    69→    .replace(/assistant\s*:/gi, "")
    70→    .replace(/user\s*:/gi, "")
    71→    .replace(/\[INST\]/gi, "")
    72→    .replace(/<\|[^|]*\|>/g, "")
    73→    // Trim and limit length
    74→    .trim();
    75→}
    76→
    77→/**
