   425→// ============================================================================
   426→// JSON PARSING
   427→// ============================================================================
   428→
   429→/**
   430→ * Safely parses JSON with error handling
   431→ * Uses bounded search to prevent ReDoS attacks
   432→ */
   433→export function safeJSONParse<T = unknown>(
   434→  content: string,
   435→  fallback?: T
   436→): { success: true; data: T } | { success: false; error: string } {
   437→  try {
   438→    // Limit input size to prevent DoS
   439→    const MAX_CONTENT_LENGTH = 500000; // 500KB
   440→    if (content.length > MAX_CONTENT_LENGTH) {
   441→      throw new Error("Content too large to parse");
   442→    }
   443→
   444→    let jsonString = content;
   445→
   446→    // Try to extract JSON from markdown code blocks first (non-greedy, bounded)
   447→    const codeBlockMatch = content.match(/```(?:json)?\s*([\s\S]*?)```/);
   448→    if (codeBlockMatch && codeBlockMatch[1]) {
   449→      jsonString = codeBlockMatch[1].trim();
   450→    } else {
