/**
 * Centralized validation and security utilities
 * Handles input validation, sanitization, rate limiting, and error handling
 */

// ============================================================================
// CONSTANTS
// ============================================================================

export const LIMITS = {
  TOPIC_MAX_LENGTH: 500,
  TWEET_MAX_LENGTH: 1000,
  MANUAL_TWEETS_MAX_COUNT: 100,
  MANUAL_TWEET_MIN_LENGTH: 10,
  USERNAME_MAX_LENGTH: 50,
  BIO_MAX_LENGTH: 500,
  THREAD_LENGTH_OPTIONS: [3, 5, 7, 10] as const,
  THREAD_LENGTH_DEFAULT: 5,
  THREAD_LENGTH_MAX: 10,
} as const;

export const VALID_LENGTHS = ["short", "medium", "long"] as const;
export const VALID_TONES = ["professional", "casual", "humorous", "motivational", "informative"] as const;
export const VALID_QUOTE_STYLES = ["insight", "hot_take", "story", "data", "contrarian"] as const;
export const VALID_REPLY_STYLES = ["agree", "disagree", "question", "add_value", "witty"] as const;

// ============================================================================
// TYPE DEFINITIONS
// ============================================================================

export type TweetLength = typeof VALID_LENGTHS[number];
export type TweetTone = typeof VALID_TONES[number];
export type QuoteStyle = typeof VALID_QUOTE_STYLES[number];
export type ReplyStyle = typeof VALID_REPLY_STYLES[number];
export type ThreadLength = typeof LIMITS.THREAD_LENGTH_OPTIONS[number];

export interface ValidationResult {
  valid: boolean;
  error?: string;
  sanitized?: unknown;
}

export interface APIError {
  code: string;
  message: string;
  details?: Record<string, unknown>;
}

// ============================================================================
// SANITIZATION FUNCTIONS
// ============================================================================

/**
 * Sanitizes text for use in prompts to prevent injection attacks
 * Escapes special characters and removes control sequences
 */
export function sanitizeForPrompt(text: string): string {
  if (typeof text !== "string") return "";

  return text
    // Remove null bytes and control characters
    .replace(/[\x00-\x08\x0B\x0C\x0E-\x1F\x7F]/g, "")
    // Escape potential prompt injection patterns
    .replace(/---+/g, "-")
    .replace(/===+/g, "=")
    .replace(/\n{3,}/g, "\n\n")
    // Remove potential system prompt overrides
    .replace(/system\s*:/gi, "")
    .replace(/assistant\s*:/gi, "")
    .replace(/user\s*:/gi, "")
    .replace(/\[INST\]/gi, "")
    .replace(/<\|[^|]*\|>/g, "")
    // Trim and limit length
    .trim();
}

/**
 * Sanitizes username (removes @ and special characters)
 */
export function sanitizeUsername(username: string): string {
  if (typeof username !== "string") return "";

  return username
    .replace(/^@/, "")
    .replace(/[^\w_]/g, "")
    .slice(0, LIMITS.USERNAME_MAX_LENGTH)
    .toLowerCase();
}

/**
 * Escapes text for safe inclusion in JSON strings
 */
export function escapeForJSON(text: string): string {
  if (typeof text !== "string") return "";

  return text
    .replace(/\\/g, "\\\\")
    .replace(/"/g, '\\"')
    .replace(/\n/g, "\\n")
    .replace(/\r/g, "\\r")
    .replace(/\t/g, "\\t");
}

// ============================================================================
// VALIDATION FUNCTIONS
// ============================================================================

/**
 * Validates and sanitizes topic input
 */
export function validateTopic(topic: unknown): ValidationResult {
  if (typeof topic !== "string") {
    return { valid: false, error: "Topic must be a string" };
  }

  const trimmed = topic.trim();

  if (!trimmed) {
    return { valid: false, error: "Topic is required" };
  }

  if (trimmed.length > LIMITS.TOPIC_MAX_LENGTH) {
    return { valid: false, error: `Topic must be less than ${LIMITS.TOPIC_MAX_LENGTH} characters` };
  }

  return {
    valid: true,
    sanitized: sanitizeForPrompt(trimmed)
  };
}

/**
 * Validates tweet length parameter
 */
export function validateLength(length: unknown): ValidationResult {
  if (length === undefined || length === null) {
    return { valid: true, sanitized: "medium" };
  }

  if (typeof length !== "string") {
    return { valid: false, error: "Length must be a string" };
  }

  if (!VALID_LENGTHS.includes(length as TweetLength)) {
    return { valid: false, error: `Invalid length. Must be one of: ${VALID_LENGTHS.join(", ")}` };
  }

  return { valid: true, sanitized: length };
}

/**
 * Validates tone parameter
 * @param tone - The tone value to validate
 * @param allowCustom - If true, allows custom tone values (sanitized). If false, only predefined tones.
 */
export function validateTone(tone: unknown, allowCustom: boolean = true): ValidationResult {
  if (tone === undefined || tone === null) {
    return { valid: true, sanitized: "professional" };
  }

  if (typeof tone !== "string") {
    return { valid: false, error: "Tone must be a string" };
  }

  const trimmed = tone.trim().toLowerCase();

  // Check if it's a predefined tone
  if (VALID_TONES.includes(trimmed as TweetTone)) {
    return { valid: true, sanitized: trimmed };
  }

  // Only allow custom tones if explicitly permitted
  if (allowCustom) {
    // Sanitize custom tone for prompt safety
    return { valid: true, sanitized: sanitizeForPrompt(tone).slice(0, 50) };
  }

  return {
    valid: false,
    error: `Invalid tone. Must be one of: ${VALID_TONES.join(", ")}`
  };
}

/**
 * Validates thread length parameter with strict bounds
 */
export function validateThreadLength(threadLength: unknown): ValidationResult {
  if (threadLength === undefined || threadLength === null) {
    return { valid: true, sanitized: LIMITS.THREAD_LENGTH_DEFAULT };
  }

  const num = Number(threadLength);

  if (isNaN(num) || !Number.isInteger(num)) {
    return { valid: false, error: "Thread length must be an integer" };
  }

  if (num < 3 || num > LIMITS.THREAD_LENGTH_MAX) {
    return {
      valid: false,
      error: `Thread length must be between 3 and ${LIMITS.THREAD_LENGTH_MAX}`
    };
  }

  // Snap to valid options
  const validOptions = LIMITS.THREAD_LENGTH_OPTIONS;
  const closest = validOptions.reduce((prev, curr) =>
    Math.abs(curr - num) < Math.abs(prev - num) ? curr : prev
  );

  return { valid: true, sanitized: closest };
}

/**
 * Validates original tweet input
 */
export function validateOriginalTweet(tweet: unknown): ValidationResult {
  if (typeof tweet !== "string") {
    return { valid: false, error: "Original tweet must be a string" };
  }

  const trimmed = tweet.trim();

  if (!trimmed) {
    return { valid: false, error: "Original tweet is required" };
  }

  if (trimmed.length > LIMITS.TWEET_MAX_LENGTH) {
    return { valid: false, error: `Tweet must be less than ${LIMITS.TWEET_MAX_LENGTH} characters` };
  }

  return {
    valid: true,
    sanitized: sanitizeForPrompt(trimmed)
  };
}

/**
 * Validates quote style parameter
 */
export function validateQuoteStyle(style: unknown): ValidationResult {
  if (style === undefined || style === null) {
    return { valid: true, sanitized: "insight" };
  }

  if (typeof style !== "string") {
    return { valid: false, error: "Quote style must be a string" };
  }

  if (!VALID_QUOTE_STYLES.includes(style as QuoteStyle)) {
    return { valid: false, error: `Invalid quote style. Must be one of: ${VALID_QUOTE_STYLES.join(", ")}` };
  }

  return { valid: true, sanitized: style };
}

/**
 * Validates reply style parameter
 */
export function validateReplyStyle(style: unknown): ValidationResult {
  if (style === undefined || style === null) {
    return { valid: true, sanitized: "add_value" };
  }

  if (typeof style !== "string") {
    return { valid: false, error: "Reply style must be a string" };
  }

  if (!VALID_REPLY_STYLES.includes(style as ReplyStyle)) {
    return { valid: false, error: `Invalid reply style. Must be one of: ${VALID_REPLY_STYLES.join(", ")}` };
  }

  return { valid: true, sanitized: style };
}

/**
 * Validates username parameter
 */
export function validateUsername(username: unknown): ValidationResult {
  if (typeof username !== "string") {
    return { valid: false, error: "Username must be a string" };
  }

  const sanitized = sanitizeUsername(username);

  if (!sanitized) {
    return { valid: false, error: "Username is required" };
  }

  if (sanitized.length < 1 || sanitized.length > 15) {
    return { valid: false, error: "Invalid username format" };
  }

  return { valid: true, sanitized };
}

/**
 * Validates manual tweets input
 */
export function validateManualTweets(tweets: unknown): ValidationResult {
  if (typeof tweets !== "string") {
    return { valid: false, error: "Manual tweets must be a string" };
  }

  const lines = tweets
    .split("\n")
    .map(t => t.trim())
    .filter(t => t.length >= LIMITS.MANUAL_TWEET_MIN_LENGTH);

  if (lines.length < 3) {
    return { valid: false, error: "At least 3 tweets required (minimum 10 characters each)" };
  }

  if (lines.length > LIMITS.MANUAL_TWEETS_MAX_COUNT) {
    return { valid: false, error: `Maximum ${LIMITS.MANUAL_TWEETS_MAX_COUNT} tweets allowed` };
  }

  const sanitized = lines.map(t => sanitizeForPrompt(t).slice(0, LIMITS.TWEET_MAX_LENGTH));

  return { valid: true, sanitized };
}

/**
 * Validates persona object structure
 */
export function validatePersona(persona: unknown): ValidationResult {
  if (!persona || typeof persona !== "object") {
    return { valid: false, error: "Invalid persona object" };
  }

  const p = persona as Record<string, unknown>;

  if (typeof p.name !== "string" || !p.name.trim()) {
    return { valid: false, error: "Persona name is required" };
  }

  if (typeof p.description !== "string") {
    return { valid: false, error: "Persona description is required" };
  }

  if (typeof p.style !== "string") {
    return { valid: false, error: "Persona style is required" };
  }

  if (typeof p.tone !== "string") {
    return { valid: false, error: "Persona tone is required" };
  }

  if (!Array.isArray(p.example_tweets)) {
    return { valid: false, error: "Persona example_tweets must be an array" };
  }

  // Sanitize all string fields
  const sanitized = {
    ...p,
    id: typeof p.id === "string" ? p.id : `custom_${Date.now()}`,
    name: sanitizeForPrompt(String(p.name)).slice(0, 100),
    description: sanitizeForPrompt(String(p.description)).slice(0, 500),
    style: sanitizeForPrompt(String(p.style)).slice(0, 1000),
    tone: sanitizeForPrompt(String(p.tone)).slice(0, 50),
    example_tweets: (p.example_tweets as unknown[])
      .filter(t => typeof t === "string")
      .map(t => sanitizeForPrompt(String(t)).slice(0, 500))
      .slice(0, 10),
  };

  return { valid: true, sanitized };
}

// ============================================================================
// ERROR HANDLING
// ============================================================================

/**
 * Creates a standardized API error object
 */
export function createAPIError(
  code: string,
  message: string,
  details?: Record<string, unknown>
): APIError {
  return { code, message, details };
}

/**
 * Safely extracts error message from unknown error
 */
export function getErrorMessage(error: unknown): string {
  if (error instanceof Error) {
    return error.message;
  }
  if (typeof error === "string") {
    return error;
  }
  return "An unexpected error occurred";
}

/**
 * Determines appropriate HTTP status code for error
 */
export function getErrorStatusCode(error: unknown): number {
  if (error instanceof Error) {
    const message = error.message.toLowerCase();

    if (message.includes("validation") || message.includes("invalid") || message.includes("required")) {
      return 400;
    }
    if (message.includes("unauthorized") || message.includes("api key")) {
      return 401;
    }
    if (message.includes("forbidden") || message.includes("access denied")) {
      return 403;
    }
    if (message.includes("not found")) {
      return 404;
    }
    if (message.includes("rate limit") || message.includes("too many")) {
      return 429;
    }
  }

  return 500;
}

// ============================================================================
// JSON PARSING
// ============================================================================

/**
 * Safely parses JSON with error handling
 * Uses bounded search to prevent ReDoS attacks
 */
export function safeJSONParse<T = unknown>(
  content: string,
  fallback?: T
): { success: true; data: T } | { success: false; error: string } {
  try {
    // Limit input size to prevent DoS
    const MAX_CONTENT_LENGTH = 500000; // 500KB
    if (content.length > MAX_CONTENT_LENGTH) {
      throw new Error("Content too large to parse");
    }

    let jsonString = content;

    // Try to extract JSON from markdown code blocks first (non-greedy, bounded)
    const codeBlockMatch = content.match(/```(?:json)?\s*([\s\S]*?)```/);
    if (codeBlockMatch && codeBlockMatch[1]) {
      jsonString = codeBlockMatch[1].trim();
    } else {
      // Use indexOf/lastIndexOf for bounded JSON object extraction (safer than regex)
      const jsonStart = content.indexOf("{");
      const jsonEnd = content.lastIndexOf("}");

      if (jsonStart !== -1 && jsonEnd > jsonStart) {
        jsonString = content.slice(jsonStart, jsonEnd + 1);
      }
      // If no braces found, try the content as-is
    }

    const data = JSON.parse(jsonString) as T;

    return { success: true, data };
  } catch (e) {
    if (fallback !== undefined) {
      return { success: true, data: fallback };
    }
    return {
      success: false,
      error: `Failed to parse JSON: ${getErrorMessage(e)}`
    };
  }
}

// ============================================================================
// RATE LIMITING (Simple in-memory implementation with memory protection)
// ============================================================================

interface RateLimitEntry {
  count: number;
  resetAt: number;
}

const rateLimitStore = new Map<string, RateLimitEntry>();

// Memory protection: Maximum number of entries to prevent unbounded growth
const MAX_RATE_LIMIT_ENTRIES = 10000;

export interface RateLimitConfig {
  windowMs: number;  // Time window in milliseconds
  maxRequests: number;  // Max requests per window
}

const DEFAULT_RATE_LIMIT: RateLimitConfig = {
  windowMs: 60 * 1000,  // 1 minute
  maxRequests: 20,  // 20 requests per minute
};

/**
 * Prune oldest entries when store reaches capacity
 */
function pruneRateLimitStore(): void {
  if (rateLimitStore.size < MAX_RATE_LIMIT_ENTRIES) return;

  // Remove 20% of oldest entries to create headroom
  const entriesToRemove = Math.floor(MAX_RATE_LIMIT_ENTRIES * 0.2);
  const entries = Array.from(rateLimitStore.entries())
    .sort((a, b) => a[1].resetAt - b[1].resetAt)
    .slice(0, entriesToRemove);

  for (const [key] of entries) {
    rateLimitStore.delete(key);
  }
}

/**
 * Checks if request should be rate limited
 * Returns true if request is allowed, false if rate limited
 */
export function checkRateLimit(
  identifier: string,
  config: RateLimitConfig = DEFAULT_RATE_LIMIT
): { allowed: boolean; remaining: number; resetIn: number } {
  const now = Date.now();
  const key = identifier;

  let entry = rateLimitStore.get(key);

  // Clean expired entry
  if (entry && entry.resetAt <= now) {
    rateLimitStore.delete(key);
    entry = undefined;
  }

  if (!entry) {
    // Prune store if at capacity before adding new entry
    pruneRateLimitStore();

    // First request in window
    rateLimitStore.set(key, {
      count: 1,
      resetAt: now + config.windowMs,
    });
    return {
      allowed: true,
      remaining: config.maxRequests - 1,
      resetIn: config.windowMs
    };
  }

  if (entry.count >= config.maxRequests) {
    // Rate limited
    return {
      allowed: false,
      remaining: 0,
      resetIn: entry.resetAt - now
    };
  }

  // Increment and allow
  entry.count++;
  return {
    allowed: true,
    remaining: config.maxRequests - entry.count,
    resetIn: entry.resetAt - now
  };
}

/**
 * Gets client identifier from request
 */
export function getClientIdentifier(request: Request): string {
  // Try to get IP from various headers
  const forwarded = request.headers.get("x-forwarded-for");
  const realIP = request.headers.get("x-real-ip");
  const cfIP = request.headers.get("cf-connecting-ip");

  const ip = cfIP || realIP || (forwarded ? forwarded.split(",")[0].trim() : null);

  // Fallback to a hash of user-agent if no IP
  if (!ip) {
    const ua = request.headers.get("user-agent") || "unknown";
    return `ua_${simpleHash(ua)}`;
  }

  return `ip_${ip}`;
}

/**
 * Improved hash function using djb2 algorithm with better distribution
 * Falls back to this when crypto is not available
 */
function improvedHash(str: string): string {
  let hash = 5381;
  for (let i = 0; i < str.length; i++) {
    // Use XOR for better bit distribution
    hash = ((hash << 5) + hash) ^ str.charCodeAt(i);
    // Keep within 32-bit integer range
    hash = hash >>> 0;
  }
  return hash.toString(36);
}

/**
 * Generate a secure hash using Web Crypto API when available
 * Falls back to improved djb2 hash
 */
async function _generateSecureHash(str: string): Promise<string> {
  // Try Web Crypto API first (available in modern browsers and Node 18+)
  if (typeof crypto !== "undefined" && crypto.subtle) {
    try {
      const encoder = new TextEncoder();
      const data = encoder.encode(str);
      const hashBuffer = await crypto.subtle.digest("SHA-256", data);
      const hashArray = Array.from(new Uint8Array(hashBuffer));
      return hashArray.map(b => b.toString(16).padStart(2, "0")).join("").slice(0, 16);
    } catch {
      // Fall through to improved hash
    }
  }
  return improvedHash(str);
}

/**
 * Synchronous hash for immediate use (fallback)
 */
function simpleHash(str: string): string {
  return improvedHash(str);
}

// Clean up old rate limit entries periodically
if (typeof setInterval !== "undefined") {
  setInterval(() => {
    const now = Date.now();
    for (const [key, entry] of rateLimitStore.entries()) {
      if (entry.resetAt <= now) {
        rateLimitStore.delete(key);
      }
    }
  }, 60 * 1000); // Clean every minute
}

