import { SavedPersona, StyleAnalysis, HistoryItem } from "@/types";
import { safeGetJSON, safeSetJSON } from "./storage";
import { getHistory } from "./history";

const SAVED_PERSONAS_KEY = "saved_personas";
const MAX_PERSONAS = 50;

/**
 * Tüm kaydedilmiş personaları getir
 */
export function getSavedPersonas(): SavedPersona[] {
  if (typeof window === "undefined") return [];
  return safeGetJSON<SavedPersona[]>(SAVED_PERSONAS_KEY, []);
}

/**
 * Persona ID'sine göre getir
 */
export function getSavedPersonaById(id: string): SavedPersona | undefined {
  return getSavedPersonas().find(p => p.id === id);
}

/**
 * Username'e göre persona getir
 */
export function getSavedPersonaByUsername(username: string): SavedPersona | undefined {
  const normalizedUsername = username.toLowerCase().replace("@", "");
  return getSavedPersonas().find(
    p => p.sourceUsername.toLowerCase() === normalizedUsername
  );
}

/**
 * Yeni persona kaydet
 */
export function saveSavedPersona(data: {
  username: string;
  displayName: string;
  bio: string;
  originalTweets: string[];
  styleAnalysis: StyleAnalysis;
  persona: Omit<SavedPersona, "id" | "isCustom" | "sourceUsername" | "analyzedAt" | "displayName" | "bio" | "originalTweets" | "styleAnalysis" | "createdAt" | "updatedAt" | "tweetCount">;
}): SavedPersona {
  const personas = getSavedPersonas();
  const normalizedUsername = data.username.toLowerCase().replace("@", "");

  // Aynı username varsa güncelle
  const existingIndex = personas.findIndex(
    p => p.sourceUsername.toLowerCase() === normalizedUsername
  );

  const now = new Date().toISOString();
  const id = existingIndex >= 0
    ? personas[existingIndex].id
    : `persona_${normalizedUsername}_${Date.now()}`;

  const savedPersona: SavedPersona = {
    ...data.persona,
    id,
    isCustom: true,
    sourceUsername: normalizedUsername,
    displayName: data.displayName,
    bio: data.bio,
    originalTweets: data.originalTweets,
    styleAnalysis: data.styleAnalysis,
    analyzedAt: now,
    createdAt: existingIndex >= 0 ? personas[existingIndex].createdAt : now,
    updatedAt: now,
    tweetCount: existingIndex >= 0 ? personas[existingIndex].tweetCount : 0,
  };

  if (existingIndex >= 0) {
    personas[existingIndex] = savedPersona;
  } else {
    personas.unshift(savedPersona);
    // Max limit
    if (personas.length > MAX_PERSONAS) {
      personas.pop();
    }
  }

  safeSetJSON(SAVED_PERSONAS_KEY, personas);
  return savedPersona;
}

/**
 * Persona sil
 */
export function deleteSavedPersona(id: string): boolean {
  const personas = getSavedPersonas();
  const filtered = personas.filter(p => p.id !== id);

  if (filtered.length === personas.length) {
    return false; // Bulunamadı
  }

  safeSetJSON(SAVED_PERSONAS_KEY, filtered);
  return true;
}

/**
 * Persona'nın tweet sayısını artır
 */
export function incrementPersonaTweetCount(personaId: string): void {
  const personas = getSavedPersonas();
  const persona = personas.find(p => p.id === personaId);

  if (persona) {
    persona.tweetCount += 1;
    persona.updatedAt = new Date().toISOString();
    safeSetJSON(SAVED_PERSONAS_KEY, personas);
  }
}

/**
 * Bir persona ile üretilen tüm tweet'leri getir
 */
export function getTweetsByPersonaId(personaId: string): HistoryItem[] {
  const history = getHistory();
  return history.filter(item => item.personaId === personaId);
}

/**
 * Persona adına göre tweet'leri getir (eski kayıtlar için)
 */
export function getTweetsByPersonaName(personaName: string): HistoryItem[] {
  const history = getHistory();
  return history.filter(item =>
    item.persona.toLowerCase() === personaName.toLowerCase()
  );
}

/**
 * Persona istatistiklerini getir
 */
export function getPersonaStats(personaId: string): {
  totalTweets: number;
  averageScore: number;
  favoriteCount: number;
  postedCount: number;
  lastUsed: string | null;
} {
  const tweets = getTweetsByPersonaId(personaId);

  if (tweets.length === 0) {
    return {
      totalTweets: 0,
      averageScore: 0,
      favoriteCount: 0,
      postedCount: 0,
      lastUsed: null,
    };
  }

  const totalScore = tweets.reduce((sum, t) => sum + t.score, 0);
  const favoriteCount = tweets.filter(t => t.isFavorite).length;
  const postedCount = tweets.filter(t => t.posted).length;
  const sortedByDate = [...tweets].sort(
    (a, b) => new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime()
  );

  return {
    totalTweets: tweets.length,
    averageScore: Math.round(totalScore / tweets.length),
    favoriteCount,
    postedCount,
    lastUsed: sortedByDate[0]?.createdAt || null,
  };
}

/**
 * Tüm kaydedilmiş personaları temizle
 */
export function clearAllSavedPersonas(): void {
  safeSetJSON(SAVED_PERSONAS_KEY, []);
}

/**
 * Personaları JSON olarak export et
 */
export function exportPersonas(): string {
  const personas = getSavedPersonas();
  return JSON.stringify(personas, null, 2);
}

/**
 * Personaları JSON'dan import et
 */
export function importPersonas(jsonString: string): { success: boolean; count: number; error?: string } {
  try {
    const imported = JSON.parse(jsonString);

    if (!Array.isArray(imported)) {
      return { success: false, count: 0, error: "Geçersiz format: Array bekleniyor" };
    }

    const personas = getSavedPersonas();
    let importCount = 0;

    for (const item of imported) {
      if (item.id && item.sourceUsername && item.name) {
        // Aynı username varsa atla
        const exists = personas.some(
          p => p.sourceUsername.toLowerCase() === item.sourceUsername.toLowerCase()
        );

        if (!exists) {
          personas.push({
            ...item,
            createdAt: item.createdAt || new Date().toISOString(),
            updatedAt: new Date().toISOString(),
          });
          importCount++;
        }
      }
    }

    if (importCount > 0) {
      safeSetJSON(SAVED_PERSONAS_KEY, personas);
    }

    return { success: true, count: importCount };
  } catch {
    return { success: false, count: 0, error: "JSON parse hatası" };
  }
}

