     1→/**
     2→ * X Algorithm-Inspired Tweet Scoring System
     3→ * Based on: https://github.com/xai-org/x-algorithm
     4→ *
     5→ * This implements a simplified version of X's Phoenix engagement prediction
     6→ * and weighted scoring mechanism for tweet quality assessment.
     7→ */
     8→
     9→// ============================================================================
    10→// ENGAGEMENT ACTION TYPES (Inspired by Phoenix's 19 action predictions)
    11→// ============================================================================
    12→
    13→export interface EngagementPredictions {
    14→  // Core engagement (12 original)
    15→  favorite_score: number;        // Likelihood of like
    16→  reply_score: number;           // Likelihood of reply
    17→  repost_score: number;          // Likelihood of retweet
    18→  click_score: number;           // Likelihood of click to expand
    19→  profile_click_score: number;   // Likelihood of profile visit
    20→  share_score: number;           // Likelihood of share
    21→  dwell_score: number;           // Time spent on tweet
    22→  quote_score: number;           // Likelihood of quote tweet
    23→  follow_author_score: number;   // Likelihood of follow
    24→  bookmark_score: number;        // Likelihood of bookmark
    25→
    26→  // NEW: Extended engagement types from X Algorithm (7 new)
    27→  photo_expand_score: number;    // Likelihood of expanding photo
    28→  share_via_dm_score: number;    // Likelihood of DM sharing
    29→  share_via_copy_link_score: number; // Likelihood of link copy
    30→  cont_dwell_time_score: number; // Continuous reading time
    31→  quoted_click_score: number;    // Click on quoted tweet
    32→
    33→  // Negative signals (enhanced)
    34→  not_interested_score: number;
    35→  skip_score: number;
    36→  block_author_score: number;    // NEW: Risk of block
    37→  mute_author_score: number;     // NEW: Risk of mute
    38→  report_score: number;          // NEW: Risk of report
    39→}
    40→
    41→// ============================================================================
    42→// WEIGHTED SCORING WEIGHTS (Approximated from X Algorithm patterns)
    43→// ============================================================================
    44→
    45→const ENGAGEMENT_WEIGHTS = {
    46→  // Positive weights - Updated based on X Algorithm weighted_scorer.rs patterns
    47→  favorite: 0.5,           // Likes are common, lower weight
    48→  reply: 1.0,              // Replies are X's most valued engagement
    49→  repost: 1.1,             // Retweets very valuable
    50→  quote: 0.8,              // Quote tweets valuable
    51→  share: 0.6,
    52→  bookmark: 0.4,           // Bookmarks indicate save-worthy content
    53→  follow_author: 1.5,      // Follows are extremely valuable
    54→
    55→  // Medium impact
    56→  click: 0.3,
    57→  profile_click: 0.25,
    58→  dwell: 0.2,
    59→
    60→  // NEW: Extended engagement weights
    61→  photo_expand: 0.3,       // Photo expansion
    62→  share_via_dm: 0.4,       // DM share - high intent signal
    63→  share_via_copy_link: 0.35, // Link copy - intent to share externally
    64→  cont_dwell_time: 0.3,    // Continuous reading
    65→  quoted_click: 0.2,       // Click on quoted content
    66→
    67→  // Negative weights - Enhanced
    68→  not_interested: -1.5,
    69→  skip: -0.5,
    70→  block_author: -4.0,      // Block is severe negative signal
    71→  mute_author: -3.0,       // Mute is strong negative signal
    72→  report: -5.0,            // Report is most severe
    73→};
    74→
    75→// ============================================================================
    76→// CONTENT ANALYSIS FACTORS
    77→// ============================================================================
    78→
    79→interface ContentFeatures {
    80→  // Hook analysis
    81→  hasStrongHook: boolean;
    82→  hookType: 'question' | 'statement' | 'story' | 'data' | 'contrarian' | 'none';
    83→
    84→  // Content structure
    85→  hasLineBreaks: boolean;
    86→  sentenceCount: number;
    87→  avgSentenceLength: number;
    88→
    89→  // Engagement triggers
    90→  hasQuestion: boolean;
    91→  hasCallToAction: boolean;
    92→  hasNumbers: boolean;
    93→  hasEmoji: boolean;
    94→  hasHashtag: boolean;
    95→  hasMention: boolean;
    96→
    97→  // Content type signals
    98→  isThread: boolean;
    99→  hasMedia: boolean;
   100→  isReply: boolean;
   101→  isQuote: boolean;
   102→
   103→  // Length optimization
   104→  charCount: number;
   105→  isOptimalLength: boolean;
   106→
   107→  // Emotional triggers
   108→  emotionalIntensity: number;
   109→  curiosityGap: boolean;
   110→}
   111→
   112→// ============================================================================
   113→// HOOK PATTERNS (What makes first 3 seconds compelling)
   114→// ============================================================================
   115→
   116→const STRONG_HOOK_PATTERNS = [
   117→  // Question hooks
   118→  /^(neden|nasıl|ne zaman|kim|hangisi|kaç|what|how|why|when|who|which)/i,
   119→  /^[^.!?]*\?/,
   120→
   121→  // Data/Number hooks
   122→  /^(\d+%|\d+x|\$\d+|\d+ (yıl|gün|saat|dakika))/i,
   123→  /^\d+\./,
   124→
   125→  // Contrarian hooks
   126→  /^(herkes yanılıyor|kimse bilmiyor|unpopular opinion|hot take)/i,
   127→
   128→  // Story hooks
   129→  /^(dün|geçen hafta|bu sabah|yesterday|last week|today)/i,
   130→  /^(bir arkadaşım|biri bana|someone told me)/i,
   131→
   132→  // Curiosity gap hooks
   133→  /^(bunu kimse bilmiyor|sır:|secret:|the truth about)/i,
   134→  /(işte nedeni|here's why|here's how)$/i,
   135→];
   136→
   137→const CALL_TO_ACTION_PATTERNS = [
   138→  /(düşüncelerinizi yazın|ne düşünüyorsunuz|yorumlarınızı bekliyorum)/i,
   139→  /(retweet|rt|paylaş|share|save this|bookmark)/i,
   140→  /(takip et|follow|join)/i,
   141→  /(link bio|link in|biyografide)/i,
   142→  /(\?$)/,
   143→];
   144→
   145→// ============================================================================
   146→// MAIN SCORING FUNCTIONS
   147→// ============================================================================
   148→
   149→/**
   150→ * Analyze content features for scoring
   151→ */
   152→export function analyzeContentFeatures(content: string, context?: {
   153→  isThread?: boolean;
   154→  isReply?: boolean;
   155→  isQuote?: boolean;
   156→  hasMedia?: boolean;
   157→}): ContentFeatures {
   158→  const lines = content.split('\n').filter(l => l.trim());
   159→  const sentences = content.split(/[.!?]+/).filter(s => s.trim());
   160→
   161→  // Hook detection
   162→  let hookType: ContentFeatures['hookType'] = 'none';
   163→  let hasStrongHook = false;
   164→
   165→  for (const pattern of STRONG_HOOK_PATTERNS) {
   166→    if (pattern.test(content)) {
   167→      hasStrongHook = true;
   168→
   169→      if (/\?/.test(content.split(/[.!]/)[0])) hookType = 'question';
   170→      else if (/^\d/.test(content)) hookType = 'data';
   171→      else if (/^(herkes|kimse|unpopular|hot take)/i.test(content)) hookType = 'contrarian';
   172→      else if (/^(dün|geçen|bu sabah|yesterday|last)/i.test(content)) hookType = 'story';
   173→      else hookType = 'statement';
   174→      break;
   175→    }
   176→  }
   177→
   178→  // CTA detection
   179→  const hasCallToAction = CALL_TO_ACTION_PATTERNS.some(p => p.test(content));
   180→
   181→  // Emotional intensity (simplified)
   182→  const emotionalWords = content.match(/(harika|müthiş|korkunç|inanılmaz|amazing|incredible|terrible|shocking|!{2,})/gi) || [];
   183→  const emotionalIntensity = Math.min(emotionalWords.length / 3, 1);
   184→
   185→  // Curiosity gap
   186→  const curiosityGap = /(işte nedeni|here's why|sır:|secret:|bunu kimse|kimse bilmiyor)/i.test(content);
   187→
   188→  return {
   189→    hasStrongHook,
   190→    hookType,
   191→    hasLineBreaks: lines.length > 1,
   192→    sentenceCount: sentences.length,
   193→    avgSentenceLength: content.length / Math.max(sentences.length, 1),
   194→    hasQuestion: /\?/.test(content),
   195→    hasCallToAction,
   196→    hasNumbers: /\d/.test(content),
   197→    hasEmoji: /\p{Emoji}/u.test(content),
   198→    hasHashtag: /#\w+/.test(content),
   199→    hasMention: /@\w+/.test(content),
   200→    isThread: context?.isThread || false,
   201→    hasMedia: context?.hasMedia || false,
   202→    isReply: context?.isReply || false,
   203→    isQuote: context?.isQuote || false,
   204→    charCount: content.length,
   205→    isOptimalLength: content.length >= 100 && content.length <= 280,
   206→    emotionalIntensity,
   207→    curiosityGap,
   208→  };
   209→}
   210→
   211→/**
   212→ * Predict engagement probabilities based on content features
   213→ * Inspired by Phoenix's multi-action prediction model
   214→ * Enhanced with all 19 X Algorithm engagement types
   215→ */
   216→export function predictEngagement(features: ContentFeatures, content: string = ""): EngagementPredictions {
   217→  const base = 0.5;
   218→
   219→  // ---- FAVORITE SCORE ----
   220→  let favorite = base;
   221→  if (features.hasStrongHook) favorite += 0.15;
   222→  if (features.hasEmoji) favorite += 0.05;
   223→  if (features.isOptimalLength) favorite += 0.1;
   224→  if (features.emotionalIntensity > 0.5) favorite += 0.1;
   225→
   226→  // ---- REPLY SCORE ----
   227→  let reply = base * 0.8;
   228→  if (features.hasQuestion) reply += 0.25;
   229→  if (features.hasCallToAction) reply += 0.15;
   230→  if (features.hookType === 'contrarian') reply += 0.2;
   231→  if (features.curiosityGap) reply += 0.1;
   232→
   233→  // ---- REPOST SCORE ----
   234→  let repost = base * 0.6;
   235→  if (features.hookType === 'data') repost += 0.2;
   236→  if (features.hasNumbers) repost += 0.1;
   237→  if (features.hasStrongHook) repost += 0.15;
   238→  if (features.isOptimalLength) repost += 0.1;
   239→
   240→  // ---- CLICK SCORE ----
   241→  let click = base * 0.7;
   242→  if (features.curiosityGap) click += 0.25;
   243→  if (features.hasStrongHook) click += 0.1;
   244→  if (features.hasLineBreaks && features.charCount > 200) click += 0.1;
   245→
   246→  // ---- PROFILE CLICK SCORE ----
   247→  let profile_click = base * 0.4;
   248→  if (features.hookType === 'story') profile_click += 0.15;
   249→  if (features.emotionalIntensity > 0.7) profile_click += 0.1;
   250→
   251→  // ---- SHARE SCORE ----
   252→  let share = base * 0.5;
   253→  if (features.hookType === 'data') share += 0.2;
   254→  if (features.hasNumbers) share += 0.1;
   255→  if (features.hasStrongHook) share += 0.1;
   256→
   257→  // ---- DWELL SCORE ----
   258→  let dwell = base * 0.6;
   259→  if (features.hasLineBreaks) dwell += 0.15;
   260→  if (features.sentenceCount > 2) dwell += 0.1;
   261→  if (features.charCount > 150) dwell += 0.1;
   262→
   263→  // ---- QUOTE SCORE ----
   264→  let quote = base * 0.4;
   265→  if (features.hookType === 'contrarian') quote += 0.25;
   266→  if (features.hasQuestion) quote += 0.1;
   267→  if (features.emotionalIntensity > 0.5) quote += 0.1;
   268→
   269→  // ---- FOLLOW AUTHOR SCORE ----
   270→  let follow_author = base * 0.3;
   271→  if (features.hookType === 'data') follow_author += 0.15;
   272→  if (features.hookType === 'story') follow_author += 0.1;
   273→  if (features.hasStrongHook) follow_author += 0.1;
   274→
   275→  // ---- BOOKMARK SCORE ----
   276→  let bookmark = base * 0.4;
   277→  if (features.hookType === 'data') bookmark += 0.2;
   278→  if (features.hasNumbers) bookmark += 0.15;
   279→  if (features.charCount > 200) bookmark += 0.1;
   280→
   281→  // ---- NEW: PHOTO EXPAND SCORE ----
   282→  let photo_expand = base * 0.5;
   283→  if (features.hasMedia) photo_expand += 0.3;
   284→  if (features.hasStrongHook) photo_expand += 0.1;
   285→
   286→  // ---- NEW: SHARE VIA DM SCORE ----
   287→  let share_via_dm = base * 0.3;
   288→  if (features.hookType === 'data') share_via_dm += 0.15;
   289→  if (features.emotionalIntensity > 0.6) share_via_dm += 0.15;
   290→  if (features.hookType === 'story') share_via_dm += 0.1;
   291→
   292→  // ---- NEW: SHARE VIA COPY LINK SCORE ----
   293→  let share_via_copy_link = base * 0.3;
   294→  if (features.hookType === 'data') share_via_copy_link += 0.2;
   295→  if (features.hasNumbers) share_via_copy_link += 0.1;
   296→  if (features.hasStrongHook) share_via_copy_link += 0.1;
   297→
   298→  // ---- NEW: CONTINUOUS DWELL TIME SCORE ----
   299→  let cont_dwell_time = base * 0.4;
   300→  if (features.hasLineBreaks) cont_dwell_time += 0.2;
   301→  if (features.sentenceCount > 3) cont_dwell_time += 0.15;
   302→  if (features.charCount > 200) cont_dwell_time += 0.1;
   303→  if (features.curiosityGap) cont_dwell_time += 0.1;
   304→
   305→  // ---- NEW: QUOTED CLICK SCORE ----
   306→  let quoted_click = base * 0.3;
   307→  if (features.isQuote) quoted_click += 0.2;
   308→  if (features.hasCallToAction) quoted_click += 0.1;
   309→
   310→  // ---- NEGATIVE SIGNALS (Enhanced) ----
   311→  let not_interested = 0.1;
   312→  let skip = 0.15;
   313→  let block_author = 0.02;  // Very low base
   314→  let mute_author = 0.03;   // Low base
   315→  let report = 0.01;        // Very low base
   316→
   317→  // Increase negative signals based on content issues
   318→  if (!features.hasStrongHook) {
   319→    not_interested += 0.08;
   320→    skip += 0.12;
   321→  }
   322→  if (features.charCount < 50) {
   323→    skip += 0.08;
   324→    not_interested += 0.05;
   325→  }
   326→  if (features.avgSentenceLength > 100) {
   327→    not_interested += 0.08;
   328→    skip += 0.08;
   329→  }
   330→
   331→  // Spam-like content increases block/mute/report risk
   332→  const hashtagCount = (content.match(/#\w+/g) || []).length;
   333→  const mentionCount = (content.match(/@\w+/g) || []).length;
   334→
   335→  if (hashtagCount > 3) {
   336→    not_interested += 0.1;
   337→    mute_author += 0.05;
   338→    block_author += 0.03;
   339→  }
   340→  if (mentionCount > 3) {
   341→    not_interested += 0.08;
   342→    mute_author += 0.04;
   343→  }
   344→
   345→  // Excessive caps or repetition
   346→  const capsRatio = (content.match(/[A-Z]/g) || []).length / content.length;
   347→  if (capsRatio > 0.5 && content.length > 20) {
   348→    not_interested += 0.1;
   349→    mute_author += 0.05;
   350→    report += 0.02;
   351→  }
   352→
   353→  // Normalize all scores to 0-1
   354→  const normalize = (v: number) => Math.max(0, Math.min(1, v));
   355→
   356→  return {
   357→    favorite_score: normalize(favorite),
   358→    reply_score: normalize(reply),
   359→    repost_score: normalize(repost),
   360→    click_score: normalize(click),
   361→    profile_click_score: normalize(profile_click),
   362→    share_score: normalize(share),
   363→    dwell_score: normalize(dwell),
   364→    quote_score: normalize(quote),
   365→    follow_author_score: normalize(follow_author),
   366→    bookmark_score: normalize(bookmark),
   367→    // NEW engagement types
   368→    photo_expand_score: normalize(photo_expand),
   369→    share_via_dm_score: normalize(share_via_dm),
   370→    share_via_copy_link_score: normalize(share_via_copy_link),
   371→    cont_dwell_time_score: normalize(cont_dwell_time),
   372→    quoted_click_score: normalize(quoted_click),
   373→    // Negative signals (enhanced)
   374→    not_interested_score: normalize(not_interested),
   375→    skip_score: normalize(skip),
   376→    block_author_score: normalize(block_author),
   377→    mute_author_score: normalize(mute_author),
   378→    report_score: normalize(report),
   379→  };
   380→}
   381→
   382→/**
   383→ * Calculate weighted score from engagement predictions
   384→ * Based on X's weighted_scorer.rs pattern with all 19 engagement types
   385→ */
   386→export function calculateWeightedScore(predictions: EngagementPredictions): number {
   387→  // Core positive engagements
   388→  const corePositive =
   389→    predictions.favorite_score * ENGAGEMENT_WEIGHTS.favorite +
   390→    predictions.reply_score * ENGAGEMENT_WEIGHTS.reply +
   391→    predictions.repost_score * ENGAGEMENT_WEIGHTS.repost +
   392→    predictions.click_score * ENGAGEMENT_WEIGHTS.click +
   393→    predictions.profile_click_score * ENGAGEMENT_WEIGHTS.profile_click +
   394→    predictions.share_score * ENGAGEMENT_WEIGHTS.share +
   395→    predictions.dwell_score * ENGAGEMENT_WEIGHTS.dwell +
   396→    predictions.quote_score * ENGAGEMENT_WEIGHTS.quote +
   397→    predictions.follow_author_score * ENGAGEMENT_WEIGHTS.follow_author +
   398→    predictions.bookmark_score * ENGAGEMENT_WEIGHTS.bookmark;
   399→
   400→  // Extended positive engagements
   401→  const extendedPositive =
   402→    predictions.photo_expand_score * ENGAGEMENT_WEIGHTS.photo_expand +
   403→    predictions.share_via_dm_score * ENGAGEMENT_WEIGHTS.share_via_dm +
   404→    predictions.share_via_copy_link_score * ENGAGEMENT_WEIGHTS.share_via_copy_link +
   405→    predictions.cont_dwell_time_score * ENGAGEMENT_WEIGHTS.cont_dwell_time +
   406→    predictions.quoted_click_score * ENGAGEMENT_WEIGHTS.quoted_click;
   407→
   408→  // Negative signals
   409→  const negativeScore =
   410→    predictions.not_interested_score * ENGAGEMENT_WEIGHTS.not_interested +
   411→    predictions.skip_score * ENGAGEMENT_WEIGHTS.skip +
   412→    predictions.block_author_score * ENGAGEMENT_WEIGHTS.block_author +
   413→    predictions.mute_author_score * ENGAGEMENT_WEIGHTS.mute_author +
   414→    predictions.report_score * ENGAGEMENT_WEIGHTS.report;
   415→
   416→  const rawScore = corePositive + extendedPositive + negativeScore;
   417→
   418→  // Normalize to 0-100 scale
   419→  // Max possible positive: ~7 (all predictions at 1.0)
   420→  // Min possible with negatives: ~-5
   421→  // Range: -5 to 7, normalize to 0-100
   422→  const normalizedScore = ((rawScore + 5) / 12) * 100;
   423→
   424→  return Math.max(0, Math.min(100, Math.round(normalizedScore)));
   425→}
