   430→
   431→export interface XAlgorithmScore {
   432→  // Overall
   433→  total: number;
   434→
   435→  // Breakdown by category (0-20 each, total 100)
   436→  hook_strength: number;
   437→  engagement_potential: number;
   438→  viral_potential: number;
   439→  algorithm_fit: number;
   440→  content_quality: number;
   441→
   442→  // Detailed predictions
   443→  predictions: EngagementPredictions;
   444→
   445→  // Analysis
