   447→
   448→  // Reasoning
   449→  strengths: string[];
   450→  improvements: string[];
   451→}
   452→
   453→/**
   454→ * Generate comprehensive X Algorithm score with breakdown
   455→ */
   456→export function generateXAlgorithmScore(
   457→  content: string,
   458→  context?: {
   459→    isThread?: boolean;
   460→    isReply?: boolean;
   461→    isQuote?: boolean;
   462→    hasMedia?: boolean;
   463→    personaMatch?: number; // 0-1 from AI
   464→  }
   465→): XAlgorithmScore {
   466→  const features = analyzeContentFeatures(content, context);
   467→  const predictions = predictEngagement(features, content);
   468→  const weightedScore = calculateWeightedScore(predictions);
   469→
   470→  // Calculate category scores (0-20 each, total 100)
   471→
   472→  // Hook Strength (0-20 points)
   473→  let hookStrength = 10;
   474→  if (features.hasStrongHook) hookStrength += 5;
   475→  if (features.hookType === 'question') hookStrength += 2;
   476→  if (features.hookType === 'data') hookStrength += 2;
   477→  if (features.hookType === 'contrarian') hookStrength += 3;
   478→  if (features.curiosityGap) hookStrength += 3;
   479→  hookStrength = Math.min(20, hookStrength);
   480→
   481→  // Engagement Potential (0-20 points)
   482→  let engagementPotential = 10 + Math.round(
   483→    (predictions.reply_score + predictions.quote_score + predictions.repost_score) / 3 * 10
   484→  );
   485→  engagementPotential = Math.min(20, engagementPotential);
   486→
   487→  // Viral Potential (0-20 points)
   488→  let viralPotential = 8 + Math.round(
   489→    (predictions.repost_score * 0.4 + predictions.share_score * 0.3 + predictions.bookmark_score * 0.3) * 12
   490→  );
   491→  viralPotential = Math.min(20, viralPotential);
   492→
   493→  // Algorithm Fit (0-20 points)
   494→  let algorithmFit = 10;
   495→  if (features.isOptimalLength) algorithmFit += 3;
   496→  if (features.hasEmoji) algorithmFit += 2;
   497→  if (features.hasHashtag) algorithmFit += 1;
   498→  if (features.hasLineBreaks) algorithmFit += 2;
   499→  if (predictions.dwell_score > 0.6) algorithmFit += 2;
   500→  algorithmFit = Math.min(20, Math.round(algorithmFit));
   501→
   502→  // Content Quality (0-20 points)
   503→  let contentQuality = 10;
   504→  if (features.hasNumbers) contentQuality += 2;
   505→  if (features.sentenceCount >= 2 && features.sentenceCount <= 4) contentQuality += 2;
   506→  if (features.avgSentenceLength >= 30 && features.avgSentenceLength <= 80) contentQuality += 2;
   507→  // Fix: Check for undefined/null explicitly to allow personaMatch: 0
   508→  if (context?.personaMatch !== undefined && context.personaMatch !== null) {
   509→    contentQuality += Math.round(context.personaMatch * 4);
   510→  }
   511→  contentQuality = Math.min(20, contentQuality);
   512→
   513→  // Generate insights
   514→  const strengths: string[] = [];
   515→  const improvements: string[] = [];
   516→
   517→  if (features.hasStrongHook) {
   518→    strengths.push(`Güçlü ${features.hookType} hook'u dikkat çekiyor`);
   519→  } else {
   520→    improvements.push("Daha güçlü bir açılış hook'u ekleyin");
   521→  }
   522→
   523→  if (predictions.reply_score > 0.7) {
   524→    strengths.push("Yüksek yanıt alma potansiyeli");
   525→  }
   526→
   527→  if (predictions.repost_score > 0.6) {
   528→    strengths.push("Retweet potansiyeli yüksek");
   529→  } else {
   530→    improvements.push("Paylaşılabilirliği artırmak için veri/rakam ekleyin");
   531→  }
   532→
   533→  if (features.hasQuestion) {
   534→    strengths.push("Soru formatı etkileşimi artırır");
   535→  } else {
   536→    improvements.push("Bir soru ekleyerek etkileşimi artırabilirsiniz");
   537→  }
   538→
   539→  if (!features.isOptimalLength) {
   540→    improvements.push(
   541→      features.charCount < 100
   542→        ? "Tweet biraz daha uzun olabilir (100-280 karakter ideal)"
   543→        : "Tweet biraz kısaltılabilir"
   544→    );
   545→  }
   546→
   547→  if (features.curiosityGap) {
   548→    strengths.push("Merak açığı oluşturulmuş - tıklama oranı yüksek olacak");
   549→  }
   550→
   551→  if (predictions.not_interested_score > 0.3) {
   552→    improvements.push("İçerik daha ilgi çekici hale getirilebilir");
   553→  }
   554→
   555→  return {
   556→    total: weightedScore,
   557→    hook_strength: hookStrength,
   558→    engagement_potential: engagementPotential,
   559→    viral_potential: viralPotential,
   560→    algorithm_fit: algorithmFit,
   561→    content_quality: contentQuality,
   562→    predictions,
   563→    features,
   564→    strengths: strengths.slice(0, 3),
   565→    improvements: improvements.slice(0, 3),
   566→  };
   567→}
   568→
   569→// ============================================================================
   570→// AUTHOR DIVERSITY SCORER (For threads)
   571→// ============================================================================
   572→
   573→/**
   574→ * Apply diversity decay to thread tweets
   575→ * Based on X's author_diversity_scorer.rs
   576→ *
   577→ * Formula: multiplier(position) = (1 - floor) × decay_factor^position + floor
   578→ */
   579→export function applyDiversityDecay(
   580→  scores: number[],
   581→  decayFactor: number = 0.85,
   582→  floor: number = 0.3
   583→): number[] {
   584→  return scores.map((score, position) => {
   585→    if (position === 0) return score; // First tweet gets full score
   586→
   587→    const multiplier = (1 - floor) * Math.pow(decayFactor, position) + floor;
   588→    return Math.round(score * multiplier);
   589→  });
   590→}
   591→
   592→/**
   593→ * Calculate thread total score with diversity consideration
   594→ */
   595→export function calculateThreadScore(tweetScores: XAlgorithmScore[]): {
   596→  totalScore: number;
   597→  adjustedScores: number[];
   598→  hookScore: number;
   599→  averageEngagement: number;
   600→} {
   601→  const rawScores = tweetScores.map(s => s.total);
   602→  const adjustedScores = applyDiversityDecay(rawScores);
   603→
   604→  // Hook tweet (first) is weighted more heavily
   605→  const hookScore = tweetScores[0]?.hook_strength || 0;
   606→
   607→  // Average engagement across thread
   608→  const averageEngagement = tweetScores.reduce(
   609→    (sum, s) => sum + s.engagement_potential, 0
   610→  ) / tweetScores.length;
   611→
   612→  // Total score: weighted average with hook bonus
   613→  const totalScore = Math.round(
   614→    (adjustedScores.reduce((a, b) => a + b, 0) / adjustedScores.length) * 0.7 +
   615→    hookScore * 1.5 + // Hook bonus
   616→    averageEngagement * 0.5
   617→  );
   618→
   619→  return {
   620→    totalScore: Math.min(100, totalScore),
   621→    adjustedScores,
   622→    hookScore,
   623→    averageEngagement,
   624→  };
   625→}
