   627→// ============================================================================
   628→// FAZ 3: SENTIMENT ANALYSIS
   629→// ============================================================================
   630→
   631→// Toxic/negative word patterns (Turkish + English)
   632→const TOXIC_PATTERNS = [
   633→  // Offensive language
   634→  /\b(aptal|salak|mal|gerizekalı|idiot|stupid|dumb|moron)\b/gi,
   635→  // Aggressive language
   636→  /\b(öldür|gebertir|kill|die|hate|nefret)\b/gi,
   637→  // Profanity indicators (mild check)
   638→  /\b(s[ıi]kt[ıi]r|bok|shit|fuck|damn)\b/gi,
   639→];
   640→
   641→const POSITIVE_PATTERNS = [
   642→  // Achievement/Success
   643→  /\b(başardı|kazandı|harika|muhteşem|mükemmel|amazing|awesome|incredible|success|won|achieved)\b/gi,
   644→  // Gratitude
   645→  /\b(teşekkür|minnettar|grateful|thanks|appreciate)\b/gi,
   646→  // Excitement
   647→  /\b(heyecanlı|mutlu|sevinçli|excited|happy|thrilled|love)\b/gi,
   648→  // Inspiration
   649→  /\b(ilham|motivasyon|inspire|motivated|dream)\b/gi,
   650→];
   651→
   652→const NEGATIVE_PATTERNS = [
   653→  // Disappointment
   654→  /\b(hayal kırıklığı|üzgün|disappointed|sad|unfortunately|sadly)\b/gi,
   655→  // Frustration
   656→  /\b(sinir|kızgın|angry|frustrated|annoyed|irritated)\b/gi,
   657→  // Complaint
   658→  /\b(şikayet|sorun|problem|issue|complaint|broken|terrible)\b/gi,
   659→];
   660→
   661→export interface SentimentAnalysis {
   662→  // Overall sentiment score (-1 to 1)
   663→  score: number;
   664→  // Sentiment label
   665→  label: 'positive' | 'negative' | 'neutral';
   666→  // Confidence (0-1)
   667→  confidence: number;
   668→  // Toxicity risk (0-1)
   669→  toxicityRisk: number;
   670→  // Detected patterns
   671→  positiveWords: string[];
   672→  negativeWords: string[];
   673→  toxicWords: string[];
   674→  // Recommendation
   675→  recommendation: string;
   676→}
   677→
   678→/**
   679→ * Analyze sentiment of tweet content
   680→ */
   681→export function analyzeSentiment(content: string): SentimentAnalysis {
   682→  const lowerContent = content.toLowerCase();
   683→
   684→  // Find matches
   685→  const positiveMatches: string[] = [];
   686→  const negativeMatches: string[] = [];
   687→  const toxicMatches: string[] = [];
   688→
   689→  POSITIVE_PATTERNS.forEach(pattern => {
   690→    const matches = lowerContent.match(pattern);
   691→    if (matches) positiveMatches.push(...matches);
   692→  });
   693→
   694→  NEGATIVE_PATTERNS.forEach(pattern => {
   695→    const matches = lowerContent.match(pattern);
   696→    if (matches) negativeMatches.push(...matches);
   697→  });
   698→
   699→  TOXIC_PATTERNS.forEach(pattern => {
   700→    const matches = lowerContent.match(pattern);
   701→    if (matches) toxicMatches.push(...matches);
   702→  });
   703→
   704→  // Calculate scores
   705→  const positiveScore = positiveMatches.length * 0.3;
   706→  const negativeScore = negativeMatches.length * 0.3;
   707→  const toxicScore = toxicMatches.length * 0.5;
   708→
   709→  // Overall sentiment (-1 to 1)
   710→  let rawScore = positiveScore - negativeScore - toxicScore;
   711→  rawScore = Math.max(-1, Math.min(1, rawScore));
   712→
   713→  // Toxicity risk (0-1)
   714→  const toxicityRisk = Math.min(1, toxicMatches.length * 0.4);
   715→
   716→  // Determine label
   717→  let label: 'positive' | 'negative' | 'neutral' = 'neutral';
   718→  if (rawScore > 0.2) label = 'positive';
   719→  else if (rawScore < -0.2 || toxicityRisk > 0.3) label = 'negative';
   720→
   721→  // Confidence based on word count
   722→  const totalWords = content.split(/\s+/).length;
   723→  const detectedWords = positiveMatches.length + negativeMatches.length + toxicMatches.length;
   724→  const confidence = Math.min(1, detectedWords / Math.max(totalWords * 0.2, 1));
   725→
   726→  // Generate recommendation
   727→  let recommendation = '';
   728→  if (toxicityRisk > 0.3) {
   729→    recommendation = 'Dikkat: Toksik içerik algılandı. Bu tweet block/report riskine sahip.';
   730→  } else if (label === 'negative') {
   731→    recommendation = 'Negatif ton algılandı. Daha yapıcı bir dil düşünün.';
   732→  } else if (label === 'positive') {
   733→    recommendation = 'Pozitif ton - engagement için iyi!';
   734→  } else {
   735→    recommendation = 'Nötr ton. Daha duygusal bağ kurmak için pozitif kelimeler ekleyebilirsiniz.';
   736→  }
   737→
   738→  return {
   739→    score: rawScore,
   740→    label,
   741→    confidence,
   742→    toxicityRisk,
   743→    positiveWords: [...new Set(positiveMatches)],
   744→    negativeWords: [...new Set(negativeMatches)],
   745→    toxicWords: [...new Set(toxicMatches)],
   746→    recommendation,
   747→  };
   748→}
