   750→// ============================================================================
   751→// FAZ 3: HASHTAG QUALITY CHECK
   752→// ============================================================================
   753→
   754→export interface HashtagAnalysis {
   755→  // Found hashtags
   756→  hashtags: string[];
   757→  // Count
   758→  count: number;
   759→  // Quality score (0-100)
   760→  qualityScore: number;
   761→  // Is optimal count (1-2 ideal for X)
   762→  isOptimalCount: boolean;
   763→  // Issues found
   764→  issues: string[];
   765→  // Recommendations
   766→  recommendations: string[];
   767→}
   768→
   769→// Common low-quality hashtag patterns
   770→const LOW_QUALITY_HASHTAG_PATTERNS = [
   771→  /^#(follow|followme|like|likeforlike|f4f|l4l|followback)$/i,
   772→  /^#(instagood|photooftheday|picoftheday|instadaily)$/i, // Instagram-specific
   773→  /^#\d+$/,  // Just numbers
   774→];
   775→
   776→// Overly generic hashtags
   777→const GENERIC_HASHTAGS = [
   778→  '#tech', '#business', '#success', '#motivation', '#life', '#love',
   779→  '#happy', '#goals', '#money', '#entrepreneur',
   780→];
   781→
   782→/**
   783→ * Analyze hashtag usage in content
   784→ */
   785→export function analyzeHashtags(content: string): HashtagAnalysis {
   786→  const hashtagRegex = /#[\wğüşıöçĞÜŞİÖÇ]+/g;
   787→  const hashtags = content.match(hashtagRegex) || [];
   788→  const count = hashtags.length;
   789→
   790→  const issues: string[] = [];
   791→  const recommendations: string[] = [];
   792→  let qualityDeduction = 0;
   793→
   794→  // Check count (X algorithm penalizes 3+ hashtags)
   795→  const isOptimalCount = count >= 0 && count <= 2;
   796→
   797→  if (count === 0) {
   798→    recommendations.push('Konuyla ilgili 1-2 hashtag eklemek erişimi artırabilir');
   799→  } else if (count > 3) {
   800→    issues.push(`${count} hashtag çok fazla - X algoritması bunu spam olarak değerlendiriyor`);
   801→    qualityDeduction += 30;
   802→  } else if (count === 3) {
   803→    issues.push('3 hashtag sınırda - 1-2 hashtag daha etkili');
   804→    qualityDeduction += 10;
   805→  }
   806→
   807→  // Check for low-quality hashtags
   808→  hashtags.forEach(tag => {
   809→    const isLowQuality = LOW_QUALITY_HASHTAG_PATTERNS.some(p => p.test(tag));
   810→    if (isLowQuality) {
   811→      issues.push(`"${tag}" spam hashtag - kaçının`);
   812→      qualityDeduction += 15;
   813→    }
   814→
   815→    const isGeneric = GENERIC_HASHTAGS.includes(tag.toLowerCase());
   816→    if (isGeneric) {
   817→      issues.push(`"${tag}" çok genel - daha spesifik hashtag seçin`);
   818→      qualityDeduction += 10;
   819→    }
   820→
   821→    // Check hashtag length
   822→    if (tag.length > 25) {
   823→      issues.push(`"${tag}" çok uzun - kısa hashtagler daha etkili`);
   824→      qualityDeduction += 5;
   825→    }
   826→  });
   827→
   828→  // Generate recommendations
   829→  if (count > 0 && issues.length === 0) {
   830→    recommendations.push('Hashtag kullanımı optimal!');
   831→  }
   832→
   833→  if (count > 2) {
   834→    recommendations.push('En alakalı 1-2 hashtagi tutun, diğerlerini kaldırın');
   835→  }
   836→
   837→  const qualityScore = Math.max(0, 100 - qualityDeduction);
   838→
   839→  return {
   840→    hashtags,
   841→    count,
   842→    qualityScore,
   843→    isOptimalCount,
   844→    issues,
   845→    recommendations,
   846→  };
   847→}
   848→
   849→// ============================================================================
   850→// FAZ 3: OPTIMAL POSTING TIME
   851→// ============================================================================
   852→
   853→export interface PostingTimeRecommendation {
   854→  // Current time info
   855→  currentHour: number;
   856→  currentDay: string;
   857→  timezone: string;
   858→
   859→  // Is current time optimal?
   860→  isOptimalNow: boolean;
   861→
   862→  // Score for current time (0-100)
   863→  currentTimeScore: number;
   864→
   865→  // Best times today
   866→  bestTimesToday: string[];
   867→
   868→  // Best days of week
   869→  bestDays: string[];
   870→
   871→  // Recommendation message
   872→  recommendation: string;
   873→
   874→  // Detailed schedule
   875→  schedule: {
   876→    day: string;
   877→    times: { hour: string; score: number; label: string }[];
   878→  }[];
   879→}
   880→
   881→// Turkey timezone engagement data (based on X analytics patterns)
   882→const TURKEY_ENGAGEMENT_HOURS: Record<number, number> = {
   883→  // Hour: Score (0-100)
   884→  0: 20, 1: 15, 2: 10, 3: 8, 4: 5, 5: 10,
   885→  6: 25, 7: 40, 8: 70, 9: 85, // Morning peak
   886→  10: 80, 11: 75, 12: 85, 13: 80, // Lunch peak
   887→  14: 70, 15: 65, 16: 60, 17: 70,
   888→  18: 80, 19: 90, 20: 95, 21: 90, // Evening peak (BEST)
   889→  22: 75, 23: 50,
   890→};
   891→
   892→// Day of week multipliers
   893→const DAY_MULTIPLIERS: Record<string, number> = {
   894→  'Pazartesi': 0.9,
   895→  'Salı': 1.0,
   896→  'Çarşamba': 1.0,
   897→  'Perşembe': 1.05,
   898→  'Cuma': 0.95,
   899→  'Cumartesi': 0.85,
   900→  'Pazar': 0.8,
   901→};
   902→
   903→const DAY_NAMES_TR = ['Pazar', 'Pazartesi', 'Salı', 'Çarşamba', 'Perşembe', 'Cuma', 'Cumartesi'];
   904→
   905→/**
   906→ * Get optimal posting time recommendations for Turkey timezone
   907→ */
   908→export function getPostingTimeRecommendation(): PostingTimeRecommendation {
   909→  // Get Turkey time using Intl.DateTimeFormat for accurate timezone handling
   910→  const now = new Date();
   911→
   912→  // Use Intl API for reliable timezone conversion (handles DST correctly)
   913→  const turkeyFormatter = new Intl.DateTimeFormat('en-US', {
   914→    timeZone: 'Europe/Istanbul',
   915→    hour: 'numeric',
   916→    hour12: false,
   917→    weekday: 'short'
   918→  });
   919→
   920→  const parts = turkeyFormatter.formatToParts(now);
   921→  const hourPart = parts.find(p => p.type === 'hour');
   922→  const dayPart = parts.find(p => p.type === 'weekday');
   923→
   924→  const currentHour = hourPart ? parseInt(hourPart.value, 10) : now.getHours();
   925→
   926→  // Map English weekday to day index
   927→  const dayMap: Record<string, number> = { 'Sun': 0, 'Mon': 1, 'Tue': 2, 'Wed': 3, 'Thu': 4, 'Fri': 5, 'Sat': 6 };
   928→  const currentDayIndex = dayPart ? (dayMap[dayPart.value] ?? now.getDay()) : now.getDay();
   929→  const currentDay = DAY_NAMES_TR[currentDayIndex];
   930→
   931→  // Calculate current time score
   932→  const baseScore = TURKEY_ENGAGEMENT_HOURS[currentHour] || 50;
   933→  const dayMultiplier = DAY_MULTIPLIERS[currentDay] || 1.0;
   934→  const currentTimeScore = Math.round(baseScore * dayMultiplier);
   935→
   936→  // Is optimal now? (score > 75)
   937→  const isOptimalNow = currentTimeScore >= 75;
   938→
   939→  // Find best times today
   940→  const bestTimesToday: string[] = [];
   941→  Object.entries(TURKEY_ENGAGEMENT_HOURS)
   942→    .filter(([_, score]) => score * dayMultiplier >= 80)
   943→    .sort((a, b) => b[1] - a[1])
   944→    .slice(0, 4)
   945→    .forEach(([hour]) => {
   946→      const h = parseInt(hour);
   947→      bestTimesToday.push(`${h.toString().padStart(2, '0')}:00`);
   948→    });
   949→
   950→  // Best days
   951→  const bestDays = Object.entries(DAY_MULTIPLIERS)
   952→    .sort((a, b) => b[1] - a[1])
   953→    .slice(0, 3)
   954→    .map(([day]) => day);
   955→
   956→  // Generate recommendation
   957→  let recommendation = '';
   958→  if (isOptimalNow) {
   959→    recommendation = `Şu an paylaşım için iyi bir zaman! (Skor: ${currentTimeScore}/100)`;
   960→  } else if (currentTimeScore >= 60) {
   961→    recommendation = `Orta seviye engagement bekleniyor. Daha iyi sonuç için ${bestTimesToday[0]} saatini deneyin.`;
   962→  } else {
   963→    recommendation = `Şu an engagement düşük olabilir. En iyi saatler: ${bestTimesToday.slice(0, 2).join(', ')}`;
   964→  }
   965→
   966→  // Generate weekly schedule
   967→  const schedule = DAY_NAMES_TR.slice(1).concat(DAY_NAMES_TR[0]).map(day => {
   968→    const mult = DAY_MULTIPLIERS[day] || 1.0;
   969→    const times = [8, 12, 19, 20, 21].map(hour => ({
   970→      hour: `${hour.toString().padStart(2, '0')}:00`,
   971→      score: Math.round(TURKEY_ENGAGEMENT_HOURS[hour] * mult),
   972→      label: TURKEY_ENGAGEMENT_HOURS[hour] * mult >= 80 ? 'Optimal' :
   973→             TURKEY_ENGAGEMENT_HOURS[hour] * mult >= 60 ? 'İyi' : 'Düşük',
   974→    }));
   975→    return { day, times };
   976→  });
   977→
   978→  return {
   979→    currentHour,
   980→    currentDay,
   981→    timezone: 'Europe/Istanbul (UTC+3)',
   982→    isOptimalNow,
   983→    currentTimeScore,
   984→    bestTimesToday,
   985→    bestDays,
   986→    recommendation,
   987→    schedule,
   988→  };
   989→}
   990→
   991→// ============================================================================
   992→// FAZ 3: COMPREHENSIVE CONTENT ANALYSIS (Combines all Faz 3 features)
   993→// ============================================================================
   994→
   995→export interface ContentAnalysisResult {
   996→  // X Algorithm Score (Faz 1-2)
   997→  xScore: XAlgorithmScore;
   998→
   999→  // Sentiment Analysis (Faz 3)
  1000→  sentiment: SentimentAnalysis;
  1001→
  1002→  // Hashtag Analysis (Faz 3)
  1003→  hashtags: HashtagAnalysis;
  1004→
  1005→  // Posting Time (Faz 3)
  1006→  postingTime: PostingTimeRecommendation;
  1007→
  1008→  // Overall recommendations
  1009→  topRecommendations: string[];
  1010→
  1011→  // Risk alerts
  1012→  alerts: string[];
  1013→}
  1014→
  1015→/**
  1016→ * Comprehensive content analysis with all Faz 1-3 features
  1017→ */
  1018→export function analyzeContentComprehensive(
  1019→  content: string,
  1020→  context?: {
  1021→    isThread?: boolean;
  1022→    isReply?: boolean;
  1023→    isQuote?: boolean;
  1024→    hasMedia?: boolean;
  1025→    personaMatch?: number;
  1026→  }
  1027→): ContentAnalysisResult {
  1028→  // Get all analyses
  1029→  const xScore = generateXAlgorithmScore(content, context);
  1030→  const sentiment = analyzeSentiment(content);
  1031→  const hashtags = analyzeHashtags(content);
  1032→  const postingTime = getPostingTimeRecommendation();
  1033→
  1034→  // Compile top recommendations
  1035→  const topRecommendations: string[] = [];
  1036→  const alerts: string[] = [];
  1037→
  1038→  // From X Score
  1039→  xScore.improvements.slice(0, 2).forEach(i => topRecommendations.push(i));
  1040→
  1041→  // From Sentiment
  1042→  if (sentiment.toxicityRisk > 0.3) {
  1043→    alerts.push(`⚠️ Toxicity Risk: ${sentiment.recommendation}`);
  1044→  } else if (sentiment.label === 'negative') {
  1045→    topRecommendations.push(sentiment.recommendation);
  1046→  }
  1047→
  1048→  // From Hashtags
  1049→  if (!hashtags.isOptimalCount) {
  1050→    topRecommendations.push(hashtags.recommendations[0] || 'Hashtag sayısını optimize edin');
  1051→  }
  1052→  hashtags.issues.slice(0, 1).forEach(i => alerts.push(`#️⃣ ${i}`));
  1053→
  1054→  // From Posting Time
  1055→  if (!postingTime.isOptimalNow && postingTime.currentTimeScore < 60) {
  1056→    topRecommendations.push(`⏰ ${postingTime.recommendation}`);
  1057→  }
  1058→
  1059→  return {
  1060→    xScore,
  1061→    sentiment,
  1062→    hashtags,
  1063→    postingTime,
  1064→    topRecommendations: topRecommendations.slice(0, 5),
  1065→    alerts,
  1066→  };
  1067→}
  1068→
  1069→// ============================================================================
  1070→// DATA-DRIVEN SCORING ENHANCEMENT (Scraper Integration)
  1071→// ============================================================================
  1072→
  1073→const SCRAPER_API_URL = typeof window !== 'undefined'
  1074→  ? (window as unknown as { __SCRAPER_API_URL?: string }).__SCRAPER_API_URL || 'http://localhost:3001'
  1075→  : 'http://localhost:3001';
  1076→
  1077→let cachedPatternWeights: Record<string, number> | null = null;
  1078→let patternWeightsCacheTime = 0;
  1079→
  1080→export async function fetchPatternWeights(): Promise<Record<string, number> | null> {
  1081→  const now = Date.now();
  1082→  if (cachedPatternWeights && now - patternWeightsCacheTime < 5 * 60 * 1000) {
  1083→    return cachedPatternWeights;
  1084→  }
  1085→
  1086→  try {
  1087→    const res = await fetch(`${SCRAPER_API_URL}/api/patterns`, { signal: AbortSignal.timeout(3000) });
  1088→    if (!res.ok) return null;
  1089→    const data = await res.json();
  1090→    if (data.success && data.data) {
  1091→      const weights: Record<string, number> = {};
  1092→      data.data.forEach((p: { pattern: string; avgEngagement: number }) => {
  1093→        weights[p.pattern] = p.avgEngagement;
  1094→      });
  1095→      cachedPatternWeights = weights;
  1096→      patternWeightsCacheTime = now;
  1097→      return weights;
  1098→    }
  1099→  } catch {
  1100→    // Scraper offline - use rule-based system
  1101→  }
  1102→  return null;
  1103→}
