/**
 * X Algorithm-Inspired Tweet Scoring System
 * Based on: https://github.com/xai-org/x-algorithm
 *
 * This implements a simplified version of X's Phoenix engagement prediction
 * and weighted scoring mechanism for tweet quality assessment.
 */

// ============================================================================
// ENGAGEMENT ACTION TYPES (Inspired by Phoenix's 19 action predictions)
// ============================================================================

export interface EngagementPredictions {
  // Core engagement (12 original)
  favorite_score: number;        // Likelihood of like
  reply_score: number;           // Likelihood of reply
  repost_score: number;          // Likelihood of retweet
  click_score: number;           // Likelihood of click to expand
  profile_click_score: number;   // Likelihood of profile visit
  share_score: number;           // Likelihood of share
  dwell_score: number;           // Time spent on tweet
  quote_score: number;           // Likelihood of quote tweet
  follow_author_score: number;   // Likelihood of follow
  bookmark_score: number;        // Likelihood of bookmark

  // NEW: Extended engagement types from X Algorithm (7 new)
  photo_expand_score: number;    // Likelihood of expanding photo
  share_via_dm_score: number;    // Likelihood of DM sharing
  share_via_copy_link_score: number; // Likelihood of link copy
  cont_dwell_time_score: number; // Continuous reading time
  quoted_click_score: number;    // Click on quoted tweet

  // Negative signals (enhanced)
  not_interested_score: number;
  skip_score: number;
  block_author_score: number;    // NEW: Risk of block
  mute_author_score: number;     // NEW: Risk of mute
  report_score: number;          // NEW: Risk of report
}

// ============================================================================
// WEIGHTED SCORING WEIGHTS (Approximated from X Algorithm patterns)
// ============================================================================

const ENGAGEMENT_WEIGHTS = {
  // Positive weights - Updated based on X Algorithm weighted_scorer.rs patterns
  favorite: 0.5,           // Likes are common, lower weight
  reply: 1.0,              // Replies are X's most valued engagement
  repost: 1.1,             // Retweets very valuable
  quote: 0.8,              // Quote tweets valuable
  share: 0.6,
  bookmark: 0.4,           // Bookmarks indicate save-worthy content
  follow_author: 1.5,      // Follows are extremely valuable

  // Medium impact
  click: 0.3,
  profile_click: 0.25,
  dwell: 0.2,

  // NEW: Extended engagement weights
  photo_expand: 0.3,       // Photo expansion
  share_via_dm: 0.4,       // DM share - high intent signal
  share_via_copy_link: 0.35, // Link copy - intent to share externally
  cont_dwell_time: 0.3,    // Continuous reading
  quoted_click: 0.2,       // Click on quoted content

  // Negative weights - Enhanced
  not_interested: -1.5,
  skip: -0.5,
  block_author: -4.0,      // Block is severe negative signal
  mute_author: -3.0,       // Mute is strong negative signal
  report: -5.0,            // Report is most severe
};

// ============================================================================
// CONTENT ANALYSIS FACTORS
// ============================================================================

interface ContentFeatures {
  // Hook analysis
  hasStrongHook: boolean;
  hookType: 'question' | 'statement' | 'story' | 'data' | 'contrarian' | 'none';

  // Content structure
  hasLineBreaks: boolean;
  sentenceCount: number;
  avgSentenceLength: number;

  // Engagement triggers
  hasQuestion: boolean;
  hasCallToAction: boolean;
  hasNumbers: boolean;
  hasEmoji: boolean;
  hasHashtag: boolean;
  hasMention: boolean;

  // Content type signals
  isThread: boolean;
  hasMedia: boolean;
  isReply: boolean;
  isQuote: boolean;

  // Length optimization
  charCount: number;
  isOptimalLength: boolean;

  // Emotional triggers
  emotionalIntensity: number;
  curiosityGap: boolean;
}

// ============================================================================
// HOOK PATTERNS (What makes first 3 seconds compelling)
// ============================================================================

const STRONG_HOOK_PATTERNS = [
  // Question hooks
  /^(neden|nasıl|ne zaman|kim|hangisi|kaç|what|how|why|when|who|which)/i,
  /^[^.!?]*\?/,

  // Data/Number hooks
  /^(\d+%|\d+x|\$\d+|\d+ (yıl|gün|saat|dakika))/i,
  /^\d+\./,

  // Contrarian hooks
  /^(herkes yanılıyor|kimse bilmiyor|unpopular opinion|hot take)/i,

  // Story hooks
  /^(dün|geçen hafta|bu sabah|yesterday|last week|today)/i,
  /^(bir arkadaşım|biri bana|someone told me)/i,

  // Curiosity gap hooks
  /^(bunu kimse bilmiyor|sır:|secret:|the truth about)/i,
  /(işte nedeni|here's why|here's how)$/i,
];

const CALL_TO_ACTION_PATTERNS = [
  /(düşüncelerinizi yazın|ne düşünüyorsunuz|yorumlarınızı bekliyorum)/i,
  /(retweet|rt|paylaş|share|save this|bookmark)/i,
  /(takip et|follow|join)/i,
  /(link bio|link in|biyografide)/i,
  /(\?$)/,
];

// ============================================================================
// MAIN SCORING FUNCTIONS
// ============================================================================

/**
 * Analyze content features for scoring
 */
export function analyzeContentFeatures(content: string, context?: {
  isThread?: boolean;
  isReply?: boolean;
  isQuote?: boolean;
  hasMedia?: boolean;
}): ContentFeatures {
  const lines = content.split('\n').filter(l => l.trim());
  const sentences = content.split(/[.!?]+/).filter(s => s.trim());

  // Hook detection
  let hookType: ContentFeatures['hookType'] = 'none';
  let hasStrongHook = false;

  for (const pattern of STRONG_HOOK_PATTERNS) {
    if (pattern.test(content)) {
      hasStrongHook = true;

      if (/\?/.test(content.split(/[.!]/)[0])) hookType = 'question';
      else if (/^\d/.test(content)) hookType = 'data';
      else if (/^(herkes|kimse|unpopular|hot take)/i.test(content)) hookType = 'contrarian';
      else if (/^(dün|geçen|bu sabah|yesterday|last)/i.test(content)) hookType = 'story';
      else hookType = 'statement';
      break;
    }
  }

  // CTA detection
  const hasCallToAction = CALL_TO_ACTION_PATTERNS.some(p => p.test(content));

  // Emotional intensity (simplified)
  const emotionalWords = content.match(/(harika|müthiş|korkunç|inanılmaz|amazing|incredible|terrible|shocking|!{2,})/gi) || [];
  const emotionalIntensity = Math.min(emotionalWords.length / 3, 1);

  // Curiosity gap
  const curiosityGap = /(işte nedeni|here's why|sır:|secret:|bunu kimse|kimse bilmiyor)/i.test(content);

  return {
    hasStrongHook,
    hookType,
    hasLineBreaks: lines.length > 1,
    sentenceCount: sentences.length,
    avgSentenceLength: content.length / Math.max(sentences.length, 1),
    hasQuestion: /\?/.test(content),
    hasCallToAction,
    hasNumbers: /\d/.test(content),
    hasEmoji: /\p{Emoji}/u.test(content),
    hasHashtag: /#\w+/.test(content),
    hasMention: /@\w+/.test(content),
    isThread: context?.isThread || false,
    hasMedia: context?.hasMedia || false,
    isReply: context?.isReply || false,
    isQuote: context?.isQuote || false,
    charCount: content.length,
    isOptimalLength: content.length >= 100 && content.length <= 280,
    emotionalIntensity,
    curiosityGap,
  };
}

/**
 * Predict engagement probabilities based on content features
 * Inspired by Phoenix's multi-action prediction model
 * Enhanced with all 19 X Algorithm engagement types
 */
export function predictEngagement(features: ContentFeatures, content: string = ""): EngagementPredictions {
  const base = 0.5;

  // ---- FAVORITE SCORE ----
  let favorite = base;
  if (features.hasStrongHook) favorite += 0.15;
  if (features.hasEmoji) favorite += 0.05;
  if (features.isOptimalLength) favorite += 0.1;
  if (features.emotionalIntensity > 0.5) favorite += 0.1;

  // ---- REPLY SCORE ----
  let reply = base * 0.8;
  if (features.hasQuestion) reply += 0.25;
  if (features.hasCallToAction) reply += 0.15;
  if (features.hookType === 'contrarian') reply += 0.2;
  if (features.curiosityGap) reply += 0.1;

  // ---- REPOST SCORE ----
  let repost = base * 0.6;
  if (features.hookType === 'data') repost += 0.2;
  if (features.hasNumbers) repost += 0.1;
  if (features.hasStrongHook) repost += 0.15;
  if (features.isOptimalLength) repost += 0.1;

  // ---- CLICK SCORE ----
  let click = base * 0.7;
  if (features.curiosityGap) click += 0.25;
  if (features.hasStrongHook) click += 0.1;
  if (features.hasLineBreaks && features.charCount > 200) click += 0.1;

  // ---- PROFILE CLICK SCORE ----
  let profile_click = base * 0.4;
  if (features.hookType === 'story') profile_click += 0.15;
  if (features.emotionalIntensity > 0.7) profile_click += 0.1;

  // ---- SHARE SCORE ----
  let share = base * 0.5;
  if (features.hookType === 'data') share += 0.2;
  if (features.hasNumbers) share += 0.1;
  if (features.hasStrongHook) share += 0.1;

  // ---- DWELL SCORE ----
  let dwell = base * 0.6;
  if (features.hasLineBreaks) dwell += 0.15;
  if (features.sentenceCount > 2) dwell += 0.1;
  if (features.charCount > 150) dwell += 0.1;

  // ---- QUOTE SCORE ----
  let quote = base * 0.4;
  if (features.hookType === 'contrarian') quote += 0.25;
  if (features.hasQuestion) quote += 0.1;
  if (features.emotionalIntensity > 0.5) quote += 0.1;

  // ---- FOLLOW AUTHOR SCORE ----
  let follow_author = base * 0.3;
  if (features.hookType === 'data') follow_author += 0.15;
  if (features.hookType === 'story') follow_author += 0.1;
  if (features.hasStrongHook) follow_author += 0.1;

  // ---- BOOKMARK SCORE ----
  let bookmark = base * 0.4;
  if (features.hookType === 'data') bookmark += 0.2;
  if (features.hasNumbers) bookmark += 0.15;
  if (features.charCount > 200) bookmark += 0.1;

  // ---- NEW: PHOTO EXPAND SCORE ----
  let photo_expand = base * 0.5;
  if (features.hasMedia) photo_expand += 0.3;
  if (features.hasStrongHook) photo_expand += 0.1;

  // ---- NEW: SHARE VIA DM SCORE ----
  let share_via_dm = base * 0.3;
  if (features.hookType === 'data') share_via_dm += 0.15;
  if (features.emotionalIntensity > 0.6) share_via_dm += 0.15;
  if (features.hookType === 'story') share_via_dm += 0.1;

  // ---- NEW: SHARE VIA COPY LINK SCORE ----
  let share_via_copy_link = base * 0.3;
  if (features.hookType === 'data') share_via_copy_link += 0.2;
  if (features.hasNumbers) share_via_copy_link += 0.1;
  if (features.hasStrongHook) share_via_copy_link += 0.1;

  // ---- NEW: CONTINUOUS DWELL TIME SCORE ----
  let cont_dwell_time = base * 0.4;
  if (features.hasLineBreaks) cont_dwell_time += 0.2;
  if (features.sentenceCount > 3) cont_dwell_time += 0.15;
  if (features.charCount > 200) cont_dwell_time += 0.1;
  if (features.curiosityGap) cont_dwell_time += 0.1;

  // ---- NEW: QUOTED CLICK SCORE ----
  let quoted_click = base * 0.3;
  if (features.isQuote) quoted_click += 0.2;
  if (features.hasCallToAction) quoted_click += 0.1;

  // ---- NEGATIVE SIGNALS (Enhanced) ----
  let not_interested = 0.1;
  let skip = 0.15;
  let block_author = 0.02;  // Very low base
  let mute_author = 0.03;   // Low base
  let report = 0.01;        // Very low base

  // Increase negative signals based on content issues
  if (!features.hasStrongHook) {
    not_interested += 0.08;
    skip += 0.12;
  }
  if (features.charCount < 50) {
    skip += 0.08;
    not_interested += 0.05;
  }
  if (features.avgSentenceLength > 100) {
    not_interested += 0.08;
    skip += 0.08;
  }

  // Spam-like content increases block/mute/report risk
  const hashtagCount = (content.match(/#\w+/g) || []).length;
  const mentionCount = (content.match(/@\w+/g) || []).length;

  if (hashtagCount > 3) {
    not_interested += 0.1;
    mute_author += 0.05;
    block_author += 0.03;
  }
  if (mentionCount > 3) {
    not_interested += 0.08;
    mute_author += 0.04;
  }

  // Excessive caps or repetition
  const capsRatio = (content.match(/[A-Z]/g) || []).length / content.length;
  if (capsRatio > 0.5 && content.length > 20) {
    not_interested += 0.1;
    mute_author += 0.05;
    report += 0.02;
  }

  // Normalize all scores to 0-1
  const normalize = (v: number) => Math.max(0, Math.min(1, v));

  return {
    favorite_score: normalize(favorite),
    reply_score: normalize(reply),
    repost_score: normalize(repost),
    click_score: normalize(click),
    profile_click_score: normalize(profile_click),
    share_score: normalize(share),
    dwell_score: normalize(dwell),
    quote_score: normalize(quote),
    follow_author_score: normalize(follow_author),
    bookmark_score: normalize(bookmark),
    // NEW engagement types
    photo_expand_score: normalize(photo_expand),
    share_via_dm_score: normalize(share_via_dm),
    share_via_copy_link_score: normalize(share_via_copy_link),
    cont_dwell_time_score: normalize(cont_dwell_time),
    quoted_click_score: normalize(quoted_click),
    // Negative signals (enhanced)
    not_interested_score: normalize(not_interested),
    skip_score: normalize(skip),
    block_author_score: normalize(block_author),
    mute_author_score: normalize(mute_author),
    report_score: normalize(report),
  };
}

/**
 * Calculate weighted score from engagement predictions
 * Based on X's weighted_scorer.rs pattern with all 19 engagement types
 */
export function calculateWeightedScore(predictions: EngagementPredictions): number {
  // Core positive engagements
  const corePositive =
    predictions.favorite_score * ENGAGEMENT_WEIGHTS.favorite +
    predictions.reply_score * ENGAGEMENT_WEIGHTS.reply +
    predictions.repost_score * ENGAGEMENT_WEIGHTS.repost +
    predictions.click_score * ENGAGEMENT_WEIGHTS.click +
    predictions.profile_click_score * ENGAGEMENT_WEIGHTS.profile_click +
    predictions.share_score * ENGAGEMENT_WEIGHTS.share +
    predictions.dwell_score * ENGAGEMENT_WEIGHTS.dwell +
    predictions.quote_score * ENGAGEMENT_WEIGHTS.quote +
    predictions.follow_author_score * ENGAGEMENT_WEIGHTS.follow_author +
    predictions.bookmark_score * ENGAGEMENT_WEIGHTS.bookmark;

  // Extended positive engagements
  const extendedPositive =
    predictions.photo_expand_score * ENGAGEMENT_WEIGHTS.photo_expand +
    predictions.share_via_dm_score * ENGAGEMENT_WEIGHTS.share_via_dm +
    predictions.share_via_copy_link_score * ENGAGEMENT_WEIGHTS.share_via_copy_link +
    predictions.cont_dwell_time_score * ENGAGEMENT_WEIGHTS.cont_dwell_time +
    predictions.quoted_click_score * ENGAGEMENT_WEIGHTS.quoted_click;

  // Negative signals
  const negativeScore =
    predictions.not_interested_score * ENGAGEMENT_WEIGHTS.not_interested +
    predictions.skip_score * ENGAGEMENT_WEIGHTS.skip +
    predictions.block_author_score * ENGAGEMENT_WEIGHTS.block_author +
    predictions.mute_author_score * ENGAGEMENT_WEIGHTS.mute_author +
    predictions.report_score * ENGAGEMENT_WEIGHTS.report;

  const rawScore = corePositive + extendedPositive + negativeScore;

  // Normalize to 0-100 scale
  // Max possible positive: ~7 (all predictions at 1.0)
  // Min possible with negatives: ~-5
  // Range: -5 to 7, normalize to 0-100
  const normalizedScore = ((rawScore + 5) / 12) * 100;

  return Math.max(0, Math.min(100, Math.round(normalizedScore)));
}

// ============================================================================
// DETAILED SCORE BREAKDOWN (For UI display)
// ============================================================================

export interface XAlgorithmScore {
  // Overall
  total: number;

  // Breakdown by category (0-20 each, total 100)
  hook_strength: number;
  engagement_potential: number;
  viral_potential: number;
  algorithm_fit: number;
  content_quality: number;

  // Detailed predictions
  predictions: EngagementPredictions;

  // Analysis
  features: ContentFeatures;

  // Reasoning
  strengths: string[];
  improvements: string[];
}

/**
 * Generate comprehensive X Algorithm score with breakdown
 */
export function generateXAlgorithmScore(
  content: string,
  context?: {
    isThread?: boolean;
    isReply?: boolean;
    isQuote?: boolean;
    hasMedia?: boolean;
    personaMatch?: number; // 0-1 from AI
  }
): XAlgorithmScore {
  const features = analyzeContentFeatures(content, context);
  const predictions = predictEngagement(features, content);
  const weightedScore = calculateWeightedScore(predictions);

  // Calculate category scores (0-20 each, total 100)

  // Hook Strength (0-20 points)
  let hookStrength = 10;
  if (features.hasStrongHook) hookStrength += 5;
  if (features.hookType === 'question') hookStrength += 2;
  if (features.hookType === 'data') hookStrength += 2;
  if (features.hookType === 'contrarian') hookStrength += 3;
  if (features.curiosityGap) hookStrength += 3;
  hookStrength = Math.min(20, hookStrength);

  // Engagement Potential (0-20 points)
  let engagementPotential = 10 + Math.round(
    (predictions.reply_score + predictions.quote_score + predictions.repost_score) / 3 * 10
  );
  engagementPotential = Math.min(20, engagementPotential);

  // Viral Potential (0-20 points)
  let viralPotential = 8 + Math.round(
    (predictions.repost_score * 0.4 + predictions.share_score * 0.3 + predictions.bookmark_score * 0.3) * 12
  );
  viralPotential = Math.min(20, viralPotential);

  // Algorithm Fit (0-20 points)
  let algorithmFit = 10;
  if (features.isOptimalLength) algorithmFit += 3;
  if (features.hasEmoji) algorithmFit += 2;
  if (features.hasHashtag) algorithmFit += 1;
  if (features.hasLineBreaks) algorithmFit += 2;
  if (predictions.dwell_score > 0.6) algorithmFit += 2;
  algorithmFit = Math.min(20, Math.round(algorithmFit));

  // Content Quality (0-20 points)
  let contentQuality = 10;
  if (features.hasNumbers) contentQuality += 2;
  if (features.sentenceCount >= 2 && features.sentenceCount <= 4) contentQuality += 2;
  if (features.avgSentenceLength >= 30 && features.avgSentenceLength <= 80) contentQuality += 2;
  // Fix: Check for undefined/null explicitly to allow personaMatch: 0
  if (context?.personaMatch !== undefined && context.personaMatch !== null) {
    contentQuality += Math.round(context.personaMatch * 4);
  }
  contentQuality = Math.min(20, contentQuality);

  // Generate insights
  const strengths: string[] = [];
  const improvements: string[] = [];

  if (features.hasStrongHook) {
    strengths.push(`Güçlü ${features.hookType} hook'u dikkat çekiyor`);
  } else {
    improvements.push("Daha güçlü bir açılış hook'u ekleyin");
  }

  if (predictions.reply_score > 0.7) {
    strengths.push("Yüksek yanıt alma potansiyeli");
  }

  if (predictions.repost_score > 0.6) {
    strengths.push("Retweet potansiyeli yüksek");
  } else {
    improvements.push("Paylaşılabilirliği artırmak için veri/rakam ekleyin");
  }

  if (features.hasQuestion) {
    strengths.push("Soru formatı etkileşimi artırır");
  } else {
    improvements.push("Bir soru ekleyerek etkileşimi artırabilirsiniz");
  }

  if (!features.isOptimalLength) {
    improvements.push(
      features.charCount < 100
        ? "Tweet biraz daha uzun olabilir (100-280 karakter ideal)"
        : "Tweet biraz kısaltılabilir"
    );
  }

  if (features.curiosityGap) {
    strengths.push("Merak açığı oluşturulmuş - tıklama oranı yüksek olacak");
  }

  if (predictions.not_interested_score > 0.3) {
    improvements.push("İçerik daha ilgi çekici hale getirilebilir");
  }

  return {
    total: weightedScore,
    hook_strength: hookStrength,
    engagement_potential: engagementPotential,
    viral_potential: viralPotential,
    algorithm_fit: algorithmFit,
    content_quality: contentQuality,
    predictions,
    features,
    strengths: strengths.slice(0, 3),
    improvements: improvements.slice(0, 3),
  };
}

// ============================================================================
// AUTHOR DIVERSITY SCORER (For threads)
// ============================================================================

/**
 * Apply diversity decay to thread tweets
 * Based on X's author_diversity_scorer.rs
 *
 * Formula: multiplier(position) = (1 - floor) × decay_factor^position + floor
 */
export function applyDiversityDecay(
  scores: number[],
  decayFactor: number = 0.85,
  floor: number = 0.3
): number[] {
  return scores.map((score, position) => {
    if (position === 0) return score; // First tweet gets full score

    const multiplier = (1 - floor) * Math.pow(decayFactor, position) + floor;
    return Math.round(score * multiplier);
  });
}

/**
 * Calculate thread total score with diversity consideration
 */
export function calculateThreadScore(tweetScores: XAlgorithmScore[]): {
  totalScore: number;
  adjustedScores: number[];
  hookScore: number;
  averageEngagement: number;
} {
  const rawScores = tweetScores.map(s => s.total);
  const adjustedScores = applyDiversityDecay(rawScores);

  // Hook tweet (first) is weighted more heavily
  const hookScore = tweetScores[0]?.hook_strength || 0;

  // Average engagement across thread
  const averageEngagement = tweetScores.reduce(
    (sum, s) => sum + s.engagement_potential, 0
  ) / tweetScores.length;

  // Total score: weighted average with hook bonus
  const totalScore = Math.round(
    (adjustedScores.reduce((a, b) => a + b, 0) / adjustedScores.length) * 0.7 +
    hookScore * 1.5 + // Hook bonus
    averageEngagement * 0.5
  );

  return {
    totalScore: Math.min(100, totalScore),
    adjustedScores,
    hookScore,
    averageEngagement,
  };
}

