// Toxic/negative word patterns (Turkish + English)
const TOXIC_PATTERNS = [
  // Offensive language
  /\b(aptal|salak|mal|gerizekalı|idiot|stupid|dumb|moron)\b/gi,
  // Aggressive language
  /\b(öldür|gebertir|kill|die|hate|nefret)\b/gi,
  // Profanity indicators (mild check)
  /\b(s[ıi]kt[ıi]r|bok|shit|fuck|damn)\b/gi,
];

const POSITIVE_PATTERNS = [
  // Achievement/Success
  /\b(başardı|kazandı|harika|muhteşem|mükemmel|amazing|awesome|incredible|success|won|achieved)\b/gi,
  // Gratitude
  /\b(teşekkür|minnettar|grateful|thanks|appreciate)\b/gi,
  // Excitement
  /\b(heyecanlı|mutlu|sevinçli|excited|happy|thrilled|love)\b/gi,
  // Inspiration
  /\b(ilham|motivasyon|inspire|motivated|dream)\b/gi,
];

const NEGATIVE_PATTERNS = [
  // Disappointment
  /\b(hayal kırıklığı|üzgün|disappointed|sad|unfortunately|sadly)\b/gi,
  // Frustration
  /\b(sinir|kızgın|angry|frustrated|annoyed|irritated)\b/gi,
  // Complaint
  /\b(şikayet|sorun|problem|issue|complaint|broken|terrible)\b/gi,
];

export interface SentimentAnalysis {
  // Overall sentiment score (-1 to 1)
  score: number;
  // Sentiment label
  label: 'positive' | 'negative' | 'neutral';
  // Confidence (0-1)
  confidence: number;
  // Toxicity risk (0-1)
  toxicityRisk: number;
  // Detected patterns
  positiveWords: string[];
  negativeWords: string[];
  toxicWords: string[];
  // Recommendation
  recommendation: string;
}

/**
 * Analyze sentiment of tweet content
 */
export function analyzeSentiment(content: string): SentimentAnalysis {
  const lowerContent = content.toLowerCase();

  // Find matches
  const positiveMatches: string[] = [];
  const negativeMatches: string[] = [];
  const toxicMatches: string[] = [];

  POSITIVE_PATTERNS.forEach(pattern => {
    const matches = lowerContent.match(pattern);
    if (matches) positiveMatches.push(...matches);
  });

  NEGATIVE_PATTERNS.forEach(pattern => {
    const matches = lowerContent.match(pattern);
    if (matches) negativeMatches.push(...matches);
  });

  TOXIC_PATTERNS.forEach(pattern => {
    const matches = lowerContent.match(pattern);
    if (matches) toxicMatches.push(...matches);
  });

  // Calculate scores
  const positiveScore = positiveMatches.length * 0.3;
  const negativeScore = negativeMatches.length * 0.3;
  const toxicScore = toxicMatches.length * 0.5;

  // Overall sentiment (-1 to 1)
  let rawScore = positiveScore - negativeScore - toxicScore;
  rawScore = Math.max(-1, Math.min(1, rawScore));

  // Toxicity risk (0-1)
  const toxicityRisk = Math.min(1, toxicMatches.length * 0.4);

  // Determine label
  let label: 'positive' | 'negative' | 'neutral' = 'neutral';
  if (rawScore > 0.2) label = 'positive';
  else if (rawScore < -0.2 || toxicityRisk > 0.3) label = 'negative';

  // Confidence based on word count
  const totalWords = content.split(/\s+/).length;
  const detectedWords = positiveMatches.length + negativeMatches.length + toxicMatches.length;
  const confidence = Math.min(1, detectedWords / Math.max(totalWords * 0.2, 1));

  // Generate recommendation
  let recommendation = '';
  if (toxicityRisk > 0.3) {
    recommendation = 'Dikkat: Toksik içerik algılandı. Bu tweet block/report riskine sahip.';
  } else if (label === 'negative') {
    recommendation = 'Negatif ton algılandı. Daha yapıcı bir dil düşünün.';
  } else if (label === 'positive') {
    recommendation = 'Pozitif ton - engagement için iyi!';
  } else {
    recommendation = 'Nötr ton. Daha duygusal bağ kurmak için pozitif kelimeler ekleyebilirsiniz.';
  }

  return {
    score: rawScore,
    label,
    confidence,
    toxicityRisk,
    positiveWords: [...new Set(positiveMatches)],
    negativeWords: [...new Set(negativeMatches)],
    toxicWords: [...new Set(toxicMatches)],
    recommendation,
  };
}

