// FAZ 3: HASHTAG QUALITY CHECK
// ============================================================================

export interface HashtagAnalysis {
  // Found hashtags
  hashtags: string[];
  // Count
  count: number;
  // Quality score (0-100)
  qualityScore: number;
  // Is optimal count (1-2 ideal for X)
  isOptimalCount: boolean;
  // Issues found
  issues: string[];
  // Recommendations
  recommendations: string[];
}

// Common low-quality hashtag patterns
const LOW_QUALITY_HASHTAG_PATTERNS = [
  /^#(follow|followme|like|likeforlike|f4f|l4l|followback)$/i,
  /^#(instagood|photooftheday|picoftheday|instadaily)$/i, // Instagram-specific
  /^#\d+$/,  // Just numbers
];

// Overly generic hashtags
const GENERIC_HASHTAGS = [
  '#tech', '#business', '#success', '#motivation', '#life', '#love',
  '#happy', '#goals', '#money', '#entrepreneur',
];

/**
 * Analyze hashtag usage in content
 */
export function analyzeHashtags(content: string): HashtagAnalysis {
  const hashtagRegex = /#[\wğüşıöçĞÜŞİÖÇ]+/g;
  const hashtags = content.match(hashtagRegex) || [];
  const count = hashtags.length;

  const issues: string[] = [];
  const recommendations: string[] = [];
  let qualityDeduction = 0;

  // Check count (X algorithm penalizes 3+ hashtags)
  const isOptimalCount = count >= 0 && count <= 2;

  if (count === 0) {
    recommendations.push('Konuyla ilgili 1-2 hashtag eklemek erişimi artırabilir');
  } else if (count > 3) {
    issues.push(`${count} hashtag çok fazla - X algoritması bunu spam olarak değerlendiriyor`);
    qualityDeduction += 30;
  } else if (count === 3) {
    issues.push('3 hashtag sınırda - 1-2 hashtag daha etkili');
    qualityDeduction += 10;
  }

  // Check for low-quality hashtags
  hashtags.forEach(tag => {
    const isLowQuality = LOW_QUALITY_HASHTAG_PATTERNS.some(p => p.test(tag));
    if (isLowQuality) {
      issues.push(`"${tag}" spam hashtag - kaçının`);
      qualityDeduction += 15;
    }

    const isGeneric = GENERIC_HASHTAGS.includes(tag.toLowerCase());
    if (isGeneric) {
      issues.push(`"${tag}" çok genel - daha spesifik hashtag seçin`);
      qualityDeduction += 10;
    }

    // Check hashtag length
    if (tag.length > 25) {
      issues.push(`"${tag}" çok uzun - kısa hashtagler daha etkili`);
      qualityDeduction += 5;
    }
  });

  // Generate recommendations
  if (count > 0 && issues.length === 0) {
    recommendations.push('Hashtag kullanımı optimal!');
  }

  if (count > 2) {
    recommendations.push('En alakalı 1-2 hashtagi tutun, diğerlerini kaldırın');
  }

  const qualityScore = Math.max(0, 100 - qualityDeduction);

  return {
    hashtags,
    count,
    qualityScore,
    isOptimalCount,
    issues,
    recommendations,
  };
}

