// ============================================================================

export interface PostingTimeRecommendation {
  // Current time info
  currentHour: number;
  currentDay: string;
  timezone: string;

  // Is current time optimal?
  isOptimalNow: boolean;

  // Score for current time (0-100)
  currentTimeScore: number;

  // Best times today
  bestTimesToday: string[];

  // Best days of week
  bestDays: string[];

  // Recommendation message
  recommendation: string;

  // Detailed schedule
  schedule: {
    day: string;
    times: { hour: string; score: number; label: string }[];
  }[];
}

// Turkey timezone engagement data (based on X analytics patterns)
const TURKEY_ENGAGEMENT_HOURS: Record<number, number> = {
  // Hour: Score (0-100)
  0: 20, 1: 15, 2: 10, 3: 8, 4: 5, 5: 10,
  6: 25, 7: 40, 8: 70, 9: 85, // Morning peak
  10: 80, 11: 75, 12: 85, 13: 80, // Lunch peak
  14: 70, 15: 65, 16: 60, 17: 70,
  18: 80, 19: 90, 20: 95, 21: 90, // Evening peak (BEST)
  22: 75, 23: 50,
};

// Day of week multipliers
const DAY_MULTIPLIERS: Record<string, number> = {
  'Pazartesi': 0.9,
  'Salı': 1.0,
  'Çarşamba': 1.0,
  'Perşembe': 1.05,
  'Cuma': 0.95,
  'Cumartesi': 0.85,
  'Pazar': 0.8,
};

const DAY_NAMES_TR = ['Pazar', 'Pazartesi', 'Salı', 'Çarşamba', 'Perşembe', 'Cuma', 'Cumartesi'];

/**
 * Get optimal posting time recommendations for Turkey timezone
 */
export function getPostingTimeRecommendation(): PostingTimeRecommendation {
  // Get Turkey time using Intl.DateTimeFormat for accurate timezone handling
  const now = new Date();

  // Use Intl API for reliable timezone conversion (handles DST correctly)
  const turkeyFormatter = new Intl.DateTimeFormat('en-US', {
    timeZone: 'Europe/Istanbul',
    hour: 'numeric',
    hour12: false,
    weekday: 'short'
  });

  const parts = turkeyFormatter.formatToParts(now);
  const hourPart = parts.find(p => p.type === 'hour');
  const dayPart = parts.find(p => p.type === 'weekday');

  const currentHour = hourPart ? parseInt(hourPart.value, 10) : now.getHours();

  // Map English weekday to day index
  const dayMap: Record<string, number> = { 'Sun': 0, 'Mon': 1, 'Tue': 2, 'Wed': 3, 'Thu': 4, 'Fri': 5, 'Sat': 6 };
  const currentDayIndex = dayPart ? (dayMap[dayPart.value] ?? now.getDay()) : now.getDay();
  const currentDay = DAY_NAMES_TR[currentDayIndex];

  // Calculate current time score
  const baseScore = TURKEY_ENGAGEMENT_HOURS[currentHour] || 50;
  const dayMultiplier = DAY_MULTIPLIERS[currentDay] || 1.0;
  const currentTimeScore = Math.round(baseScore * dayMultiplier);

  // Is optimal now? (score > 75)
  const isOptimalNow = currentTimeScore >= 75;

  // Find best times today
  const bestTimesToday: string[] = [];
  Object.entries(TURKEY_ENGAGEMENT_HOURS)
    .filter(([_, score]) => score * dayMultiplier >= 80)
    .sort((a, b) => b[1] - a[1])
    .slice(0, 4)
    .forEach(([hour]) => {
      const h = parseInt(hour);
      bestTimesToday.push(`${h.toString().padStart(2, '0')}:00`);
    });

  // Best days
  const bestDays = Object.entries(DAY_MULTIPLIERS)
    .sort((a, b) => b[1] - a[1])
    .slice(0, 3)
    .map(([day]) => day);

  // Generate recommendation
  let recommendation = '';
  if (isOptimalNow) {
    recommendation = `Şu an paylaşım için iyi bir zaman! (Skor: ${currentTimeScore}/100)`;
  } else if (currentTimeScore >= 60) {
    recommendation = `Orta seviye engagement bekleniyor. Daha iyi sonuç için ${bestTimesToday[0]} saatini deneyin.`;
  } else {
    recommendation = `Şu an engagement düşük olabilir. En iyi saatler: ${bestTimesToday.slice(0, 2).join(', ')}`;
  }

  // Generate weekly schedule
  const schedule = DAY_NAMES_TR.slice(1).concat(DAY_NAMES_TR[0]).map(day => {
    const mult = DAY_MULTIPLIERS[day] || 1.0;
    const times = [8, 12, 19, 20, 21].map(hour => ({
      hour: `${hour.toString().padStart(2, '0')}:00`,
      score: Math.round(TURKEY_ENGAGEMENT_HOURS[hour] * mult),
      label: TURKEY_ENGAGEMENT_HOURS[hour] * mult >= 80 ? 'Optimal' :
             TURKEY_ENGAGEMENT_HOURS[hour] * mult >= 60 ? 'İyi' : 'Düşük',
    }));
    return { day, times };
  });

  return {
    currentHour,
    currentDay,
    timezone: 'Europe/Istanbul (UTC+3)',
    isOptimalNow,
    currentTimeScore,
    bestTimesToday,
    bestDays,
    recommendation,
    schedule,
  };
}

// ============================================================================
// FAZ 3: COMPREHENSIVE CONTENT ANALYSIS (Combines all Faz 3 features)
// ============================================================================

export interface ContentAnalysisResult {
  // X Algorithm Score (Faz 1-2)
  xScore: XAlgorithmScore;

  // Sentiment Analysis (Faz 3)
  sentiment: SentimentAnalysis;

  // Hashtag Analysis (Faz 3)
  hashtags: HashtagAnalysis;

  // Posting Time (Faz 3)
  postingTime: PostingTimeRecommendation;

  // Overall recommendations
  topRecommendations: string[];

  // Risk alerts
  alerts: string[];
}

/**
 * Comprehensive content analysis with all Faz 1-3 features
 */
export function analyzeContentComprehensive(
  content: string,
  context?: {
    isThread?: boolean;
    isReply?: boolean;
    isQuote?: boolean;
    hasMedia?: boolean;
    personaMatch?: number;
  }
): ContentAnalysisResult {
  // Get all analyses
  const xScore = generateXAlgorithmScore(content, context);
  const sentiment = analyzeSentiment(content);
  const hashtags = analyzeHashtags(content);
  const postingTime = getPostingTimeRecommendation();

  // Compile top recommendations
  const topRecommendations: string[] = [];
  const alerts: string[] = [];

  // From X Score
  xScore.improvements.slice(0, 2).forEach(i => topRecommendations.push(i));

  // From Sentiment
  if (sentiment.toxicityRisk > 0.3) {
    alerts.push(`⚠️ Toxicity Risk: ${sentiment.recommendation}`);
  } else if (sentiment.label === 'negative') {
    topRecommendations.push(sentiment.recommendation);
  }

  // From Hashtags
  if (!hashtags.isOptimalCount) {
    topRecommendations.push(hashtags.recommendations[0] || 'Hashtag sayısını optimize edin');
  }
  hashtags.issues.slice(0, 1).forEach(i => alerts.push(`#️⃣ ${i}`));

  // From Posting Time
  if (!postingTime.isOptimalNow && postingTime.currentTimeScore < 60) {
    topRecommendations.push(`⏰ ${postingTime.recommendation}`);
  }

  return {
    xScore,
    sentiment,
    hashtags,
    postingTime,
    topRecommendations: topRecommendations.slice(0, 5),
    alerts,
  };
}

// ============================================================================
// DATA-DRIVEN SCORING ENHANCEMENT (Scraper Integration)
// ============================================================================

const SCRAPER_API_URL = typeof window !== 'undefined'
  ? (window as unknown as { __SCRAPER_API_URL?: string }).__SCRAPER_API_URL || 'http://localhost:3001'
  : 'http://localhost:3001';

let cachedPatternWeights: Record<string, number> | null = null;
let patternWeightsCacheTime = 0;

export async function fetchPatternWeights(): Promise<Record<string, number> | null> {
  const now = Date.now();
  if (cachedPatternWeights && now - patternWeightsCacheTime < 5 * 60 * 1000) {
    return cachedPatternWeights;
  }

  try {
    const res = await fetch(`${SCRAPER_API_URL}/api/patterns`, { signal: AbortSignal.timeout(3000) });
    if (!res.ok) return null;
    const data = await res.json();
    if (data.success && data.data) {
      const weights: Record<string, number> = {};
      data.data.forEach((p: { pattern: string; avgEngagement: number }) => {
        weights[p.pattern] = p.avgEngagement;
      });
      cachedPatternWeights = weights;
      patternWeightsCacheTime = now;
      return weights;
    }
  } catch {
    // Scraper offline - use rule-based system
  }
  return null;
}

