/**
 * Safe localStorage wrapper with error handling and quota management
 */

const STORAGE_WARNING_THRESHOLD = 0.9; // Warn when 90% full

/**
 * Safely get item from localStorage
 * Returns null if localStorage is unavailable or on error
 */
export function safeGetItem(key: string): string | null {
  if (typeof window === "undefined") return null;

  try {
    return localStorage.getItem(key);
  } catch (error) {
    console.error(`localStorage getItem failed for key "${key}":`, error);
    return null;
  }
}

/**
 * Safely set item in localStorage
 * Returns true on success, false on failure
 * Handles quota exceeded errors gracefully
 */
export function safeSetItem(key: string, value: string): boolean {
  if (typeof window === "undefined") return false;

  try {
    localStorage.setItem(key, value);
    return true;
  } catch (error) {
    if (error instanceof DOMException) {
      if (error.name === "QuotaExceededError" || error.code === 22) {
        console.error("localStorage quota exceeded. Consider clearing old data.");
        // Optionally dispatch event for UI notification
        if (typeof window !== "undefined") {
          window.dispatchEvent(new CustomEvent("storage-quota-exceeded", {
            detail: { key, size: value.length }
          }));
        }
      }
    }
    console.error(`localStorage setItem failed for key "${key}":`, error);
    return false;
  }
}

/**
 * Safely remove item from localStorage
 * Returns true on success, false on failure
 */
export function safeRemoveItem(key: string): boolean {
  if (typeof window === "undefined") return false;

  try {
    localStorage.removeItem(key);
    return true;
  } catch (error) {
    console.error(`localStorage removeItem failed for key "${key}":`, error);
    return false;
  }
}

/**
 * Safely parse JSON from localStorage
 * Returns fallback value on error
 */
export function safeGetJSON<T>(key: string, fallback: T): T {
  const value = safeGetItem(key);
  if (value === null) return fallback;

  try {
    const parsed = JSON.parse(value);
    return parsed as T;
  } catch (error) {
    console.error(`Failed to parse JSON from localStorage key "${key}":`, error);
    return fallback;
  }
}

/**
 * Safely store JSON in localStorage
 * Returns true on success, false on failure
 */
export function safeSetJSON<T>(key: string, value: T): boolean {
  try {
    const serialized = JSON.stringify(value);
    return safeSetItem(key, serialized);
  } catch (error) {
    console.error(`Failed to serialize JSON for localStorage key "${key}":`, error);
    return false;
  }
}

/**
 * Get estimated localStorage usage
 * Returns object with used bytes, total estimated capacity, and percentage
 */
export function getStorageUsage(): { used: number; estimated: number; percentage: number } | null {
  if (typeof window === "undefined") return null;

  try {
    let used = 0;
    for (let i = 0; i < localStorage.length; i++) {
      const key = localStorage.key(i);
      if (key) {
        const value = localStorage.getItem(key);
        if (value) {
          // Each character is 2 bytes in JavaScript strings (UTF-16)
          used += (key.length + value.length) * 2;
        }
      }
    }

    // Most browsers have 5-10MB limit, assume 5MB conservatively
    const estimated = 5 * 1024 * 1024;
    const percentage = (used / estimated) * 100;

    return { used, estimated, percentage };
  } catch (error) {
    console.error("Failed to calculate storage usage:", error);
    return null;
  }
}

/**
 * Check if storage is near capacity
 */
export function isStorageNearCapacity(): boolean {
  const usage = getStorageUsage();
  if (!usage) return false;
  return usage.percentage >= STORAGE_WARNING_THRESHOLD * 100;
}

/**
 * Clear all items with a specific prefix from localStorage
 * Useful for clearing app-specific data without affecting other apps
 */
export function clearStorageByPrefix(prefix: string): number {
  if (typeof window === "undefined") return 0;

  try {
    const keysToRemove: string[] = [];
    for (let i = 0; i < localStorage.length; i++) {
      const key = localStorage.key(i);
      if (key && key.startsWith(prefix)) {
        keysToRemove.push(key);
      }
    }

    keysToRemove.forEach(key => localStorage.removeItem(key));
    return keysToRemove.length;
  } catch (error) {
    console.error(`Failed to clear storage by prefix "${prefix}":`, error);
    return 0;
  }
}

