'use client';

import { useState } from 'react';
import { copyToClipboard } from '@/lib/utils';

interface CopyButtonProps {
  text: string;
  variant?: 'primary' | 'secondary' | 'ghost';
  colorScheme?: 'red' | 'purple' | 'amber' | 'cyan' | 'green' | 'gray';
  size?: 'sm' | 'md';
  className?: string;
  label?: string;
}

const colorClasses = {
  red: {
    primary: 'bg-red-500 hover:bg-red-600 text-white',
    secondary: 'bg-red-500/20 hover:bg-red-500/30 text-red-400 border border-red-500/30',
    ghost: 'hover:bg-red-500/10 text-red-400',
  },
  purple: {
    primary: 'bg-purple-500 hover:bg-purple-600 text-white',
    secondary: 'bg-purple-500/20 hover:bg-purple-500/30 text-purple-400 border border-purple-500/30',
    ghost: 'hover:bg-purple-500/10 text-purple-400',
