    secondary: 'bg-amber-500/20 hover:bg-amber-500/30 text-amber-400 border border-amber-500/30',
    ghost: 'hover:bg-amber-500/10 text-amber-400',
  },
  cyan: {
    primary: 'bg-cyan-500 hover:bg-cyan-600 text-white',
    secondary: 'bg-cyan-500/20 hover:bg-cyan-500/30 text-cyan-400 border border-cyan-500/30',
    ghost: 'hover:bg-cyan-500/10 text-cyan-400',
