'use client';

import { getScoreColor, getCategoryColor, formatScore } from '@/lib/utils';

interface ScoreDisplayProps {
  score: number;
  maxScore?: number;
  label?: string;
  icon?: string;
  showBar?: boolean;
  size?: 'sm' | 'md' | 'lg';
  colorScheme?: 'auto' | 'green' | 'yellow' | 'red';
}

const sizeClasses = {
  sm: {
    container: 'text-xs',
    score: 'text-sm font-medium',
    bar: 'h-1',
  },
  md: {
    container: 'text-sm',
    score: 'text-base font-semibold',
    bar: 'h-1.5',
  },
  lg: {
    container: 'text-base',
    score: 'text-lg font-bold',
    bar: 'h-2',
  },
};

export default function ScoreDisplay({
  score,
  maxScore = 20,
  label,
  icon,
  showBar = true,
  size = 'sm',
  colorScheme = 'auto',
}: ScoreDisplayProps) {
  const percentage = (score / maxScore) * 100;
  const textColor = colorScheme === 'auto' ? getScoreColor(score, maxScore) : `text-${colorScheme}-400`;
  const barColor = colorScheme === 'auto' ? getCategoryColor(score, maxScore) : `bg-${colorScheme}-500`;
  const classes = sizeClasses[size];

  return (
    <div className={`${classes.container}`}>
      <div className="flex items-center justify-between mb-1">
        <div className="flex items-center gap-1.5">
          {icon && <span aria-hidden="true">{icon}</span>}
          {label && <span className="text-gray-400">{label}</span>}
        </div>
        <span className={`${classes.score} ${textColor}`}>
          {formatScore(score)}/{maxScore}
        </span>
      </div>
      {showBar && (
        <div className="w-full bg-gray-700/50 rounded-full overflow-hidden">
          <div
            className={`${classes.bar} ${barColor} rounded-full transition-all duration-500`}
            style={{ width: `${Math.min(percentage, 100)}%` }}
            role="progressbar"
            aria-valuenow={score}
            aria-valuemin={0}
            aria-valuemax={maxScore}
            aria-label={label ? `${label}: ${formatScore(score)}/${maxScore}` : undefined}
          />
        </div>
      )}
    </div>
  );
}

