'use client';

import type { XAlgorithmScore } from '@/types';
import { getTotalScoreGradient, getScoreBgColor, SCORE_CATEGORIES, ENGAGEMENT_LABELS, formatScore } from '@/lib/utils';
import ScoreDisplay from './ScoreDisplay';

interface XAlgorithmScoreCardProps {
  xScore: XAlgorithmScore;
  variant?: 'full' | 'compact' | 'minimal';
  showPredictions?: boolean;
  showStrengths?: boolean;
  showImprovements?: boolean;
}

export default function XAlgorithmScoreCard({
  xScore,
  variant = 'full',
  showPredictions = true,
  showStrengths = true,
  showImprovements = true,
}: XAlgorithmScoreCardProps) {
  const gradientClass = getTotalScoreGradient(xScore.total);
  const bgClass = getScoreBgColor(xScore.total);

  if (variant === 'minimal') {
    return (
      <div className={`inline-flex items-center gap-2 px-3 py-1.5 rounded-lg border ${bgClass}`}>
        <span className="text-xs text-gray-400">X Skor</span>
        <span className={`font-bold bg-gradient-to-r ${gradientClass} bg-clip-text text-transparent`}>
          {formatScore(xScore.total)}
        </span>
      </div>
    );
  }

  return (
    <div className="space-y-4">
      {/* Total Score Header */}
      <div className="flex items-center justify-between">
        <div className="flex items-center gap-2">
          <div className={`w-10 h-10 rounded-xl bg-gradient-to-br ${gradientClass} flex items-center justify-center shadow-lg`}>
            <span className="text-white font-bold text-sm">{formatScore(xScore.total)}</span>
          </div>
          <div>
            <p className="text-xs text-gray-400">X Algoritma Skoru</p>
            <p className={`text-sm font-medium bg-gradient-to-r ${gradientClass} bg-clip-text text-transparent`}>
              {xScore.total >= 80 ? 'Mukemmel' : xScore.total >= 60 ? 'Iyi' : 'Gelistirilebilir'}
            </p>
          </div>
        </div>
      </div>

      {/* Category Scores Grid */}
      <div className={`grid ${variant === 'compact' ? 'grid-cols-2 sm:grid-cols-3 md:grid-cols-5' : 'grid-cols-2 sm:grid-cols-3 md:grid-cols-5'} gap-3`}>
        {SCORE_CATEGORIES.map((category) => {
          const score = xScore[category.key];
          return (
            <div
              key={category.key}
              className="bg-gray-800/50 rounded-lg p-2.5 border border-gray-700/50"
            >
              <ScoreDisplay
                score={score}
                maxScore={20}
                label={category.labelTr}
                icon={category.icon}
                size="sm"
              />
            </div>
          );
        })}
      </div>

      {/* Engagement Predictions */}
      {showPredictions && variant !== 'compact' && (
        <div className="space-y-2">
          <h4 className="text-xs font-medium text-gray-400 uppercase tracking-wider">
            Tahminler
          </h4>
          <div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-6 gap-2">
            {ENGAGEMENT_LABELS.map((engagement) => {
              const score = xScore.predictions[engagement.key as keyof typeof xScore.predictions];
              if (score === undefined) return null;
              const percentage = Math.round(score * 100);
              return (
                <div
                  key={engagement.key}
                  className="bg-gray-800/30 rounded-lg p-2 text-center"
                >
                  <span className="text-lg" aria-hidden="true">{engagement.icon}</span>
                  <p className="text-xs text-gray-400 mt-1">{engagement.labelTr}</p>
                  <p className="text-sm font-medium text-gray-200">{percentage}%</p>
                </div>
              );
            })}
          </div>
        </div>
      )}

      {/* Strengths & Improvements */}
      {(showStrengths || showImprovements) && variant === 'full' && (
        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
          {showStrengths && xScore.strengths.length > 0 && (
            <div className="space-y-2">
              <h4 className="text-xs font-medium text-green-400 uppercase tracking-wider flex items-center gap-1.5">
                <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor" aria-hidden="true">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5 13l4 4L19 7" />
                </svg>
                Guclu Yanlar
              </h4>
              <ul className="space-y-1.5">
                {xScore.strengths.slice(0, 3).map((strength, i) => (
                  <li key={i} className="text-xs text-gray-300 flex items-start gap-2">
                    <span className="text-green-400 mt-0.5">+</span>
                    {strength}
                  </li>
                ))}
              </ul>
            </div>
          )}

          {showImprovements && xScore.improvements.length > 0 && (
            <div className="space-y-2">
              <h4 className="text-xs font-medium text-amber-400 uppercase tracking-wider flex items-center gap-1.5">
                <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor" aria-hidden="true">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 10V3L4 14h7v7l9-11h-7z" />
                </svg>
                Gelistirme Onerileri
              </h4>
              <ul className="space-y-1.5">
                {xScore.improvements.slice(0, 3).map((improvement, i) => (
                  <li key={i} className="text-xs text-gray-300 flex items-start gap-2">
                    <span className="text-amber-400 mt-0.5">!</span>
                    {improvement}
                  </li>
                ))}
              </ul>
            </div>
          )}
        </div>
      )}
    </div>
  );
}

