'use client';

import { useState, useEffect, useCallback } from 'react';

interface ErrorMessageProps {
  error: string | null;
  onDismiss?: () => void;
  onRetry?: () => void;
  retryAfter?: number;
  variant?: 'inline' | 'toast';
}

export default function ErrorMessage({
  error,
  onDismiss,
  onRetry,
  retryAfter,
  variant = 'inline',
}: ErrorMessageProps) {
  const [countdown, setCountdown] = useState(retryAfter || 0);
  const [canRetry, setCanRetry] = useState(!retryAfter || retryAfter <= 0);

  useEffect(() => {
    if (retryAfter && retryAfter > 0) {
      setCountdown(retryAfter);
      setCanRetry(false);
    }
  }, [retryAfter]);

  useEffect(() => {
    if (countdown <= 0) {
      setCanRetry(true);
      return;
    }

    const timer = setInterval(() => {
      setCountdown((prev) => {
        if (prev <= 1) {
          setCanRetry(true);
          return 0;
        }
        return prev - 1;
      });
    }, 1000);

    return () => clearInterval(timer);
  }, [countdown]);

  const handleRetry = useCallback(() => {
    if (canRetry && onRetry) {
      onRetry();
    }
  }, [canRetry, onRetry]);

  if (!error) return null;

  const isRateLimitError = error.toLowerCase().includes('fazla istek') ||
                           error.toLowerCase().includes('bekleyin') ||
                           countdown > 0;

  if (variant === 'toast') {
    return (
      <div
        role="alert"
        className="fixed bottom-4 right-4 z-50 bg-red-500/90 backdrop-blur-sm text-white px-4 py-3 rounded-xl shadow-lg shadow-red-500/25 flex items-center gap-3 animate-in slide-in-from-right"
      >
        <svg
          className="w-5 h-5 flex-shrink-0"
          fill="none"
          viewBox="0 0 24 24"
          stroke="currentColor"
          aria-hidden="true"
        >
          <path
            strokeLinecap="round"
            strokeLinejoin="round"
            strokeWidth={2}
            d="M12 8v4m0 4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z"
          />
        </svg>
        <span className="flex-1">{error}</span>
        {onDismiss && (
          <button
            onClick={onDismiss}
            aria-label="Hatay\u0131 kapat"
            className="p-1 hover:bg-white/20 rounded-lg transition-colors"
          >
            <svg
              className="w-4 h-4"
              fill="none"
              viewBox="0 0 24 24"
              stroke="currentColor"
              aria-hidden="true"
            >
              <path
                strokeLinecap="round"
                strokeLinejoin="round"
                strokeWidth={2}
                d="M6 18L18 6M6 6l12 12"
              />
            </svg>
          </button>
        )}
      </div>
    );
  }

  const bgColor = isRateLimitError ? 'bg-amber-500/10 border-amber-500/30' : 'bg-red-500/10 border-red-500/30';
  const textColor = isRateLimitError ? 'text-amber-400' : 'text-red-400';
  const hoverBg = isRateLimitError ? 'hover:bg-amber-500/20' : 'hover:bg-red-500/20';

  return (
    <div
      role="alert"
      className={`${bgColor} ${textColor} border px-4 py-3 rounded-xl flex flex-col gap-2`}
    >
      <div className="flex items-center gap-3">
        <svg
          className="w-5 h-5 flex-shrink-0"
          fill="none"
          viewBox="0 0 24 24"
          stroke="currentColor"
          aria-hidden="true"
        >
          {isRateLimitError ? (
            <path
              strokeLinecap="round"
              strokeLinejoin="round"
              strokeWidth={2}
              d="M12 8v4l3 3m6-3a9 9 0 11-18 0 9 9 0 0118 0z"
            />
          ) : (
            <path
              strokeLinecap="round"
              strokeLinejoin="round"
              strokeWidth={2}
              d="M12 8v4m0 4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z"
            />
          )}
        </svg>
        <span className="flex-1">{error}</span>
        {onDismiss && (
          <button
            onClick={onDismiss}
            aria-label="Hatayi kapat"
            className={`p-1 ${hoverBg} rounded-lg transition-colors`}
          >
            <svg
              className="w-4 h-4"
              fill="none"
              viewBox="0 0 24 24"
              stroke="currentColor"
              aria-hidden="true"
            >
              <path
                strokeLinecap="round"
                strokeLinejoin="round"
                strokeWidth={2}
                d="M6 18L18 6M6 6l12 12"
              />
            </svg>
          </button>
        )}
      </div>

      {/* Rate limit countdown or retry button */}
      {(countdown > 0 || onRetry) && (
        <div className="flex items-center gap-3 pl-8">
          {countdown > 0 && (
            <div className="flex items-center gap-2 text-sm">
              <div className="w-16 h-1.5 bg-gray-700 rounded-full overflow-hidden">
                <div
                  className="h-full bg-amber-500 transition-all duration-1000"
                  style={{ width: `${(countdown / (retryAfter || 60)) * 100}%` }}
                />
              </div>
              <span className="tabular-nums font-medium">{countdown}s</span>
            </div>
          )}
          {onRetry && (
            <button
              onClick={handleRetry}
              disabled={!canRetry}
              className={`text-sm font-medium px-3 py-1 rounded-lg transition-all ${
                canRetry
                  ? 'bg-green-500/20 text-green-400 hover:bg-green-500/30'
                  : 'bg-gray-700/50 text-gray-500 cursor-not-allowed'
              }`}
            >
              {canRetry ? 'Tekrar Dene' : 'Bekleyin...'}
            </button>
          )}
        </div>
      )}
    </div>
  );
}

'use client';

import { ButtonHTMLAttributes } from 'react';

interface LoadingButtonProps extends ButtonHTMLAttributes<HTMLButtonElement> {
  loading: boolean;
  loadingText?: string;
  colorScheme?: 'red' | 'purple' | 'amber' | 'cyan' | 'green';
  fullWidth?: boolean;
  onCancel?: () => void;
}

const gradientClasses = {
  red: 'from-red-500 to-rose-600 hover:from-red-600 hover:to-rose-700',
  purple: 'from-purple-500 to-violet-600 hover:from-purple-600 hover:to-violet-700',
  amber: 'from-amber-500 to-orange-600 hover:from-amber-600 hover:to-orange-700',
  cyan: 'from-cyan-500 to-blue-600 hover:from-cyan-600 hover:to-blue-700',
  green: 'from-green-500 to-emerald-600 hover:from-green-600 hover:to-emerald-700',
};

export default function LoadingButton({
  loading,
  loadingText = 'Yukleniyor...',
  colorScheme = 'red',
  fullWidth = true,
  onCancel,
  children,
  className = '',
  disabled,
  ...props
}: LoadingButtonProps) {
  if (loading && onCancel) {
    return (
      <div className={`flex gap-2 ${fullWidth ? 'w-full' : ''}`}>
        <button
          type="button"
          disabled
          aria-busy={true}
          className={`
            flex-1
            bg-gradient-to-r ${gradientClasses[colorScheme]}
            text-white font-medium py-3 px-6 rounded-xl
            shadow-lg
            opacity-80 cursor-wait
          `}
        >
          <span className="flex items-center justify-center">
            <svg
              className="animate-spin -ml-1 mr-3 h-5 w-5 text-white"
              xmlns="http://www.w3.org/2000/svg"
              fill="none"
              viewBox="0 0 24 24"
              aria-hidden="true"
            >
              <circle
                className="opacity-25"
                cx="12"
                cy="12"
                r="10"
                stroke="currentColor"
                strokeWidth="4"
              />
              <path
                className="opacity-75"
                fill="currentColor"
                d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"
              />
            </svg>
            {loadingText}
          </span>
        </button>
        <button
          type="button"
          onClick={onCancel}
          className="px-4 py-3 rounded-xl bg-gray-700 hover:bg-gray-600 text-white font-medium transition-colors"
          aria-label="Istegi iptal et"
        >
          Iptal
        </button>
      </div>
    );
  }

  return (
    <button
      {...props}
      disabled={loading || disabled}
      aria-busy={loading}
      className={`
        ${fullWidth ? 'w-full' : ''}
        bg-gradient-to-r ${gradientClasses[colorScheme]}
        text-white font-medium py-3 px-6 rounded-xl
        shadow-lg shadow-${colorScheme}-500/25
        transform transition-all duration-200
        hover:scale-[1.02] hover:shadow-xl
        disabled:opacity-70 disabled:cursor-not-allowed disabled:hover:scale-100 disabled:from-gray-500 disabled:to-gray-600
        ${className}
      `}
    >
      {loading ? (
        <span className="flex items-center justify-center">
          <svg
            className="animate-spin -ml-1 mr-3 h-5 w-5 text-white"
            xmlns="http://www.w3.org/2000/svg"
            fill="none"
            viewBox="0 0 24 24"
            aria-hidden="true"
          >
            <circle
              className="opacity-25"
              cx="12"
              cy="12"
              r="10"
              stroke="currentColor"
              strokeWidth="4"
            />
            <path
              className="opacity-75"
              fill="currentColor"
              d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"
            />
          </svg>
          {loadingText}
        </span>
      ) : (
        children
      )}
    </button>
  );
}

