"use client";

import { useState } from "react";
import { XAlgorithmScore } from "@/types";
import { copyToClipboard, getScoreColor, getCategoryColor } from "@/lib/utils";

interface ThreadTweetCardProps {
  tweet: {
    position: number;
    content: string;
    isHook?: boolean;
    xScore?: XAlgorithmScore;
  };
  index: number;
  isLast: boolean;
}

export default function ThreadTweetCard({ tweet, index, isLast }: ThreadTweetCardProps) {
  const [expanded, setExpanded] = useState(false);
  const [copied, setCopied] = useState(false);

  const handleCopy = async () => {
    const success = await copyToClipboard(tweet.content);
    if (success) {
      setCopied(true);
      setTimeout(() => setCopied(false), 2000);
    }
  };

  return (
    <div className={`relative pl-8 ${!isLast ? "pb-4" : ""}`}>
      {/* Timeline line */}
      {!isLast && (
        <div className="absolute left-3 top-8 bottom-0 w-0.5 bg-purple-500/30" aria-hidden="true" />
      )}

      {/* Timeline dot */}
      <div
        className={`absolute left-0 top-2 w-6 h-6 rounded-full flex items-center justify-center text-xs font-bold ${
          tweet.isHook
            ? "bg-gradient-to-r from-purple-500 to-pink-500 text-white"
            : "bg-gray-700 text-gray-400"
        }`}
        aria-hidden="true"
      >
        {index + 1}
      </div>

      {/* Tweet Card */}
      <div className={`bg-gray-900/50 rounded-xl p-4 border ${
        tweet.isHook ? "border-purple-500/50" : "border-gray-700/50"
      }`}>
        {/* Header */}
        <div className="flex items-center justify-between mb-2">
          <div className="flex items-center gap-2">
            {tweet.isHook && (
              <span className="inline-block bg-purple-500/20 text-purple-400 text-xs font-medium px-2 py-1 rounded">
                HOOK
              </span>
            )}
          </div>
          {tweet.xScore && (
            <div className="flex items-center gap-2">
              <span className={`text-sm font-bold ${getScoreColor(tweet.xScore.total, 100)}`}>
                X {tweet.xScore.total}
              </span>
              <button
                onClick={() => setExpanded(!expanded)}
                aria-expanded={expanded}
                aria-label={`Tweet ${index + 1} detaylarini ${expanded ? 'gizle' : 'goster'}`}
                className="text-gray-400 hover:text-purple-400 transition"
              >
                <svg
                  className={`w-4 h-4 transition-transform ${expanded ? 'rotate-180' : ''}`}
                  fill="none"
                  stroke="currentColor"
                  viewBox="0 0 24 24"
                  aria-hidden="true"
                >
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 9l-7 7-7-7" />
                </svg>
              </button>
            </div>
          )}
        </div>

        <p className="text-white whitespace-pre-wrap">{tweet.content}</p>

        {/* Expanded Score Details */}
        {tweet.xScore && expanded && (
          <div className="mt-3 bg-gray-800/50 rounded-lg p-3">
            <div className="text-xs text-gray-400 mb-2 font-medium">X Algorithm Analizi</div>
            <div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-5 gap-2 text-xs mb-3">
              {[
                { label: "Hook", key: "hook_strength" as const },
                { label: "Engage", key: "engagement_potential" as const },
                { label: "Viral", key: "viral_potential" as const },
                { label: "Algo", key: "algorithm_fit" as const },
                { label: "Kalite", key: "content_quality" as const },
              ].map((item) => (
                <div key={item.key} className="text-center">
                  <div className="text-gray-500 mb-1">{item.label}</div>
                  <div className="h-1.5 bg-gray-700 rounded-full overflow-hidden">
                    <div
                      className={`h-full ${getCategoryColor(tweet.xScore![item.key])} transition-all`}
                      style={{ width: `${(tweet.xScore![item.key] / 20) * 100}%` }}
                    />
                  </div>
                  <div className={`font-bold mt-1 ${getScoreColor(tweet.xScore![item.key], 20)}`}>
                    {tweet.xScore![item.key]}
                  </div>
                </div>
              ))}
            </div>
            <div className="flex flex-wrap gap-2 text-xs">
              <span className="px-2 py-1 bg-gray-700 rounded text-gray-400">
                {Math.round(tweet.xScore.predictions.favorite_score * 100)}%
              </span>
              <span className="px-2 py-1 bg-gray-700 rounded text-gray-400">
                {Math.round(tweet.xScore.predictions.reply_score * 100)}%
              </span>
              <span className="px-2 py-1 bg-gray-700 rounded text-gray-400">
                {Math.round(tweet.xScore.predictions.repost_score * 100)}%
              </span>
              <span className="px-2 py-1 bg-gray-700 rounded text-gray-400">
                {Math.round(tweet.xScore.predictions.bookmark_score * 100)}%
              </span>
            </div>
          </div>
        )}

        <div className="flex items-center justify-between mt-3 text-sm text-gray-500">
          <span>{tweet.content.length} karakter</span>
          <button
            onClick={handleCopy}
            aria-label={copied ? "Kopyalandi" : `Tweet ${index + 1}'i kopyala`}
            className={`flex items-center gap-1 transition ${
              copied ? "text-green-400" : "text-gray-400 hover:text-purple-400"
            }`}
          >
            {copied ? (
              <>
                <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24" aria-hidden="true">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5 13l4 4L19 7" />
                </svg>
                Kopyalandi
              </>
            ) : (
              <>
                <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24" aria-hidden="true">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M8 16H6a2 2 0 01-2-2V6a2 2 0 012-2h8a2 2 0 012 2v2m-6 12h8a2 2 0 002-2v-8a2 2 0 00-2-2h-8a2 2 0 00-2 2v8a2 2 0 002 2z" />
                </svg>
                Kopyala
              </>
            )}
          </button>
        </div>
      </div>
    </div>
  );
}

"use client";

interface ThreadStatsProps {
  hookScore: number;
  averageEngagement: number;
  totalScore: number;
}

export default function ThreadStats({ hookScore, averageEngagement, totalScore }: ThreadStatsProps) {
  return (
    <div className="bg-gray-900/50 rounded-xl p-4 border border-gray-700/50">
      <h4 className="text-sm font-semibold text-gray-300 mb-3">Thread Istatistikleri</h4>
      <div className="grid grid-cols-3 gap-4 text-center">
        <div>
          <div className="text-2xl font-bold text-purple-400">{hookScore}</div>
          <div className="text-xs text-gray-500">Hook Skoru</div>
        </div>
        <div>
          <div className="text-2xl font-bold text-cyan-400">{Math.round(averageEngagement)}</div>
          <div className="text-xs text-gray-500">Ort. Engagement</div>
        </div>
        <div>
          <div className="text-2xl font-bold text-amber-400">{totalScore}</div>
          <div className="text-xs text-gray-500">Toplam Skor</div>
        </div>
      </div>
    </div>
  );
}

