"use client";

interface ThreadAnalysisPanelProps {
  strengths: string[];
  improvements: string[];
}

export default function ThreadAnalysisPanel({ strengths, improvements }: ThreadAnalysisPanelProps) {
  if (strengths.length === 0 && improvements.length === 0) {
    return null;
  }

  return (
    <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
      {strengths.length > 0 && (
        <div className="bg-green-500/10 border border-green-500/30 rounded-xl p-4">
          <h4 className="text-sm font-semibold text-green-400 mb-2 flex items-center gap-1">
            <span aria-hidden="true">✓</span> Guclu Yonler
          </h4>
