"use client";

import { useState } from "react";
import { HistoryItem, ThreadTweet, isThreadHistory } from "@/types";
import { copyToClipboard, threadToText } from "@/lib/utils";

interface HistoryItemCardProps {
  item: HistoryItem;
  onToggleFavorite: (id: string) => void;
  onDelete: (id: string) => void;
}

const getTypeIcon = (type: string) => {
  switch (type) {
    case "tweet": return "⚡";
    case "thread": return "🧵";
    case "reply": return "💬";
    case "quote": return "🔄";
    default: return "📝";
  }
};

const getTypeLabel = (type: string) => {
  switch (type) {
    case "tweet": return "Tweet";
    case "thread": return "Thread";
    case "reply": return "Reply";
    case "quote": return "Quote";
    default: return type;
  }
};

export default function HistoryItemCard({ item, onToggleFavorite, onDelete }: HistoryItemCardProps) {
  const [copied, setCopied] = useState(false);

  const handleCopy = async () => {
    let text: string;
    if (isThreadHistory(item)) {
      text = threadToText(item.content as ThreadTweet[]);
    } else {
      text = item.content as string;
    }
    const success = await copyToClipboard(text);
    if (success) {
      setCopied(true);
      setTimeout(() => setCopied(false), 2000);
    }
  };

  return (
    <div className="bg-[#1e2028] rounded-xl p-4 border border-gray-800 hover:border-gray-700 transition-colors">
      <div className="flex items-start justify-between gap-4">
        <div className="flex-1">
          {/* Meta */}
          <div className="flex items-center gap-2 mb-2 text-sm text-gray-500 flex-wrap">
            <span className="px-2 py-0.5 bg-gray-800 rounded-full">
              {getTypeIcon(item.type)} {getTypeLabel(item.type)}
            </span>
            {item.posted && (
              <a
                href={`https://x.com/i/status/${item.tweetId}`}
                target="_blank"
                rel="noopener noreferrer"
                className="px-2 py-0.5 bg-green-900/50 text-green-400 rounded-full hover:bg-green-800/50 transition-colors"
              >
                ✓ Gönderildi
              </a>
            )}
            <span>•</span>
            <span>{item.persona}</span>
            <span>•</span>
            <span className="text-green-500">{item.score}/100</span>
            <span>•</span>
            <span>{new Date(item.createdAt).toLocaleDateString("tr-TR")}</span>
            {item.postedAt && (
              <>
                <span>•</span>
                <span className="text-green-400">
                  Gönderim: {new Date(item.postedAt).toLocaleString("tr-TR")}
                </span>
              </>
            )}
          </div>

          {/* Topic */}
          <p className="text-xs text-gray-500 mb-2">Konu: {item.topic}</p>

          {/* Content */}
          <div className="text-gray-200">
            {Array.isArray(item.content) ? (
              <div className="space-y-2">
                {(item.content as ThreadTweet[]).map((tweet, i) => (
                  <div key={i} className="pl-3 border-l-2 border-gray-700">
                    <span className="text-xs text-gray-500">{i + 1}.</span>{" "}
                    {tweet.content}
                  </div>
                ))}
              </div>
            ) : (
              <p>{item.content}</p>
            )}
          </div>
        </div>

        {/* Actions */}
        <div className="flex flex-col gap-2">
          <button
            onClick={() => onToggleFavorite(item.id)}
            aria-label={item.isFavorite ? "Favorilerden cikar" : "Favorilere ekle"}
            aria-pressed={item.isFavorite}
            className={`p-2 rounded-lg transition-colors ${
              item.isFavorite
                ? "bg-yellow-600/20 text-yellow-500"
                : "bg-gray-800 text-gray-400 hover:text-yellow-500"
            }`}
          >
            <span aria-hidden="true">{item.isFavorite ? "⭐" : "☆"}</span>
          </button>
          <button
            onClick={handleCopy}
            aria-label={copied ? "Kopyalandi" : "Kopyala"}
            className={`p-2 rounded-lg transition-colors ${
              copied
                ? "bg-green-600/20 text-green-400"
                : "bg-gray-800 hover:bg-gray-700 text-gray-400"
            }`}
          >
            <span aria-hidden="true">{copied ? "✓" : "📋"}</span>
          </button>
          <button
            onClick={() => onDelete(item.id)}
            aria-label="Sil"
            className="p-2 bg-gray-800 hover:bg-red-900/50 rounded-lg text-gray-400 hover:text-red-400 transition-colors"
          >
            <span aria-hidden="true">🗑️</span>
          </button>
        </div>
      </div>
    </div>
  );
}

