"use client";

type FilterType = "all" | "favorites" | "posted" | "unposted";

interface HistoryFiltersProps {
  filter: FilterType;
  onFilterChange: (filter: FilterType) => void;
  typeFilter: string;
  onTypeFilterChange: (type: string) => void;
}

export default function HistoryFilters({
  filter,
  onFilterChange,
  typeFilter,
  onTypeFilterChange,
}: HistoryFiltersProps) {
  return (
    <div className="flex flex-wrap gap-3 items-center" role="group" aria-label="Gecmis filtreleri">
      <div className="flex gap-2" role="tablist" aria-label="Durum filtreleri">
        <button
          onClick={() => onFilterChange("all")}
          role="tab"
          aria-selected={filter === "all"}
          aria-label="Tum gecmisi goster"
          className={`px-4 py-2 rounded-full text-sm font-medium transition-colors focus:outline-none focus:ring-2 focus:ring-blue-500/50 ${
            filter === "all"
              ? "bg-blue-600 text-white"
              : "bg-gray-800 text-gray-300 hover:bg-gray-700"
          }`}
        >
          Tümü
        </button>
        <button
          onClick={() => onFilterChange("favorites")}
          role="tab"
          aria-selected={filter === "favorites"}
          aria-label="Favori icerikleri goster"
          className={`px-4 py-2 rounded-full text-sm font-medium transition-colors focus:outline-none focus:ring-2 focus:ring-yellow-500/50 ${
            filter === "favorites"
              ? "bg-yellow-600 text-white"
              : "bg-gray-800 text-gray-300 hover:bg-gray-700"
          }`}
        >
          <span aria-hidden="true">⭐ </span>Favoriler
        </button>
        <button
          onClick={() => onFilterChange("posted")}
          role="tab"
          aria-selected={filter === "posted"}
          aria-label="Gonderilmis icerikleri goster"
          className={`px-4 py-2 rounded-full text-sm font-medium transition-colors focus:outline-none focus:ring-2 focus:ring-green-500/50 ${
            filter === "posted"
              ? "bg-green-600 text-white"
              : "bg-gray-800 text-gray-300 hover:bg-gray-700"
          }`}
        >
          <span aria-hidden="true">✓ </span>Gönderildi
        </button>
        <button
          onClick={() => onFilterChange("unposted")}
          role="tab"
          aria-selected={filter === "unposted"}
          aria-label="Gonderilmemis icerikleri goster"
          className={`px-4 py-2 rounded-full text-sm font-medium transition-colors focus:outline-none focus:ring-2 focus:ring-gray-500/50 ${
            filter === "unposted"
              ? "bg-gray-600 text-white"
              : "bg-gray-800 text-gray-300 hover:bg-gray-700"
          }`}
        >
          Gönderilmedi
        </button>
      </div>

      <select
        value={typeFilter}
        onChange={(e) => onTypeFilterChange(e.target.value)}
        aria-label="Icerik tipine gore filtrele"
        className="bg-gray-800 border border-gray-700 rounded-lg px-3 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-blue-500/50"
      >
        <option value="all">Tüm Tipler</option>
        <option value="tweet">Tweet</option>
        <option value="thread">Thread</option>
        <option value="reply">Reply</option>
        <option value="quote">Quote</option>
      </select>
    </div>
  );
}

