"use client";

import { SavedPersona } from "@/types";
import { getPersonaStats } from "@/lib/personaStorage";
import { useMemo } from "react";

interface PersonaCardProps {
  persona: SavedPersona;
  onSelect: (persona: SavedPersona) => void;
  onDelete: (id: string) => void;
  isSelected?: boolean;
}

export default function PersonaCard({
  persona,
  onSelect,
  onDelete,
  isSelected,
}: PersonaCardProps) {
  const stats = useMemo(() => getPersonaStats(persona.id), [persona.id]);

  const formatDate = (dateString: string) => {
    return new Date(dateString).toLocaleDateString("tr-TR", {
      day: "numeric",
      month: "short",
      year: "numeric",
    });
  };

  const getUsageLabel = (usage: string) => {
    const labels: Record<string, string> = {
      none: "Yok",
      minimal: "Az",
      moderate: "Orta",
      heavy: "Yoğun",
    };
    return labels[usage] || usage;
  };

  return (
    <div
      className={`bg-gray-800/50 backdrop-blur rounded-xl p-4 border transition-all cursor-pointer hover:border-emerald-500/50 ${
        isSelected
          ? "border-emerald-500 ring-2 ring-emerald-500/20"
          : "border-gray-700/50"
      }`}
      onClick={() => onSelect(persona)}
    >
      {/* Header */}
      <div className="flex items-start gap-3 mb-3">
        <div className="w-12 h-12 bg-gradient-to-br from-emerald-500 to-teal-600 rounded-full flex items-center justify-center text-white text-lg font-bold shrink-0">
          {persona.displayName.charAt(0).toUpperCase()}
        </div>
        <div className="flex-1 min-w-0">
          <h3 className="font-semibold text-white truncate">
            {persona.displayName}
          </h3>
          <p className="text-sm text-gray-400">@{persona.sourceUsername}</p>
        </div>
        <button
          onClick={(e) => {
            e.stopPropagation();
            onDelete(persona.id);
          }}
          className="p-1.5 text-gray-500 hover:text-red-400 hover:bg-red-500/10 rounded-lg transition-colors"
          title="Sil"
        >
          <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" />
          </svg>
        </button>
      </div>

      {/* Bio */}
      {persona.bio && (
        <p className="text-sm text-gray-400 mb-3 line-clamp-2">{persona.bio}</p>
      )}

      {/* Style Tags */}
      <div className="flex flex-wrap gap-1.5 mb-3">
        <span className="px-2 py-0.5 bg-emerald-500/10 text-emerald-400 text-xs rounded-full">
          {persona.styleAnalysis.tone}
        </span>
        <span className="px-2 py-0.5 bg-blue-500/10 text-blue-400 text-xs rounded-full">
          Emoji: {getUsageLabel(persona.styleAnalysis.emojiUsage)}
        </span>
        <span className="px-2 py-0.5 bg-purple-500/10 text-purple-400 text-xs rounded-full">
          ~{persona.styleAnalysis.averageLength} kar.
        </span>
      </div>

      {/* Stats */}
      <div className="grid grid-cols-3 gap-2 pt-3 border-t border-gray-700/50">
        <div className="text-center">
          <div className="text-lg font-bold text-white">{stats.totalTweets}</div>
          <div className="text-xs text-gray-500">Tweet</div>
        </div>
        <div className="text-center">
          <div className="text-lg font-bold text-emerald-400">{stats.averageScore}</div>
          <div className="text-xs text-gray-500">Ort. Skor</div>
        </div>
        <div className="text-center">
          <div className="text-lg font-bold text-amber-400">{stats.favoriteCount}</div>
          <div className="text-xs text-gray-500">Favori</div>
        </div>
      </div>

      {/* Footer */}
      <div className="mt-3 pt-3 border-t border-gray-700/50 flex items-center justify-between text-xs text-gray-500">
        <span>Analiz: {formatDate(persona.analyzedAt)}</span>
        <span>{persona.originalTweets.length} tweet analiz edildi</span>
      </div>
    </div>
  );
}

"use client";

import { SavedPersona, HistoryItem, ThreadTweet } from "@/types";
import { getTweetsByPersonaId, getTweetsByPersonaName, getPersonaStats } from "@/lib/personaStorage";
import { useMemo, useState } from "react";

interface PersonaDetailProps {
  persona: SavedPersona;
  onBack: () => void;
  onUsePersona: (persona: SavedPersona) => void;
}

export default function PersonaDetail({
  persona,
  onBack,
  onUsePersona,
}: PersonaDetailProps) {
  const [activeTab, setActiveTab] = useState<"analysis" | "original" | "generated">("analysis");

  const stats = useMemo(() => getPersonaStats(persona.id), [persona.id]);

  const generatedTweets = useMemo(() => {
    // Hem personaId hem de persona name ile ara (eski kayıtlar için)
    const byId = getTweetsByPersonaId(persona.id);
    const byName = getTweetsByPersonaName(persona.name);

    // Birleştir ve tekrarları kaldır
    const combined = [...byId];
    for (const tweet of byName) {
      if (!combined.some(t => t.id === tweet.id)) {
        combined.push(tweet);
      }
    }

    return combined.sort(
      (a, b) => new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime()
    );
  }, [persona.id, persona.name]);

  const formatDate = (dateString: string) => {
    return new Date(dateString).toLocaleDateString("tr-TR", {
      day: "numeric",
      month: "short",
      year: "numeric",
      hour: "2-digit",
      minute: "2-digit",
    });
  };

  const getUsageLabel = (usage: string) => {
    const labels: Record<string, string> = {
      none: "Hiç Kullanmaz",
      minimal: "Nadiren Kullanır",
      moderate: "Orta Düzeyde Kullanır",
      heavy: "Sık Kullanır",
    };
    return labels[usage] || usage;
  };

  const getContentPreview = (item: HistoryItem): string => {
    if (typeof item.content === "string") {
      return item.content;
    }
    // Thread ise ilk tweet'i göster
    const threads = item.content as ThreadTweet[];
    return threads[0]?.content || "";
  };

  const tabs = [
    { id: "analysis" as const, label: "Stil Analizi", icon: "📊" },
    { id: "original" as const, label: `Orijinal (${persona.originalTweets.length})`, icon: "📝" },
    { id: "generated" as const, label: `Üretilen (${generatedTweets.length})`, icon: "🤖" },
  ];

  return (
    <div className="bg-gray-800/50 backdrop-blur rounded-2xl shadow-xl border border-gray-700/50 overflow-hidden">
      {/* Header */}
      <div className="p-6 border-b border-gray-700/50">
        <button
          onClick={onBack}
          className="flex items-center gap-2 text-gray-400 hover:text-white mb-4 transition-colors"
        >
          <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 19l-7-7 7-7" />
          </svg>
          Geri
        </button>

        <div className="flex items-start gap-4">
          <div className="w-16 h-16 bg-gradient-to-br from-emerald-500 to-teal-600 rounded-full flex items-center justify-center text-white text-2xl font-bold">
            {persona.displayName.charAt(0).toUpperCase()}
          </div>
          <div className="flex-1">
            <h2 className="text-2xl font-bold text-white">{persona.displayName}</h2>
            <p className="text-gray-400">@{persona.sourceUsername}</p>
            {persona.bio && (
              <p className="mt-2 text-gray-300">{persona.bio}</p>
            )}
          </div>
          <button
            onClick={() => onUsePersona(persona)}
            className="px-4 py-2 bg-gradient-to-r from-emerald-500 to-teal-600 hover:from-emerald-600 hover:to-teal-700 text-white font-medium rounded-xl transition-all"
          >
            Bu Tarzı Kullan
          </button>
        </div>

        {/* Quick Stats */}
        <div className="grid grid-cols-4 gap-4 mt-6">
          <div className="bg-gray-900/50 rounded-xl p-3 text-center">
            <div className="text-2xl font-bold text-white">{stats.totalTweets}</div>
            <div className="text-xs text-gray-500">Üretilen Tweet</div>
          </div>
          <div className="bg-gray-900/50 rounded-xl p-3 text-center">
            <div className="text-2xl font-bold text-emerald-400">{stats.averageScore}</div>
            <div className="text-xs text-gray-500">Ort. Skor</div>
          </div>
          <div className="bg-gray-900/50 rounded-xl p-3 text-center">
            <div className="text-2xl font-bold text-amber-400">{stats.favoriteCount}</div>
            <div className="text-xs text-gray-500">Favori</div>
          </div>
          <div className="bg-gray-900/50 rounded-xl p-3 text-center">
            <div className="text-2xl font-bold text-blue-400">{stats.postedCount}</div>
            <div className="text-xs text-gray-500">Paylaşılan</div>
          </div>
        </div>
      </div>

      {/* Tabs */}
      <div className="flex border-b border-gray-700/50">
        {tabs.map((tab) => (
          <button
            key={tab.id}
            onClick={() => setActiveTab(tab.id)}
            className={`flex-1 py-3 px-4 text-sm font-medium transition-colors ${
              activeTab === tab.id
                ? "text-emerald-400 border-b-2 border-emerald-400 bg-emerald-500/5"
                : "text-gray-400 hover:text-white"
            }`}
          >
            {tab.icon} {tab.label}
          </button>
        ))}
      </div>

      {/* Tab Content */}
      <div className="p-6 max-h-[500px] overflow-y-auto">
        {activeTab === "analysis" && (
          <div className="space-y-6">
            {/* Tone & Style */}
            <div className="grid grid-cols-2 gap-4">
              <div className="bg-gray-900/50 rounded-xl p-4">
                <div className="text-sm text-gray-500 mb-1">Ton</div>
                <div className="text-lg font-medium text-white">{persona.styleAnalysis.tone}</div>
              </div>
              <div className="bg-gray-900/50 rounded-xl p-4">
                <div className="text-sm text-gray-500 mb-1">Yazım Tarzı</div>
                <div className="text-lg font-medium text-white">{persona.styleAnalysis.writingStyle}</div>
              </div>
            </div>

            {/* Usage Stats */}
            <div className="grid grid-cols-2 gap-4">
              <div className="bg-gray-900/50 rounded-xl p-4">
                <div className="text-sm text-gray-500 mb-1">Emoji Kullanımı</div>
                <div className="text-white">{getUsageLabel(persona.styleAnalysis.emojiUsage)}</div>
              </div>
              <div className="bg-gray-900/50 rounded-xl p-4">
                <div className="text-sm text-gray-500 mb-1">Hashtag Kullanımı</div>
                <div className="text-white">{getUsageLabel(persona.styleAnalysis.hashtagUsage)}</div>
              </div>
            </div>

            {/* Average Length */}
            <div className="bg-gray-900/50 rounded-xl p-4">
              <div className="text-sm text-gray-500 mb-1">Ortalama Tweet Uzunluğu</div>
              <div className="text-white">{persona.styleAnalysis.averageLength} karakter</div>
            </div>

            {/* Topics */}
            <div className="bg-gray-900/50 rounded-xl p-4">
              <div className="text-sm text-gray-500 mb-2">Konular</div>
              <div className="flex flex-wrap gap-2">
                {persona.styleAnalysis.topics.map((topic, i) => (
                  <span
                    key={i}
                    className="px-3 py-1 bg-emerald-500/10 text-emerald-400 text-sm rounded-full"
                  >
                    {topic}
                  </span>
                ))}
              </div>
            </div>

            {/* Vocabulary */}
            {persona.styleAnalysis.vocabulary && (
              <div className="bg-gray-900/50 rounded-xl p-4">
                <div className="text-sm text-gray-500 mb-1">Kelime Dağarcığı</div>
                <div className="text-gray-300">{persona.styleAnalysis.vocabulary}</div>
              </div>
            )}

            {/* Engagement Patterns */}
            {persona.styleAnalysis.engagement_patterns?.length > 0 && (
              <div className="bg-gray-900/50 rounded-xl p-4">
                <div className="text-sm text-gray-500 mb-2">Etkileşim Kalıpları</div>
                <ul className="space-y-1">
                  {persona.styleAnalysis.engagement_patterns.map((pattern, i) => (
                    <li key={i} className="text-gray-300 text-sm flex items-start gap-2">
                      <span className="text-emerald-400">-</span>
                      {pattern}
                    </li>
                  ))}
                </ul>
              </div>
            )}

            {/* Metadata */}
            <div className="text-xs text-gray-500 pt-4 border-t border-gray-700/50">
              <p>Analiz Tarihi: {formatDate(persona.analyzedAt)}</p>
              <p>Son Güncelleme: {formatDate(persona.updatedAt)}</p>
            </div>
          </div>
        )}

        {activeTab === "original" && (
          <div className="space-y-3">
            {persona.originalTweets.length === 0 ? (
              <div className="text-center py-8 text-gray-500">
                Orijinal tweet bulunamadı
              </div>
            ) : (
              persona.originalTweets.map((tweet, i) => (
                <div
                  key={i}
                  className="bg-gray-900/50 rounded-xl p-4 border-l-4 border-blue-500"
                >
                  <p className="text-gray-300 whitespace-pre-wrap">{tweet}</p>
                </div>
              ))
            )}
          </div>
        )}

        {activeTab === "generated" && (
          <div className="space-y-3">
            {generatedTweets.length === 0 ? (
              <div className="text-center py-8 text-gray-500">
                <p>Henüz bu persona ile tweet üretilmemiş</p>
                <button
                  onClick={() => onUsePersona(persona)}
                  className="mt-4 px-4 py-2 bg-emerald-500/10 text-emerald-400 rounded-lg hover:bg-emerald-500/20 transition-colors"
                >
                  Şimdi Tweet Üret
                </button>
              </div>
            ) : (
              generatedTweets.map((item) => (
                <div
                  key={item.id}
                  className="bg-gray-900/50 rounded-xl p-4 border-l-4 border-emerald-500"
                >
                  <div className="flex items-center justify-between mb-2">
                    <span className="text-xs text-gray-500">
                      {item.type === "thread" ? "Thread" : item.type === "reply" ? "Yanıt" : item.type === "quote" ? "Alıntı" : "Tweet"}
                    </span>
                    <div className="flex items-center gap-2">
                      {item.isFavorite && <span className="text-amber-400">star</span>}
                      <span className="text-xs text-emerald-400 font-medium">{item.score}/100</span>
                    </div>
                  </div>
                  <p className="text-gray-300 whitespace-pre-wrap">
                    {getContentPreview(item)}
                  </p>
                  <div className="mt-2 flex items-center justify-between text-xs text-gray-500">
                    <span>{formatDate(item.createdAt)}</span>
                    <span>{item.topic}</span>
                  </div>
                </div>
              ))
            )}
          </div>
        )}
      </div>
    </div>
  );
}

