"use client";

import { useState, useEffect, useCallback } from "react";
import { SavedPersona } from "@/types";
import { getSavedPersonas, deleteSavedPersona, exportPersonas } from "@/lib/personaStorage";
import PersonaCard from "./PersonaCard";
import PersonaDetail from "./PersonaDetail";
import { ConfirmDialog } from "@/components/ui";

interface SavedPersonasProps {
  onUsePersona: (persona: SavedPersona) => void;
  refreshKey?: number;
}

export default function SavedPersonas({ onUsePersona, refreshKey }: SavedPersonasProps) {
  const [personas, setPersonas] = useState<SavedPersona[]>([]);
  const [selectedPersona, setSelectedPersona] = useState<SavedPersona | null>(null);
  const [deleteConfirm, setDeleteConfirm] = useState<string | null>(null);
  const [searchQuery, setSearchQuery] = useState("");

  const loadPersonas = useCallback(() => {
    setPersonas(getSavedPersonas());
  }, []);

  useEffect(() => {
    loadPersonas();
  }, [loadPersonas, refreshKey]);

  const handleDelete = (id: string) => {
    setDeleteConfirm(id);
  };

  const confirmDelete = () => {
    if (deleteConfirm) {
      deleteSavedPersona(deleteConfirm);
      loadPersonas();
      if (selectedPersona?.id === deleteConfirm) {
        setSelectedPersona(null);
      }
      setDeleteConfirm(null);
    }
  };

  const handleExport = () => {
    const json = exportPersonas();
    const blob = new Blob([json], { type: "application/json" });
    const url = URL.createObjectURL(blob);
    const a = document.createElement("a");
    a.href = url;
    a.download = `personas-${new Date().toISOString().split("T")[0]}.json`;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
  };

  const filteredPersonas = personas.filter((p) => {
    if (!searchQuery) return true;
    const query = searchQuery.toLowerCase();
    return (
      p.name.toLowerCase().includes(query) ||
      p.displayName.toLowerCase().includes(query) ||
      p.sourceUsername.toLowerCase().includes(query) ||
      p.styleAnalysis.tone.toLowerCase().includes(query)
    );
  });

  // Detail view
  if (selectedPersona) {
    return (
      <PersonaDetail
        persona={selectedPersona}
        onBack={() => setSelectedPersona(null)}
        onUsePersona={onUsePersona}
      />
    );
  }

  return (
    <div className="bg-gray-800/50 backdrop-blur rounded-2xl shadow-xl p-6 border border-gray-700/50">
      {/* Header */}
      <div className="flex items-center justify-between mb-6">
        <div className="flex items-center gap-3">
          <span className="text-3xl">👤</span>
          <div>
            <h2 className="text-xl font-bold text-white">Kaydedilmiş Personalar</h2>
            <p className="text-sm text-gray-400">
              {personas.length} persona kayıtlı
            </p>
          </div>
        </div>
        {personas.length > 0 && (
          <button
            onClick={handleExport}
            className="px-3 py-1.5 text-sm text-gray-400 hover:text-white hover:bg-gray-700/50 rounded-lg transition-colors"
            title="Personaları Dışa Aktar"
          >
            Dışa Aktar
          </button>
        )}
      </div>

      {/* Search */}
      {personas.length > 0 && (
        <div className="mb-6">
          <div className="relative">
            <svg
              className="absolute left-3 top-1/2 -translate-y-1/2 w-5 h-5 text-gray-500"
              fill="none"
              stroke="currentColor"
              viewBox="0 0 24 24"
            >
              <path
                strokeLinecap="round"
                strokeLinejoin="round"
                strokeWidth={2}
                d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z"
              />
            </svg>
            <input
              type="text"
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
              placeholder="Persona ara..."
              className="w-full pl-10 pr-4 py-2.5 bg-gray-900/50 border border-gray-700 rounded-xl focus:ring-2 focus:ring-emerald-500 focus:border-transparent text-white placeholder-gray-500"
            />
          </div>
        </div>
      )}

      {/* Empty State */}
      {personas.length === 0 ? (
        <div className="text-center py-12">
          <div className="text-6xl mb-4">🔍</div>
          <h3 className="text-lg font-medium text-white mb-2">
            Henüz Persona Yok
          </h3>
          <p className="text-gray-400 mb-6">
            "Analiz" sekmesinden bir X hesabını analiz ederek persona oluşturabilirsiniz.
          </p>
        </div>
      ) : filteredPersonas.length === 0 ? (
        <div className="text-center py-12">
          <div className="text-4xl mb-4">🤷</div>
          <p className="text-gray-400">
            "{searchQuery}" ile eşleşen persona bulunamadı
          </p>
        </div>
      ) : (
        /* Persona Grid */
        <div className="grid gap-4 md:grid-cols-2">
          {filteredPersonas.map((persona) => (
            <PersonaCard
              key={persona.id}
              persona={persona}
              onSelect={setSelectedPersona}
              onDelete={handleDelete}
            />
          ))}
        </div>
      )}

      {/* Delete Confirmation */}
      <ConfirmDialog
        isOpen={!!deleteConfirm}
        onCancel={() => setDeleteConfirm(null)}
        onConfirm={confirmDelete}
        title="Persona Sil"
        message="Bu personayı silmek istediğinize emin misiniz? Bu işlem geri alınamaz."
        confirmText="Sil"
        cancelText="Vazgeç"
        variant="danger"
      />
    </div>
  );
}

